function summarizeRow(row) {
  const counts = row.indicators.reduce((acc, item) => {
    acc[item.signal] += 1;
    return acc;
  }, { buy: 0, hold: 0, sell: 0 });

  return `${row.ticker}: ${counts.buy} buy, ${counts.hold} hold, ${counts.sell} sell signals.`;
}

function countDominantSignal(row) {
  const counts = row.indicators.reduce((acc, item) => {
    acc[item.signal] += 1;
    return acc;
  }, { buy: 0, hold: 0, sell: 0 });

  if (counts.buy >= counts.hold && counts.buy >= counts.sell) return "buy";
  if (counts.sell >= counts.buy && counts.sell >= counts.hold) return "sell";
  return "hold";
}

function formatChangePercent(value) {
  if (value == null || Number.isNaN(value)) return "—";
  const numeric = Number(value);
  return `${numeric >= 0 ? "+" : ""}${numeric.toFixed(1)}%`;
}

function determineSetupAction({ score, srAnalysis, rsi14, fibPosition, price, ma20, ma50, changePercent, profile, optionsMarket }) {
  const supportDistance = srAnalysis?.supportDistancePct;
  const resistanceDistance = srAnalysis?.resistanceDistancePct;
  const supportStrength = srAnalysis?.supportStrength ?? 0;
  const resistanceStrength = srAnalysis?.resistanceStrength ?? 0;
  const riskReward = srAnalysis?.riskReward;
  const optionsRead = buildOptionsRead({ price, technicals: { optionsMarket } });

  const nearSupport = supportDistance != null && supportDistance <= 3.2;
  const atSupport = supportDistance != null && supportDistance <= 1.2;
  const nearResistance = resistanceDistance != null && resistanceDistance <= 1.6;
  const strongSupport = supportStrength >= 48;
  const strongResistance = resistanceStrength >= 62;
  const goodReward = riskReward != null && riskReward >= 1.35;
  const poorReward = riskReward != null && riskReward < 0.9;
  const extended = price > ma20 * 1.04 || rsi14 >= 65 || fibPosition >= 0.8 || changePercent >= 3.5;
  const washedOut = rsi14 <= 45 || fibPosition <= 0.4;
  const trendBroken = price < ma50 * 0.95;
  const trendHealthy = price >= ma50 * 0.98;
  const qualityName = (profile?.quality ?? 0) >= 0.55 && (profile?.growth ?? 0) >= 0.45 && (profile?.cash ?? 0) >= 0;
  const optionsSupportive = optionsRead.signal === "buy";
  const optionsCapped = optionsRead.signal === "sell";

  if (atSupport && strongSupport && washedOut && !extended && !trendBroken && qualityName && score >= 74 && !optionsCapped) {
    return "Strong Buy";
  }

  if (nearSupport && strongSupport && goodReward && washedOut && trendHealthy && score >= 58 && !optionsCapped) {
    return "Buy";
  }

  if (score >= 72 && atSupport && !extended && trendHealthy && qualityName && !optionsCapped) {
    return "Buy";
  }

  if (optionsSupportive && nearSupport && trendHealthy && score >= 55 && !extended) {
    return score >= 74 ? "Strong Buy" : "Buy";
  }

  if (nearResistance && strongResistance && extended && poorReward && score < 30) {
    return "Strong Sell";
  }

  if ((nearResistance && strongResistance && (extended || poorReward)) || (optionsCapped && nearResistance)) {
    return "Sell";
  }

  if (trendBroken && score < 20 && !nearSupport) {
    return "Short";
  }

  if (trendBroken && score < 38 && !nearSupport) {
    return "Strong Sell";
  }

  return "Hold";
}

function scoreToBand(score) {
  if (!Number.isFinite(score)) return { tone: "hold", label: localizedActionLabel("Hold") };
  if (score >= CALIBRATION_CONFIG.rating_thresholds.strong_buy) return { tone: "buy", label: t("aiRatingScaleStrongBuy") };
  if (score >= CALIBRATION_CONFIG.rating_thresholds.buy) return { tone: "buy", label: t("aiRatingScaleBuy") };
  if (score >= CALIBRATION_CONFIG.rating_thresholds.hold) return { tone: "hold", label: t("aiRatingScaleHold") };
  if (score >= CALIBRATION_CONFIG.rating_thresholds.reduce) return { tone: "sell", label: currentLanguage === "zh" ? "谨慎减仓" : "Reduce" };
  if (score >= CALIBRATION_CONFIG.rating_thresholds.sell_avoid) return { tone: "sell", label: currentLanguage === "zh" ? "卖出 / 避免" : "Sell / Avoid" };
  if (score >= CALIBRATION_CONFIG.rating_thresholds.strong_sell) return { tone: "sell", label: t("aiRatingScaleStrongSell") };
  return { tone: "sell", label: currentLanguage === "zh" ? "做空候选" : "Short Candidate" };
}

function scoreValue(score) {
  return Number.isFinite(score) ? `${Math.round(score)}${t("scoreOutOf100")}` : "—";
}

function signalToScore(signal) {
  return Math.round((signalScoreMap[signal] ?? 0.5) * 100);
}

function averageScoreFromSignals(items) {
  const valid = items.filter((item) => item && item.signal);
  if (!valid.length) return 50;
  return Math.round(valid.reduce((sum, item) => sum + signalToScore(item.signal), 0) / valid.length);
}

function countSignals(row) {
  return row.indicators.reduce((acc, item) => {
    acc[item.signal] += 1;
    return acc;
  }, { buy: 0, hold: 0, sell: 0 });
}

function buildConsensus(row) {
  const counts = countSignals(row);
  const total = Math.max(1, counts.buy + counts.hold + counts.sell);
  const dominantCount = Math.max(counts.buy, counts.hold, counts.sell);
  const confidence = Math.round((dominantCount / total) * 100);
  const dominant = dominantCount === counts.buy ? "buy" : dominantCount === counts.sell ? "sell" : "hold";
  return { counts, total, confidence, dominant };
}

function buildMainReason(row) {
  const sr = row.technicals?.srAnalysis;
  const tech = row.technicals || {};
  const optionsRead = row.research?.optionsRead || buildOptionsRead(row);
  if (row.noData) return t("noSignalReason");
  if (optionsRead.signal === "buy" && optionsRead.putWallDistancePct != null && optionsRead.putWallDistancePct <= 2.5) {
    return currentLanguage === "zh"
      ? `股价靠近 Put Wall ${formatCurrency(optionsRead.putWall, row.currencyCode)}，短线有期权支撑。`
      : `Price is close to the put wall at ${formatCurrency(optionsRead.putWall, row.currencyCode)}, which can help near-term support.`;
  }
  if (optionsRead.signal === "sell" && optionsRead.callWallDistancePct != null && optionsRead.callWallDistancePct <= 2) {
    return currentLanguage === "zh"
      ? `股价靠近 Call Wall ${formatCurrency(optionsRead.callWall, row.currencyCode)}，上方期权压力较大。`
      : `Price is close to the call wall at ${formatCurrency(optionsRead.callWall, row.currencyCode)}, which can cap near-term upside.`;
  }
  if (row.action === "Buy" && sr?.supportDistancePct != null && sr.supportDistancePct <= 3) {
    return currentLanguage === "zh" ? "股价接近支撑区，适合分批建仓。" : "Price is close to support, which favors staged accumulation.";
  }
  if (row.action === "Sell" && sr?.resistanceDistancePct != null && sr.resistanceDistancePct <= 3) {
    return currentLanguage === "zh" ? "股价接近压力区，风险收益比不理想。" : "Price is near resistance and risk/reward looks less favorable.";
  }
  if (tech.pricePressure < 0 && tech.ma200 && row.price > tech.ma200) {
    return currentLanguage === "zh" ? "长期趋势未破坏，但短线信号仍需确认。" : "The long-term trend is intact, but short-term confirmation is still missing.";
  }
  if ((row.indicatorMap?.macd?.signal || "hold") === "buy" && row.action === "Hold") {
    return currentLanguage === "zh" ? "趋势正在改善，但当前买点仍不够理想。" : "Trend is improving, but the current entry still looks suboptimal.";
  }
  return row.note || t("neutralSetup");
}

function buildProfessionalReasonLines(row) {
  const research = row.research || buildLongTermResearch(row);
  const lines = [];
  const tech = row.technicals || {};
  lines.push(`${t("stockType")}: ${research.stockTypeLabel}`);
  if (row.price != null && tech.ma200 != null) {
    lines.push(row.price >= tech.ma200
      ? (currentLanguage === "zh" ? "长期趋势仍站在 MA200 上方" : "Long-term trend remains above MA200")
      : (currentLanguage === "zh" ? "长期趋势跌破 MA200，需要更谨慎" : "Long-term trend is below MA200 and needs more caution"));
  }
  if (research.optionsRead?.available) {
    lines.push(
      research.optionsRead.signal === "buy"
        ? (currentLanguage === "zh" ? "期权墙位偏支撑，短线更利于等回踩观察" : "Options walls are more supportive, which favors buying pullbacks.")
        : research.optionsRead.signal === "sell"
          ? (currentLanguage === "zh" ? "期权墙位偏压制，短线更适合等待突破确认" : "Options walls are acting as resistance, so waiting for a breakout is cleaner.")
          : (currentLanguage === "zh" ? "期权墙位中性，仍以趋势和支撑阻力为主" : "Options walls are mixed, so trend and price levels matter more.")
    );
  }
  lines.push(`${t("longTermFit")}: ${research.longTermFit}`);
  return lines.slice(0, 3);
}

function buildDimensionScores(row) {
  const map = row.indicatorMap || {};
  const technical = averageScoreFromSignals([
    map.ema12, map.ema26, map.macd, map.rsi, map.fibonacci, map.ma20, map.ma50, map.ma200, map.upper, map.middle, map.lower,
  ]);
  const fundamental = averageScoreFromSignals([map.rev, map.eps, map.gross, map.fcf, map.roe]);

  const flowInputs = [
    map.volume,
    { signal: Number.isFinite(row.changePercent) ? (row.changePercent >= 1 ? "buy" : row.changePercent <= -1 ? "sell" : "hold") : "hold" },
    { signal: (row.technicals?.volumeRatio ?? 1) >= 1.2 ? "buy" : (row.technicals?.volumeRatio ?? 1) <= 0.85 ? "sell" : "hold" },
  ];
  const moneyFlow = averageScoreFromSignals(flowInputs);

  let riskPenalty = 0;
  if ((row.technicals?.rsi14 ?? 50) >= 70) riskPenalty += 18;
  if ((row.technicals?.rsi14 ?? 50) <= 32) riskPenalty += 10;
  if ((row.technicals?.srAnalysis?.resistanceDistancePct ?? 99) <= 2) riskPenalty += 12;
  if ((row.technicals?.srAnalysis?.supportDistancePct ?? 0) >= 6) riskPenalty += 10;
  if (row.price != null && row.technicals?.ma50 != null && row.price < row.technicals.ma50) riskPenalty += 14;
  if (row.price != null && row.technicals?.ma200 != null && row.price < row.technicals.ma200) riskPenalty += 12;
  if ((row.trailingPE ?? 0) >= 35) riskPenalty += 10;
  if ((row.forwardPE ?? 0) >= 30) riskPenalty += 6;
  if (map.fcf?.signal === "sell") riskPenalty += 12;
  if ((row.changePercent ?? 0) <= -4) riskPenalty += 12;
  const risk = clamp(100 - riskPenalty, 5, 95);

  return {
    overall: Number.isFinite(row.score) ? row.score : 50,
    technical,
    fundamental,
    moneyFlow,
    risk,
  };
}

function riskLevelFromScore(score) {
  if (score >= 70) return t("low");
  if (score >= 45) return t("moderate");
  return t("elevated");
}

function metricScore(value, low, high) {
  if (!Number.isFinite(value)) return 50;
  if (high === low) return clamp(Math.round(value), 0, 100);
  return clamp(Math.round(((value - low) / (high - low)) * 100), 0, 100);
}

function inverseMetricScore(value, low, high) {
  return 100 - metricScore(value, low, high);
}

function scoreBucketLabel(score) {
  if (score >= CALIBRATION_CONFIG.rating_thresholds.strong_buy) return "Strong Buy";
  if (score >= CALIBRATION_CONFIG.rating_thresholds.buy) return "Buy";
  if (score >= CALIBRATION_CONFIG.rating_thresholds.hold) return "Hold-Watch";
  if (score >= CALIBRATION_CONFIG.rating_thresholds.reduce) return "Reduce";
  if (score >= CALIBRATION_CONFIG.rating_thresholds.sell_avoid) return "Sell-Avoid";
  if (score >= CALIBRATION_CONFIG.rating_thresholds.strong_sell) return "Strong Sell";
  if (score >= 0) return "Short Candidate";
  return "Strong Sell";
}

function stockTypeConfig(type) {
  const configs = {
    megaCap: {
      label: t("megaCap"),
      modelLabel: t("megaCapModel"),
      weights: { fundamental: 0.35, quality: 0.3, growth: 0.15, technical: 0.1, moneyFlow: 0.1 },
    },
    growth: {
      label: t("growthType"),
      modelLabel: t("growthModel"),
      weights: { growth: 0.3, fundamental: 0.25, quality: 0.2, technical: 0.15, moneyFlow: 0.1 },
    },
    value: {
      label: t("valueType"),
      modelLabel: t("valueModel"),
      weights: { fundamental: 0.3, quality: 0.25, valuation: 0.25, growth: 0.1, technical: 0.05, moneyFlow: 0.05 },
    },
    dividend: {
      label: t("dividendType"),
      modelLabel: t("dividendModel"),
      weights: { fundamental: 0.3, quality: 0.3, valuation: 0.2, moneyFlow: 0.1, technical: 0.1 },
    },
    speculative: {
      label: t("speculativeType"),
      modelLabel: t("speculativeModel"),
      weights: { technical: 0.35, moneyFlow: 0.3, growth: 0.2, fundamental: 0.15 },
    },
    turnaround: {
      label: t("turnaroundType"),
      modelLabel: t("turnaroundModel"),
      weights: { fundamental: 0.25, quality: 0.2, growth: 0.2, technical: 0.2, moneyFlow: 0.15 },
    },
    newlyListed: {
      label: t("newlyListedType"),
      modelLabel: t("newlyListedModel"),
      weights: { technical: 0.3, moneyFlow: 0.25, growth: 0.2, fundamental: 0.15, quality: 0.1 },
    },
  };
  return configs[type] || configs.growth;
}

function buildResearchMetrics(row) {
  const profile = row.profile || profileForTicker(row.ticker);
  const map = row.indicatorMap || {};
  const revenueGrowth = map.rev?.value ?? null;
  const epsGrowth = map.eps?.value ?? null;
  const grossMargin = map.gross?.value ?? null;
  const freeCashFlow = map.fcf?.value ?? null;
  const roe = map.roe?.value ?? null;
  const operatingMargin = clamp(0.05 + profile.quality * 0.2 + profile.cash * 0.06 + profile.growth * 0.05, 0.02, 0.42);
  const debtRatio = clamp(0.72 - profile.cash * 0.23 - profile.quality * 0.12 + profile.volatility * 0.05, 0.18, 0.88);
  const cashReserve = clamp(0.07 + profile.cash * 0.52 + profile.quality * 0.06, 0.04, 0.74);
  const fcfGrowth = clamp((freeCashFlow ?? 0) / 16 + profile.growth * 0.12 + profile.sentiment * 0.04, -0.18, 0.42);
  const analystView = clamp(0.04 + profile.growth * 0.18 + profile.sentiment * 0.1, -0.08, 0.36);
  const guidance = clamp(0.02 + profile.growth * 0.16 + profile.quality * 0.06, -0.08, 0.32);
  const pe = Number.isFinite(row.trailingPE) ? row.trailingPE : null;
  const forwardPe = Number.isFinite(row.forwardPE) ? row.forwardPE : null;
  const peg = Number.isFinite(row.metadata?.pegRatio)
    ? row.metadata.pegRatio
    : (forwardPe != null && (epsGrowth ?? 0) > 0 ? forwardPe / Math.max((epsGrowth ?? 0) * 100, 1) : null);
  const evEbitda = Number.isFinite(row.metadata?.enterpriseToEbitda)
    ? row.metadata.enterpriseToEbitda
    : (pe != null ? clamp(pe * (0.65 + profile.quality * 0.18), 4, 60) : null);
  const psRatio = clamp(1.2 + profile.growth * 7.5 + profile.quality * 1.4 + profile.sentiment * 0.8, 0.8, 18);

  return {
    revenueGrowth: Number.isFinite(row.metadata?.revenueGrowth) ? row.metadata.revenueGrowth : revenueGrowth,
    epsGrowth,
    grossMargin,
    freeCashFlow,
    roe,
    operatingMargin,
    debtRatio,
    cashReserve,
    fcfGrowth,
    analystView,
    guidance,
    pe,
    forwardPe,
    peg,
    evEbitda,
    psRatio,
  };
}

function buildQualityScore(metrics) {
  const parts = [
    metricScore((metrics.roe ?? 0) * 100, 5, 25),
    metricScore((metrics.grossMargin ?? 0) * 100, 20, 60),
    metricScore(metrics.operatingMargin * 100, 8, 30),
    metricScore(metrics.freeCashFlow ?? 0, -2, 8),
    inverseMetricScore(metrics.debtRatio * 100, 35, 80),
    metricScore(metrics.cashReserve * 100, 10, 45),
  ];
  return clamp(Math.round(mean(parts) ?? 50), 0, 100);
}

function buildGrowthScore(metrics) {
  const parts = [
    metricScore((metrics.revenueGrowth ?? 0) * 100, 3, 28),
    metricScore((metrics.epsGrowth ?? 0) * 100, 2, 24),
    metricScore(metrics.fcfGrowth * 100, -5, 22),
    metricScore(metrics.guidance * 100, 0, 20),
    metricScore(metrics.analystView * 100, 0, 24),
  ];
  return clamp(Math.round(mean(parts) ?? 50), 0, 100);
}

function buildValuationScore(metrics, profile) {
  const parts = [];
  if (metrics.pe != null) parts.push(inverseMetricScore(metrics.pe, 12, 48));
  if (metrics.forwardPe != null) parts.push(inverseMetricScore(metrics.forwardPe, 10, 40));
  if (metrics.peg != null) parts.push(inverseMetricScore(metrics.peg, 0.8, 2.8));
  if (metrics.evEbitda != null) parts.push(inverseMetricScore(metrics.evEbitda, 8, 28));
  if (metrics.psRatio != null) parts.push(inverseMetricScore(metrics.psRatio, 2.5, 14));
  if (!parts.length) {
    parts.push(inverseMetricScore(18 + profile.growth * 28 - profile.cash * 6, 10, 40));
  }
  return clamp(Math.round(mean(parts) ?? 50), 0, 100);
}

function valuationStateFromScore(score) {
  if (score >= 67) return t("undervalued");
  if (score >= 40) return t("fairlyValued");
  return t("overvalued");
}

function classifyStockType(row, dims, metrics, qualityScore, growthScore, valuationScore) {
  const marketCap = row.marketCap ?? 0;
  const price = row.price ?? 0;
  const pe = metrics.pe;
  const forwardPe = metrics.forwardPe;
  const historyCount = row.technicals?.history?.closes?.length ?? 0;
  const revenueGrowth = metrics.revenueGrowth ?? 0;
  const epsGrowth = metrics.epsGrowth ?? 0;
  const veryRichValuation = (pe ?? 0) >= 60 || (forwardPe ?? 0) >= 45 || valuationScore <= 35;
  const strongGrowthProfile = growthScore >= 68 || revenueGrowth >= 0.16 || epsGrowth >= 0.14 || (row.profile?.growth ?? 0) >= 0.68;
  const unstableQuality = qualityScore < 40 && dims.fundamental < 40;

  if (historyCount > 0 && historyCount < 120) return "newlyListed";
  if (price < 5 || (((pe ?? 80) > 80 || (forwardPe ?? 80) > 60) && growthScore < 60) || ((row.profile?.cash ?? 0) < 0 && dims.fundamental < 40)) return "speculative";
  if (qualityScore < 40 && growthScore < 45 && dims.technical < 55) return "turnaround";
  if ((pe ?? 999) < 18 && valuationScore >= 60 && qualityScore >= 50) return "value";
  if ((row.profile?.cash ?? 0) > 0.45 && qualityScore >= 68 && growthScore < 58) return "dividend";
  if (strongGrowthProfile && (veryRichValuation || marketCap < 500_000_000_000 || qualityScore < 78)) return "growth";
  if (marketCap >= 500_000_000_000 && !veryRichValuation && !unstableQuality) return "megaCap";
  if (strongGrowthProfile) return "growth";
  return marketCap >= 150_000_000_000 ? "megaCap" : "value";
}

function weightedResearchScore(weights, scores) {
  let total = 0;
  let weightSum = 0;
  Object.entries(weights).forEach(([key, weight]) => {
    const value = scores[key];
    if (!Number.isFinite(value)) return;
    total += value * weight;
    weightSum += weight;
  });
  return weightSum ? Math.round(total / weightSum) : 50;
}

function longTermActionFromScore(score) {
  return scoreBucketLabel(score);
}

function longTermFitFromScore(score, action) {
  if (action === "Buy" && score >= 72) return t("suitableForAccumulation");
  if (score >= 58) return t("suitableForWatchlist");
  if (score >= 40) return t("needsMoreProof");
  return t("unsuitableForLongTerm");
}

function buildInvestmentThesis(row, dims, metrics, research) {
  const own = [];
  const watch = [];

  if (research.stockType === "megaCap") own.push(currentLanguage === "zh" ? "龙头平台属性强，经营韧性更高" : "Platform scale and operating resilience remain strong");
  if (research.stockType === "growth") own.push(currentLanguage === "zh" ? "成长逻辑仍在，市场愿意为增速付溢价" : "Growth remains the main reason investors are willing to pay up");
  if ((metrics.revenueGrowth ?? 0) >= 0.14) own.push(currentLanguage === "zh" ? "营收增长仍在健康区间" : "Revenue growth is still running at a healthy clip");
  if ((metrics.epsGrowth ?? 0) >= 0.12) own.push(currentLanguage === "zh" ? "利润扩张能力仍在改善" : "EPS growth still points to improving earnings power");
  if ((metrics.freeCashFlow ?? 0) > 0) own.push(currentLanguage === "zh" ? "自由现金流为正，长期容错率更高" : "Free cash flow is positive, which improves long-term durability");
  if (research.qualityScore >= 75) own.push(currentLanguage === "zh" ? "企业质量较高，适合长期跟踪" : "Business quality is strong enough for long-term monitoring");

  if ((metrics.pe ?? 0) >= 35 || research.valuationScore < 40) watch.push(currentLanguage === "zh" ? "当前估值不便宜，需要更好的进入位置" : "Valuation is still rich, so entry price matters");
  if ((row.technicals?.rsi14 ?? 50) >= 68) watch.push(currentLanguage === "zh" ? "RSI 偏热，短线不适合追高" : "RSI is elevated, which argues against chasing");
  if (row.price != null && row.technicals?.ma50 != null && row.price < row.technicals.ma50) watch.push(currentLanguage === "zh" ? "价格跌破 MA50，趋势确认还不够" : "Price is below MA50, so trend confirmation is incomplete");
  if ((metrics.freeCashFlow ?? 0) < 0) watch.push(currentLanguage === "zh" ? "自由现金流为负，长期兑现需要继续观察" : "Negative free cash flow lowers long-term confidence");
  if ((row.technicals?.srAnalysis?.resistanceDistancePct ?? 99) <= 2.5) watch.push(currentLanguage === "zh" ? "股价接近压力位，短期波动可能加大" : "Price is close to resistance, which can increase near-term volatility");
  if (research.stockType === "speculative") watch.push(currentLanguage === "zh" ? "投机属性较强，更适合观察名单而非重仓" : "Speculative profile makes this better for a watchlist than a core position");

  return {
    own: own.slice(0, 4),
    watch: watch.slice(0, 4),
    summary: row.profile?.note || t("neutralSetup"),
  };
}

function buildOptionsRead(row) {
  const options = row.technicals?.optionsMarket;
  const price = row.price ?? 0;
  const volatilityFallback = computeOptionsVolatilityFallback(row, options);
  if (!options?.available) {
    return {
      available: false,
      summary: t("optionsUnavailable"),
      signal: "hold",
      scoreAdjustment: 0,
      longScoreAdjustment: 0,
      callWall: null,
      putWall: null,
      gammaFlip: null,
      callWallDistancePct: null,
      putWallDistancePct: null,
      gammaFlipDistancePct: null,
      impliedVolatility: volatilityFallback.impliedVolatility,
      historicVolatility: volatilityFallback.historicVolatility,
      ivPercentile: volatilityFallback.ivPercentile,
      ivRank: volatilityFallback.ivRank,
      netGex: Number.isFinite(options?.netGammaExposure) ? options.netGammaExposure : null,
    };
  }

  const callWall = options.callWall?.strike ?? null;
  const putWall = options.putWall?.strike ?? null;
  const rawGammaFlip = options.gammaFlip?.strike ?? null;
  const gammaMethod = String(options.gammaFlip?.method || options.coverage || "").toLowerCase();
  const gammaFlipReliable = Number.isFinite(options.netGammaExposure)
    && Number.isFinite(rawGammaFlip)
    && gammaMethod
    && !gammaMethod.includes("estimated");
  const gammaFlip = gammaFlipReliable ? rawGammaFlip : null;
  const callWallDistancePct = Number.isFinite(callWall) && price > 0 ? ((callWall - price) / price) * 100 : null;
  const putWallDistancePct = Number.isFinite(putWall) && price > 0 ? ((price - putWall) / price) * 100 : null;
  const gammaFlipDistancePct = Number.isFinite(gammaFlip) && price > 0 ? ((price - gammaFlip) / price) * 100 : null;

  const nearCallWall = callWallDistancePct != null && callWallDistancePct >= 0 && callWallDistancePct <= 2;
  const nearPutWall = putWallDistancePct != null && putWallDistancePct >= 0 && putWallDistancePct <= 2.5;
  const aboveGamma = gammaFlip == null ? null : price >= gammaFlip;
  let signal = "hold";
  let summary = t("optionsNeutral");
  let scoreAdjustment = 0;
  let longScoreAdjustment = 0;

  if (nearPutWall && aboveGamma !== false) {
    signal = "buy";
    summary = t("optionsSupportive");
    scoreAdjustment = 6;
    longScoreAdjustment = 3;
  } else if (nearCallWall || aboveGamma === false) {
    signal = "sell";
    summary = t("optionsCapped");
    scoreAdjustment = -8;
    longScoreAdjustment = -4;
  }

  return {
    available: true,
    summary,
    signal,
    scoreAdjustment,
    longScoreAdjustment,
    callWall,
    putWall,
    gammaFlip,
    callWallDistancePct,
    putWallDistancePct,
    gammaFlipDistancePct,
    impliedVolatility: options.impliedVolatility ?? volatilityFallback.impliedVolatility,
    historicVolatility: options.historicVolatility ?? volatilityFallback.historicVolatility,
    ivPercentile: options.ivPercentile ?? volatilityFallback.ivPercentile,
    ivRank: options.ivRank ?? volatilityFallback.ivRank,
    netGex: options.netGammaExposure ?? null,
    nearestExpiry: options.nearestExpiry ?? null,
    coverage: options.coverage ?? null,
    totalCallOpenInterest: options.totalCallOpenInterest ?? null,
    totalPutOpenInterest: options.totalPutOpenInterest ?? null,
  };
}

function buildLongTermResearch(row) {
  if (row.noData) {
    return {
      technical: 50,
      fundamental: 50,
      moneyFlow: 50,
      risk: 50,
      qualityScore: 50,
      growthScore: 50,
      valuationScore: 50,
      overallScore: 50,
      longTermRating: "Hold",
      currentAction: "Hold",
      stockType: "growth",
      stockTypeLabel: t("growthType"),
      modelLabel: t("growthModel"),
      weights: stockTypeConfig("growth").weights,
      valuationState: t("fairlyValued"),
      longTermFit: t("needsMoreProof"),
      metrics: buildResearchMetrics(row),
      thesis: { own: [], watch: [t("noSignalReason")], summary: t("noSignalReason") },
    };
  }

  const dims = buildDimensionScores(row);
  const metrics = buildResearchMetrics(row);
  const qualityScore = buildQualityScore(metrics);
  const growthScore = buildGrowthScore(metrics);
  const valuationScore = buildValuationScore(metrics, row.profile || profileForTicker(row.ticker));
  const fundamental = clamp(Math.round(((dims.fundamental * 0.45) + (qualityScore * 0.3) + (growthScore * 0.15) + (valuationScore * 0.1))), 0, 100);
  const stockType = classifyStockType(row, dims, metrics, qualityScore, growthScore, valuationScore);
  const config = stockTypeConfig(stockType);
  const optionsRead = buildOptionsRead(row);
  const componentScores = {
    technical: dims.technical,
    fundamental,
    moneyFlow: dims.moneyFlow,
    quality: qualityScore,
    growth: growthScore,
    valuation: valuationScore,
  };
  const overallScore = clamp(weightedResearchScore(config.weights, componentScores) + optionsRead.longScoreAdjustment, 0, 100);
  const longTermRating = longTermActionFromScore(overallScore);
  const currentAction = determineSetupAction({
    score: overallScore,
    srAnalysis: row.technicals?.srAnalysis,
    rsi14: row.technicals?.rsi14 ?? 50,
    fibPosition: row.technicals?.fibPosition ?? 0.5,
    price: row.price ?? 0,
    ma20: row.technicals?.ma20 ?? row.price ?? 0,
    ma50: row.technicals?.ma50 ?? row.price ?? 0,
    changePercent: row.changePercent ?? 0,
    profile: row.profile,
    optionsMarket: row.technicals?.optionsMarket,
  });
  const longTermFit = longTermFitFromScore(overallScore, longTermRating);
  const thesis = buildInvestmentThesis(row, { ...dims, fundamental }, metrics, {
    stockType,
    qualityScore,
    growthScore,
    valuationScore,
  });

  return {
    ...dims,
    fundamental,
    qualityScore,
    growthScore,
    valuationScore,
    overallScore,
    longTermRating,
    currentAction,
    stockType,
    stockTypeLabel: config.label,
    modelLabel: config.modelLabel,
    weights: config.weights,
    valuationState: valuationStateFromScore(valuationScore),
    longTermFit,
    metrics,
    thesis,
    optionsRead,
  };
}

function compactLevelList(values, count = 2) {
  return values.filter((value) => Number.isFinite(value)).slice(0, count);
}

function buildDecisionLevels(row) {
  const tech = row.technicals || {};
  const sr = tech.srAnalysis || {};
  const optionsRead = row.research?.optionsRead || buildOptionsRead(row);
  const shortSupportPool = [
    ...(sr.support || []).map((item) => item.price),
    optionsRead.putWall,
    Number.isFinite(optionsRead.gammaFlip) && optionsRead.gammaFlip <= (row.price ?? Number.POSITIVE_INFINITY) ? optionsRead.gammaFlip : null,
  ].filter((value) => Number.isFinite(value) && value <= (row.price ?? Number.POSITIVE_INFINITY));
  const shortResistancePool = [
    ...(sr.resistance || []).map((item) => item.price),
    optionsRead.callWall,
    Number.isFinite(optionsRead.gammaFlip) && optionsRead.gammaFlip >= (row.price ?? 0) ? optionsRead.gammaFlip : null,
  ].filter((value) => Number.isFinite(value) && value >= (row.price ?? 0));
  const shortSupport = [...new Set(shortSupportPool.map((value) => Number(value.toFixed(2))))].sort((a, b) => b - a).slice(0, 2);
  const shortResistance = [...new Set(shortResistancePool.map((value) => Number(value.toFixed(2))))].sort((a, b) => a - b).slice(0, 2);
  const longSupportPool = [
    tech.ma200,
    tech.ma100,
    tech.rangeLow,
    optionsRead.putWall,
    Number.isFinite(optionsRead.gammaFlip) && optionsRead.gammaFlip <= (row.price ?? Number.POSITIVE_INFINITY) ? optionsRead.gammaFlip : null,
    (sr.support || [])[2]?.price,
    (sr.support || [])[1]?.price,
  ].filter((value) => Number.isFinite(value) && value <= (row.price ?? Number.POSITIVE_INFINITY));
  const longResistancePool = [
    tech.rangeHigh,
    tech.ma50 > (row.price ?? 0) ? tech.ma50 : null,
    tech.upperBand > (row.price ?? 0) ? tech.upperBand : null,
    optionsRead.callWall,
    Number.isFinite(optionsRead.gammaFlip) && optionsRead.gammaFlip >= (row.price ?? 0) ? optionsRead.gammaFlip : null,
    (sr.resistance || [])[2]?.price,
    (sr.resistance || [])[1]?.price,
  ].filter((value) => Number.isFinite(value) && value >= (row.price ?? 0));

  const longSupport = [...new Set(longSupportPool.map((value) => Number(value.toFixed(2))))].sort((a, b) => b - a).slice(0, 2);
  const longResistance = [...new Set(longResistancePool.map((value) => Number(value.toFixed(2))))].sort((a, b) => a - b).slice(0, 2);
  const nearestSupport = shortSupport[0] ?? longSupport[0] ?? null;
  const nearestResistance = shortResistance[0] ?? longResistance[0] ?? null;
  return {
    shortSupport,
    shortResistance,
    longSupport,
    longResistance,
    callWall: optionsRead.callWall,
    putWall: optionsRead.putWall,
    gammaFlip: optionsRead.gammaFlip,
    supportDistancePct: nearestSupport != null && row.price ? ((row.price - nearestSupport) / row.price) * 100 : null,
    resistanceDistancePct: nearestResistance != null && row.price ? ((nearestResistance - row.price) / row.price) * 100 : null,
  };
}

function moneyFlowStageSummary(row) {
  const reason = row.indicatorMap?.volume?.reason || "";
  const lower = reason.toLowerCase();
  if (reason.includes("大涨 + 放量 + 收在高位")) return { behavior: reason, stage: t("markup") };
  if (reason.includes("小涨 + 放量 + 收在高位")) return { behavior: reason, stage: t("launch") };
  if (reason.includes("大涨 + 放量 + 收盘回落") || reason.includes("巨量 + 收盘不强")) return { behavior: reason, stage: t("distribution") };
  if (reason.includes("缩量 + 收稳") || reason.includes("缩量且收盘中性")) return { behavior: reason, stage: t("shakeout") };
  if (reason.includes("下跌 + 放量 + 收在低位") || reason.includes("小跌 + 放量 + 收在低位")) return { behavior: reason, stage: t("decline") };
  if (reason.includes("放量且收在高位") || lower.includes("supportive")) return { behavior: reason, stage: t("absorption") };
  return { behavior: reason || (currentLanguage === "zh" ? "组合信号中性" : "Flow is mixed"), stage: t("shakeout") };
}

function buildTargetStop(row) {
  const sr = row.technicals?.srAnalysis;
  const support = sr?.support || [];
  const resistance = sr?.resistance || [];
  const currentPrice = row.price ?? 0;
  const targetSource = resistance.find((item) => item.price > currentPrice * 1.02) || resistance[0];
  const stopSource = support.find((item) => item.price < currentPrice * 0.99) || support[0];
  const target = targetSource?.price ?? currentPrice * 1.08;
  const stop = stopSource?.price ?? currentPrice * 0.92;
  const upside = currentPrice > 0 ? ((target - currentPrice) / currentPrice) * 100 : null;
  const downside = currentPrice > 0 ? ((currentPrice - stop) / currentPrice) * 100 : null;
  const riskReward = downside && downside > 0 && upside != null ? upside / downside : null;
  const rating = riskReward == null ? t("moderate") : riskReward >= 2 ? (currentLanguage === "zh" ? "偏积极" : "Constructive") : riskReward >= 1.2 ? (currentLanguage === "zh" ? "中性" : "Neutral") : (currentLanguage === "zh" ? "偏弱" : "Weak");
  return { target, stop, upside, downside, riskReward, rating };
}

function buildAiReasons(row) {
  const positives = [];
  const warnings = [];
  const map = row.indicatorMap || {};
  const tech = row.technicals || {};
  const sr = tech.srAnalysis || {};
  const optionsRead = row.research?.optionsRead || buildOptionsRead(row);
  const companyNews = row.companyNews || {};
  const macroNews = row.globalMarketContext?.broad_macro_news || {};

  if (map.macd?.signal === "buy") positives.push(currentLanguage === "zh" ? "MACD 偏多" : "MACD trend is supportive");
  if ((tech.ema12 ?? 0) > (tech.ema26 ?? 0)) positives.push(currentLanguage === "zh" ? "EMA 仍保持上行结构" : "EMA structure is still positive");
  if (row.price != null && tech.ma50 != null && row.price > tech.ma50) positives.push(currentLanguage === "zh" ? "股价站上 MA50" : "Price remains above MA50");
  if (map.rev?.signal === "buy" && map.eps?.signal === "buy") positives.push(currentLanguage === "zh" ? "营收和利润增长仍然健康" : "Revenue and EPS growth remain healthy");
  if (map.fcf?.signal === "buy") positives.push(currentLanguage === "zh" ? "自由现金流为正" : "Free cash flow remains positive");
  if ((sr.supportDistancePct ?? 99) <= 3 && (sr.supportStrength ?? 0) >= 50) positives.push(currentLanguage === "zh" ? "距离强支撑不远" : "Price is not far from a stronger support zone");
  if (optionsRead.signal === "buy" && Number.isFinite(optionsRead.putWall)) positives.push(currentLanguage === "zh" ? `Put Wall 支撑在 ${formatCurrency(optionsRead.putWall, row.currencyCode)}` : `Put wall support sits near ${formatCurrency(optionsRead.putWall, row.currencyCode)}`);
  if (companyNews.sentiment === "bullish" && companyNews.key_catalysts?.length) positives.push(companyNews.key_catalysts[0]);

  if ((tech.rsi14 ?? 50) >= 68) warnings.push(currentLanguage === "zh" ? "RSI 偏高，不适合追涨" : "RSI is elevated, so chasing strength is less attractive");
  if (row.price != null && tech.ma20 != null && row.price < tech.ma20) warnings.push(currentLanguage === "zh" ? "价格跌破 MA20，短线动能转弱" : "Price is below MA20, which weakens short-term momentum");
  if ((sr.resistanceDistancePct ?? 99) <= 2) warnings.push(currentLanguage === "zh" ? "股价接近压力区" : "Price is already close to resistance");
  if (map.fcf?.signal === "sell") warnings.push(currentLanguage === "zh" ? "自由现金流为负" : "Free cash flow is negative");
  if ((row.trailingPE ?? 0) >= 35) warnings.push(currentLanguage === "zh" ? "估值偏高" : "Valuation is rich");
  if ((row.changePercent ?? 0) <= -3) warnings.push(currentLanguage === "zh" ? "单日跌幅较大，情绪偏弱" : "The latest selloff shows weaker short-term sentiment");
  if (optionsRead.signal === "sell" && Number.isFinite(optionsRead.callWall)) warnings.push(currentLanguage === "zh" ? `Call Wall 压力在 ${formatCurrency(optionsRead.callWall, row.currencyCode)}` : `Call wall resistance sits near ${formatCurrency(optionsRead.callWall, row.currencyCode)}`);
  if (companyNews.sentiment === "bearish" && companyNews.risk_events?.length) warnings.push(companyNews.risk_events[0]);
  if (macroNews.sentiment === "bearish" && macroNews.major_events?.length) {
    warnings.push(currentLanguage === "zh" ? `大环境偏空：${macroNews.major_events[0].headline}` : `Broader macro flow is risk-off: ${macroNews.major_events[0].headline}`);
  }

  return {
    positives: positives.slice(0, 4),
    warnings: warnings.slice(0, 4),
  };
}

function buildTrendSummary(row) {
  const tech = row.technicals || {};
  return [
    {
      label: t("shortTermTrend"),
      value: Number.isFinite(tech.ema12) && Number.isFinite(tech.ema26)
        ? `${formatCurrency(tech.ema12, row.currencyCode)} ${tech.ema12 > tech.ema26 ? ">" : "<"} ${formatCurrency(tech.ema26, row.currencyCode)}`
        : "—",
      signal: tech.ema12 > tech.ema26 ? "buy" : tech.ema12 < tech.ema26 ? "sell" : "hold",
      note: currentLanguage === "zh"
        ? (tech.ema12 > tech.ema26 ? "短期均线仍偏多" : tech.ema12 < tech.ema26 ? "短期均线转弱" : "短期均线中性")
        : (tech.ema12 > tech.ema26 ? "Short-term EMA trend is positive" : tech.ema12 < tech.ema26 ? "Short-term EMA trend is weakening" : "Short-term EMA trend is neutral"),
    },
    {
      label: t("midTermTrend"),
      value: Number.isFinite(tech.ma50) && row.price != null
        ? `${formatCurrency(row.price, row.currencyCode)} ${row.price > tech.ma50 ? ">" : "<"} ${formatCurrency(tech.ma50, row.currencyCode)}`
        : "—",
      signal: row.price > tech.ma50 ? "buy" : row.price < tech.ma50 ? "sell" : "hold",
      note: currentLanguage === "zh"
        ? (row.price > tech.ma50 ? "价格高于 MA50" : "价格低于 MA50")
        : (row.price > tech.ma50 ? "Price remains above MA50" : "Price is below MA50"),
    },
    {
      label: t("longTermTrend"),
      value: Number.isFinite(tech.ma200) && row.price != null
        ? `${formatCurrency(row.price, row.currencyCode)} ${row.price > tech.ma200 ? ">" : "<"} ${formatCurrency(tech.ma200, row.currencyCode)}`
        : "—",
      signal: row.price > tech.ma200 ? "buy" : row.price < tech.ma200 ? "sell" : "hold",
      note: currentLanguage === "zh"
        ? (row.price > tech.ma200 ? "长期趋势仍在 MA200 上方" : "长期趋势跌破 MA200")
        : (row.price > tech.ma200 ? "Long-term trend is still above MA200" : "Long-term trend is below MA200"),
    },
  ];
}

function buildTechnicalConclusion(row, score) {
  if (score >= 70) return currentLanguage === "zh" ? "技术趋势整体偏多，适合继续跟踪中期趋势是否延续。" : "Technicals support the medium-term trend and remain worth tracking.";
  if (score >= 45) return currentLanguage === "zh" ? "技术面中性，说明趋势没有明显破坏，但也缺少强确认。" : "Technicals are mixed, which means the trend is intact but not fully confirmed.";
  return currentLanguage === "zh" ? "技术结构偏弱，当前更像等待而不是主动加仓的阶段。" : "Technical structure is weak, so patience matters more than aggressive adds.";
}

function buildFundamentalConclusion(row, research) {
  if ((research.qualityScore ?? 50) >= 75 && (research.growthScore ?? 50) >= 65) {
    return currentLanguage === "zh" ? "质量和成长兼备，符合优质成长股思路。" : "Business quality and growth both support a longer-duration growth thesis.";
  }
  if ((research.fundamental ?? 50) >= 55) {
    return currentLanguage === "zh" ? "基本面可以支撑继续观察，但估值和兑现节奏仍要跟踪。" : "Fundamentals justify staying engaged, though execution and valuation still need monitoring.";
  }
  return currentLanguage === "zh" ? "基本面支撑不够强，长期持有的容错率有限。" : "Fundamentals are not strong enough to offer much long-term margin of safety.";
}

function buildFlowConclusion(row, score) {
  const reason = row.indicatorMap?.volume?.reason;
  if (reason && currentLanguage === "zh") return reason;
  if (reason) return reason;
  if (score >= 65) return currentLanguage === "zh" ? "资金和量能配合较好，说明市场承接尚可。" : "Flow and volume remain supportive, which suggests healthy sponsorship.";
  if (score >= 45) return currentLanguage === "zh" ? "资金面中性，说明市场还在等待更多催化。" : "Money flow is neutral and still waiting for stronger catalysts.";
  return currentLanguage === "zh" ? "资金承接偏弱，说明市场对当前价格并不积极。" : "Money flow is weak, which points to less enthusiastic sponsorship at current levels.";
}

function buildRiskReasons(row, riskScore) {
  const reasons = [];
  const tech = row.technicals || {};
  if ((tech.rsi14 ?? 50) >= 68) reasons.push(currentLanguage === "zh" ? "RSI 接近超买" : "RSI is close to overbought");
  if ((row.trailingPE ?? 0) >= 35) reasons.push(currentLanguage === "zh" ? "PE 高于常规舒适区间" : "PE is above a comfortable valuation range");
  if ((row.forwardPE ?? 0) >= 30) reasons.push(currentLanguage === "zh" ? "远期市盈率仍偏高" : "Forward PE is still elevated");
  if (row.indicatorMap?.fcf?.signal === "sell") reasons.push(currentLanguage === "zh" ? "自由现金流为负" : "Free cash flow is negative");
  if ((tech.srAnalysis?.resistanceDistancePct ?? 99) <= 2.5) reasons.push(currentLanguage === "zh" ? "股价接近压力位" : "Price is close to resistance");
  if (row.price != null && tech.ma50 != null && row.price < tech.ma50) reasons.push(currentLanguage === "zh" ? "价格跌破 MA50" : "Price is below MA50");
  if ((row.changePercent ?? 0) <= -3) reasons.push(currentLanguage === "zh" ? "近期波动放大" : "Recent volatility has expanded");
  if (!reasons.length) {
    reasons.push(riskScore >= 70
      ? (currentLanguage === "zh" ? "当前主要风险不突出。" : "No single risk factor is dominating right now.")
      : (currentLanguage === "zh" ? "风险暂时可控，但需要继续观察。" : "Risks are manageable, but still worth monitoring."));
  }
  return reasons.slice(0, 4);
}

function buildDetailPayload(row) {
  const research = row.research || buildLongTermResearch(row);
  const consensus = buildConsensus(row);
  const levels = buildDecisionLevels(row);
  const optionsRead = research.optionsRead || buildOptionsRead(row);
  const flowStage = moneyFlowStageSummary(row);
  const technicalConclusion = buildTechnicalConclusion(row, research.technical);
  const fundamentalConclusion = buildFundamentalConclusion(row, research);
  const flowConclusion = buildFlowConclusion(row, research.moneyFlow);
  const technicalRisks = buildRiskReasons(row, research.risk).slice(0, 3);
  const fundamentalRisks = [
    (research.valuationScore ?? 50) < 40 ? (currentLanguage === "zh" ? "估值仍偏高，需要更高兑现度" : "Valuation is still rich and needs stronger execution") : null,
    (research.metrics.freeCashFlow ?? 0) < 0 ? (currentLanguage === "zh" ? "自由现金流仍为负" : "Free cash flow is still negative") : null,
    (research.metrics.debtRatio ?? 0) > 0.62 ? (currentLanguage === "zh" ? "资产负债率偏高" : "Debt load looks elevated") : null,
  ].filter(Boolean);
  const flowRisks = [
    (row.technicals?.volumeRatio ?? 1) < 0.85 ? (currentLanguage === "zh" ? "量比偏低，说明承接一般" : "Volume ratio is light, which suggests softer sponsorship") : null,
    (row.changePercent ?? 0) <= -3 ? (currentLanguage === "zh" ? "最近单日跌幅较大，情绪转弱" : "Recent downside move shows weaker near-term sentiment") : null,
    row.indicatorMap?.volume?.signal === "sell" ? (currentLanguage === "zh" ? "成交量结构偏弱" : "Volume structure is leaning weak") : null,
  ].filter(Boolean);
  const scoreDelta = clamp(
    Math.round(
      ((row.changePercent ?? 0) * 0.45)
      + (((research.technical ?? 50) - (research.fundamental ?? 50)) / 28)
      + (((research.moneyFlow ?? 50) - 50) / 22),
    ),
    -8,
    8,
  );
  const previousScore = clamp((research.overallScore ?? 50) - scoreDelta, 0, 100);
  const scoreBreakdown = Object.entries(research.weights).map(([key, weight]) => ({
    key,
    label: key === "technical"
      ? t("technicalScore")
      : key === "fundamental"
        ? t("fundamentalScore")
        : key === "moneyFlow"
          ? t("moneyFlowScore")
          : key === "quality"
            ? t("qualityScore")
            : key === "growth"
              ? t("growthScore")
              : t("valuationScore"),
    value: key === "technical"
      ? research.technical
      : key === "fundamental"
        ? research.fundamental
        : key === "moneyFlow"
          ? research.moneyFlow
          : key === "quality"
            ? research.qualityScore
            : key === "growth"
              ? research.growthScore
              : research.valuationScore,
    weight,
  }));
  const currentActionReason = row.action === "Buy" || row.action === "Strong Buy"
    ? (optionsRead.signal === "buy" && Number.isFinite(optionsRead.putWall)
      ? (currentLanguage === "zh" ? `短线更接近 Put Wall 支撑 ${formatCurrency(optionsRead.putWall, row.currencyCode)}，可以围绕关键位分批观察。` : `Price is close to the put wall support near ${formatCurrency(optionsRead.putWall, row.currencyCode)}, which allows more controlled scaling.`)
      : (currentLanguage === "zh" ? "短期价格位置更接近支撑区，可以围绕关键位分批观察。" : "Short-term price is closer to support, which allows more controlled scaling."))
    : row.action === "Hold"
      ? (optionsRead.signal === "sell" && Number.isFinite(optionsRead.callWall)
        ? (currentLanguage === "zh" ? `上方 Call Wall ${formatCurrency(optionsRead.callWall, row.currencyCode)} 仍在压制，优先等回踩支撑或突破确认。` : `The call wall near ${formatCurrency(optionsRead.callWall, row.currencyCode)} is still capping price, so waiting for support or a confirmed breakout is cleaner.`)
        : (currentLanguage === "zh" ? "当前买点一般，优先等回踩支撑或突破确认后再看。" : "The entry is average here, so it is better to wait for support or a confirmed breakout."))
      : (currentLanguage === "zh" ? "短期先等价格重新站稳关键位，再评估是否参与。" : "Wait for price to reclaim key levels before reconsidering a short-term entry.");
  const buyTrigger = Number.isFinite(optionsRead.callWall)
    ? (currentLanguage === "zh"
      ? `放量突破 ${formatCurrency(optionsRead.callWall, row.currencyCode)}（Call Wall）`
      : `Break above the call wall at ${formatCurrency(optionsRead.callWall, row.currencyCode)} on stronger volume`)
    : levels.shortResistance[0] != null
      ? (currentLanguage === "zh"
        ? `放量突破 ${formatCurrency(levels.shortResistance[0], row.currencyCode)}`
        : `Break above ${formatCurrency(levels.shortResistance[0], row.currencyCode)} on stronger volume`)
      : t("noSignalReason");
  const waitZone = Number.isFinite(optionsRead.putWall)
    ? formatCurrency(optionsRead.putWall, row.currencyCode)
    : levels.shortSupport[0] != null
      ? formatCurrency(levels.shortSupport[0], row.currencyCode)
      : "—";
  const shortTermPlan = row.action === "Hold"
    ? (optionsRead.signal === "sell" && Number.isFinite(optionsRead.callWall)
      ? (currentLanguage === "zh" ? `不追高，优先观察 ${formatCurrency(optionsRead.callWall, row.currencyCode)} 一带是否被有效突破。` : `Do not chase. Watch for a clean break above ${formatCurrency(optionsRead.callWall, row.currencyCode)} first.`)
      : (currentLanguage === "zh" ? `不追高，优先等待回踩 ${waitZone} 附近或突破后再看。` : `Do not chase. Prefer a pullback toward ${waitZone} or a confirmed breakout.`))
    : row.action.includes("Buy")
      ? (currentLanguage === "zh" ? `可以小仓位试探，优先围绕 ${waitZone} 分批观察。` : `A small starter position is reasonable around ${waitZone}.`)
      : (currentLanguage === "zh" ? "先观察结构修复，不急着逆势加仓。" : "Wait for structure repair before getting involved.");
  const longTermPlan = research.longTermRating === "Buy" || research.longTermRating === "Strong Buy"
    ? (optionsRead.signal === "sell" && Number.isFinite(optionsRead.callWall)
      ? (currentLanguage === "zh" ? `长期逻辑仍可跟踪，但更适合等待突破 ${formatCurrency(optionsRead.callWall, row.currencyCode)} 或回踩支撑后再分批布局。` : `The long-term thesis is still workable, but entries look better after a break above ${formatCurrency(optionsRead.callWall, row.currencyCode)} or a pullback into support.`)
      : (currentLanguage === "zh" ? "适合分批建仓，不建议一次性满仓。" : "Suitable for staged accumulation rather than a full-size entry."))
    : research.longTermRating === "Hold"
      ? (currentLanguage === "zh" ? "适合继续放在观察名单，等估值或买点更有利。" : "Keep it on the watchlist and wait for a better entry or valuation.")
      : (currentLanguage === "zh" ? "长期吸引力不足，除非逻辑明显改善。" : "Long-term appeal is limited unless the thesis improves materially.");

  return {
    dims: {
      overall: research.overallScore,
      technical: research.technical,
      fundamental: research.fundamental,
      moneyFlow: research.moneyFlow,
      quality: research.qualityScore,
      growth: research.growthScore,
      valuation: research.valuationScore,
    },
    consensus,
    research,
    technicalConclusion,
    fundamentalConclusion,
    flowConclusion,
    trendSummary: buildTrendSummary(row),
    previousScore,
    scoreDelta,
    scoreBreakdown,
    reasonLines: buildProfessionalReasonLines(row),
    technicalRisks,
    fundamentalRisks,
    flowRisks,
    optionsRead,
    levels,
    flowStage,
    currentActionReason,
    buyTrigger,
    waitZone,
    shortTermPlan,
    longTermPlan,
  };
}

function levelStrengthLabel(score) {
  if (score >= 70) return "strong";
  if (score >= 45) return "medium";
  return "weak";
}

function localizedStrength(value) {
  if (value === "strong") return t("strong");
  if (value === "medium") return t("medium");
  return t("weak");
}

function ratingTone(value) {
  const normalized = normalizeSixAction(value);
  if (["strong_buy", "accumulate"].includes(normalized)) return "buy";
  if (normalized === "hold_watch") return "hold";
  if (normalized === "trim_reduce") return "reduce";
  if (normalized === "take_profit") return "reduce";
  if (normalized === "avoid") return "sell";
  if (normalized.includes("buy")) return "buy";
  if (normalized.includes("weak hold")) return "hold";
  if (normalized.includes("reduce")) return "reduce";
  if (normalized.includes("sell") || normalized.includes("avoid") || normalized.includes("short")) return "sell";
  return "hold";
}

function normalizeWeights(weights) {
  const entries = Object.entries(weights);
  const total = entries.reduce((sum, [, value]) => sum + value, 0) || 1;
  return Object.fromEntries(entries.map(([key, value]) => [key, value / total]));
}

function ratingDirection(score) {
  if (!Number.isFinite(score)) return 0;
  if (score >= 70) return 1;
  if (score >= 55) return 0;
  return -1;
}

function makeUnavailableBlock(fields = {}) {
  return { available: false, ...fields };
}

function calculateConfidence(values, missingCount = 0) {
  const valid = values.filter(Number.isFinite);
  if (!valid.length) return 35;
  const directions = valid.map(ratingDirection);
  const directionalVotes = directions.filter((value) => value !== 0);
  const consensus = directionalVotes.length
    ? Math.max(
      directionalVotes.filter((value) => value > 0).length,
      directionalVotes.filter((value) => value < 0).length,
    ) / directionalVotes.length
    : 0.5;
  const spread = stdDev(valid) ?? 0;
  const extremeDistance = mean(valid.map((value) => Math.abs(value - 50))) ?? 0;
  const dataCoverage = valid.length / Math.max(values.length || 1, 1);
  const score = 34
    + consensus * 28
    + dataCoverage * 16
    + Math.min(12, extremeDistance * 0.35)
    - Math.min(18, spread * 0.28)
    - missingCount * 7;
  return clamp(Math.round(score), 25, 92);
}

function neutralScore(value) {
  return Number.isFinite(value) ? value : CALIBRATION_CONFIG.missing_data_neutral_score;
}

function classificationBucketKey(primaryCategory, tags = []) {
  if (["SoftwareCloud", "SocialMediaAds", "DigitalAdsCloud", "EcommerceCloud"].includes(primaryCategory)) return "megaCap";
  if (["AIInfrastructure", "MemoryStorage", "ChinaSemiconductor", "PCBDataCenter", "PCBConsumerElectronics", "OpticalCommunication"].includes(primaryCategory)) return "growth";
  if (["REITDividend"].includes(primaryCategory)) return "dividend";
  if (["HealthcareInsurance"].includes(primaryCategory)) return "megaCap";
  if (["EVAuto"].includes(primaryCategory)) return "growth";
  if (primaryCategory === "MegaCap") return "megaCap";
  if (["Growth", "HighGrowth"].includes(primaryCategory)) return "growth";
  if (["Speculative", "IPO", "NewlyListed"].includes(primaryCategory)) return "speculative";
  if (["Dividend", "REIT"].includes(primaryCategory)) return "dividend";
  if (primaryCategory === "Value") return "value";
  if (tags.includes("MegaCap")) return "megaCap";
  if (tags.includes("Growth") || tags.includes("HighGrowth")) return "growth";
  if (tags.includes("Speculative") || tags.includes("IPO") || tags.includes("NewlyListed")) return "speculative";
  if (tags.includes("Dividend") || tags.includes("REIT")) return "dividend";
  if (tags.includes("Value")) return "value";
  return "growth";
}

function companyProfileTextBlob(row) {
  return [
    row.shortName,
    row.longName,
    row.metadata?.sector,
    row.metadata?.industry,
    row.metadata?.businessSummary,
  ].filter(Boolean).join(" ").toLowerCase();
}

function companyProfileSectorBlob(row) {
  return [
    row.metadata?.sector,
    row.metadata?.industry,
  ].filter(Boolean).join(" ").toLowerCase();
}

function countRegexMatches(text, regex) {
  if (!text) return 0;
  const matches = String(text).match(regex);
  return matches ? matches.length : 0;
}

function computeReturnPct(closes, lookback) {
  if (!Array.isArray(closes) || closes.length <= lookback) return null;
  const current = closes[closes.length - 1];
  const previous = closes[closes.length - 1 - lookback];
  if (!Number.isFinite(current) || !Number.isFinite(previous) || previous === 0) return null;
  return ((current - previous) / previous) * 100;
}

function computeAnnualizedVolatility(closes, lookback) {
  if (!Array.isArray(closes) || closes.length <= lookback + 1) return null;
  const slice = closes.slice(-lookback);
  const returns = [];
  for (let i = 1; i < slice.length; i += 1) {
    const prev = slice[i - 1];
    const next = slice[i];
    if (!Number.isFinite(prev) || !Number.isFinite(next) || prev === 0) continue;
    returns.push((next - prev) / prev);
  }
  const sigma = stdDev(returns);
  return Number.isFinite(sigma) ? sigma * Math.sqrt(252) * 100 : null;
}

function computeParkinsonVolatility(highs, lows, lookback) {
  if (!Array.isArray(highs) || !Array.isArray(lows) || highs.length < lookback || lows.length < lookback) return null;
  const highSlice = highs.slice(-lookback);
  const lowSlice = lows.slice(-lookback);
  const squaredLogRanges = [];
  for (let i = 0; i < highSlice.length; i += 1) {
    const high = highSlice[i];
    const low = lowSlice[i];
    if (!Number.isFinite(high) || !Number.isFinite(low) || high <= 0 || low <= 0 || high < low) continue;
    squaredLogRanges.push(Math.log(high / low) ** 2);
  }
  if (!squaredLogRanges.length) return null;
  const averageRange = mean(squaredLogRanges);
  return Number.isFinite(averageRange)
    ? Math.sqrt(averageRange / (4 * Math.log(2))) * Math.sqrt(252) * 100
    : null;
}

function computeHistoricVolatilityBlend(history) {
  const closes = history?.closes || [];
  const highs = history?.highs || [];
  const lows = history?.lows || [];
  const hv20 = computeAnnualizedVolatility(closes, 20);
  if (Number.isFinite(hv20)) return hv20;
  const components = [
    [computeAnnualizedVolatility(closes, 30), 0.65],
    [computeParkinsonVolatility(highs, lows, 20), 0.35],
  ].filter(([value]) => Number.isFinite(value));
  if (!components.length) return null;
  const totalWeight = components.reduce((sum, [, weight]) => sum + weight, 0);
  return components.reduce((sum, [value, weight]) => sum + value * weight, 0) / totalWeight;
}

function computeRollingHistoricVolSeries(history, minHistory = 40) {
  const closes = history?.closes || [];
  const highs = history?.highs || [];
  const lows = history?.lows || [];
  const length = Math.min(closes.length, highs.length, lows.length);
  const series = [];
  for (let endIndex = minHistory; endIndex <= length; endIndex += 1) {
    const value = computeHistoricVolatilityBlend({
      closes: closes.slice(0, endIndex),
      highs: highs.slice(0, endIndex),
      lows: lows.slice(0, endIndex),
    });
    if (Number.isFinite(value)) series.push(value);
  }
  return series;
}

function computeMedian(values) {
  const filtered = (values || []).filter((value) => Number.isFinite(value)).sort((a, b) => a - b);
  if (!filtered.length) return null;
  const mid = Math.floor(filtered.length / 2);
  return filtered.length % 2 ? filtered[mid] : (filtered[mid - 1] + filtered[mid]) / 2;
}

function computeIvHistoryProxySeries(rollingSeries) {
  if (!rollingSeries.length) return [];
  const medianHv = computeMedian(rollingSeries);
  if (!Number.isFinite(medianHv) || medianHv <= 0) return [];
  const volOfVol = stdDev(rollingSeries);
  const normalizedVolOfVol = Number.isFinite(volOfVol) ? volOfVol / medianHv : 0;
  const basePremium = clamp(1.05 + (Math.min(medianHv, 100) / 100) * 0.18 + Math.min(normalizedVolOfVol, 1) * 0.08, 1.04, 1.28);
  const regimeReactivity = clamp(0.34 + Math.min(normalizedVolOfVol, 1) * 0.10 + (Math.min(medianHv, 100) / 100) * 0.06, 0.32, 0.52);
  const anchor = medianHv * basePremium;
  return rollingSeries.map((hv) => Math.max(anchor + ((hv - medianHv) * regimeReactivity), medianHv * 0.55));
}

function computeImpliedVolatilityProxy(row, options, history, historicVolatility) {
  if (Number.isFinite(options?.impliedVolatility)) return options.impliedVolatility;
  if (!Number.isFinite(historicVolatility)) return null;
  const rollingSeries = computeRollingHistoricVolSeries(history);
  const proxySeries = computeIvHistoryProxySeries(rollingSeries);
  const medianProxyIv = computeMedian(proxySeries);
  const medianHv = computeMedian(rollingSeries);
  const dailyMoveBoost = Number.isFinite(row.changePercent) ? Math.min(Math.abs(row.changePercent) / 40, 0.08) : 0;
  if (Number.isFinite(medianProxyIv) && Number.isFinite(medianHv) && medianHv > 0) {
    const regimeAdjustment = (historicVolatility - medianHv) * 0.38;
    return medianProxyIv + regimeAdjustment + (historicVolatility * dailyMoveBoost);
  }
  return historicVolatility * 1.08;
}

function computeOptionsVolatilityFallback(row, options) {
  const history = row.technicals?.history || row.history || {};
  const historicVolatility = Number.isFinite(options?.historicVolatility)
    ? options.historicVolatility
    : computeHistoricVolatilityBlend(history);
  const impliedVolatility = computeImpliedVolatilityProxy(row, options, history, historicVolatility);
  const rollingSeries = computeRollingHistoricVolSeries(history);
  const ivProxySeries = computeIvHistoryProxySeries(rollingSeries);
  let ivRank = Number.isFinite(options?.ivRank) ? options.ivRank : null;
  let ivPercentile = Number.isFinite(options?.ivPercentile) ? options.ivPercentile : null;

  if ((!Number.isFinite(ivRank) || !Number.isFinite(ivPercentile)) && Number.isFinite(impliedVolatility) && ivProxySeries.length) {
    const minValue = Math.min(...ivProxySeries);
    const maxValue = Math.max(...ivProxySeries);
    if (!Number.isFinite(ivRank) && maxValue > minValue) {
      ivRank = clamp(((impliedVolatility - minValue) / (maxValue - minValue)) * 100, 0, 100);
    }
    if (!Number.isFinite(ivPercentile)) {
      const belowCount = ivProxySeries.filter((value) => value <= impliedVolatility).length;
      ivPercentile = clamp((belowCount / ivProxySeries.length) * 100, 0, 100);
    }
  }

  return {
    impliedVolatility: Number.isFinite(impliedVolatility) ? impliedVolatility : null,
    historicVolatility: Number.isFinite(historicVolatility) ? historicVolatility : null,
    ivPercentile: Number.isFinite(ivPercentile) ? ivPercentile : null,
    ivRank: Number.isFinite(ivRank) ? ivRank : null,
  };
}

function normalizeRatioPercent(value) {
  if (value == null || !Number.isFinite(Number(value))) return null;
  const numeric = Number(value);
  return Math.abs(numeric) <= 2 ? numeric * 100 : numeric;
}

function normalizeExpectedMove(raw = {}, currentPrice = null) {
  const price = finiteNumberOrNull(currentPrice);
  const warnings = [];
  const sourceUnits = {};
  const readFirst = (keys) => {
    for (const key of keys) {
      const value = raw?.[key];
      if (value != null && Number.isFinite(Number(value))) return Number(value);
    }
    return null;
  };
  const normalizeOne = (horizon, pctKeys, priceKeys) => {
    const rawPct = readFirst(pctKeys);
    const rawPrice = readFirst(priceKeys);
    let decimalFromPct = null;
    let pctUnit = null;
    if (Number.isFinite(rawPct)) {
      if (Math.abs(rawPct) > 100) {
        pctUnit = "suspicious_pct";
        warnings.push(`${horizon}_pct_suspicious`);
      } else if (Math.abs(rawPct) > 1) {
        decimalFromPct = rawPct / 100;
        pctUnit = "pct";
      } else {
        decimalFromPct = rawPct;
        pctUnit = "decimal";
      }
    }
    let decimalFromPrice = null;
    let priceUnit = null;
    if (Number.isFinite(rawPrice) && rawPrice >= 0 && Number.isFinite(price) && price > 0) {
      decimalFromPrice = rawPrice / price;
      priceUnit = "price";
      if (decimalFromPrice > 1) {
        warnings.push(`${horizon}_price_suspicious`);
      }
    }
    let selectedDecimal = decimalFromPct;
    let selectedUnit = pctUnit;
    if (Number.isFinite(decimalFromPrice)) {
      if (Number.isFinite(decimalFromPct)) {
        const tolerance = Math.max(0.005, Math.abs(decimalFromPct) * 0.35);
        if (Math.abs(decimalFromPrice - decimalFromPct) > tolerance) {
          warnings.push(`${horizon}_unit_conflict`);
          selectedDecimal = decimalFromPrice;
          selectedUnit = "price";
        }
      } else {
        selectedDecimal = decimalFromPrice;
        selectedUnit = "price";
      }
    }
    if (!Number.isFinite(selectedDecimal) || selectedDecimal < 0 || selectedDecimal > 1) {
      selectedDecimal = null;
      selectedUnit = selectedUnit || "unavailable";
    }
    const movePrice = Number.isFinite(selectedDecimal) && Number.isFinite(price) && price > 0 ? selectedDecimal * price : null;
    sourceUnits[horizon] = {
      pct: pctUnit || "unavailable",
      price: priceUnit || "unavailable",
      selected: selectedUnit || "unavailable",
    };
    return {
      decimal: Number.isFinite(selectedDecimal) ? Number(selectedDecimal.toFixed(6)) : null,
      pct: Number.isFinite(selectedDecimal) ? Number((selectedDecimal * 100).toFixed(2)) : null,
      price: Number.isFinite(movePrice) ? Number(movePrice.toFixed(2)) : null,
      lower: Number.isFinite(price) && Number.isFinite(movePrice) ? Number(Math.max(0.01, price - movePrice).toFixed(2)) : null,
      upper: Number.isFinite(price) && Number.isFinite(movePrice) ? Number((price + movePrice).toFixed(2)) : null,
    };
  };
  const move7 = normalizeOne("7d", ["move_7d_pct", "expected_move_7d_pct", "sevenDayMovePct"], ["move_7d_price", "expected_move_7d", "sevenDayMove"]);
  const move30 = normalizeOne("30d", ["move_30d_pct", "expected_move_30d_pct", "thirtyDayMovePct"], ["move_30d_price", "expected_move_30d", "thirtyDayMove"]);
  return {
    move_7d_decimal: move7.decimal,
    move_7d_pct: move7.pct,
    move_7d_price: move7.price,
    lower_7d: move7.lower,
    upper_7d: move7.upper,
    move_30d_decimal: move30.decimal,
    move_30d_pct: move30.pct,
    move_30d_price: move30.price,
    lower_30d: move30.lower,
    upper_30d: move30.upper,
    source_units: sourceUnits,
    normalization_warning: warnings.length ? [...new Set(warnings)] : null,
  };
}

function formatUnavailableReason(sourceName) {
  return currentLanguage === "zh"
    ? `${sourceName} 暂不可用；需要历史分析师预期快照或外部数据源。`
    : `${sourceName} is unavailable; it requires historical estimate snapshots or an external feed.`;
}

function analystTrendLabel(value) {
  if (!value) return t("dataUnavailable");
  if (currentLanguage !== "zh") return localizedDashboardText(value);
  if (value === "improving") return "改善";
  if (value === "deteriorating") return "转弱";
  if (value === "stable") return "稳定";
  return localizedDashboardText(value);
}

function estimateExpectedMoveFromIv(price, ivPercent, days) {
  if (!Number.isFinite(price) || price <= 0 || !Number.isFinite(ivPercent) || ivPercent <= 0 || !Number.isFinite(days) || days <= 0) {
    return { move: null, move_pct: null, source: null };
  }
  const movePct = (ivPercent / 100) * Math.sqrt(days / 365) * 100;
  return {
    move: price * movePct / 100,
    move_pct: movePct,
    source: "iv-fallback",
  };
}

function buildOptionsExpectedMoveModule(row, options = {}) {
  const rawExpectedMove = row.technicals?.optionsMarket?.expectedMove || {};
  const rawSkew = row.technicals?.optionsMarket?.skew || {};
  const rawTermStructure = row.technicals?.optionsMarket?.termStructure || {};
  const iv = Number.isFinite(options.implied_volatility)
    ? options.implied_volatility
    : Number.isFinite(row.technicals?.optionsMarket?.impliedVolatility)
      ? row.technicals.optionsMarket.impliedVolatility
      : null;
  const fallback7 = estimateExpectedMoveFromIv(row.price, iv, 7);
  const fallback30 = estimateExpectedMoveFromIv(row.price, iv, 30);
  const sevenDayMovePct = rawExpectedMove.sevenDayMovePct ?? fallback7.move_pct;
  const thirtyDayMovePct = rawExpectedMove.thirtyDayMovePct ?? fallback30.move_pct;
  const rawOutput = {
    atm_straddle_implied_move: rawExpectedMove.atmStraddleMove ?? null,
    atm_straddle_implied_move_pct: rawExpectedMove.atmStraddleMovePct ?? null,
    expected_move_7d: rawExpectedMove.sevenDayMove ?? fallback7.move,
    expected_move_7d_pct: sevenDayMovePct,
    expected_move_30d: rawExpectedMove.thirtyDayMove ?? fallback30.move,
    expected_move_30d_pct: thirtyDayMovePct,
    iv_percentile: options.iv_percentile ?? row.technicals?.optionsMarket?.ivPercentile ?? null,
    iv_rank: options.iv_rank ?? row.technicals?.optionsMarket?.ivRank ?? null,
    skew: rawSkew.putCallIvSkew ?? null,
    skew_method: rawSkew.method ?? null,
    term_structure: rawTermStructure,
    term_structure_slope: rawTermStructure.slope ?? null,
    term_structure_regime: rawTermStructure.regime ?? null,
    source: rawExpectedMove.source || fallback30.source || null,
  };
  const normalized = normalizeExpectedMove(rawOutput, row.price);
  return {
    ...rawOutput,
    raw_expected_move_7d: rawOutput.expected_move_7d,
    raw_expected_move_7d_pct: rawOutput.expected_move_7d_pct,
    raw_expected_move_30d: rawOutput.expected_move_30d,
    raw_expected_move_30d_pct: rawOutput.expected_move_30d_pct,
    expected_move_7d: normalized.move_7d_price,
    expected_move_7d_pct: normalized.move_7d_pct,
    expected_move_30d: normalized.move_30d_price,
    expected_move_30d_pct: normalized.move_30d_pct,
    expected_move: normalized,
    source_units: normalized.source_units,
    normalization_warning: normalized.normalization_warning,
  };
}

function buildAnalystRevisionModule(row, fundamental = {}) {
  const metadata = row.metadata || {};
  const targetMeanPrice = metadata.targetMeanPrice ?? null;
  const targetMedianPrice = metadata.targetMedianPrice ?? null;
  const targetRevisionTrend = metadata.targetRevisionTrend ?? null;
  const revenueRevision = metadata.revenueEstimateRevision ?? null;
  const revenueEstimateGrowth = metadata.revenueEstimateGrowth ?? null;
  const epsRevisionNote = metadata.epsEstimateRevision30d == null
    ? formatUnavailableReason(currentLanguage === "zh" ? "EPS 7/30/90日预期修正" : "EPS 7/30/90D estimate revisions")
    : "";
  const revenueRevisionNote = revenueRevision == null && revenueEstimateGrowth != null
    ? (currentLanguage === "zh" ? "Yahoo 当前提供收入预期增长/快照，未提供收入预期历史修正序列。" : "Yahoo provides revenue estimate growth/snapshot here, not historical revenue revision snapshots.")
    : revenueRevision == null
      ? formatUnavailableReason(currentLanguage === "zh" ? "收入预期修正" : "Revenue estimate revisions")
      : "";
  const targetRevisionNote = targetRevisionTrend == null
    ? formatUnavailableReason(currentLanguage === "zh" ? "目标价修正趋势" : "Analyst target revision trend")
    : metadata.targetRevisionTrendProxy
      ? (currentLanguage === "zh" ? `目标价历史不可用；当前使用 ${metadata.targetRevisionTrendProxy} 作为趋势代理。` : `Target-price history unavailable; using ${metadata.targetRevisionTrendProxy} as a trend proxy.`)
      : "";
  return {
    eps_estimate_revisions_7d: metadata.epsEstimateRevision7d ?? null,
    eps_estimate_revisions_30d: metadata.epsEstimateRevision30d ?? null,
    eps_estimate_revisions_90d: metadata.epsEstimateRevision90d ?? null,
    eps_estimate_current: metadata.epsEstimateCurrent ?? null,
    eps_estimate_30d_ago: metadata.epsEstimate30DaysAgo ?? null,
    revenue_estimate_revisions: revenueRevision,
    revenue_estimate_growth: revenueEstimateGrowth,
    revenue_estimate_current: metadata.revenueEstimateCurrent ?? null,
    next_year_eps_growth: metadata.nextYearEpsGrowth ?? metadata.earningsGrowth ?? metadata.earningsQuarterlyGrowth ?? fundamental.growth?.eps_growth ?? null,
    forward_guidance_changes: metadata.forwardGuidanceChange ?? fundamental.growth?.forward_guidance ?? null,
    analyst_target_revision_trend: targetRevisionTrend,
    analyst_target_revision_trend_proxy: metadata.targetRevisionTrendProxy ?? null,
    recommendation_trend_delta: metadata.recommendationTrendDelta ?? null,
    analyst_upgrade_count_recent: metadata.analystUpgradeCountRecent ?? null,
    analyst_downgrade_count_recent: metadata.analystDowngradeCountRecent ?? null,
    target_mean_price: targetMeanPrice,
    target_median_price: targetMedianPrice,
    recommendation_mean: metadata.recommendationMean ?? null,
    recommendation_key: metadata.recommendationKey ?? null,
    analyst_count: metadata.numberOfAnalystOpinions ?? null,
    source_status: {
      revisions: metadata.epsEstimateRevision30d == null ? "unavailable" : "available",
      revenue_revisions: revenueRevision == null ? (revenueEstimateGrowth == null ? "unavailable" : "snapshot_only") : "available",
      target_snapshot: targetMeanPrice != null || targetMedianPrice != null ? "available" : "unavailable",
      target_trend: targetRevisionTrend == null ? "unavailable" : (metadata.targetRevisionTrendProxy ? "proxy" : "available"),
    },
    eps_revision_note: epsRevisionNote,
    revenue_revision_note: revenueRevisionNote,
    target_revision_note: targetRevisionNote,
    notes: [
      epsRevisionNote,
      revenueRevisionNote,
      targetRevisionNote,
    ].filter(Boolean),
  };
}

function benchmarkTrendReturn(trend, lookback) {
  if (!trend) return null;
  const key = `change_${lookback}d_pct`;
  return Number.isFinite(trend[key]) ? trend[key] : null;
}

function sectorEtfForClassification(companyProfile = {}) {
  const tags = new Set([...(companyProfile.tags || []), ...(companyProfile.top_tags || [])]);
  if (tags.has("Semiconductor") || tags.has("AIInfrastructure") || tags.has("MemoryStorage")) return "SMH";
  if (tags.has("Software") || tags.has("Cloud")) return "IGV";
  if (tags.has("Healthcare") || tags.has("HealthInsurance") || tags.has("HealthcareServices")) return "XLV";
  if (tags.has("REIT") || tags.has("RealEstate")) return "XLRE";
  if (tags.has("Banking") || tags.has("Fintech")) return "XLF";
  if (tags.has("Energy")) return "XLE";
  if (tags.has("Industrial") || tags.has("Defense")) return "XLI";
  if (tags.has("EV") || tags.has("AutoManufacturer") || tags.has("Consumer") || tags.has("Ecommerce")) return "XLY";
  return null;
}

function buildRelativeStrengthModule(row, marketContext = {}, companyProfile = {}) {
  const closes = row.technicals?.history?.closes || row.history?.closes || [];
  const stockReturns = {
    "20d": computeReturnPct(closes, 20),
    "60d": computeReturnPct(closes, 60),
    "120d": computeReturnPct(closes, 120),
  };
  const spyTrend = marketContext.market_engine?.equity_trend?.spy || marketContext.enhanced_context?.spy_trend || {};
  const qqqTrend = marketContext.market_engine?.equity_trend?.qqq || marketContext.enhanced_context?.qqq_trend || {};
  const vsBenchmark = (trend, lookback) => {
    const stockValue = stockReturns[`${lookback}d`];
    const benchmarkValue = benchmarkTrendReturn(trend, lookback);
    return Number.isFinite(stockValue) && Number.isFinite(benchmarkValue) ? stockValue - benchmarkValue : null;
  };
  const sectorEtf = sectorEtfForClassification(companyProfile);
  const spyHasAllLookbacks = [20, 60, 120].every((lookback) => Number.isFinite(benchmarkTrendReturn(spyTrend, lookback)));
  const qqqHasAllLookbacks = [20, 60, 120].every((lookback) => Number.isFinite(benchmarkTrendReturn(qqqTrend, lookback)));
  return {
    stock_return_20d: stockReturns["20d"],
    stock_return_60d: stockReturns["60d"],
    stock_return_120d: stockReturns["120d"],
    stock_vs_spy_20d: vsBenchmark(spyTrend, 20),
    stock_vs_spy_60d: vsBenchmark(spyTrend, 60),
    stock_vs_spy_120d: vsBenchmark(spyTrend, 120),
    stock_vs_qqq_20d: vsBenchmark(qqqTrend, 20),
    stock_vs_qqq_60d: vsBenchmark(qqqTrend, 60),
    stock_vs_qqq_120d: vsBenchmark(qqqTrend, 120),
    stock_vs_sector_etf: null,
    sector_etf: sectorEtf,
    relative_strength_percentile: null,
    source_status: {
      spy: spyHasAllLookbacks ? "available" : Number.isFinite(benchmarkTrendReturn(spyTrend, 20)) ? "partial" : "unavailable",
      qqq: qqqHasAllLookbacks ? "available" : Number.isFinite(benchmarkTrendReturn(qqqTrend, 20)) ? "partial" : "unavailable",
      sector_etf: "unavailable",
      percentile: "unavailable",
    },
    note: sectorEtf
      ? (currentLanguage === "zh" ? `行业ETF参考 ${sectorEtf}，当前尚未抓取该ETF历史序列。` : `Sector ETF reference is ${sectorEtf}; its history is not fetched yet.`)
      : (currentLanguage === "zh" ? "未识别到稳定行业ETF参考。" : "No stable sector ETF reference was identified."),
  };
}

function buildEarningsEventRiskModule(row, optionsExpectedMove = {}) {
  const metadata = row.metadata || {};
  const earningsDate = metadata.earningsDate || row.earnings?.earningsDate || null;
  const daysToEarnings = Number.isFinite(metadata.daysToEarnings)
    ? metadata.daysToEarnings
    : Number.isFinite(row.earnings?.daysToEarnings)
      ? row.earnings.daysToEarnings
      : null;
  return {
    days_to_earnings: daysToEarnings,
    earnings_date: earningsDate,
    historical_earnings_gap: metadata.historicalEarningsGap ?? null,
    expected_move_from_options: optionsExpectedMove.expected_move_30d_pct ?? optionsExpectedMove.atm_straddle_implied_move_pct ?? null,
    post_earnings_drift: metadata.postEarningsDrift ?? null,
    source_status: {
      calendar: earningsDate != null || daysToEarnings != null ? "available" : "unavailable",
      historical_gap: metadata.historicalEarningsGap == null ? "unavailable" : "available",
      expected_move: optionsExpectedMove.expected_move_30d_pct == null && optionsExpectedMove.atm_straddle_implied_move_pct == null ? "unavailable" : "available",
      drift: metadata.postEarningsDrift == null ? "unavailable" : "available",
    },
    note: currentLanguage === "zh"
      ? "历史财报跳空和财报后漂移需要历史财报日期序列；缺失时不会伪造。"
      : "Historical earnings gap and post-earnings drift require past earnings-date series and are not fabricated when unavailable.",
  };
}

function finiteNumberOrNull(value) {
  const numeric = Number(value);
  return Number.isFinite(numeric) ? numeric : null;
}

function scoreFromPercentSignal(value, band = 15) {
  const numeric = finiteNumberOrNull(value);
  if (numeric == null || !Number.isFinite(band) || band <= 0) return null;
  const capped = clamp(numeric, -band, band);
  return clamp(Math.round(50 + (capped / band) * 35), 0, 100);
}

function averageAvailableScores(items = []) {
  const valid = items.filter(Number.isFinite);
  return valid.length ? Math.round(mean(valid)) : null;
}

function normalizeDirectionFromScore(score) {
  if (!Number.isFinite(score)) return "unavailable";
  if (score >= 68) return "improving";
  if (score <= 42) return "deteriorating";
  return "neutral";
}

function buildRelativeStrengthState(relativeStrength = {}, companyProfile = {}) {
  const tags = companyProfile?.tags || [];
  const qqqHeavy = hasAnyTag(tags, ["AIInfrastructure", "Software", "Cloud", "Semiconductor", "GPU", "DataCenter", "HighGrowth"]);
  const spyHeavy = hasAnyTag(tags, ["Healthcare", "HealthInsurance", "HealthcareServices", "REIT", "Dividend", "Defensive"]);
  const chinaAdr = hasAnyTag(tags, ["ChinaADR", "ChinaInternet", "ChinaConsumer"]);
  const weights = chinaAdr
    ? { stock: 0.6, spy: 0.25, qqq: 0.15 }
    : qqqHeavy
      ? { stock: 0.35, spy: 0.25, qqq: 0.4 }
      : spyHeavy
        ? { stock: 0.35, spy: 0.45, qqq: 0.2 }
        : { stock: 0.4, spy: 0.3, qqq: 0.3 };
  const horizonScore = (lookback, band) => {
    const stock = scoreFromPercentSignal(relativeStrength[`stock_return_${lookback}d`], band);
    const spy = scoreFromPercentSignal(relativeStrength[`stock_vs_spy_${lookback}d`], Math.max(8, band * 0.75));
    const qqq = scoreFromPercentSignal(relativeStrength[`stock_vs_qqq_${lookback}d`], Math.max(8, band * 0.75));
    const components = [
      { score: stock, weight: weights.stock },
      { score: spy, weight: weights.spy },
      { score: qqq, weight: weights.qqq },
    ].filter((item) => Number.isFinite(item.score));
    const total = components.reduce((sum, item) => sum + item.weight, 0);
    if (!total) return null;
    return Math.round(components.reduce((sum, item) => sum + item.score * item.weight, 0) / total);
  };
  const shortScore = horizonScore(20, 18);
  const midCore = horizonScore(60, 25);
  const longCore = horizonScore(120, 35);
  const midScore = averageAvailableScores([midCore, shortScore]);
  const longScore = averageAvailableScores([longCore, midCore, shortScore]);
  const available = [shortScore, midScore, longScore].filter(Number.isFinite);
  const composite = available.length ? Math.round(mean(available)) : null;
  const improving = Number.isFinite(shortScore) && Number.isFinite(midCore) && shortScore >= midCore + 4;
  const deteriorating = Number.isFinite(shortScore) && Number.isFinite(midCore) && shortScore <= midCore - 6;
  const regime = normalizeDirectionFromScore(composite);
  return {
    stock_return_20d: relativeStrength.stock_return_20d ?? null,
    stock_return_60d: relativeStrength.stock_return_60d ?? null,
    stock_return_120d: relativeStrength.stock_return_120d ?? null,
    vs_spy_20d: relativeStrength.stock_vs_spy_20d ?? null,
    vs_spy_60d: relativeStrength.stock_vs_spy_60d ?? null,
    vs_spy_120d: relativeStrength.stock_vs_spy_120d ?? null,
    vs_qqq_20d: relativeStrength.stock_vs_qqq_20d ?? null,
    vs_qqq_60d: relativeStrength.stock_vs_qqq_60d ?? null,
    vs_qqq_120d: relativeStrength.stock_vs_qqq_120d ?? null,
    short_score: shortScore,
    mid_score: midScore,
    long_score: longScore,
    regime,
    improving,
    deteriorating,
    profile_weights: weights,
    explanation: currentLanguage === "zh"
      ? `相对强度按本股涨跌与 SPY / QQQ 超额收益标准化，当前状态：${localizedDashboardText(regime)}。`
      : `Relative strength normalizes stock returns and excess returns versus SPY / QQQ. Current regime: ${regime}.`,
  };
}

function buildGuidanceState(analystRevisions = {}, fundamental = {}) {
  const rawGuidance = analystRevisions.forward_guidance_changes ?? fundamental.growth?.forward_guidance ?? null;
  const guidancePct = normalizeRatioPercent(rawGuidance);
  let direction = "unavailable";
  if (Number.isFinite(guidancePct)) {
    if (guidancePct >= 2) direction = "raised";
    else if (guidancePct <= -2) direction = "lowered";
    else direction = "maintained";
  }
  const epsSignals = [
    analystRevisions.eps_estimate_revisions_7d,
    analystRevisions.eps_estimate_revisions_30d,
    analystRevisions.eps_estimate_revisions_90d,
  ].filter(Number.isFinite);
  const epsRevisionScore = epsSignals.length ? scoreFromPercentSignal(mean(epsSignals), 12) : null;
  const targetTrend = analystRevisions.analyst_target_revision_trend || analystRevisions.analyst_target_revision_trend_proxy || null;
  let targetScore = null;
  if (targetTrend === "improving") targetScore = 68;
  else if (targetTrend === "deteriorating") targetScore = 36;
  else if (targetTrend === "stable") targetScore = 52;
  const directionScore = direction === "raised" ? 75 : direction === "maintained" ? 55 : direction === "lowered" ? 25 : null;
  const score = averageAvailableScores([directionScore, epsRevisionScore, targetScore]);
  return {
    direction,
    magnitude: Number.isFinite(guidancePct) ? Number(guidancePct.toFixed(1)) : null,
    recency: analystRevisions.source_status?.revisions === "available" ? "recent_snapshot" : "unavailable",
    score,
    eps_revision_score: epsRevisionScore,
    target_revision_score: targetScore,
    explanation: currentLanguage === "zh"
      ? direction === "raised"
        ? "前瞻指引或盈利预期上修，长期买入和卖出区间可适度上移。"
        : direction === "lowered"
          ? "前瞻指引或预期转弱，买入区间更保守，并提高基本面止损风险。"
          : direction === "maintained"
            ? "前瞻指引维持，中性处理，不重复计权。"
            : "前瞻指引变化暂无稳定数据，相关权重从判断中移除。"
      : direction === "raised"
        ? "Forward guidance or estimates improved, allowing modestly higher long-term zones."
        : direction === "lowered"
          ? "Forward guidance or estimates weakened, making entries more conservative and raising fundamental-stop risk."
          : direction === "maintained"
            ? "Forward guidance is maintained and treated as neutral without double counting."
            : "Forward guidance data is unavailable and removed from related weights.",
  };
}

function buildValuationState(row, fundamental = {}, guidanceState = {}, companyProfile = {}) {
  const valuation = fundamental.valuation || {};
  const tags = companyProfile?.tags || [];
  const pe = finiteNumberOrNull(valuation.pe ?? row.metadata?.trailingPE);
  const forwardPe = finiteNumberOrNull(valuation.forward_pe ?? row.metadata?.forwardPE);
  const peg = finiteNumberOrNull(valuation.peg ?? row.metadata?.pegRatio);
  const priceFcf = finiteNumberOrNull(valuation.price_fcf ?? row.metadata?.priceToFreeCashflow);
  const revenueGrowth = normalizeRatioPercent(fundamental.growth?.revenue_growth ?? row.metadata?.revenueGrowth);
  const multipleScores = [];
  if (Number.isFinite(forwardPe)) multipleScores.push(clamp(Math.round(88 - forwardPe * (hasAnyTag(tags, ["HighGrowth", "AIInfrastructure"]) ? 0.75 : 1.05)), 15, 90));
  if (Number.isFinite(pe)) multipleScores.push(clamp(Math.round(86 - pe * 0.85), 12, 88));
  if (Number.isFinite(peg)) multipleScores.push(clamp(Math.round(82 - peg * 16), 12, 88));
  if (Number.isFinite(priceFcf)) multipleScores.push(clamp(Math.round(86 - priceFcf * 1.1), 12, 88));
  if (Number.isFinite(revenueGrowth) && hasAnyTag(tags, ["HighGrowth", "AIInfrastructure", "Software", "Cloud"])) {
    multipleScores.push(clamp(Math.round(45 + revenueGrowth * 0.9), 30, 86));
  }
  let score = averageAvailableScores(multipleScores);
  if (guidanceState.direction === "raised" && Number.isFinite(score)) score = clamp(score + 5, 0, 100);
  if (guidanceState.direction === "lowered" && Number.isFinite(score)) score = clamp(score - 8, 0, 100);
  return {
    pe,
    forward_pe: forwardPe,
    peg,
    price_fcf: priceFcf,
    revenue_growth: revenueGrowth,
    score,
    regime: !Number.isFinite(score) ? "unavailable" : score >= 68 ? "reasonable" : score >= 45 ? "neutral" : score >= 28 ? "expensive" : "extreme",
    fair_value_bias: guidanceState.direction === "raised" ? "upward" : guidanceState.direction === "lowered" ? "downward" : "stable",
    explanation: currentLanguage === "zh"
      ? "估值状态综合 Forward PE、PEG、Price/FCF、收入增长和指引变化；缺失字段重新归一化。"
      : "Valuation blends forward PE, PEG, price/FCF, revenue growth, and guidance changes with missing fields re-normalized.",
  };
}

function buildFundamentalHealthState(fundamental = {}, guidanceState = {}, companyProfile = {}) {
  const profileScore = fundamental.profile_fundamental?.score ?? fundamental.fundamental_score ?? null;
  const components = fundamental.profile_fundamental?.components || {};
  const values = [
    profileScore,
    components.free_cash_flow,
    components.profit_margin,
    components.balance_sheet_quality,
    components.revenue_growth,
  ].filter(Number.isFinite);
  let score = values.length ? Math.round(mean(values)) : null;
  if (guidanceState.direction === "raised" && Number.isFinite(score)) score = clamp(score + 5, 0, 100);
  if (guidanceState.direction === "lowered" && Number.isFinite(score)) score = clamp(score - 10, 0, 100);
  const debtRisk = components.debt_risk ?? (fundamental.profile_fundamental?.high_dividend_debt_risk ? 25 : null);
  const dividendSafety = components.dividend_safety ?? null;
  return {
    score,
    regime: !Number.isFinite(score) ? "unavailable" : score >= 70 ? "healthy" : score >= 48 ? "mixed" : "weak",
    debt_risk_score: debtRisk,
    dividend_safety_score: dividendSafety,
    high_dividend_debt_risk: Boolean(fundamental.profile_fundamental?.high_dividend_debt_risk),
    explanation: currentLanguage === "zh"
      ? "基本面健康度综合现金流、利润率、资产负债表、收入增长和指引变化。"
      : "Fundamental health blends cash flow, margins, balance sheet, revenue growth, and guidance.",
  };
}

function buildTrendState(row, technical = {}) {
  const tech = row.technicals || {};
  const price = finiteNumberOrNull(row.price);
  const ma20 = finiteNumberOrNull(tech.ma20);
  const ma50 = finiteNumberOrNull(tech.ma50);
  const ma100 = finiteNumberOrNull(tech.ma100);
  const ma200 = finiteNumberOrNull(tech.ma200);
  const aboveMaScore = averageAvailableScores([
    Number.isFinite(price) && Number.isFinite(ma20) ? (price > ma20 ? 68 : 38) : null,
    Number.isFinite(price) && Number.isFinite(ma50) ? (price > ma50 ? 66 : 40) : null,
    Number.isFinite(price) && Number.isFinite(ma200) ? (price > ma200 ? 62 : 42) : null,
  ]);
  const structureScore = Number.isFinite(ma20) && Number.isFinite(ma50)
    ? (ma20 > ma50 ? 66 : ma20 > ma50 * 0.98 ? 55 : 38)
    : null;
  const score = averageAvailableScores([aboveMaScore, structureScore, technical.trend_confirmation?.score]);
  return {
    price,
    ma20,
    ma50,
    ma100,
    ma200,
    score,
    regime: normalizeDirectionFromScore(score),
    explanation: currentLanguage === "zh"
      ? "趋势状态综合价格相对均线、MA20/MA50 结构和现有趋势确认。"
      : "Trend state blends price versus moving averages, MA20/MA50 structure, and existing trend confirmation.",
  };
}

function buildVolumeState(technical = {}) {
  const volume = technical.volume_confirmation || {};
  const score = averageAvailableScores([
    volume.money_flow_score,
    volume.score,
    volume.relative_volume_score,
    volume.close_location_score,
  ]);
  const obvTrendValue = volume.obv_trend_20d || volume.obv_trend || null;
  return {
    score,
    regime: volume.behavior_key || normalizeDirectionFromScore(score),
    obv_trend_20d: obvTrendValue,
    relative_volume_20d: volume.relative_volume_20d ?? null,
    close_location_pct: volume.close_location_pct ?? null,
    turnover_state: volume.turnover_state || null,
    distribution_risk: ["distribution_risk", "panic_selling"].includes(volume.behavior_key),
    explanation: volume.summary || volume.behavior_label || (currentLanguage === "zh" ? "量能状态中性。" : "Volume state is neutral."),
  };
}

function normalizeExpectedMovePayload(row, optionsExpectedMove = {}) {
  return optionsExpectedMove.expected_move?.source_units
    ? optionsExpectedMove.expected_move
    : normalizeExpectedMove(optionsExpectedMove, row.price);
}

function buildOptionsState(row, optionsExpectedMove = {}, optionsModule = {}) {
  const expectedMove = normalizeExpectedMovePayload(row, optionsExpectedMove);
  const ivPercentile = finiteNumberOrNull(optionsExpectedMove.iv_percentile ?? optionsModule.iv_percentile);
  const ivRank = finiteNumberOrNull(optionsExpectedMove.iv_rank ?? optionsModule.iv_rank);
  const ivScores = [ivPercentile, ivRank].filter(Number.isFinite);
  const combinedIv = ivScores.length ? mean(ivScores) : null;
  const ivConflict = Number.isFinite(ivPercentile) && Number.isFinite(ivRank) && Math.abs(ivPercentile - ivRank) >= 30;
  const combinedState = !Number.isFinite(combinedIv)
    ? "unavailable"
    : combinedIv >= 80 ? "extreme" : combinedIv >= 55 ? "elevated" : combinedIv >= 25 ? "normal" : "low";
  const termRegime = optionsExpectedMove.term_structure_regime || optionsExpectedMove.term_structure?.regime || "unavailable";
  const skew = finiteNumberOrNull(optionsExpectedMove.skew);
  return {
    expected_move_7d: expectedMove.move_7d_price,
    expected_move_7d_pct: expectedMove.move_7d_pct,
    expected_move_30d: expectedMove.move_30d_price,
    expected_move_30d_pct: expectedMove.move_30d_pct,
    iv_percentile: ivPercentile,
    iv_rank: ivRank,
    skew,
    term_structure: termRegime,
    option_chain_status: optionsModule.status || "unavailable",
    expected_move: expectedMove,
    iv_regime: {
      percentile_state: Number.isFinite(ivPercentile) ? (ivPercentile >= 80 ? "extreme" : ivPercentile >= 55 ? "elevated" : ivPercentile >= 25 ? "normal" : "low") : "unavailable",
      rank_state: Number.isFinite(ivRank) ? (ivRank >= 80 ? "extreme" : ivRank >= 55 ? "elevated" : ivRank >= 25 ? "normal" : "low") : "unavailable",
      combined_state: combinedState,
      premium_attractiveness: ["elevated", "extreme"].includes(combinedState) ? "higher" : combinedState === "low" ? "lower" : "normal",
      volatility_risk: combinedState === "extreme" || termRegime === "backwardation" ? "high" : combinedState === "elevated" ? "elevated" : "normal",
      conflict: ivConflict,
    },
    options_risk_regime: termRegime === "backwardation" ? "event_risk" : combinedState,
    source_units: expectedMove.source_units,
    normalization_warning: expectedMove.normalization_warning,
    explanation: currentLanguage === "zh"
      ? "期权状态用于可达性、止损宽度和期权 strike 校验，不替代结构性支撑压力。"
      : "Options state informs reachability, stop width, and option strike checks, without replacing structural levels.",
  };
}

function buildCycleState(row, companyProfile = {}, fundamental = {}) {
  const tags = companyProfile?.tags || [];
  const isMemory = hasAnyTag(tags, ["MemoryStorage", "DRAMNAND", "NAND"]);
  const isReit = hasAnyTag(tags, ["REIT", "RealEstate", "HealthcareRealEstate"]);
  const score = isMemory
    ? averageAvailableScores([
      fundamental.profile_fundamental?.components?.gross_margin_trend,
      fundamental.profile_fundamental?.components?.inventory_cycle,
      fundamental.profile_fundamental?.components?.free_cash_flow,
    ])
    : isReit
      ? averageAvailableScores([
        fundamental.profile_fundamental?.components?.dividend_safety,
        fundamental.profile_fundamental?.components?.debt_risk,
        fundamental.profile_fundamental?.components?.free_cash_flow,
      ])
      : null;
  return {
    profile: isMemory ? "memory_cycle" : isReit ? "reit_dividend" : "generic",
    score,
    regime: normalizeDirectionFromScore(score),
    explanation: isMemory
      ? (currentLanguage === "zh" ? "存储周期重点参考毛利率、库存周期、行业景气和量能。" : "Memory cycle focuses on gross margin, inventory cycle, sector demand, and volume.")
      : isReit
        ? (currentLanguage === "zh" ? "REIT / 分红周期重点参考债务、现金流、股息安全和 10Y 利率。" : "REIT / dividend cycle focuses on debt, cash flow, dividend safety, and 10Y rates.")
        : (currentLanguage === "zh" ? "当前按通用周期处理。" : "Generic cycle treatment."),
  };
}

function buildCompanyRiskState({ fundamentalHealth, guidanceState, valuationState, volumeState, companyProfile }) {
  const tags = companyProfile?.tags || [];
  const riskFactors = [
    guidanceState.direction === "lowered" ? (currentLanguage === "zh" ? "前瞻指引下调" : "Guidance lowered") : null,
    fundamentalHealth.regime === "weak" ? (currentLanguage === "zh" ? "基本面健康度偏弱" : "Weak fundamental health") : null,
    fundamentalHealth.high_dividend_debt_risk ? (currentLanguage === "zh" ? "高股息叠加债务风险" : "High dividend with debt risk") : null,
    volumeState.distribution_risk ? (currentLanguage === "zh" ? "量价分配风险" : "Distribution risk") : null,
    valuationState.regime === "extreme" ? (currentLanguage === "zh" ? "估值极端" : "Extreme valuation") : null,
    hasAnyTag(tags, ["RegulatoryRisk"]) ? (currentLanguage === "zh" ? "监管风险" : "Regulatory risk") : null,
  ].filter(Boolean);
  return {
    company_specific_risk: riskFactors.length >= 2 || guidanceState.direction === "lowered" || fundamentalHealth.regime === "weak",
    falling_knife_risk: volumeState.distribution_risk && guidanceState.direction !== "raised",
    risk_factors: riskFactors,
	  };
	}

function buildGapDownRiskModel({
  row,
  supportResistance,
  technical,
  marketContext,
  tradeContext,
  companyProfile,
}) {
  const price = finiteNumberOrNull(row?.price);
  const previousClose = finiteNumberOrNull(row?.previousClose);
  const atr = finiteNumberOrNull(row?.technicals?.atr14);
  const dayChangePct = finiteNumberOrNull(row?.changePercent);
  const dayChangeAmount = Number.isFinite(price) && Number.isFinite(previousClose) ? price - previousClose : null;
  const dropInAtr = Number.isFinite(dayChangeAmount) && Number.isFinite(atr) && atr > 0 ? Math.abs(dayChangeAmount) / atr : null;
  const overnightGapPct = null;
  const tags = decisionTagSet(companyProfile, companyProfile?.decision_profile || {});
  const volatileProfile = hasAnyTag(tags, ["HighVolatility", "Speculative", "Meme", "NewlyListed", "IPO"]);
  const defensiveProfile = hasAnyTag(tags, ["MegaCap", "Defensive", "Healthcare", "HealthInsurance", "HealthcareServices"]);
  const pctTrigger = volatileProfile ? -7 : defensiveProfile ? -5.8 : -5;
  const active = (Number.isFinite(dayChangePct) && dayChangePct <= pctTrigger)
    || (Number.isFinite(overnightGapPct) && overnightGapPct <= -4)
    || (Number.isFinite(dropInAtr) && dropInAtr >= 1.5);
  const volume = technical?.volume_confirmation || tradeContext?.volume_state || {};
  const closeLocation = finiteNumberOrNull(volume.close_location_pct ?? row?.technicals?.closePosition * 100);
  const volumeRatio = finiteNumberOrNull(volume.relative_volume_20d ?? row?.technicals?.volumeRatio);
  const supports = supportResistance?.supports || [];
  const ma20 = finiteNumberOrNull(row?.technicals?.ma20);
  const ma50 = finiteNumberOrNull(row?.technicals?.ma50);
  const brokeSupport = Number.isFinite(price) && Number.isFinite(previousClose)
    ? supports.slice(0, 2).some((level) => Number.isFinite(level?.price) && previousClose >= level.price && price < level.price)
    : false;
  const brokeMa20 = Number.isFinite(price) && Number.isFinite(previousClose) && Number.isFinite(ma20) ? previousClose >= ma20 && price < ma20 : false;
  const brokeMa50 = Number.isFinite(price) && Number.isFinite(previousClose) && Number.isFinite(ma50) ? previousClose >= ma50 && price < ma50 : false;
  const obvTrend = volume.obv_trend_20d || tradeContext?.volume_state?.obv_trend_20d || "neutral";
  const obvConfirmation = obvTrend !== "falling";
  const relativeStrengthShock = [
    tradeContext?.relative_strength_state?.vs_spy_20d,
    tradeContext?.relative_strength_state?.vs_qqq_20d,
  ].some((value) => Number.isFinite(value) && value <= -4);
  const guidanceRisk = tradeContext?.guidance_state?.direction === "lowered";
  const earningsDays = finiteNumberOrNull(marketContext?.earnings_event_risk?.days_to_earnings ?? row?.metadata?.daysToEarnings);
  const earningsEventProximity = Number.isFinite(earningsDays) && Math.abs(earningsDays) <= 3;
  const newsItems = Array.isArray(row?.companyNews)
    ? row.companyNews
    : row?.companyNews && typeof row.companyNews === "object"
      ? Object.values(row.companyNews)
      : [];
  const newsBlob = newsItems.map((item) => `${item?.title || ""} ${item?.summary || ""}`).join(" ").toLowerCase();
  const companySpecificNewsRisk = /guidance|earnings miss|downgrade|investigation|lawsuit|regulator|sec\b|fraud|probe|cut forecast|weak forecast|slashed/i.test(newsBlob);
  const marketRegime = marketRegimeFromContext(marketContext);
  const marketWideSelloff = ["risk_off", "panic"].includes(marketRegime)
    || (marketContext?.enhanced_context?.spy_trend?.change_5d_pct ?? 0) <= -3
    || (marketContext?.enhanced_context?.qqq_trend?.change_5d_pct ?? 0) <= -3;
  const closeStrong = Number.isFinite(closeLocation) && closeLocation >= 62;
  const supportHeld = active && !brokeSupport && !brokeMa50;
  const intradayRecoveryPct = Number.isFinite(closeLocation) ? closeLocation : null;
  let riskScore = 0;
  if (active) riskScore += 25;
  if (Number.isFinite(volumeRatio) && volumeRatio >= 1.5) riskScore += 12;
  if (Number.isFinite(closeLocation) && closeLocation < 35) riskScore += 14;
  if (brokeSupport) riskScore += 16;
  if (brokeMa20) riskScore += 8;
  if (brokeMa50) riskScore += 12;
  if (!obvConfirmation) riskScore += 10;
  if (relativeStrengthShock) riskScore += 10;
  if (guidanceRisk) riskScore += 18;
  if (earningsEventProximity) riskScore += 8;
  if (companySpecificNewsRisk) riskScore += 18;
  if (marketWideSelloff && !companySpecificNewsRisk && !guidanceRisk) riskScore -= 10;
  if (closeStrong) riskScore -= 10;
  if (supportHeld) riskScore -= 8;
  riskScore = clamp(Math.round(riskScore), 0, 100);
  let classification = "normal_pullback";
  if (!active) classification = "normal_pullback";
  else if (!Number.isFinite(dayChangePct) && !Number.isFinite(dropInAtr)) classification = "data_insufficient";
  else if ((guidanceRisk || companySpecificNewsRisk) && (brokeSupport || brokeMa50 || riskScore >= 65)) classification = "company_specific_breakdown";
  else if (riskScore >= 72 && (brokeSupport || !obvConfirmation) && !closeStrong) classification = "falling_knife";
  else if (guidanceRisk || companySpecificNewsRisk || earningsEventProximity) classification = "event_driven_gap_down";
  else if (marketWideSelloff && supportHeld) classification = "market_driven_selloff";
  else if (closeStrong && supportHeld && riskScore < 58) classification = "capitulation_with_recovery";
  const followThroughRequired = ["event_driven_gap_down", "company_specific_breakdown", "falling_knife"].includes(classification);
  const followThroughConfirmed = !followThroughRequired && (closeStrong || supportHeld) && obvConfirmation;
  return {
    active,
    gap_pct: overnightGapPct,
    day_change_pct: dayChangePct,
    overnight_gap_pct: overnightGapPct,
    drop_in_atr: Number.isFinite(dropInAtr) ? Number(dropInAtr.toFixed(2)) : null,
    abnormal_volume_ratio: volumeRatio,
    close_location: closeLocation,
    intraday_recovery_pct: intradayRecoveryPct,
    broke_support: brokeSupport,
    broke_ma20: brokeMa20,
    broke_ma50: brokeMa50,
    obv_confirmation: obvConfirmation,
    relative_strength_shock: relativeStrengthShock,
    event_risk: earningsEventProximity || guidanceRisk || companySpecificNewsRisk,
    earnings_event_proximity: earningsEventProximity,
    guidance_risk: guidanceRisk,
    company_specific_news_risk: companySpecificNewsRisk,
    market_wide_selloff: marketWideSelloff,
    stabilization_state: followThroughConfirmed ? "confirmed" : supportHeld || closeStrong ? "early" : active ? "unconfirmed" : "not_required",
    risk_score: riskScore,
    classification,
    follow_through_confirmation: {
      required: followThroughRequired,
      confirmed: followThroughConfirmed,
      days_required: followThroughRequired ? 2 : 0,
      reclaim_level: Number.isFinite(ma20) ? ma20 : supports[0]?.price ?? null,
      volume_requirement: followThroughRequired ? "no further high-volume downside expansion" : null,
      obv_requirement: followThroughRequired ? "OBV stops deteriorating" : null,
      reason: followThroughRequired
        ? (currentLanguage === "zh" ? "事件型急跌或破位需要 1-2 个交易日确认止稳。" : "Event-driven gap-down or breakdown needs 1-2 sessions of follow-through stabilization.")
        : null,
    },
    explanation: active
      ? (currentLanguage === "zh" ? `急跌分类：${classification}，风险分 ${riskScore}/100。` : `Gap-down classification: ${classification}, risk ${riskScore}/100.`)
      : (currentLanguage === "zh" ? "未触发单日急跌风险模型。" : "Gap-down risk model was not triggered."),
  };
}

function buildTradeContextFieldMapping(row, context = {}) {
  const now = new Date().toISOString();
  const rows = [
    ["本股20日涨跌", "relative_strength_state.stock_return_20d", context.relative_strength_state?.stock_return_20d, "%", "relative_strength_state"],
    ["本股60日涨跌", "relative_strength_state.stock_return_60d", context.relative_strength_state?.stock_return_60d, "%", "relative_strength_state"],
    ["本股120日涨跌", "relative_strength_state.stock_return_120d", context.relative_strength_state?.stock_return_120d, "%", "relative_strength_state"],
    ["相对SPY 20日", "relative_strength_state.vs_spy_20d", context.relative_strength_state?.vs_spy_20d, "percentage points", "relative_strength_state"],
    ["相对SPY 60日", "relative_strength_state.vs_spy_60d", context.relative_strength_state?.vs_spy_60d, "percentage points", "relative_strength_state"],
    ["相对SPY 120日", "relative_strength_state.vs_spy_120d", context.relative_strength_state?.vs_spy_120d, "percentage points", "relative_strength_state"],
    ["相对QQQ 20日", "relative_strength_state.vs_qqq_20d", context.relative_strength_state?.vs_qqq_20d, "percentage points", "relative_strength_state"],
    ["相对QQQ 60日", "relative_strength_state.vs_qqq_60d", context.relative_strength_state?.vs_qqq_60d, "percentage points", "relative_strength_state"],
    ["相对QQQ 120日", "relative_strength_state.vs_qqq_120d", context.relative_strength_state?.vs_qqq_120d, "percentage points", "relative_strength_state"],
    ["7日期权预期波动", "options_state.expected_move.move_7d_pct", context.options_state?.expected_move?.move_7d_pct, "%", "options_state"],
    ["30日期权预期波动", "options_state.expected_move.move_30d_pct", context.options_state?.expected_move?.move_30d_pct, "%", "options_state"],
    ["IV Percentile", "options_state.iv_percentile", context.options_state?.iv_percentile, "percentile", "options_state"],
    ["IV Rank", "options_state.iv_rank", context.options_state?.iv_rank, "rank", "options_state"],
    ["Options Skew", "options_state.skew", context.options_state?.skew, "vol points", "options_state"],
    ["Options Term Structure", "options_state.term_structure", context.options_state?.term_structure, "regime", "options_state"],
    ["Forward Guidance Change", "guidance_state.direction / magnitude", context.guidance_state?.direction === "unavailable" ? null : context.guidance_state?.magnitude, "%", "guidance_state"],
  ];
  return rows.map(([standard, actual, value, unit, usage]) => ({
    standard_field: standard,
    actual_field: actual,
    data_type: value == null ? "null" : typeof value,
    unit,
    missing_rate: value == null ? "100%" : "0%",
    updated_at: row.updatedAt || row.updated_at || row.last_quote_time || now,
    current_usage: usage,
  }));
}

function buildTradeContext({
  row,
  companyProfile,
  dataQuality,
  marketContext,
  fundamental,
  technical,
  optionsModule,
  optionsExpectedMove,
  analystRevisions,
  relativeStrength,
}) {
  const guidanceState = buildGuidanceState(analystRevisions, fundamental);
  const valuationState = buildValuationState(row, fundamental, guidanceState, companyProfile);
  const fundamentalHealth = buildFundamentalHealthState(fundamental, guidanceState, companyProfile);
  const trendState = buildTrendState(row, technical);
  const relativeStrengthState = buildRelativeStrengthState(relativeStrength, companyProfile);
  const volumeState = buildVolumeState(technical);
  const optionsState = buildOptionsState(row, optionsExpectedMove, optionsModule);
  const cycleState = buildCycleState(row, companyProfile, fundamental);
  const companyRisk = buildCompanyRiskState({
    fundamentalHealth,
    guidanceState,
    valuationState,
    volumeState,
    companyProfile,
  });
  const context = {
    decision_profile: companyProfile?.decision_profile || null,
    data_quality: dataQuality || null,
    market_context: marketContext || null,
    fundamental_health: fundamentalHealth,
    guidance_state: guidanceState,
    valuation_state: valuationState,
    trend_state: trendState,
    relative_strength_state: relativeStrengthState,
    volume_state: volumeState,
    options_state: optionsState,
    cycle_state: cycleState,
    company_risk: companyRisk,
    structural_levels: null,
  };
  context.field_mapping = buildTradeContextFieldMapping(row, context);
  return context;
}

function yearsSinceIsoDate(value) {
  if (!value) return null;
  const parsed = new Date(value);
  if (Number.isNaN(parsed.getTime())) return null;
  return (Date.now() - parsed.getTime()) / (365.25 * 24 * 60 * 60 * 1000);
}

function daysSinceTimestamp(value) {
  if (value == null || value === "") return null;
  const numeric = Number(value);
  let parsedMs = null;
  if (Number.isFinite(numeric)) {
    parsedMs = numeric > 10_000_000_000 ? numeric : numeric * 1000;
  } else {
    const parsed = new Date(value);
    parsedMs = Number.isNaN(parsed.getTime()) ? null : parsed.getTime();
  }
  if (!Number.isFinite(parsedMs)) return null;
  const ageMs = Date.now() - parsedMs;
  return ageMs >= 0 ? ageMs / (24 * 60 * 60 * 1000) : null;
}

function listingAgeDaysFromMetadata(row) {
  const metadata = row?.metadata || {};
  const candidates = [
    metadata.ipoDate,
    metadata.listingDate,
    metadata.firstTradeDate,
    metadata.firstTradeDateEpochUtc,
    metadata.firstTradeDateMilliseconds,
  ];
  for (const candidate of candidates) {
    const ageDays = daysSinceTimestamp(candidate);
    if (Number.isFinite(ageDays)) return ageDays;
  }
  return null;
}

function normalizeInstrumentMetadata(raw) {
  const row = raw?.metadata ? raw : { metadata: raw || {} };
  const metadata = row?.metadata || {};
  const ticker = normalizeTickerInput(row?.ticker || row?.symbol || metadata.symbol || metadata.underlyingSymbol || "");
  const supportedEtfMetadata = SUPPORTED_ETF_METADATA[ticker] || null;
  const read = (keys) => {
    for (const key of keys) {
      const value = metadata[key] ?? row?.[key];
      if (value != null && String(value).trim()) return String(value).trim();
    }
    return "";
  };
  const quoteType = read(["quoteType", "quote_type"]);
  const instrumentType = read(["instrumentType", "instrument_type"]);
  const securityType = read(["securityType", "security_type"]);
  const type = read(["type", "fundType", "assetClass"]);
  const exchange = read(["exchange", "fullExchangeName"]) || row?.exchangeName || "";
  const currency = read(["currency", "financialCurrency"]) || row?.currencyCode || "";
  const values = [quoteType, instrumentType, securityType, type].map((value) => value.toLowerCase()).filter(Boolean);
  const exactEtf = values.some((value) => ["etf", "exchange traded fund", "exchange-traded fund", "exchange_traded_fund"].includes(value)) || Boolean(supportedEtfMetadata);
  const exactEtn = values.some((value) => ["etn", "exchange traded note", "exchange-traded note", "exchange_traded_note"].includes(value));
  const exactFund = values.some((value) => ["mutualfund", "mutual fund", "fund", "closed end fund", "closed-end fund"].includes(value));
  const exactEquity = values.some((value) => ["equity", "common stock", "commonstock", "stock", "ordinary share"].includes(value));
  const adr = values.some((value) => /\badr\b|\bads\b|depositary/i.test(value))
    || /\badr\b|\bads\b|depositary/i.test(`${metadata.longName || ""} ${metadata.shortName || ""}`);
  const explicitSignals = [quoteType, instrumentType, securityType].filter(Boolean).length;
  const conflicting = (exactEtf || exactEtn || exactFund) && exactEquity;
  let status = "unavailable";
  if (conflicting) status = "conflicting";
  else if (explicitSignals >= 1) status = "verified";
  else if (type || exchange || currency) status = "partial";
  if (supportedEtfMetadata) status = "verified";
  const confidence = supportedEtfMetadata
    ? 96
    : status === "verified"
    ? (exactEtf || exactEtn || exactFund || exactEquity ? 92 : 76)
    : status === "conflicting" ? 35 : status === "partial" ? 52 : 20;
  return {
    instrument_type: instrumentType || null,
    quote_type: quoteType || null,
    security_type: supportedEtfMetadata ? "ETF" : securityType || type || null,
    exchange: exchange || null,
    currency: currency || null,
    is_equity: !supportedEtfMetadata && (exactEquity || (!exactEtf && !exactEtn && !exactFund && status === "verified")),
    is_etf: exactEtf,
    is_etn: exactEtn,
    is_fund: exactFund,
    is_adr: adr,
    is_common_stock: exactEquity,
    metadata_confidence: confidence,
    metadata_source: supportedEtfMetadata ? "supported_etf_metadata" : explicitSignals ? "quote_metadata" : status === "partial" ? "partial_metadata" : "unavailable",
    metadata_status: status,
    instrument_metadata_status: status,
    metadata_warning: status === "conflicting"
      ? "instrument metadata is conflicting"
      : status === "partial" || status === "unavailable"
        ? "security type needs verified quote metadata"
        : null,
  };
}

function buildETFProfile(instrumentMetadata = {}, tickerMetadata = {}) {
  const ticker = normalizeTickerInput(tickerMetadata.ticker || tickerMetadata.symbol || tickerMetadata.metadata?.symbol || "");
  const metadata = SUPPORTED_ETF_METADATA[ticker] || null;
  if (!metadata) return null;
  const leveraged = Math.abs(metadata.leverage_multiple || 1) > 1 || metadata.daily_reset;
  const inverse = metadata.direction === "inverse";
  return {
    instrument_type: "ETF",
    etf_type: metadata.etf_type,
    benchmark: metadata.benchmark,
    direction: metadata.direction,
    leverage_multiple: metadata.leverage_multiple,
    daily_reset: metadata.daily_reset,
    sector: metadata.sector || null,
    factor_style: metadata.factor_style || null,
    suitable_horizons: metadata.suitable_horizons,
    benchmark_tickers: metadata.benchmark_tickers || [],
    underlying_proxy: metadata.underlying_proxy || metadata.benchmark_tickers?.[0] || null,
    relative_strength_benchmarks: metadata.relative_strength_benchmarks || [],
    decay_risk: leveraged ? (Math.abs(metadata.leverage_multiple) >= 3 ? "high" : "elevated") : "low",
    path_dependency_risk: leveraged ? "high" : "low",
    inverse_risk: inverse ? "high" : "none",
    concentration_risk: metadata.etf_type === "broad_index" || /technology|semiconductor/i.test(metadata.sector || "") ? "elevated" : "normal",
    liquidity_risk: "unknown",
    options_behavior: leveraged
      ? "tactical_options_only"
      : "standard_etf_options",
    confidence: instrumentMetadata?.is_etf || instrumentMetadata?.metadata_source === "supported_etf_metadata" ? 96 : 88,
    holding_horizon_warning: leveraged
      ? (currentLanguage === "zh"
        ? "该 ETF 采用每日杠杆和每日再平衡，不适合作为普通长期核心仓位。长期表现可能因波动和路径依赖偏离标的累计收益的简单倍数。"
        : "This ETF uses daily leverage and daily rebalancing. It is not a normal long-term core holding; volatility and path dependency can make long-run returns diverge from a simple multiple of the underlying.")
      : null,
  };
}

function hasReliableEtfMetadata(row) {
  const metadata = normalizeInstrumentMetadata(row);
  return (metadata.is_etf || metadata.is_etn) && metadata.metadata_confidence >= 80;
}

function buildCashCowEvidence(row, metrics = {}) {
  const metadata = row?.metadata || {};
  const revenue = finiteNumberOrNull(metrics.revenue ?? metadata.totalRevenue ?? metadata.revenue);
  const freeCashFlow = finiteNumberOrNull(metrics.freeCashFlow ?? metadata.freeCashflow ?? metadata.freeCashFlow);
  const operatingCashFlow = finiteNumberOrNull(metrics.operatingCashFlow ?? metadata.operatingCashflow ?? metadata.operatingCashFlow ?? metadata.totalCashFromOperatingActivities);
  const netIncome = finiteNumberOrNull(metrics.netIncome ?? metadata.netIncomeToCommon ?? metadata.netIncome);
  const profitMargin = finiteNumberOrNull(metrics.profitMargin ?? metadata.profitMargins ?? metadata.profitMargin);
  const operatingMargin = finiteNumberOrNull(metrics.operatingMargin ?? metadata.operatingMargins);
  const freeCashFlowMargin = Number.isFinite(freeCashFlow) && Number.isFinite(revenue) && revenue > 0 ? freeCashFlow / revenue : null;
  const debtRatio = finiteNumberOrNull(metrics.debtRatio ?? (Number.isFinite(metadata.debtToEquity) ? metadata.debtToEquity / 100 : null));
  const currentRatio = finiteNumberOrNull(metrics.cashReserve ?? metadata.currentRatio);
  const revenueGrowth = normalizeRatioPercent(metrics.revenueGrowth ?? metadata.revenueGrowth);
  const positiveFcf = Number.isFinite(freeCashFlow) && freeCashFlow > 0;
  const positiveOperatingCashFlow = Number.isFinite(operatingCashFlow) && operatingCashFlow > 0;
  const positiveNetIncome = Number.isFinite(netIncome) && netIncome > 0;
  const stableMargin = (Number.isFinite(profitMargin) && profitMargin > 0.08) || (Number.isFinite(operatingMargin) && operatingMargin > 0.12);
  const fcfMarginScore = Number.isFinite(freeCashFlowMargin) ? clamp(Math.round(50 + freeCashFlowMargin * 220), 0, 100) : null;
  const balanceSheetQuality = Number.isFinite(debtRatio)
    ? (debtRatio <= 0.45 ? 78 : debtRatio <= 0.7 ? 58 : 34)
    : Number.isFinite(currentRatio) ? (currentRatio >= 1.5 ? 72 : currentRatio >= 1 ? 54 : 36) : null;
  const debtRisk = Number.isFinite(debtRatio) ? (debtRatio > 0.7 ? "high" : debtRatio > 0.45 ? "moderate" : "low") : "unavailable";
  const revenueNotDeteriorating = !Number.isFinite(revenueGrowth) || revenueGrowth > -8;
  const evidence = {
    positive_fcf: positiveFcf,
    positive_operating_cash_flow: positiveOperatingCashFlow,
    positive_net_income: positiveNetIncome,
    stable_margin: stableMargin,
    fcf_margin_score: fcfMarginScore,
    balance_sheet_quality: balanceSheetQuality,
    debt_risk: debtRisk,
    revenue_not_deteriorating: revenueNotDeteriorating,
  };
  const fields = [freeCashFlow, operatingCashFlow, netIncome, profitMargin ?? operatingMargin, freeCashFlowMargin, balanceSheetQuality, revenueGrowth];
  const dataCompleteness = Math.round((fields.filter((item) => item != null && Number.isFinite(item)).length / fields.length) * 100);
  const evidenceCount = [
    positiveFcf,
    positiveOperatingCashFlow,
    positiveNetIncome,
    stableMargin,
    Number.isFinite(fcfMarginScore) && fcfMarginScore >= 55,
    Number.isFinite(balanceSheetQuality) && balanceSheetQuality >= 55,
    debtRisk !== "high",
    revenueNotDeteriorating,
  ].filter(Boolean).length;
  const blockingReasons = [
    !positiveFcf ? "free cash flow is not positive or unavailable" : null,
    (!positiveOperatingCashFlow && !positiveNetIncome) ? "operating cash flow or net income is not positive or unavailable" : null,
    Number.isFinite(profitMargin) && profitMargin <= 0 ? "profit margin is not positive" : null,
    dataCompleteness < 55 ? "financial data completeness below CashCow minimum" : null,
    debtRisk === "high" ? "debt risk is high" : null,
    !stableMargin ? "profit / operating margin is not stable enough" : null,
    positiveFcf === false && positiveOperatingCashFlow === false ? "cash burn evidence" : null,
  ].filter(Boolean);
  const qualified = blockingReasons.length === 0
    && evidenceCount >= 5
    && dataCompleteness >= 55
    && positiveFcf
    && (positiveOperatingCashFlow || positiveNetIncome)
    && stableMargin;
  return {
    qualified,
    evidence,
    missing_fields: [
      Number.isFinite(freeCashFlow) ? null : "free_cash_flow",
      Number.isFinite(operatingCashFlow) ? null : "operating_cash_flow",
      Number.isFinite(netIncome) ? null : "net_income",
      Number.isFinite(profitMargin) || Number.isFinite(operatingMargin) ? null : "margin",
      Number.isFinite(balanceSheetQuality) ? null : "balance_sheet_quality",
    ].filter(Boolean),
    rejected_reason: qualified ? null : blockingReasons.join("; ") || "insufficient CashCow evidence",
    evidence_count: evidenceCount,
    data_completeness: dataCompleteness,
    free_cash_flow: freeCashFlow,
    operating_cash_flow: operatingCashFlow,
    net_income: netIncome,
    profit_margin: profitMargin,
    operating_margin: operatingMargin,
    free_cash_flow_margin: freeCashFlowMargin,
    balance_sheet_quality: balanceSheetQuality,
    debt_risk: debtRisk,
    explanation: qualified
      ? (currentLanguage === "zh" ? "CashCow 标签由正自由现金流、经营现金流、盈利、利润率和资产负债表共同确认。" : "CashCow is supported by FCF, operating cash flow, earnings, margins, and balance-sheet evidence.")
      : (currentLanguage === "zh" ? "CashCow 证据不足，已避免用默认标签推断。" : "CashCow evidence is insufficient, so the tag is not inferred by default."),
  };
}

function pushProfileTag(tagSet, reasons, tag, reason) {
  if (!tagSet.has(tag)) tagSet.add(tag);
  if (reason) reasons.push(reason);
}

function selectPrimaryCategory(tags) {
  const set = new Set(tags);
  if (set.has("ETF")) return "ETF";
  if (set.has("REIT")) return "REIT";
  if (set.has("Dividend")) return "Dividend";
  if (set.has("IPO")) return "IPO";
  if (set.has("NewlyListed")) return "NewlyListed";
  if (set.has("Speculative")) return "Speculative";
  if (set.has("MegaCap")) return "MegaCap";
  if (set.has("CashCow")) return "CashCow";
  if (set.has("HighGrowth")) return "HighGrowth";
  if (set.has("Growth")) return "Growth";
  if (set.has("StoryStock")) return "StoryStock";
  if (set.has("HighMultiple")) return "HighMultiple";
  if (set.has("Value")) return "Value";
  if (set.has("Cyclical")) return "Cyclical";
  if (set.has("Turnaround")) return "Turnaround";
  if (set.has("LargeCap")) return "LargeCap";
  if (set.has("MidCap")) return "MidCap";
  if (set.has("SmallCap")) return "SmallCap";
  return "Growth";
}

function buildProfilePenaltyWeights(tags, primaryCategory) {
  const buckets = [primaryCategory, ...tags].filter((tag) => PENALTY_PROFILE_WEIGHTS[tag]);
  if (!buckets.length) return { ...PROFILE_WEIGHT_DEFAULTS };
  const total = { ...PROFILE_WEIGHT_DEFAULTS };
  Object.keys(total).forEach((key) => { total[key] = 0; });
  buckets.forEach((tag) => {
    const weights = PENALTY_PROFILE_WEIGHTS[tag];
    Object.keys(total).forEach((key) => {
      total[key] += weights?.[key] ?? PROFILE_WEIGHT_DEFAULTS[key];
    });
  });
  Object.keys(total).forEach((key) => {
    total[key] = Number((total[key] / buckets.length).toFixed(2));
  });
  return total;
}

function buildScoringImpact(tags, primaryCategory) {
  const notes = [];
  const add = (text) => { if (!notes.includes(text)) notes.push(text); };
  if (tags.includes("HighMultiple") || tags.includes("StoryStock")) {
    add(currentLanguage === "zh" ? "估值惩罚权重下调，更重视成长、动量和新闻催化。" : "Valuation penalties are reduced while growth, momentum, and news matter more.");
  }
  if (tags.includes("Growth") || tags.includes("HighGrowth")) {
    add(currentLanguage === "zh" ? "成长放缓会被重点检查，收入和利润趋势权重更高。" : "Growth slowdown is watched more closely, with higher weight on revenue and EPS trends.");
  }
  if (tags.includes("MegaCap") || tags.includes("CashCow")) {
    add(currentLanguage === "zh" ? "现金流、利润率和估值纪律更重要，单日波动影响更小。" : "Cash flow, margins, and valuation discipline matter more than single-day noise.");
  }
  if (tags.includes("REIT") || tags.includes("Dividend") || tags.includes("InterestRateSensitive")) {
    add(currentLanguage === "zh" ? "债务、分红安全和利率环境权重更高。" : "Debt, dividend safety, and rates sensitivity carry more weight.");
  }
  if (tags.includes("IPO") || tags.includes("NewlyListed") || tags.includes("Speculative")) {
    add(currentLanguage === "zh" ? "历史数据不足会降低置信度，但不会因为 PE 缺失被直接重罚。" : "Limited history lowers confidence, but missing PE does not trigger a heavy penalty.");
  }
  if (tags.includes("Crypto")) {
    add(currentLanguage === "zh" ? "监管、流动性和宏观环境对评分影响更大。" : "Regulation, liquidity, and macro conditions have a larger impact.");
  }
  if (tags.includes("Cyclical") || tags.includes("Energy") || tags.includes("Semiconductor")) {
    add(currentLanguage === "zh" ? "行业周期、现金流和市场环境会更多影响评分。" : "Cycle, cash flow, and macro backdrop have a bigger influence on the model.");
  }
  if (!notes.length) {
    add(currentLanguage === "zh" ? "当前按中性权重处理，重点看技术、基本面和市场环境是否一致。" : "The model uses balanced weights and looks for agreement across technicals, fundamentals, and market context.");
  }
  return notes;
}

function buildProfileTagAudit(row, rawTags, context) {
  const sector = String(row.metadata?.sector || "").toLowerCase();
  const industry = String(row.metadata?.industry || "").toLowerCase();
  const description = String(row.metadata?.businessSummary || "").toLowerCase();
  const nameBlob = `${row.shortName || ""} ${row.longName || ""}`.toLowerCase();
  const sectorIndustryBlob = `${sector} ${industry}`;
  const coreBlob = `${sectorIndustryBlob} ${description} ${nameBlob}`;
  const rawSet = new Set(rawTags || []);
  const evidenceMap = {};
  const exposureMap = {};
  const rejected = [];
  const addEvidence = (tag, confidence, evidence, source = "core") => {
    if (!tag) return;
    evidenceMap[tag] ??= { confidence: 0, evidence: [], source_types: [] };
    evidenceMap[tag].confidence = Math.max(evidenceMap[tag].confidence, clamp(Math.round(confidence), 0, 100));
    evidenceMap[tag].evidence.push(...[].concat(evidence).filter(Boolean));
    evidenceMap[tag].source_types.push(source);
  };
  const addExposure = (tag, confidence, evidence, source = "exposure") => {
    if (!tag) return;
    exposureMap[tag] ??= { confidence: 0, evidence: [], source_types: [] };
    exposureMap[tag].confidence = Math.max(exposureMap[tag].confidence, clamp(Math.round(confidence), 0, 100));
    exposureMap[tag].evidence.push(...[].concat(evidence).filter(Boolean));
    exposureMap[tag].source_types.push(source);
  };
  const rejectTag = (tag, reason) => {
    if (!tag) return;
    rejected.push({
      tag,
      confidence: evidenceMap[tag]?.confidence ?? 0,
      reason,
      evidence: evidenceMap[tag]?.evidence || [],
    });
    delete evidenceMap[tag];
  };
	  const {
	    marketCap,
	    revenueGrowth,
	    freeCashFlow,
	    operatingCashFlow,
	    netIncome,
	    profitMargin,
	    operatingMargin,
	    grossMargin,
	    debtRatio,
    forwardPe,
    pe,
    psRatio,
    evSales,
    dividendYield: rawDividendYield,
    return30,
    return90,
    volatility30,
    relativeVolume,
    nearHigh,
    likelyIPO,
	    reitLike,
	    listingAgeDays,
	    cashCowEvidence: contextCashCowEvidence,
	    instrumentMetadata: contextInstrumentMetadata,
	  } = context;
  const dividendYield = normalizeDividendYield(rawDividendYield);
  const country = String(row.metadata?.country || "").toLowerCase();
  const exchangeName = String(row.exchangeName || row.metadata?.exchange || "").toLowerCase();
  const quoteType = String(row.metadata?.quoteType || "").toLowerCase();
	  const instrumentMetadata = contextInstrumentMetadata || normalizeInstrumentMetadata(row);
	  const etfIdentity = (instrumentMetadata.is_etf || instrumentMetadata.is_etn) && instrumentMetadata.metadata_confidence >= 80;
  const isUsListed = !isCnAShare(row) && /nasdaq|nyse|amex|nms|ngm|ncm|nyq|ase|nas/i.test(exchangeName);
  const directChinaCountry = /china|hong kong|prc/i.test(country);
  const caymanWithChinaBusiness = /cayman islands/i.test(country)
    && /(china-based|chinese company|people'?s republic of china|headquarter(?:ed|s)?\s+(?:in|at)\s+[^.]{0,80}(china|hong kong|shanghai|beijing|hangzhou|shenzhen|guangzhou))/i.test(description);
  const chinaIdentity = directChinaCountry || caymanWithChinaBusiness
    || /headquarter(?:ed|s)?\s+(?:in|at)\s+[^.]{0,80}(china|hong kong|shanghai|beijing|hangzhou|shenzhen|guangzhou)/i.test(description)
    || /(china-based|chinese company|people'?s republic of china)/i.test(description);
  const chinaExposure = /china|chinese|shanghai|beijing|shenzhen|hong kong/i.test(description);
  const adrIdentity = /adr|ads|american depositary/i.test(`${description} ${quoteType} ${exchangeName}`) || (isUsListed && chinaIdentity);
  const healthcareCore = /healthcare|health care|biotechnology|biotech|pharmaceutical|pharma|medical|medical device|health insurance|managed care|hospital|life sciences/i.test(sectorIndustryBlob)
    || /^(?:.*\b)(operates|provides|develops|manufactures|markets|sells|offers).{0,120}(healthcare services|medical devices|pharmaceuticals|therapeutics|clinical|hospital|health insurance|biotech|telehealth)/i.test(description);
  const healthcareExposure = !healthcareCore && /healthcare|health care|hospital|clinic|medical|life sciences/i.test(description);
  const autoCore = /auto manufacturers|automobile manufacturers|automotive|auto parts|vehicles/i.test(sectorIndustryBlob)
    || /(designs|develops|manufactures|sells|leases).{0,140}(electric vehicles|vehicles|automobiles|cars|trucks)/i.test(description);
  const evCore = autoCore && /electric vehicle|battery electric| evs\b|ev manufacturer|electric cars/i.test(description);
  const fintechCore = /financial technology|credit services|payments|capital markets|financial data|consumer finance|mortgage finance/i.test(sectorIndustryBlob)
    || /(operates|provides|offers).{0,140}(payments|payment network|digital banking|loans|lending|consumer finance|financial technology|brokerage|trading platform)/i.test(description);
  const bankingCore = /banks|banking|regional banks|diversified banks|commercial banks/i.test(sectorIndustryBlob)
    || /\bbank holding company\b|\bcommercial bank\b|\bprovides banking\b/i.test(description);
  const cryptoCore = /crypto|blockchain|digital asset/i.test(sectorIndustryBlob)
    || /(operates|provides|offers|issues).{0,140}(cryptocurrency|digital asset|blockchain|stablecoin|usd coin|usdc|crypto exchange)/i.test(description);
  const cloudCore = /software|internet content|information technology|communication services/i.test(sectorIndustryBlob)
    && /cloud platform|cloud infrastructure|cloud computing|saas|software-as-a-service|hyperscale|hyperscaler|azure|aws|google cloud/i.test(description);
  const softwareCore = /software|application software|infrastructure software|systems software|enterprise software/i.test(sectorIndustryBlob)
    || /(develops|provides|offers).{0,120}(software|software platform|enterprise platform|operating system|productivity applications)/i.test(description);
  const ecommerceCore = /internet retail|specialty retail|e-commerce|ecommerce/i.test(sectorIndustryBlob)
    || /e-commerce|ecommerce|online marketplace|online retail|marketplace|retail platform|consumer-to-manufacturer/i.test(description);

  if (Number.isFinite(marketCap)) {
    if (marketCap >= 200_000_000_000) addEvidence("MegaCap", 96, "market cap >= 200B", "market_cap");
    else if (marketCap >= 10_000_000_000) addEvidence("LargeCap", 92, "market cap 10B-200B", "market_cap");
    else if (marketCap >= 2_000_000_000) addEvidence("MidCap", 90, "market cap 2B-10B", "market_cap");
    else if (marketCap >= 300_000_000) addEvidence("SmallCap", 88, "market cap 300M-2B", "market_cap");
    else addEvidence("MicroCap", 88, "market cap < 300M", "market_cap");
  }

  if (isCnAShare(row)) {
    addEvidence("AShare", 96, "six-digit A-share ticker", "market");
    addExposure("ChinaMarket", 90, "China A-share market model", "market");
  } else if (isUsListed) {
    addExposure("USListed", 86, "US exchange listing", "market");
  }
  if (etfIdentity) {
    addEvidence("ETF", 94, "reliable instrument metadata indicates exchange-traded fund", "market");
  }
  if (chinaIdentity && adrIdentity && !isCnAShare(row)) {
    addEvidence("ChinaADR", 88, "company identity indicates China-based ADR / ADS listing", "market");
  } else if (chinaExposure && !isCnAShare(row)) {
    addExposure("ChinaExposure", 58, "China appears as revenue, manufacturing, supply chain, or market exposure rather than company identity", "exposure");
  }

  const semiconductorCore = /semiconductor|semiconductors|chip|chips|gpu|cpu|processor|memory|dram|nand|foundry|wafer|fabless|integrated circuit|silicon|semiconductor equipment|semiconductor material/i.test(coreBlob);
  if (semiconductorCore || rawSet.has("Semiconductor")) {
    addEvidence("Semiconductor", semiconductorCore ? 94 : 65, semiconductorCore ? "sector / industry / description points to chips or semiconductors" : "weak semiconductor keyword evidence", semiconductorCore ? "core" : "weak");
  }
  if (/gpu|ai accelerator|data center|datacenter|accelerated computing|ai server|memory|dram|hbm|networking.*data center|cloud ai infrastructure|inference|training/i.test(coreBlob) && (semiconductorCore || /cloud|data center|datacenter|infrastructure/i.test(coreBlob))) {
    addEvidence("AIInfrastructure", 88, "description links products to AI compute or data-center infrastructure", "description");
  }
  if (/artificial intelligence platform|ai platform|generative ai|machine learning platform|accelerated computing|ai infrastructure|ai accelerator|gpu|copilot|large language model|llm/i.test(coreBlob)) {
    addEvidence("AI", /gpu|ai accelerator|ai infrastructure|generative ai|ai platform/i.test(coreBlob) ? 84 : 68, "core description indicates direct AI product or infrastructure exposure", "description");
  }
  if (cloudCore) {
    addEvidence("Cloud", 84, "core business includes cloud platform / SaaS / hyperscale infrastructure", "description");
  }
  if (softwareCore) {
    addEvidence("Software", 80, "sector / description indicates software business model", "core");
  }
  if (ecommerceCore) {
    addEvidence("Ecommerce", 86, "description indicates e-commerce or marketplace business", "description");
    addEvidence("Consumer", 78, "consumer-facing commerce model", "description");
  } else if (!autoCore && /retail|consumer products|consumer goods|restaurant|apparel|merchant|shopping|household|personal care/i.test(coreBlob)) {
    addEvidence("Consumer", 78, "sector / description indicates consumer exposure", "core");
  } else if (/consumer|retail|merchant|shopping/i.test(description)) {
    addExposure("ConsumerExposure", 54, "consumer terms appear as customer or market exposure rather than core consumer business", "exposure");
  }
  if (/reit|real estate investment trust|property trust/i.test(coreBlob) || reitLike) {
    addEvidence("REIT", 95, "description / industry indicates REIT", "core");
    addEvidence("RealEstate", 88, "real estate business model", "core");
    addEvidence("InterestRateSensitive", 88, "REIT business model is rate sensitive", "business_model");
  }
  if (bankingCore || fintechCore) {
    addEvidence(bankingCore ? "Banking" : "Fintech", 82, "sector / core description indicates banking / lending / fintech business", "core");
    addEvidence("InterestRateSensitive", /mortgage|lending|consumer finance|bank/i.test(`${sectorIndustryBlob} ${description}`) ? 82 : 72, "lending / banking model is rate sensitive", "business_model");
  } else if (/bank|banking|mortgage|lending|consumer finance|personal loans|financial services|payments|fintech/i.test(description)) {
    addExposure("FinancialExposure", 55, "financial keywords appear as product, customer, or market exposure rather than core business", "exposure");
  }
  if (cryptoCore) {
    addEvidence("Crypto", 90, "core description directly references crypto / blockchain / stablecoin / digital assets", "description");
    if (/stablecoin|usd coin|usdc/i.test(description)) addEvidence("Stablecoin", 88, "core description references stablecoin / USDC", "description");
    addEvidence("Fintech", 76, "crypto financial infrastructure model", "description");
    addEvidence("InterestRateSensitive", 76, "stablecoin / crypto financial model can be rate sensitive", "business_model");
  } else if (/crypto|cryptocurrency|blockchain|bitcoin|stablecoin|digital asset|digital assets|crypto exchange|usd coin|usdc/i.test(description)) {
    addExposure("Crypto", 55, "crypto appears as holding, customer, or news exposure rather than core business", "exposure");
  }
  if (autoCore) {
    addEvidence("AutoManufacturer", 88, "sector / core description indicates vehicle manufacturing", "core");
  }
  if (evCore) {
    addEvidence("EV", 90, "industry / description indicates EV or auto manufacturing", "core");
  }
  if (/oil|gas|lng|drilling|shale|energy|solar|renewable/i.test(coreBlob)) {
    addEvidence("Energy", 84, "sector / description indicates energy exposure", "core");
  }
  if (healthcareCore) {
    addEvidence("Healthcare", 86, "sector / industry or core business indicates healthcare", "core");
  } else if (healthcareExposure) {
    addExposure("HealthcareExposure", 58, "healthcare appears as customer or market exposure rather than core business", "exposure");
  }
  if (/biotech|clinical trial|fda|drug development|therapeutics/i.test(coreBlob)) {
    addEvidence("Biotech", 86, "description indicates biotech / drug development", "description");
  }
  if (/defense|aerospace|military|government contract|national security/i.test(coreBlob)) {
    addEvidence("Defense", 84, "description indicates defense / aerospace exposure", "description");
  }

	  const cashCowEvidence = contextCashCowEvidence || buildCashCowEvidence(row, {
	    revenueGrowth,
	    freeCashFlow,
	    operatingCashFlow,
	    netIncome,
	    profitMargin,
	    operatingMargin,
	    grossMargin,
	    debtRatio,
	  });
	  if (cashCowEvidence.qualified) addEvidence("CashCow", 84, "objective CashCow evidence: positive FCF / cash flow / earnings / margins / balance sheet", "financial");
  if ((revenueGrowth ?? 0) >= 0.25 && (freeCashFlow ?? 0) > 0) addEvidence("HighGrowth", 80, "revenue growth >= 25% with positive cash flow", "financial");
  else if ((revenueGrowth ?? 0) >= 0.1) addEvidence("Growth", 76, "revenue growth >= 10%", "financial");
  if ((revenueGrowth ?? 0) >= 0.1 && (freeCashFlow ?? 0) > 0) addEvidence("ProfitableGrowth", 78, "growth supported by positive free cash flow", "financial");
  if (likelyIPO) addEvidence("NewlyListed", 82, `verified listing age ${Math.round(listingAgeDays)} days`, "metadata");
  if (likelyIPO) addEvidence("IPO", 72, `verified listing age ${Math.round(listingAgeDays)} days`, "metadata");
  if ((freeCashFlow ?? 0) < 0) addEvidence("CashBurn", 78, "free cash flow is negative", "financial");
  if ((volatility30 ?? 0) >= 55) addEvidence("HighVolatility", 78, "30D annualized volatility is elevated", "technical");
  if ((debtRatio ?? 0) > 0.7) addEvidence("HighDebtRisk", 82, "debt ratio is elevated", "financial");
  if ((dividendYield ?? 0) >= DIVIDEND_TAG_MIN_YIELD) addEvidence("Dividend", 80, "dividend yield >= 6%", "financial");
  if (rawSet.has("Speculative") && (evidenceMap.MicroCap || evidenceMap.SmallCap || evidenceMap.CashBurn || evidenceMap.HighVolatility)) addEvidence("Speculative", 78, "small / volatile / cash-burning profile", "combined");
  if (!likelyIPO && ((forwardPe ?? -1) > 50 || (pe ?? -1) > 60 || (psRatio ?? -1) > 10 || (evSales ?? -1) > 10)) addEvidence("HighMultiple", 78, "valuation multiples exceed high-multiple thresholds", "valuation");
  if ((return30 ?? 0) > 20 || (return90 ?? 0) > 35 || (nearHigh && (relativeVolume ?? 1) >= 1.15)) addEvidence("Momentum", 78, "30D / 90D return or near-high volume confirms momentum", "technical");
  if (semiconductorCore || /memory|industrial|materials|auto|travel|commodity/i.test(coreBlob)) addEvidence("Cyclical", semiconductorCore ? 76 : 68, "business has cyclical exposure", "core");

  if ((rawSet.has("ChinaADR") || chinaExposure) && !evidenceMap.ChinaADR && !isCnAShare(row)) {
    rejectTag("ChinaADR", "China appears as sales, manufacturing, supply-chain, or market exposure, not China ADR company identity.");
  }
  if ((rawSet.has("Healthcare") || healthcareExposure) && !healthcareCore) {
    rejectTag("Healthcare", "Healthcare appears as customer / market exposure, not core healthcare business.");
  }
  if ((rawSet.has("Fintech") || /payments|financial services|banking customers|finance customers/i.test(description)) && !fintechCore && !bankingCore) {
    rejectTag("Fintech", "Financial keywords appear as customer / product exposure, not core fintech business.");
  }
  if ((rawSet.has("Crypto") || /crypto|bitcoin|blockchain|stablecoin/i.test(description)) && !cryptoCore) {
    rejectTag("Crypto", "Crypto appears as holding, news, customer, or market exposure, not core crypto business.");
  }
  if ((rawSet.has("EV") || /electric vehicle|ev demand|ev customer|tesla/i.test(description)) && !evCore) {
    rejectTag("EV", "EV evidence is customer, demand, or supply-chain exposure, not core EV manufacturing.");
  }
  if ((rawSet.has("Banking") || /banking customer|banking product|financial customer/i.test(description)) && !bankingCore) {
    rejectTag("Banking", "Banking appears as customer / product exposure, not core banking business.");
  }

  if (evidenceMap.EV && !evCore) {
    rejectTag("EV", "EV evidence is not tied to core auto / EV business.");
  }
  if (evidenceMap.Crypto && !cryptoCore) {
    rejectTag("Crypto", "Crypto evidence is not tied to core business.");
  }
  if (evidenceMap.AI && evidenceMap.AI.confidence < 75) rejectTag("AI", "AI evidence is too generic.");
  if (evidenceMap.Cloud && !cloudCore) rejectTag("Cloud", "Cloud evidence is not tied to core business.");
  if (evidenceMap.ChinaADR && !chinaIdentity) rejectTag("ChinaADR", "China reference is exposure-only and does not establish China ADR identity.");
  if (evidenceMap.Healthcare && !healthcareCore) rejectTag("Healthcare", "Healthcare reference is exposure-only and does not establish healthcare as core business.");
  if (evidenceMap.REIT) {
    ["Growth", "HighGrowth", "Momentum"].forEach((tag) => {
      if (evidenceMap[tag] && evidenceMap[tag].confidence < 86) rejectTag(tag, "REIT profile takes priority over generic growth / momentum tag.");
    });
  }
  if (evidenceMap.MegaCap && evidenceMap.CashCow && evidenceMap.Speculative) rejectTag("Speculative", "Mega-cap cash-cow profile conflicts with speculative tag.");
  if (evidenceMap.NewlyListed && evidenceMap.HighMultiple && evidenceMap.HighMultiple.confidence < 85) rejectTag("HighMultiple", "Newly listed / limited data; valuation tag confidence is not high enough.");
  if (evidenceMap.Semiconductor && evidenceMap.EV && evidenceMap.EV.confidence < 92) rejectTag("EV", "Semiconductor core business is stronger than weak EV evidence.");

  Object.entries(evidenceMap).forEach(([tag, payload]) => {
    payload.evidence = [...new Set(payload.evidence)].slice(0, 4);
    payload.source_types = [...new Set(payload.source_types)];
    if (payload.source_types.length === 1 && payload.source_types[0] === "weak") payload.confidence = Math.min(payload.confidence, 60);
  });
  Object.entries(exposureMap).forEach(([, payload]) => {
    payload.evidence = [...new Set(payload.evidence)].slice(0, 4);
    payload.source_types = [...new Set(payload.source_types)];
    payload.confidence = clamp(Math.min(payload.confidence, 74), 40, 74);
  });
  Object.keys(evidenceMap).forEach((tag) => {
    if ((evidenceMap[tag]?.confidence ?? 0) < 60) rejectTag(tag, "confidence below display threshold");
  });

	  const cashCowTagEvidence = cashCowEvidence.qualified
	    ? {
	      ...(evidenceMap.CashCow || { confidence: 84, evidence: [], source_types: ["financial"] }),
	      qualified: true,
	      cash_cow_evidence: cashCowEvidence,
	    }
	    : {
	      confidence: 0,
	      evidence: [],
	      source_types: ["financial"],
	      qualified: false,
	      cash_cow_evidence: cashCowEvidence,
	      rejected_reason: cashCowEvidence.rejected_reason,
	      missing_fields: cashCowEvidence.missing_fields,
	    };
	  const fullTags = Object.keys(evidenceMap).filter((tag) => evidenceMap[tag].confidence >= 60);
  const groupOrder = {
    size: ["MegaCap", "LargeCap", "MidCap", "SmallCap", "MicroCap"],
    core: ["ETF", "Software", "Cloud", "Semiconductor", "MemoryStorage", "PowerSemiconductor", "PCB", "OpticalCommunication", "AIInfrastructure", "SocialMedia", "DigitalAds", "EV", "AutoManufacturer", "Ecommerce", "Consumer", "REIT", "Banking", "Fintech", "Energy", "Healthcare", "HealthInsurance", "HealthcareServices", "Biotech", "Crypto", "Industrial", "Defense", "RealEstate", "AI"],
    theme: ["GPU", "DataCenter", "DRAMNAND", "NAND", "IDM", "AdvancedPackaging", "ImageSensor", "PowerCable", "Networking", "ConsumerElectronics", "ConsumerPlatform", "ChinaConsumer", "HealthcareRealEstate"],
    quality: ["CashCow", "ProfitableGrowth", "HighGrowth", "Growth", "CyclicalGrowth", "Dividend", "Turnaround", "Speculative", "Defensive"],
    risk: ["HighMultiple", "ExtremeValuation", "HighVolatility", "HighDebtRisk", "CashBurn", "NewlyListed", "RegulatoryRisk"],
    cycle: ["Cyclical", "InterestRateSensitive"],
    geography: ["ChinaADR", "AShare", "USListed", "ChinaInternet"],
  };
  const priority = (tag) => {
    const entries = Object.entries(groupOrder);
    for (let groupIndex = 0; groupIndex < entries.length; groupIndex += 1) {
      const index = entries[groupIndex][1].indexOf(tag);
      if (index >= 0) return 100 - groupIndex * 15 - index * 0.25;
    }
    return 1;
  };
  const pickFromGroup = (selected, groupName, maxCount = 1) => {
    const candidates = groupOrder[groupName]
      .filter((tag) => fullTags.includes(tag) && (evidenceMap[tag]?.confidence ?? 0) >= 75 && !selected.includes(tag))
      .sort((a, b) => (evidenceMap[b].confidence - evidenceMap[a].confidence) || priority(b) - priority(a));
    candidates.slice(0, maxCount).forEach((tag) => {
      if (selected.length < 6) selected.push(tag);
    });
  };
  const topTags = [];
  pickFromGroup(topTags, "size", 1);
  pickFromGroup(topTags, "core", 3);
  pickFromGroup(topTags, "theme", 2);
  pickFromGroup(topTags, "quality", 2);
  pickFromGroup(topTags, "risk", 1);
  pickFromGroup(topTags, "cycle", 1);
  pickFromGroup(topTags, "geography", 1);
  fullTags
    .filter((tag) => (evidenceMap[tag]?.confidence ?? 0) >= 75 && !topTags.includes(tag))
    .sort((a, b) => priority(b) - priority(a) || evidenceMap[b].confidence - evidenceMap[a].confidence)
    .forEach((tag) => {
      if (topTags.length < 6) topTags.push(tag);
    });
  if (topTags.length > 6) topTags.length = 6;
  return {
    top_tags: topTags,
    full_tags: fullTags.sort((a, b) => priority(b) - priority(a) || evidenceMap[b].confidence - evidenceMap[a].confidence),
    exposure_tags: Object.keys(exposureMap).filter((tag) => exposureMap[tag].confidence >= 40)
      .sort((a, b) => exposureMap[b].confidence - exposureMap[a].confidence),
    rejected_tags: rejected,
	    tag_evidence: { ...evidenceMap, CashCow: cashCowTagEvidence },
    exposure_evidence: exposureMap,
  };
}

function buildCompanyProfile(row, research) {
  const metrics = research.metrics || {};
  const closes = row.technicals?.history?.closes || [];
  const textBlob = companyProfileTextBlob(row);
  const sectorBlob = companyProfileSectorBlob(row);
  const businessSummary = String(row.metadata?.businessSummary || "").toLowerCase();
  const marketCap = row.marketCap ?? null;
  const beta = row.metadata?.beta ?? null;
  const revenueGrowth = metrics.revenueGrowth ?? null;
	  const epsGrowth = metrics.epsGrowth ?? null;
	  const fcfGrowth = metrics.fcfGrowth ?? null;
	  const freeCashFlow = metrics.freeCashFlow ?? row.metadata?.freeCashflow ?? null;
	  const operatingCashFlow = metrics.operatingCashFlow ?? row.metadata?.operatingCashflow ?? row.metadata?.operatingCashFlow ?? null;
	  const netIncome = metrics.netIncome ?? row.metadata?.netIncomeToCommon ?? row.metadata?.netIncome ?? null;
	  const profitMargin = metrics.profitMargin ?? row.metadata?.profitMargins ?? null;
	  const netIncomeProxy = Number.isFinite(netIncome) ? netIncome : Number.isFinite(metrics.epsGrowth) ? metrics.epsGrowth : null;
  const operatingMargin = metrics.operatingMargin ?? row.metadata?.operatingMargins ?? null;
  const grossMargin = metrics.grossMargin ?? row.metadata?.grossMargins ?? null;
  const roe = metrics.roe ?? row.metadata?.returnOnEquity ?? null;
  const debtRatio = metrics.debtRatio ?? (Number.isFinite(row.metadata?.debtToEquity) ? row.metadata.debtToEquity / 100 : null);
  const cashRatio = metrics.cashReserve ?? row.metadata?.currentRatio ?? null;
  const pe = metrics.pe ?? row.trailingPE ?? null;
  const forwardPe = metrics.forwardPe ?? row.forwardPE ?? null;
  const peg = metrics.peg ?? null;
  const psRatio = metrics.psRatio ?? row.metadata?.priceToSalesTrailing12Months ?? null;
  const evEbitda = metrics.evEbitda ?? row.metadata?.enterpriseToEbitda ?? null;
  const evSales = row.metadata?.enterpriseToRevenue ?? null;
  const dividendYield = normalizeDividendYield(row.metadata?.dividendYield);
  const payoutRatio = row.metadata?.payoutRatio ?? null;
  const listingAgeDays = listingAgeDaysFromMetadata(row);
  const ipoAgeYears = Number.isFinite(listingAgeDays) ? listingAgeDays / 365.25 : null;
  const return30 = computeReturnPct(closes, 30);
  const return90 = computeReturnPct(closes, 90);
  const volatility30 = computeAnnualizedVolatility(closes, 30);
  const volatility90 = computeAnnualizedVolatility(closes, 90);
  const currentPrice = row.price ?? null;
  const high52 = row.technicals?.rangeHigh ?? null;
  const low52 = row.technicals?.rangeLow ?? null;
  const nearHigh = Number.isFinite(currentPrice) && Number.isFinite(high52) && high52 > 0 ? currentPrice >= high52 * 0.9 : false;
  const nearLow = Number.isFinite(currentPrice) && Number.isFinite(low52) && low52 > 0 ? currentPrice <= low52 * 1.15 : false;
  const relativeVolume = row.technicals?.volumeRatio ?? null;
  const tagSet = new Set();
  const reasons = [];
  const missing = [];
  const reitLike = /reit|real estate investment trust|地产信托|property trust|healthcare real estate|medical office|skilled nursing/i.test(textBlob);
  const healthcareSectorMatch = /healthcare|medical|hospital|pharma|pharmaceutical|biotech|life sciences/i.test(sectorBlob);
  const rateSensitiveKeywordCount = countRegexMatches(
    `${sectorBlob} ${businessSummary}`,
    /\breit\b|\bdividend\b|\bmortgage\b|\bbank(?:ing)?\b|\bfintech\b|\bpayments\b|\butility\b|\btreasury\b|\brate-sensitive\b|\bstablecoin\b|\bcrypto\b|\bconsumer finance\b|\bpersonal loans\b/gi,
  );
  const healthcareOperatorKeywordCount = countRegexMatches(
    businessSummary,
    /\bhospital\b|\btelehealth\b|\bpharma(?:ceutical)?\b|\bbiotech\b|\bmedical device\b|\bclinical\b|\bdrug\b/gi,
  );
	  const quoteType = String(row.metadata?.quoteType || "").toLowerCase();
	  const instrumentMetadata = normalizeInstrumentMetadata(row);
	  const etfLike = hasReliableEtfMetadata(row);
  const evKeywordCount = countRegexMatches(
    textBlob,
    /\belectric vehicle(?:s)?\b|\bev manufacturer\b|\bev maker\b|\bbattery electric vehicle\b|\bvehicle deliveries\b|\bautomaker\b|\bauto manufacturing\b|\bvehicle manufacturing\b/gi,
  );
  const evIndustryKeywordCount = countRegexMatches(
    `${sectorBlob} ${businessSummary}`,
    /\bauto(?:mobile)?\b|\bautomotive\b|\bcar maker\b|\bvehicle manufacturer\b|\bev manufacturer\b|\bev maker\b|\bvehicle manufacturing\b|\bauto manufacturing\b/gi,
  );
  const storyThemeKeywordCount = countRegexMatches(
    textBlob,
    /\bartificial intelligence\b|\bgenerative ai\b|\bcrypto\b|\bstablecoin\b|\bspace\b|\bquantum\b|\brobot(?:ics)?\b|\bautonomous\b|\belectric vehicle\b|\bev platform\b/gi,
  );

  if (!Number.isFinite(marketCap)) missing.push("market_cap");
  if (!Number.isFinite(revenueGrowth) && !Number.isFinite(epsGrowth) && !Number.isFinite(fcfGrowth)) missing.push("growth_metrics");
  if (!Number.isFinite(pe) && !Number.isFinite(forwardPe) && !Number.isFinite(psRatio)) missing.push("valuation_metrics");
  if (!textBlob) missing.push("company_metadata");

  if (isCnAShare(row)) {
    pushProfileTag(tagSet, reasons, "AShare", currentLanguage === "zh" ? "6 位数字代码识别为 A股。" : "Six-digit numeric ticker is classified as an A-share.");
    pushProfileTag(tagSet, reasons, "ChinaMarket", currentLanguage === "zh" ? "该股票使用中国 A股市场模型。" : "This stock uses the China A-share model.");
  }
  if (etfLike) {
    pushProfileTag(tagSet, reasons, "ETF", currentLanguage === "zh" ? "标的类型识别为 ETF。" : "Quote type indicates an ETF.");
  }

  if (Number.isFinite(marketCap)) {
    if (marketCap >= 200_000_000_000) pushProfileTag(tagSet, reasons, "MegaCap", currentLanguage === "zh" ? "市值大于等于 200B" : "Market cap is above $200B");
    else if (marketCap >= 10_000_000_000) pushProfileTag(tagSet, reasons, "LargeCap", currentLanguage === "zh" ? "市值位于 10B-200B" : "Market cap sits between $10B and $200B");
    else if (marketCap >= 2_000_000_000) pushProfileTag(tagSet, reasons, "MidCap", currentLanguage === "zh" ? "市值位于 2B-10B" : "Market cap sits between $2B and $10B");
    else if (marketCap >= 300_000_000) pushProfileTag(tagSet, reasons, "SmallCap", currentLanguage === "zh" ? "市值位于 300M-2B" : "Market cap sits between $300M and $2B");
    else pushProfileTag(tagSet, reasons, "MicroCap", currentLanguage === "zh" ? "市值低于 300M" : "Market cap is below $300M");
  }

  if (Number.isFinite(revenueGrowth) || Number.isFinite(epsGrowth) || Number.isFinite(fcfGrowth)) {
    if ((revenueGrowth ?? -1) >= 0.25 || (epsGrowth ?? -1) >= 0.25 || (fcfGrowth ?? -1) >= 0.25) {
      pushProfileTag(tagSet, reasons, "HighGrowth", currentLanguage === "zh" ? "增长指标大于等于 25%" : "Growth metrics are running above 25%");
    } else if ((revenueGrowth ?? -1) >= 0.1) {
      pushProfileTag(tagSet, reasons, "Growth", currentLanguage === "zh" ? "营收增长大于等于 10%" : "Revenue growth is above 10%");
    } else if ((revenueGrowth ?? -1) >= 0) {
      pushProfileTag(tagSet, reasons, "Mature", currentLanguage === "zh" ? "营收增长处于成熟区间" : "Revenue growth is in a mature range");
    } else {
      pushProfileTag(tagSet, reasons, "Declining", currentLanguage === "zh" ? "营收增长为负" : "Revenue growth is negative");
    }
  }

	  const hasPositiveIncomeProxy = (netIncomeProxy ?? -1) > 0;
	  const cashCowEvidence = buildCashCowEvidence(row, {
	    revenueGrowth,
	    freeCashFlow,
	    operatingCashFlow,
	    netIncome,
	    profitMargin,
	    operatingMargin,
	    grossMargin,
	    debtRatio,
	    cashReserve: cashRatio,
	  });
	  if (cashCowEvidence.qualified) {
	    pushProfileTag(tagSet, reasons, "CashCow", currentLanguage === "zh" ? "现金牛标签由自由现金流、经营现金流、盈利、利润率和资产负债表共同确认。" : "CashCow is confirmed by FCF, operating cash flow, earnings, margins, and balance sheet.");
	  }
  if ((revenueGrowth ?? 0) >= 0.1 && hasPositiveIncomeProxy && (freeCashFlow ?? 0) > 0) {
    pushProfileTag(tagSet, reasons, "ProfitableGrowth", currentLanguage === "zh" ? "成长和盈利兼具" : "Growth is supported by profits and free cash flow");
  }
  if ((revenueGrowth ?? 0) >= 0.15 && (!hasPositiveIncomeProxy || (freeCashFlow ?? 0) <= 0)) {
    pushProfileTag(tagSet, reasons, "UnprofitableGrowth", currentLanguage === "zh" ? "增长较快但盈利质量还不稳" : "Growth is fast but earnings quality is still unstable");
  }
  if ((freeCashFlow ?? 0) < 0 && !hasPositiveIncomeProxy) {
    pushProfileTag(tagSet, reasons, "CashBurn", currentLanguage === "zh" ? "自由现金流和盈利都偏弱" : "Free cash flow and earnings both look weak");
  }

  const likelyIPO = Number.isFinite(listingAgeDays) && listingAgeDays < 730;
  if (likelyIPO) {
    pushProfileTag(tagSet, reasons, "IPO", currentLanguage === "zh" ? "可验证上市时间不足 2 年" : "Verified listing age is under two years");
    pushProfileTag(tagSet, reasons, "NewlyListed", currentLanguage === "zh" ? "可验证上市历史仍然较短" : "Verified public listing history is still relatively short");
  }

  const speculativeBase = (
    (tagSet.has("SmallCap") || tagSet.has("MicroCap"))
    && ((freeCashFlow ?? 0) <= 0 || !hasPositiveIncomeProxy)
    && ((volatility30 ?? 0) >= 45 || (beta ?? 0) >= 1.5 || likelyIPO)
  );
  if (speculativeBase) {
    pushProfileTag(tagSet, reasons, "Speculative", currentLanguage === "zh" ? "小盘、高波动、盈利和现金流稳定性不足" : "Small cap, high volatility, and weaker cash-flow visibility make it speculative");
  }

  const valuationExempt = reitLike || tagSet.has("IPO") || tagSet.has("NewlyListed") || tagSet.has("Speculative") || tagSet.has("UnprofitableGrowth");
  if (!valuationExempt) {
    if ((forwardPe ?? -1) > 100 || (pe ?? -1) > 150 || (psRatio ?? -1) > 25 || (evSales ?? -1) > 25) {
      pushProfileTag(tagSet, reasons, "ExtremeValuation", currentLanguage === "zh" ? "估值倍数处于极高区间" : "Valuation multiples are in an extreme range");
    } else if ((forwardPe ?? -1) > 50 || (pe ?? -1) > 60 || (psRatio ?? -1) > 10 || (evSales ?? -1) > 10) {
      pushProfileTag(tagSet, reasons, "HighMultiple", currentLanguage === "zh" ? "远期 PE / PS 处于高倍数区间" : "Forward PE / PS sits in a high-multiple range");
    } else if (((forwardPe ?? -1) > 0 && (forwardPe ?? 0) < 20) || ((pe ?? -1) > 0 && (pe ?? 0) < 20)) {
      pushProfileTag(tagSet, reasons, "Value", currentLanguage === "zh" ? "传统估值处于偏低区间" : "Traditional valuation multiples look relatively low");
    } else if (((forwardPe ?? -1) >= 20 && (forwardPe ?? 0) <= 40) || ((peg ?? -1) >= 0.8 && (peg ?? 0) <= 2)) {
      pushProfileTag(tagSet, reasons, "ReasonableValuation", currentLanguage === "zh" ? "估值相对合理" : "Valuation looks broadly reasonable");
    }
  }

  if (reitLike) {
    pushProfileTag(tagSet, reasons, "REIT", currentLanguage === "zh" ? "公司描述包含 REIT / 地产信托特征" : "Business description matches REIT characteristics");
  }
  if ((dividendYield ?? 0) >= DIVIDEND_TAG_MIN_YIELD) pushProfileTag(tagSet, reasons, "Dividend", currentLanguage === "zh" ? "股息率大于等于 6%" : "Dividend yield is above 6%");
  if (tagSet.has("REIT") || tagSet.has("Dividend") || rateSensitiveKeywordCount >= 1) {
    pushProfileTag(tagSet, reasons, "InterestRateSensitive", currentLanguage === "zh" ? "对利率环境更敏感" : "The business is more sensitive to interest-rate conditions");
  }

  if ((return30 ?? 0) > 20 || (relativeVolume ?? 0) > 1.5 || (beta ?? 0) > 1.5 || nearHigh) {
    pushProfileTag(tagSet, reasons, "Momentum", currentLanguage === "zh" ? "近期动量、量能或 Beta 偏高" : "Recent momentum, volume, or beta points to a momentum profile");
  }
  if ((tagSet.has("HighMultiple") || tagSet.has("ExtremeValuation")) && (storyThemeKeywordCount >= 1 || tagSet.has("Momentum"))) {
    pushProfileTag(tagSet, reasons, "StoryStock", currentLanguage === "zh" ? "估值更多依赖未来叙事和情绪催化" : "Valuation depends heavily on future narrative and sentiment catalysts");
  }
  if (nearLow && (revenueGrowth ?? 0) >= 0 && (operatingMargin ?? 0) >= 0.05 && (fcfGrowth ?? 0) > -0.05) {
    pushProfileTag(tagSet, reasons, "Turnaround", currentLanguage === "zh" ? "价格偏离高点较多，但经营数据有企稳迹象" : "Price is far below prior highs while operating metrics are stabilizing");
  }

  if (/artificial intelligence|machine learning|generative ai|data platform|copilot|\bai\b/i.test(textBlob)) pushProfileTag(tagSet, reasons, "AI", currentLanguage === "zh" ? "公司描述或主题包含 AI" : "Company description or theme includes AI");
  if (/semiconductor|chip|gpu|memory|foundry|wafer|fab/i.test(textBlob)) pushProfileTag(tagSet, reasons, "Semiconductor", currentLanguage === "zh" ? "公司属于半导体 / 芯片链条" : "Business exposure points to semiconductors");
  if (/\bcloud\b|\bsaas\b|\bazure\b|\baws\b|\bgcp\b|\bcloud platform\b|\bcloud computing\b/i.test(textBlob)) pushProfileTag(tagSet, reasons, "Cloud", currentLanguage === "zh" ? "公司描述包含云 / SaaS 业务" : "Cloud / SaaS keywords are present");
  if (/advertising|ads|search/i.test(textBlob)) pushProfileTag(tagSet, reasons, "Advertising", currentLanguage === "zh" ? "业务与广告相关" : "Advertising-related business exposure is visible");
  if (/crypto|blockchain|bitcoin|stablecoin|digital asset|exchange/i.test(textBlob)) pushProfileTag(tagSet, reasons, "Crypto", currentLanguage === "zh" ? "业务与加密 / 稳定币相关" : "Business is tied to crypto / stablecoin themes");
  if (/stablecoin/i.test(textBlob)) pushProfileTag(tagSet, reasons, "Stablecoin", currentLanguage === "zh" ? "业务与稳定币相关" : "Business is tied to stablecoins");
  if (/oil|gas|lng|drilling|shale|energy/i.test(textBlob)) pushProfileTag(tagSet, reasons, "Energy", currentLanguage === "zh" ? "业务与能源周期相关" : "Business is tied to the energy cycle");
  if (!reitLike && (healthcareSectorMatch || healthcareOperatorKeywordCount >= 2)) {
    pushProfileTag(tagSet, reasons, "Healthcare", currentLanguage === "zh" ? "行业或主营业务与医疗健康相关" : "Sector or core business points to healthcare");
  }
  if (/biotech|clinical trial|fda|drug/i.test(textBlob)) pushProfileTag(tagSet, reasons, "Biotech", currentLanguage === "zh" ? "业务与生物科技 / 药物研发相关" : "Business belongs to biotech / drug development");
  if (/digital banking|lending|payments|fintech|personal finance/i.test(textBlob)) pushProfileTag(tagSet, reasons, "Fintech", currentLanguage === "zh" ? "业务与金融科技相关" : "Business belongs to fintech");
  if (/defense|aerospace|military|government contract|national security/i.test(textBlob)) pushProfileTag(tagSet, reasons, "Defense", currentLanguage === "zh" ? "业务与国防 / 政府合同相关" : "Business exposure points to defense / government contracts");
  if (/retail|e-commerce|consumer|restaurant|apparel/i.test(textBlob)) pushProfileTag(tagSet, reasons, "Consumer", currentLanguage === "zh" ? "业务与消费相关" : "Business belongs to consumer sectors");
  if (tagSet.has("Semiconductor") || tagSet.has("Energy") || /\bauto\b|\btravel\b|\bindustrial\b|\bmaterials\b|\bmemory\b/i.test(textBlob)) pushProfileTag(tagSet, reasons, "Cyclical", currentLanguage === "zh" ? "业务带有明显周期属性" : "Business has cyclical characteristics");
  if (evKeywordCount >= 2 || (evKeywordCount >= 1 && evIndustryKeywordCount >= 1)) {
    pushProfileTag(tagSet, reasons, "EV", currentLanguage === "zh" ? "主营描述明确指向电动车 / 汽车制造。" : "Core business text clearly points to EV or auto manufacturing.");
  }

  const rawTags = Array.from(tagSet);
  const tagAudit = buildProfileTagAudit(row, rawTags, {
	    marketCap,
	    revenueGrowth,
	    freeCashFlow,
	    operatingCashFlow,
	    netIncome,
	    profitMargin,
	    operatingMargin,
	    grossMargin,
    debtRatio,
    forwardPe,
    pe,
    psRatio,
    evSales,
    dividendYield,
    return30,
    return90,
    volatility30,
    relativeVolume,
    nearHigh,
    likelyIPO,
	    listingAgeDays,
	    reitLike,
	    cashCowEvidence,
	    instrumentMetadata,
	  });
  if (isCnAShare(row) && !tagAudit.top_tags.includes("AShare")) {
    tagAudit.top_tags.unshift("AShare");
    tagAudit.top_tags = [...new Set(tagAudit.top_tags)].slice(0, 6);
  }
  if (isCnAShare(row) && !tagAudit.top_tags.includes("ChinaMarket") && tagAudit.top_tags.length < 6) {
    tagAudit.top_tags.push("ChinaMarket");
  }
  if (isCnAShare(row) && !tagAudit.top_tags.includes("HighVolatility") && tagAudit.top_tags.length < 6) {
    tagAudit.top_tags.push("HighVolatility");
  }
  const fallbackTags = tagAudit.full_tags.length ? tagAudit.full_tags : rawTags.slice(0, 6);
  const fallbackTopTags = tagAudit.top_tags.length ? tagAudit.top_tags : fallbackTags.slice(0, 6);
  const fallbackCategory = selectPrimaryCategory(fallbackTopTags.length ? fallbackTopTags : fallbackTags);
  const classificationProfile = buildClassificationProfile(row, tagAudit, fallbackCategory, missing);
  const decisionProfile = buildDecisionProfile({
    ...classificationProfile,
    top_tags: classificationProfile.tags,
    full_tags: tagAudit.full_tags,
    exposure_tags: tagAudit.exposure_tags,
    rejected_tags: tagAudit.rejected_tags,
  }, schemaMarketTypeForTicker(row));
  const tags = [...new Set([...(classificationProfile.tags || []), ...fallbackTags])];
  const primaryCategory = classificationProfile.category || fallbackCategory;
  const classificationConfidence = classificationProfile.tag_confidence;
  const penaltyWeights = buildProfilePenaltyWeights(tags, primaryCategory);
  const scoringImpact = buildScoringImpact(tags, primaryCategory);
  const classificationReasons = classificationProfile.tags
    .flatMap((tag) => (classificationProfile.tag_evidence[tag]?.evidence || []).map((item) => `${localizedProfileTag(tag)}: ${localizedProfileEvidence(tag, item)}`))
    .slice(0, 5);

  return {
    primary_category: primaryCategory,
    primary_category_label: localizedProfileTag(primaryCategory),
    category_key: classificationBucketKey(primaryCategory, tags),
    category: localizedProfileTag(primaryCategory),
    tags,
    tags_label: classificationProfile.tags.slice(0, 6).map(localizedProfileTag),
    top_tags: classificationProfile.tags.slice(0, 6),
    top_tags_label: classificationProfile.tags.slice(0, 6).map(localizedProfileTag),
    full_tags: tagAudit.full_tags,
    full_tags_label: tagAudit.full_tags.map(localizedProfileTag),
    exposure_tags: tagAudit.exposure_tags,
    exposure_tags_label: tagAudit.exposure_tags.map(localizedProfileTag),
    rejected_tags: tagAudit.rejected_tags,
	    tag_evidence: classificationProfile.tag_evidence,
	    cash_cow_evidence: cashCowEvidence,
	    exposure_evidence: tagAudit.exposure_evidence,
    classification_confidence: classificationConfidence,
    classification_reasons: [...new Set(classificationReasons.length ? classificationReasons : reasons)].slice(0, 5),
    missing_classification_data: missing,
	    listing_age_days: Number.isFinite(listingAgeDays) ? Math.round(listingAgeDays) : null,
	    instrument_metadata: instrumentMetadata,
	    instrument_metadata_status: instrumentMetadata.instrument_metadata_status,
    ipo_evidence: {
      likely_ipo: likelyIPO,
      listing_age_days: Number.isFinite(listingAgeDays) ? Math.round(listingAgeDays) : null,
      source: Number.isFinite(listingAgeDays) ? "listing_metadata" : "unavailable",
      rule: "IPO/NewlyListed only when verified listing_age_days < 730",
    },
    penalty_profile_weights: penaltyWeights,
    scoring_impact: scoringImpact,
    classification: classificationProfile,
    decision_profile: decisionProfile,
    scoring_profile: classificationProfile.scoring_profile,
    scoring_profile_label: classificationProfile.scoring_profile_label,
    scoring_weights: decisionProfile.final_weights,
    tag_confidence: classificationProfile.tag_confidence,
    tag_source: classificationProfile.tag_source,
  };
}

function levelSourceLabel(item) {
  if (!item) return "";
  if (item.source === "ma") return item.label;
  if (item.source === "fib") return item.label;
  if (item.source === "bollinger") return item.label;
  if (item.source === "options") return item.label;
  if (item.source === "volume") return currentLanguage === "zh" ? "成交量密集区" : "Volume cluster";
  if (item.source === "historical") return item.label;
  if (item.source === "atr") return "ATR";
  return item.label || item.source || "";
}

function ratingRank(rating) {
  const map = {
    Short: 0,
    "Short Candidate": 0,
    "Strong Sell": 1,
    "Sell-Avoid": 2,
    Sell: 2,
    Reduce: 3,
    "Hold-Watch": 4,
    Hold: 4,
    Buy: 5,
    "Strong Buy": 6,
  };
  return map[rating] ?? 4;
}

function ratingAtLeast(rating, target) {
  return ratingRank(rating) >= ratingRank(target);
}

function zoneDistancePct(price, low, high) {
  if (!Number.isFinite(price) || !Number.isFinite(low) || !Number.isFinite(high)) return null;
  if (price >= low && price <= high) return 0;
  const boundary = price < low ? low : high;
  return Math.abs((price - boundary) / Math.max(price, 1)) * 100;
}

function isPriceInsideIdealBuyZone(price, zone) {
  return Number.isFinite(price) && Number.isFinite(zone?.low) && Number.isFinite(zone?.high) && price >= zone.low && price <= zone.high;
}

function isPriceNearIdealBuyZone(price, zone, thresholdPct = 2) {
  const distance = zoneDistancePct(price, zone?.low, zone?.high);
  return distance != null && distance <= thresholdPct;
}

function marketStateFromScores(shortScore, midScore, longScore, technicalState) {
  const blended = mean([shortScore, midScore, longScore]) ?? 50;
  if (blended >= 82 || technicalState === "Strong Bullish") return "Strong Bullish";
  if (blended >= 68) return "Bullish";
  if (blended >= 55) return "Neutral";
  if (blended >= 40) return "Bearish";
  return "Strong Bearish";
}

function supportResistanceSourceQuality(label = "") {
  const normalized = String(label).toLowerCase();
  if (normalized.includes("ma200")) return 2;
  if (normalized.includes("ma20") || normalized.includes("ma50") || normalized.includes("ma100")) return 1;
  if (normalized.includes("fib 38.2") || normalized.includes("fib 50") || normalized.includes("fib 61.8")) return 2;
  if (normalized.includes("fib")) return 1;
  if (normalized.includes("previous high") || normalized.includes("previous low")) return 1;
  if (normalized.includes("swing high") || normalized.includes("swing low")) return 1;
  if (normalized.includes("成交量密集区") || normalized.includes("volume cluster")) return 2;
  if (normalized.includes("put wall") || normalized.includes("call wall")) return 2;
  if (normalized.includes("gamma flip")) return 2;
  if (normalized.includes("upper band") || normalized.includes("lower band") || normalized.includes("middle band") || normalized.includes("布林")) return 1;
  if (normalized.includes("atr")) return 1;
  return 1;
}

function supportResistanceStrengthBand(points) {
  if (points >= 6) return "strong";
  if (points >= 3) return "medium";
  return "weak";
}

function computeLevelStrength(item, currentPrice) {
  const sources = [...new Set((item.sources || []).filter(Boolean))];
  let points = 0;

  if (sources.length >= 3) points += 3;
  else if (sources.length === 2) points += 2;
  else if (sources.length === 1) points += 1;

  points += sources.reduce((sum, source) => sum + supportResistanceSourceQuality(source), 0);

  const distancePct = Number.isFinite(currentPrice) && Number.isFinite(item.price)
    ? Math.abs((item.price - currentPrice) / Math.max(currentPrice, 1)) * 100
    : null;
  if (distancePct != null && distancePct <= 3) points += 2;
  else if (distancePct != null && distancePct <= 7) points += 1;

  const rawItems = item.raw_items || [];
  if (rawItems.length >= 2) points += 2;
  else if (rawItems.length === 1) points += 1;

  const hasVolumeCluster = sources.some((source) => /volume cluster|成交量密集区/i.test(source))
    || rawItems.some((raw) => raw?.source === "volume");
  if (hasVolumeCluster) points += 2;

  const strength = supportResistanceStrengthBand(points);
  const score = clamp(Math.round(18 + points * 11), 0, 100);
  return {
    points,
    score,
    strength,
    distance_pct: distancePct,
    has_volume_cluster: hasVolumeCluster,
    test_count: rawItems.length,
  };
}

function applyVolumeConfirmationToLevelStrength(strengthInfo, item, currentPrice, side, row) {
  const tech = row.technicals || {};
  const distancePct = Number.isFinite(currentPrice) && Number.isFinite(item.price)
    ? Math.abs((item.price - currentPrice) / Math.max(currentPrice, 1)) * 100
    : null;
  if (distancePct == null || distancePct > 3.5) return strengthInfo;

  let points = strengthInfo.points;
  const notes = [];
  const volumeRatio = tech.volumeRatio ?? 1;
  const closePosition = tech.closePosition ?? 0.5;
  const obv20 = obvTrend(tech.history?.closes || [], tech.history?.volumes || [], 20);
  const changePct = row.changePercent ?? 0;

  if (side === "support") {
    if (changePct > 0.4 && volumeRatio >= 1.2) {
      points += 2;
      notes.push(currentLanguage === "zh" ? "支撑附近放量反弹" : "volume-backed rebound near support");
    }
    if (["rising", "neutral"].includes(obv20)) {
      points += 1;
      notes.push(currentLanguage === "zh" ? "OBV 稳定或上升" : "OBV stable or rising");
    }
    if (volumeRatio >= 1.2 && closePosition >= 0.6) {
      points += 1;
      notes.push(currentLanguage === "zh" ? "高换手/放量且收盘偏强" : "active participation with a strong close");
    }
    if (changePct < -0.8 && volumeRatio >= 1.2 && closePosition <= 0.4) {
      points -= 2;
      notes.push(currentLanguage === "zh" ? "放量跌破风险" : "volume-backed support-break risk");
    }
    if (closePosition <= 0.35) {
      points -= 1;
      notes.push(currentLanguage === "zh" ? "支撑附近收盘偏弱" : "weak close near support");
    }
  } else if (side === "resistance") {
    if (changePct > 0.5 && volumeRatio >= 1.2 && closePosition < 0.55) {
      points += 2;
      notes.push(currentLanguage === "zh" ? "压力附近放量冲高回落" : "volume-backed fade near resistance");
    }
    if (volumeRatio >= 1.4 && obv20 !== "rising") {
      points += 2;
      notes.push(currentLanguage === "zh" ? "高量但 OBV 未确认" : "high volume without OBV confirmation");
    }
    if ((item.raw_items || []).length >= 2) {
      points += 2;
      notes.push(currentLanguage === "zh" ? "多次突破失败" : "multiple failed tests");
    }
    if (currentPrice > item.price * 1.005 && volumeRatio < 1.2) {
      points += 1;
      notes.push(currentLanguage === "zh" ? "突破量能不足" : "weak breakout volume");
    }
  }

  const adjustedPoints = Math.max(0, points);
  return {
    ...strengthInfo,
    points: adjustedPoints,
    score: clamp(Math.round(18 + adjustedPoints * 11), 0, 100),
    strength: supportResistanceStrengthBand(adjustedPoints),
    volume_notes: notes,
  };
}

function dedupeLevels(items, side, price, clusterMultiplier = 0.25, atr = null) {
  const tolerance = Math.max((price || 1) * 0.0075, Number.isFinite(atr) ? atr * clusterMultiplier : 0, 0.01);
  const output = [];
  items.forEach((item) => {
    if (!Number.isFinite(item.price)) return;
    const exists = output.some((entry) => Math.abs(entry.price - item.price) <= tolerance);
    if (!exists) output.push(item);
  });
  return output.sort((a, b) => (side === "support" ? b.price - a.price : a.price - b.price));
}

function classifyLevelSide(levelPrice, currentPrice) {
  if (!Number.isFinite(levelPrice) || !Number.isFinite(currentPrice) || currentPrice <= 0) return null;
  if (levelPrice < currentPrice * 0.995) return "support";
  if (levelPrice > currentPrice * 1.005) return "resistance";
  return "pivot";
}

function supportResistanceRelativeStrengthNote(side, tradeContext = null) {
  const rs = tradeContext?.relative_strength_state;
  if (!rs || rs.regime === "unavailable") {
    return currentLanguage === "zh" ? "相对强度暂无确认" : "Relative strength unavailable";
  }
  if (side === "support") {
    if (rs.improving || rs.regime === "improving") return currentLanguage === "zh" ? "相对 SPY / QQQ 改善，支撑可信度提高" : "Relative strength improving versus SPY / QQQ, support quality improves";
    if (rs.deteriorating || rs.regime === "deteriorating") return currentLanguage === "zh" ? "相对强度转弱，支撑需要更多确认" : "Relative strength weakening, support needs more confirmation";
  }
  if (side === "resistance") {
    if (rs.deteriorating || rs.regime === "deteriorating") return currentLanguage === "zh" ? "相对强度转弱，压力位卖出证据提高" : "Relative strength weakening, resistance evidence improves";
    if (rs.improving || rs.regime === "improving") return currentLanguage === "zh" ? "相对强度改善，突破压力的可能性提高" : "Relative strength improving, breakout odds improve";
  }
  return currentLanguage === "zh" ? "相对强度中性" : "Relative strength neutral";
}

function adjustLevelScoreForTradeContext(score, side, tradeContext = null) {
  let adjusted = score;
  const rs = tradeContext?.relative_strength_state;
  const volume = tradeContext?.volume_state;
  if (side === "support") {
    if (rs?.improving || rs?.regime === "improving") adjusted += 4;
    if (rs?.deteriorating || rs?.regime === "deteriorating") adjusted -= 5;
    if (volume?.obv_trend_20d === "falling" || volume?.distribution_risk) adjusted -= 6;
    if (["strong_accumulation", "early_accumulation"].includes(volume?.regime)) adjusted += 4;
  } else if (side === "resistance") {
    if (rs?.deteriorating || rs?.regime === "deteriorating") adjusted += 4;
    if (rs?.improving || rs?.regime === "improving") adjusted -= 3;
    if (volume?.distribution_risk) adjusted += 5;
    if (["strong_accumulation", "breakout_confirmation"].includes(volume?.regime)) adjusted -= 4;
  }
  return clamp(Math.round(adjusted), 0, 100);
}

function addExpectedMoveLevels(extras, row, tradeContext = null) {
  const expectedMove = tradeContext?.options_state?.expected_move;
  if (!expectedMove || !Number.isFinite(row.price)) return;
  [
    { side: "support", price: expectedMove.lower_7d, score: 28, label: "Expected Move Lower 7D" },
    { side: "support", price: expectedMove.lower_30d, score: 32, label: "Expected Move Lower 30D" },
    { side: "resistance", price: expectedMove.upper_7d, score: 28, label: "Expected Move Upper 7D" },
    { side: "resistance", price: expectedMove.upper_30d, score: 32, label: "Expected Move Upper 30D" },
  ].forEach((level) => {
    if (!Number.isFinite(level.price) || level.price <= 0) return;
    extras.push({
      side: level.side,
      price: level.price,
      score: level.score,
      sources: [level.label],
      explanation: currentLanguage === "zh"
        ? "期权预期波动边界，仅作为辅助可达性参考，不替代结构性支撑压力。"
        : "Options expected-move bound, used only as auxiliary reachability context, not a structural level replacement.",
    });
  });
}

function buildSupportResistanceSchema(row, companyProfile = null, tradeContext = null) {
  const tech = row.technicals || {};
  const sr = tech.srAnalysis || {};
  const price = row.price ?? 0;
  const rangeParams = decisionRangeParameters(row, companyProfile || {});
  const options = row.research?.optionsRead || buildOptionsRead(row);
  const fibs = [0.236, 0.382, 0.5, 0.618, 0.786]
    .map((ratio) => tech.rangeLow != null && tech.rangeHigh != null ? tech.rangeLow + (tech.rangeHigh - tech.rangeLow) * ratio : null)
    .filter(Number.isFinite);
  const extras = [
    { side: "support", price: tech.ma20, score: 54, sources: ["MA20"], explanation: currentLanguage === "zh" ? "价格接近 MA20 支撑。" : "Price is near MA20 support." },
    { side: "support", price: tech.ma50, score: 62, sources: ["MA50"], explanation: currentLanguage === "zh" ? "价格接近 MA50 支撑。" : "Price is near MA50 support." },
    { side: "support", price: tech.ma200, score: 72, sources: ["MA200"], explanation: currentLanguage === "zh" ? "价格接近 MA200 长期支撑。" : "Price is near MA200 long-term support." },
    { side: "support", price: tech.lowerBand, score: 42, sources: [currentLanguage === "zh" ? "布林下轨" : "Lower Band"], explanation: currentLanguage === "zh" ? "接近布林下轨。" : "Price is near the lower Bollinger band." },
    { side: "support", price: options.putWall, score: 74, sources: ["Put Wall"], explanation: currentLanguage === "zh" ? "期权 Put Wall 提供潜在支撑。" : "Put wall can provide structural support." },
    { side: "support", price: options.gammaFlip && options.gammaFlip <= price ? options.gammaFlip : null, score: 64, sources: ["Gamma Flip"], explanation: currentLanguage === "zh" ? "Gamma Flip 下方通常更容易形成支撑。" : "Gamma flip below spot can help support." },
    { side: "resistance", price: tech.upperBand, score: 42, sources: [currentLanguage === "zh" ? "布林上轨" : "Upper Band"], explanation: currentLanguage === "zh" ? "接近布林上轨。" : "Price is near the upper Bollinger band." },
    { side: "resistance", price: options.callWall, score: 76, sources: ["Call Wall"], explanation: currentLanguage === "zh" ? "期权 Call Wall 形成上方压力。" : "Call wall is acting as overhead resistance." },
    { side: "resistance", price: options.gammaFlip && options.gammaFlip >= price ? options.gammaFlip : null, score: 64, sources: ["Gamma Flip"], explanation: currentLanguage === "zh" ? "Gamma Flip 上方容易变成压力位。" : "Gamma flip above spot can become resistance." },
  ];
  addExpectedMoveLevels(extras, row, tradeContext);

  fibs.forEach((fibValue, index) => {
    extras.push({
      side: fibValue <= price ? "support" : "resistance",
      price: fibValue,
      score: 50,
      sources: [`Fib ${[23.6, 38.2, 50, 61.8, 78.6][index]}%`],
      explanation: currentLanguage === "zh" ? "关键斐波那契回撤位。" : "Key Fibonacci retracement level.",
    });
  });

  if (Number.isFinite(tech.atr14)) {
    extras.push({
      side: "support",
      price: price - tech.atr14,
      score: 34,
      sources: ["ATR"],
      explanation: currentLanguage === "zh" ? "ATR 下沿参考位。" : "ATR-based downside reference.",
    });
    extras.push({
      side: "resistance",
      price: price + tech.atr14,
      score: 34,
      sources: ["ATR"],
      explanation: currentLanguage === "zh" ? "ATR 上沿参考位。" : "ATR-based upside reference.",
    });
  }

  const rawLevels = [
    ...((sr.support || []).map((cluster) => ({
      side_hint: "support",
      price: cluster.price,
      score: cluster.score,
      raw_items: cluster.items || [],
      sources: [...new Set((cluster.items || []).map(levelSourceLabel).filter(Boolean))],
      explanation: currentLanguage === "zh"
        ? `该价位被多次测试，来源包括 ${(cluster.items || []).map(levelSourceLabel).filter(Boolean).slice(0, 3).join("、") || "历史位置"}。`
        : `This level has been tested repeatedly with confirmation from ${(cluster.items || []).map(levelSourceLabel).filter(Boolean).slice(0, 3).join(", ") || "historical structure"}.`,
    }))),
    ...((sr.resistance || []).map((cluster) => ({
      side_hint: "resistance",
      price: cluster.price,
      score: cluster.score,
      raw_items: cluster.items || [],
      sources: [...new Set((cluster.items || []).map(levelSourceLabel).filter(Boolean))],
      explanation: currentLanguage === "zh"
        ? `该价位附近有明显压力，来源包括 ${(cluster.items || []).map(levelSourceLabel).filter(Boolean).slice(0, 3).join("、") || "历史位置"}。`
        : `This zone shows notable resistance from ${(cluster.items || []).map(levelSourceLabel).filter(Boolean).slice(0, 3).join(", ") || "historical structure"}.`,
    }))),
    ...extras.filter((item) => Number.isFinite(item.price)),
  ];

  const classified = rawLevels.reduce((acc, item) => {
    const side = classifyLevelSide(item.price, price) || item.side_hint;
    if (side === "support") acc.support.push(item);
    else if (side === "resistance") acc.resistance.push(item);
    else if (side === "pivot") {
      acc.pivot.push({
        ...item,
        explanation: currentLanguage === "zh"
          ? `${item.explanation || "该价位"} 更接近当前价格，先视作中性枢轴区。`
          : `${item.explanation || "This level"} is sitting close to spot, so it is treated as a pivot zone for now.`,
        sources: [...new Set([...(item.sources || []), t("pivotZone")])],
      });
    }
    return acc;
  }, { support: [], resistance: [], pivot: [] });

  const supportCandidates = dedupeLevels(classified.support, "support", price, rangeParams.cluster_multiplier, tech.atr14);
  while (supportCandidates.length < 5 && Number.isFinite(price)) {
    const step = supportCandidates.length + 1;
    supportCandidates.push({
      price: price * (1 - step * 0.025),
      sources: ["ATR / Percent fallback"],
      explanation: currentLanguage === "zh" ? "备用支撑位，来源于波动区间回退。" : "Fallback support from volatility / percent spacing.",
      score: 30,
    });
  }
  const resistanceCandidates = dedupeLevels(classified.resistance, "resistance", price, rangeParams.cluster_multiplier, tech.atr14);
  while (resistanceCandidates.length < 5 && Number.isFinite(price)) {
    const step = resistanceCandidates.length + 1;
    resistanceCandidates.push({
      price: price * (1 + step * 0.025),
      sources: ["ATR / Percent fallback"],
      explanation: currentLanguage === "zh" ? "备用压力位，来源于波动区间回退。" : "Fallback resistance from volatility / percent spacing.",
      score: 30,
    });
  }

  const levelObvConfirmation = () => {
    const trend = obvTrend(tech.history?.closes || [], tech.history?.volumes || [], 20);
    if (trend === "rising") return currentLanguage === "zh" ? "OBV 上升" : "OBV rising";
    if (trend === "neutral") return currentLanguage === "zh" ? "OBV 稳定" : "OBV stable";
    if (trend === "falling") return currentLanguage === "zh" ? "OBV 下降" : "OBV falling";
    return currentLanguage === "zh" ? "OBV 暂无确认" : "OBV unavailable";
  };
  const supports = supportCandidates.slice(0, 5).map((item, index) => {
    const strengthInfo = applyVolumeConfirmationToLevelStrength(computeLevelStrength(item, price), item, price, "support", row);
    const sources = item.sources?.length ? item.sources : [currentLanguage === "zh" ? "技术结构" : "Technical structure"];
    const adjustedScore = adjustLevelScoreForTradeContext(
      clamp(Math.round(strengthInfo.score + (rangeParams.support_confidence_adjustment || 0)), 0, 100),
      "support",
      tradeContext,
    );
    const adjustedStrength = supportResistanceStrengthBand(Math.max(0, (adjustedScore - 18) / 11));
    return {
      id: `S${index + 1}`,
      level: `S${index + 1}`,
      price: Number(item.price.toFixed(2)),
      strength: adjustedStrength,
      strength_label: strengthLabelForSide(adjustedStrength, "support"),
      source: sources,
      sources,
      explanation: item.explanation,
      score: adjustedScore,
      strength_score: adjustedScore,
      points: strengthInfo.points,
      distance_pct: strengthInfo.distance_pct,
      test_count: strengthInfo.test_count,
      has_volume_cluster: strengthInfo.has_volume_cluster,
      volume_notes: strengthInfo.volume_notes || [],
      volume_confirmation: (strengthInfo.volume_notes || []).length
        ? (strengthInfo.volume_notes || []).join(" / ")
        : (currentLanguage === "zh" ? "量能未给出额外确认" : "No extra volume confirmation"),
      obv_confirmation: levelObvConfirmation(),
      relative_strength_confirmation: supportResistanceRelativeStrengthNote("support", tradeContext),
      timeframe: index <= 1 ? "short" : index <= 3 ? "mid" : "long",
      retest_count: strengthInfo.test_count,
      valid: adjustedScore >= 35,
      invalidation_condition: currentLanguage === "zh"
        ? `放量跌破 ${formatCurrency(item.price, row.currencyCode)} 且 OBV 继续转弱。`
        : `Invalidated by a high-volume break below ${formatCurrency(item.price, row.currencyCode)} with weakening OBV.`,
      notes: (strengthInfo.volume_notes || []).slice(0, 3),
    };
  });
  const resistances = resistanceCandidates.slice(0, 5).map((item, index) => {
    const strengthInfo = applyVolumeConfirmationToLevelStrength(computeLevelStrength(item, price), item, price, "resistance", row);
    const sources = item.sources?.length ? item.sources : [currentLanguage === "zh" ? "技术结构" : "Technical structure"];
    const adjustedScore = adjustLevelScoreForTradeContext(
      clamp(Math.round(strengthInfo.score + (hasAnyTag(companyProfile?.tags || [], ["HighGrowth", "AIInfrastructure"]) ? -2 : 0)), 0, 100),
      "resistance",
      tradeContext,
    );
    const adjustedStrength = supportResistanceStrengthBand(Math.max(0, (adjustedScore - 18) / 11));
    return {
      id: `R${index + 1}`,
      level: `R${index + 1}`,
      price: Number(item.price.toFixed(2)),
      strength: adjustedStrength,
      strength_label: strengthLabelForSide(adjustedStrength, "resistance"),
      source: sources,
      sources,
      explanation: item.explanation,
      score: adjustedScore,
      strength_score: adjustedScore,
      points: strengthInfo.points,
      distance_pct: strengthInfo.distance_pct,
      test_count: strengthInfo.test_count,
      has_volume_cluster: strengthInfo.has_volume_cluster,
      volume_notes: strengthInfo.volume_notes || [],
      volume_confirmation: (strengthInfo.volume_notes || []).length
        ? (strengthInfo.volume_notes || []).join(" / ")
        : (currentLanguage === "zh" ? "量能未给出额外确认" : "No extra volume confirmation"),
      obv_confirmation: levelObvConfirmation(),
      relative_strength_confirmation: supportResistanceRelativeStrengthNote("resistance", tradeContext),
      timeframe: index <= 1 ? "short" : index <= 3 ? "mid" : "long",
      retest_count: strengthInfo.test_count,
      valid: adjustedScore >= 35,
      invalidation_condition: currentLanguage === "zh"
        ? `放量突破 ${formatCurrency(item.price, row.currencyCode)} 并站稳，压力位失效。`
        : `Invalidated by a high-volume breakout above ${formatCurrency(item.price, row.currencyCode)} that holds.`,
      notes: (strengthInfo.volume_notes || []).slice(0, 3),
    };
  });

  const pivots = dedupeLevels(classified.pivot, "resistance", price, rangeParams.cluster_multiplier, tech.atr14).slice(0, 3).map((item, index) => ({
    level: `P${index + 1}`,
    price: Number(item.price.toFixed(2)),
    strength: computeLevelStrength(item, price).strength,
    source: item.sources?.length ? item.sources : [t("pivotZone")],
    explanation: item.explanation,
  }));

  return {
    supports,
    resistances,
    pivots,
    cluster_threshold: Number(Math.max((price || 1) * 0.0075, (tech.atr14 || (price || 1) * 0.025) * (rangeParams.cluster_multiplier || 0.25)).toFixed(2)),
    context_inputs: {
      relative_strength_regime: tradeContext?.relative_strength_state?.regime || "unavailable",
      options_expected_move_used: Boolean(tradeContext?.options_state?.expected_move?.move_30d_pct),
    },
  };
}

function primaryZoneMaxDrawdownPct(companyProfile, row) {
  const tags = companyProfile?.tags || [];
  if (isCnAShare(row)) return 15;
  if (hasAnyTag(tags, ["Speculative", "HighVolatility", "IPO", "NewlyListed"])) return 18;
  if (hasAnyTag(tags, ["Growth", "HighGrowth", "HighMultiple", "Momentum", "StoryStock"])) return 12;
  if (hasAnyTag(tags, ["REIT", "Dividend"])) return 12;
  if (hasAnyTag(tags, ["MegaCap", "CashCow"])) return 10;
  return 12;
}

function makeBuyZone(low, high, confidence, sources, summary, status = "available") {
  const normalizedLow = Number.isFinite(low) ? Number(Math.min(low, high).toFixed(2)) : null;
  const normalizedHigh = Number.isFinite(high) ? Number(Math.max(low, high).toFixed(2)) : null;
  return {
    low: normalizedLow,
    high: normalizedHigh,
    confidence: clamp(Math.round(confidence || 0), 0, 100),
    status: normalizedLow != null && normalizedHigh != null ? status : "unavailable",
    sources: [...new Set((sources || []).filter(Boolean))].slice(0, 6),
    reason: [...new Set((sources || []).filter(Boolean))].slice(0, 6),
    summary: summary || t("dataUnavailable"),
  };
}

function weightedZoneFromCandidates(candidates, currentPrice, { minDrawdownPct = 0, maxDrawdownPct = 20, fallback = null } = {}) {
  const valid = candidates
    .filter((item) => Number.isFinite(item.price) && item.price > 0)
    .map((item) => ({
      ...item,
      drawdownPct: ((currentPrice - item.price) / Math.max(currentPrice, 1)) * 100,
    }))
    .filter((item) => item.drawdownPct >= minDrawdownPct && item.drawdownPct <= maxDrawdownPct);
  if (!valid.length) return fallback;
  const totalWeight = valid.reduce((sum, item) => sum + (item.weight || 1), 0) || 1;
  const center = valid.reduce((sum, item) => sum + item.price * (item.weight || 1), 0) / totalWeight;
  const priceStd = stdDev(valid.map((item) => item.price)) || 0;
  const spread = Math.max(
    currentPrice * 0.006,
    Math.min(currentPrice * 0.025, priceStd || currentPrice * 0.015),
  );
  return {
    low: center - spread,
    high: center + spread,
    sources: [...new Set(valid.sort((a, b) => (b.weight || 1) - (a.weight || 1)).slice(0, 5).map((item) => item.source))],
    candidate_count: valid.length,
    source_count: [...new Set(valid.map((item) => item.source).filter(Boolean))].length,
    avg_weight: totalWeight / valid.length,
    total_weight: totalWeight,
    price_std: priceStd,
    center,
  };
}

function computeBuyZoneConfidence(kind, zoneRaw, low, high, currentPrice, context = {}) {
  if (!zoneRaw || !Number.isFinite(low) || !Number.isFinite(high) || !Number.isFinite(currentPrice) || currentPrice <= 0) {
    return kind === "primary" ? 42 : 0;
  }

  const {
    isUs = false,
    optionsAvailable = false,
    strongTrend = false,
    maxDrawdownPct = 20,
    companyProfile = null,
  } = context;
  const tags = companyProfile?.tags || [];
  const widthPct = ((high - low) / currentPrice) * 100;
  const centerPrice = zoneRaw.center ?? ((low + high) / 2);
  const drawdownPct = ((currentPrice - centerPrice) / currentPrice) * 100;
  const sourceCount = zoneRaw.source_count ?? zoneRaw.sources?.length ?? 0;
  const candidateCount = zoneRaw.candidate_count ?? 0;
  const avgWeight = zoneRaw.avg_weight ?? 1;
  const priceStd = zoneRaw.price_std ?? 0;

  const sourceTarget = kind === "primary" ? 5 : kind === "deep" ? 4 : 4;
  const candidateTarget = kind === "primary" ? 8 : kind === "deep" ? 6 : 5;
  const sourceScore = clamp((sourceCount / sourceTarget) * 16, 0, 16);
  const candidateScore = clamp((candidateCount / candidateTarget) * 16, 0, 16);
  const weightScore = clamp(((avgWeight - 0.85) / 0.7) * 12, 0, 12);
  const clusterScore = clamp((1 - (priceStd / Math.max(currentPrice * 0.03, 0.75))) * 18, 0, 18);

  let widthTarget = 2.2;
  let drawdownTarget = Math.min(Math.max(maxDrawdownPct * 0.33, 1.5), 6);
  let base = 24;
  let marketBonus = 0;

  if (kind === "deep") {
    widthTarget = 4.6;
    drawdownTarget = Math.min(Math.max(maxDrawdownPct * 0.55, 10), 18);
    base = 22;
  } else if (kind === "momentum") {
    widthTarget = 2.8;
    drawdownTarget = 0.8;
    base = 25;
    if (strongTrend) marketBonus += 6;
  } else if (kind === "primary" && isUs && optionsAvailable) {
    marketBonus += 4;
  }

  if (hasAnyTag(tags, ["Speculative", "HighVolatility", "IPO", "NewlyListed"])) {
    marketBonus -= kind === "deep" ? 2 : 3;
  }
  if (hasAnyTag(tags, ["MegaCap", "CashCow"]) && kind === "primary") {
    marketBonus += 2;
  }

  const widthScore = clamp(14 - Math.abs(widthPct - widthTarget) * 3.2, 0, 14);
  const distanceScore = clamp(14 - Math.abs(drawdownPct - drawdownTarget) * (kind === "deep" ? 0.9 : 2.2), 0, 14);

  const total = base + sourceScore + candidateScore + weightScore + clusterScore + widthScore + distanceScore + marketBonus;
  const caps = {
    primary: [40, 88],
    deep: [34, 82],
    momentum: [38, 86],
  };
  const [minScore, maxScore] = caps[kind] || [35, 88];
  return clamp(Math.round(total), minScore, maxScore);
}

function buildBuyZones(row, supportResistance, companyProfile = null) {
  const tech = row.technicals || {};
  const options = row.research?.optionsRead || buildOptionsRead(row);
  const currentPrice = row.price ?? 0;
  const isUs = isUsMarket(row);
  const atrValue = Number.isFinite(tech.atr14) ? tech.atr14 : Math.max(currentPrice * 0.025, 0.5);
  const fib382 = tech.rangeLow != null && tech.rangeHigh != null ? tech.rangeLow + (tech.rangeHigh - tech.rangeLow) * 0.382 : null;
  const fib50 = tech.rangeLow != null && tech.rangeHigh != null ? tech.rangeLow + (tech.rangeHigh - tech.rangeLow) * 0.5 : null;
  const fib618 = tech.rangeLow != null && tech.rangeHigh != null ? tech.rangeLow + (tech.rangeHigh - tech.rangeLow) * 0.618 : null;
  const fib786 = tech.rangeLow != null && tech.rangeHigh != null ? tech.rangeLow + (tech.rangeHigh - tech.rangeLow) * 0.786 : null;
  const recentSwingLow = Math.min(...(tech.history?.lows || []).slice(-30).filter(Number.isFinite));
  const majorSwingLow = Math.min(...(tech.history?.lows || []).slice(-180).filter(Number.isFinite));
  const primaryMax = Math.min(20, primaryZoneMaxDrawdownPct(companyProfile, row));
  const addCandidate = (list, price, weight, source) => {
    if (!Number.isFinite(price) || !Number.isFinite(currentPrice) || currentPrice <= 0) return;
    if (price > currentPrice * 1.06) return;
    list.push({ price, weight, source });
  };

  const primaryCandidates = [];
  supportResistance.supports.slice(0, 3).forEach((level, index) => addCandidate(primaryCandidates, level.price, 1.8 - index * 0.25, level.level));
  addCandidate(primaryCandidates, tech.ma20, 1.25, "MA20");
  addCandidate(primaryCandidates, tech.ma50, 1.35, "MA50");
  addCandidate(primaryCandidates, tech.ma100, 1.1, "MA100");
  addCandidate(primaryCandidates, tech.middleBand, 0.9, currentLanguage === "zh" ? "布林中轨" : "Bollinger Middle");
  addCandidate(primaryCandidates, tech.lowerBand, 0.95, currentLanguage === "zh" ? "布林下轨" : "Bollinger Lower");
  addCandidate(primaryCandidates, currentPrice - atrValue, 1.05, "ATR");
  addCandidate(primaryCandidates, fib382, 1.0, "Fib 38.2%");
  addCandidate(primaryCandidates, fib50, 0.95, "Fib 50%");
  addCandidate(primaryCandidates, recentSwingLow, 1.0, "Recent Swing Low");
  if (isUs) {
    addCandidate(primaryCandidates, options.putWall, 1.45, "Put Wall");
    addCandidate(primaryCandidates, options.gammaFlip && options.gammaFlip <= currentPrice ? options.gammaFlip : null, 1.15, "Gamma Flip");
  }

  const primaryRaw = weightedZoneFromCandidates(primaryCandidates, currentPrice, { minDrawdownPct: -1, maxDrawdownPct: primaryMax });
  const primaryFallbackHigh = currentPrice - Math.min(atrValue * 0.45, currentPrice * 0.025);
  const primaryFallbackLow = primaryFallbackHigh - Math.max(atrValue * 0.5, currentPrice * 0.012);
  const primary = primaryRaw
    ? makeBuyZone(
      Math.max(primaryRaw.low, currentPrice * (1 - primaryMax / 100)),
      Math.min(primaryRaw.high, currentPrice * 1.01),
      computeBuyZoneConfidence(
        "primary",
        primaryRaw,
        Math.max(primaryRaw.low, currentPrice * (1 - primaryMax / 100)),
        Math.min(primaryRaw.high, currentPrice * 1.01),
        currentPrice,
        { isUs, optionsAvailable: options.available, maxDrawdownPct: primaryMax, companyProfile },
      ),
      primaryRaw.sources,
      currentLanguage === "zh" ? "接近当前价附近的支撑共振，适合等待回踩确认。" : "Near-current support confluence for a practical pullback entry.",
    )
    : makeBuyZone(
      primaryFallbackLow,
      primaryFallbackHigh,
      42,
      ["ATR"],
      currentLanguage === "zh" ? "缺少足够支撑锚点，暂用 ATR 附近作为保守参考。" : "Limited support anchors; using an ATR-based fallback.",
    );

  const deepCandidates = [];
  addCandidate(deepCandidates, tech.ma200, 1.7, "MA200");
  addCandidate(deepCandidates, fib618, 1.25, "Fib 61.8%");
  addCandidate(deepCandidates, fib786, 1.15, "Fib 78.6%");
  addCandidate(deepCandidates, majorSwingLow, 1.3, "Major Swing Low");
  addCandidate(deepCandidates, tech.rangeLow, 1.2, "52W Support");
  supportResistance.supports.filter((level) => level.strength === "strong").forEach((level) => addCandidate(deepCandidates, level.price, 1.1, `${level.level} Strong Support`));
  addCandidate(deepCandidates, currentPrice - atrValue * 3, 0.9, "Long-Term ATR");
  const deepMax = hasAnyTag(companyProfile?.tags || [], ["Speculative", "HighVolatility", "IPO", "NewlyListed"]) ? 45 : 35;
  const deepRaw = weightedZoneFromCandidates(deepCandidates, currentPrice, { minDrawdownPct: 8, maxDrawdownPct: deepMax });
  const deep = deepRaw
    ? makeBuyZone(
      deepRaw.low,
      deepRaw.high,
      computeBuyZoneConfidence(
        "deep",
        deepRaw,
        deepRaw.low,
        deepRaw.high,
        currentPrice,
        { isUs, optionsAvailable: options.available, maxDrawdownPct: deepMax, companyProfile },
      ),
      deepRaw.sources,
      currentLanguage === "zh" ? "深度回调区，不是当前默认买入区。" : "Deep pullback reference, not the default current entry zone.",
    )
    : makeBuyZone(
      null,
      null,
      0,
      [],
      currentLanguage === "zh" ? "没有足够可靠的深度回调锚点。" : "No reliable deep-pullback anchors are available.",
      "unavailable",
    );

  const momentumShareBase = positiveOrNull(row.metadata?.floatShares ?? row.floatShares)
    ?? positiveOrNull(row.metadata?.sharesOutstanding ?? row.sharesOutstanding)
    ?? (positiveOrNull(row.marketCap) && positiveOrNull(row.price) ? row.marketCap / row.price : null);
  const momentumTurnoverScore = turnoverActivityScore(
    turnoverFromVolume(tech.latestVolume ?? latest(tech.history?.volumes || []), momentumShareBase),
    row,
    companyProfile,
  );
  const strongTrend = Number.isFinite(currentPrice)
    && currentPrice > (tech.ma20 ?? Number.POSITIVE_INFINITY)
    && (tech.ma20 ?? 0) >= (tech.ma50 ?? Number.POSITIVE_INFINITY) * 0.995
    && (tech.macd ?? 0) > 0
    && (tech.macdHistogram ?? 0) >= 0
    && ["rising", "neutral"].includes(obvTrend(tech.history?.closes || [], tech.history?.volumes || [], 20))
    && (tech.volumeRatio ?? 1) >= 1.2
    && (tech.closePosition ?? 0.5) >= 0.6
    && momentumTurnoverScore >= 55
    && momentumTurnoverScore <= 85;
  const momentumCandidates = [];
  if (strongTrend) {
    const r1 = supportResistance.resistances[0]?.price;
    addCandidate(momentumCandidates, tech.ma10, 1.2, "MA10");
    addCandidate(momentumCandidates, tech.ma20, 1.1, "MA20");
    addCandidate(momentumCandidates, currentPrice, 0.9, currentLanguage === "zh" ? "现价回踩确认" : "Spot Retest");
    if (Number.isFinite(r1) && Math.abs((r1 - currentPrice) / Math.max(currentPrice, 1)) * 100 <= 5) addCandidate(momentumCandidates, r1, 1.25, "Breakout / R1 Retest");
    addCandidate(momentumCandidates, tech.middleBand, 0.8, currentLanguage === "zh" ? "布林中轨" : "Bollinger Middle");
    addCandidate(momentumCandidates, tech.upperBand && currentPrice >= tech.upperBand * 0.98 ? tech.upperBand : null, 0.7, "Upper Band Retest");
  }
  const momentumRaw = strongTrend
    ? weightedZoneFromCandidates(momentumCandidates, currentPrice, { minDrawdownPct: -5, maxDrawdownPct: 8 })
    : null;
  const momentum = momentumRaw
    ? makeBuyZone(
      Math.max(momentumRaw.low, currentPrice * 0.97),
      Math.min(momentumRaw.high, currentPrice * 1.05),
      computeBuyZoneConfidence(
        "momentum",
        momentumRaw,
        Math.max(momentumRaw.low, currentPrice * 0.97),
        Math.min(momentumRaw.high, currentPrice * 1.05),
        currentPrice,
        { isUs, optionsAvailable: options.available, strongTrend, maxDrawdownPct: 8, companyProfile },
      ),
      momentumRaw.sources,
      currentLanguage === "zh" ? "强趋势下的突破 / 回踩确认区，需放量站稳。" : "Breakout or retest entry zone for a confirmed strong trend.",
    )
    : makeBuyZone(
      null,
      null,
      0,
      [],
      currentLanguage === "zh" ? "未触发：量能或趋势确认不足。" : "Not triggered: volume or trend confirmation is insufficient.",
      "unavailable",
    );

  return {
    primary_buy_zone: {
      ...primary,
      purpose: currentLanguage === "zh" ? "回调到合理支撑区分批买入，偏稳健。" : "Staged pullback entry near reasonable support.",
      outlier_detected: false,
      warning: null,
    },
    deep_pullback_zone: {
      ...deep,
      purpose: currentLanguage === "zh" ? "大幅回调后的长期低吸区，不代表现在必须等到这里。" : "Longer-term deep-pullback accumulation area, not a requirement to wait for it now.",
    },
    momentum_entry_zone: momentum,
  };
}

function buildIdealBuyZone(row, supportResistance, companyProfile = null) {
  return buildBuyZones(row, supportResistance, companyProfile).primary_buy_zone;
}

function atrStopMultiplier(row, companyProfile) {
  const tags = companyProfile?.tags || [];
  if (isCnAShare(row)) {
    if (hasAnyTag(tags, ["HighVolatility", "Speculative", "Momentum", "StoryStock"])) return 2.5;
    return 2.0;
  }
  if (hasAnyTag(tags, ["HighVolatility", "Speculative", "NewlyListed", "IPO", "Crypto", "StoryStock"])) return 2.5;
  if (hasAnyTag(tags, ["Semiconductor", "AIInfrastructure", "AI"])) return 2.0;
  if (hasAnyTag(tags, ["Growth", "HighGrowth", "Software", "Healthcare", "Consumer"])) return 1.7;
  if (hasAnyTag(tags, ["REIT", "Dividend"])) return 1.45;
  if (hasAnyTag(tags, ["MegaCap", "CashCow"])) return 1.5;
  return 1.8;
}

function buyZoneStopBuffer(row, companyProfile) {
  const tags = companyProfile?.tags || [];
  if (isCnAShare(row)) {
    if (hasAnyTag(tags, ["HighVolatility", "Speculative", "Momentum", "StoryStock"])) return 0.955;
    return 0.978;
  }
  if (hasAnyTag(tags, ["Speculative", "HighVolatility", "NewlyListed", "IPO", "Crypto", "StoryStock"])) return 0.955;
  if (hasAnyTag(tags, ["Semiconductor", "AIInfrastructure", "HighGrowth"])) return 0.98;
  if (hasAnyTag(tags, ["Software", "Growth", "ProfitableGrowth", "LargeCap"])) return 0.982;
  if (hasAnyTag(tags, ["REIT", "Dividend"])) return 0.988;
  if (hasAnyTag(tags, ["MegaCap", "CashCow"])) return 0.988;
  return 0.98;
}

function allocationHintForRange(companyProfile, horizon) {
  const tags = companyProfile?.tags || [];
  const profile = companyProfile?.scoring_profile || "generic";
  if (hasAnyTag(tags, ["Speculative", "HighVolatility", "NewlyListed", "Crypto"])) {
    return horizon === "short" ? "0-10%" : horizon === "mid" ? "30%" : "60%";
  }
  if (profile === "ai_infrastructure" || profile === "high_growth_cyclical") {
    return horizon === "short" ? "10%" : horizon === "mid" ? "30%" : "60%";
  }
  if (profile === "reit_dividend" && hasAnyTag(tags, ["HighDebtRisk"])) {
    return horizon === "short" ? "0-20%" : horizon === "mid" ? "30%" : "50%";
  }
  if (profile === "china_adr") {
    return horizon === "short" ? "10%" : horizon === "mid" ? "30%" : "60%";
  }
  if (profile === "healthcare_defensive" || hasAnyTag(tags, ["MegaCap", "CashCow"])) {
    return horizon === "short" ? "20%" : horizon === "mid" ? "40%" : "40%";
  }
  return horizon === "short" ? "10-25%" : horizon === "mid" ? "30-45%" : "30-60%";
}

function normalizePlanMarketRegime(marketContext = null) {
  const enhanced = marketContext?.enhanced_context;
  if (enhanced?.market_regime) return enhanced.market_regime;
  const engine = marketContext?.market_engine || {};
  const rawRegime = marketContext?.market_regime?.regime || engine.regime || "neutral";
  const vix = engine.vix || {};
  const fearGreed = engine.fear_greed || {};
  const equityTrend = engine.equity_trend || {};
  const vixValue = vix.value ?? null;
  const vix5d = vix.change_5d ?? null;
  const spyTrend = equityTrend.spy?.trend || equityTrend.spy?.signal || null;
  const qqqTrend = equityTrend.qqq?.trend || equityTrend.qqq?.signal || null;
  if ((Number.isFinite(vixValue) && vixValue >= 35) || (Number.isFinite(vix5d) && vix5d >= 20)) return "panic";
  if (fearGreed.label === "Extreme Greed") return "overheated";
  if (rawRegime === "risk_off" || equityTrend.impact === "negative" || (spyTrend === "bearish" && qqqTrend === "bearish")) return "risk_off";
  if (rawRegime === "risk_on" || equityTrend.impact === "supportive" || (spyTrend === "bullish" && qqqTrend === "bullish")) return "risk_on";
  return "neutral";
}

function marketAdjustmentForPlans(marketContext = null) {
  const regime = normalizePlanMarketRegime(marketContext);
  const multiplierMap = {
    risk_on: 1,
    neutral: 0.9,
    risk_off: 0.68,
    panic: 0.5,
    overheated: 0.7,
  };
  const noteMap = {
    risk_on: currentLanguage === "zh" ? "市场环境偏进攻，按默认分批计划执行。" : "Risk-on tape supports the default staged plan.",
    neutral: currentLanguage === "zh" ? "市场环境中性，仓位按默认计划小幅折扣。" : "Neutral tape uses a modest sizing haircut.",
    risk_off: currentLanguage === "zh" ? "市场环境偏防守，买入区间更保守，止损可略放宽但仓位必须降低。" : "Risk-off tape calls for more conservative entries, slightly wider stops, and lower sizing.",
    panic: currentLanguage === "zh" ? "波动率或风险冲击较高，优先等待企稳，只允许小仓位分批。" : "Panic conditions favor waiting for stabilization and using small staged entries.",
    overheated: currentLanguage === "zh" ? "情绪过热，不扩大止损，买入区间更保守，避免追高。" : "Overheated sentiment keeps stops tight and entries conservative; avoid chasing.",
  };
  return {
    regime,
    position_multiplier: multiplierMap[regime] ?? 0.9,
    note: noteMap[regime],
  };
}

function adjustPercentRange(rangeText, multiplier) {
  if (!rangeText || !Number.isFinite(multiplier)) return rangeText || null;
  const nums = String(rangeText).match(/\d+(?:\.\d+)?/g)?.map(Number) || [];
  if (!nums.length) return rangeText;
  const adjusted = nums.map((value) => Number((value * multiplier).toFixed(value * multiplier < 5 ? 1 : 0)));
  if (adjusted.length >= 2) return `${adjusted[0]}-${adjusted[1]}%`;
  return `${adjusted[0]}%`;
}

function buyRangeLabels(horizon) {
  const labels = {
    short: {
      label: "短期回调买入区间",
      english_label: "Short-Term Pullback Buy Range",
    },
    mid: {
      label: "中期分批加仓区间",
      english_label: "Mid-Term Accumulation Range",
    },
    long: {
      label: "长期核心布局区间",
      english_label: "Long-Term Core Accumulation Range",
    },
  };
  return labels[horizon] || labels.mid;
}

function decisionRangeParameters(row, companyProfile = {}) {
  const tags = companyProfile?.tags || [];
  const profile = companyProfile?.decision_profile?.base_profile || companyProfile?.scoring_profile || "generic";
  const params = {
    minimum_zone_gap_atr: 0.22,
    buy_zone_width_multiplier: 1,
    stop_buffer_multiplier: 1,
    sell_upside_multiplier: 1,
    cluster_multiplier: 0.25,
    support_confidence_adjustment: 0,
    sell_gap_atr: 0.22,
  };
  if (hasAnyTag(tags, ["MegaCap", "CashCow"])) {
    Object.assign(params, {
      minimum_zone_gap_atr: 0.15,
      buy_zone_width_multiplier: 0.85,
      stop_buffer_multiplier: 0.9,
      cluster_multiplier: 0.2,
      sell_gap_atr: 0.15,
    });
  } else if (hasAnyTag(tags, ["LargeCap"])) {
    params.minimum_zone_gap_atr = 0.2;
    params.cluster_multiplier = 0.25;
    params.sell_gap_atr = 0.2;
  }
  if (hasAnyTag(tags, ["AIInfrastructure", "HighGrowth"]) || ["ai_infrastructure", "high_growth_cyclical"].includes(profile)) {
    params.minimum_zone_gap_atr = Math.max(params.minimum_zone_gap_atr, 0.25);
    params.buy_zone_width_multiplier *= 1.1;
    params.stop_buffer_multiplier *= 1.15;
    params.sell_upside_multiplier *= 1.15;
    params.cluster_multiplier = Math.max(params.cluster_multiplier, 0.3);
    params.sell_gap_atr = Math.max(params.sell_gap_atr, 0.25);
  }
  if (hasAnyTag(tags, ["HighVolatility"])) {
    params.minimum_zone_gap_atr = Math.max(params.minimum_zone_gap_atr, 0.35);
    params.buy_zone_width_multiplier *= 1.2;
    params.stop_buffer_multiplier *= 1.25;
    params.cluster_multiplier = Math.max(params.cluster_multiplier, 0.35);
    params.sell_gap_atr = Math.max(params.sell_gap_atr, 0.35);
  }
  if (hasAnyTag(tags, ["Speculative", "Meme", "NewlyListed", "IPO"])) {
    params.minimum_zone_gap_atr = Math.max(params.minimum_zone_gap_atr, 0.4);
    params.buy_zone_width_multiplier *= 1.3;
    params.stop_buffer_multiplier *= 1.3;
    params.cluster_multiplier = Math.max(params.cluster_multiplier, 0.4);
    params.support_confidence_adjustment -= 8;
    params.sell_gap_atr = Math.max(params.sell_gap_atr, 0.4);
  }
  if (hasAnyTag(tags, ["REIT", "Dividend"])) {
    params.minimum_zone_gap_atr = Math.max(params.minimum_zone_gap_atr, 0.22);
    params.buy_zone_width_multiplier *= hasAnyTag(tags, ["HighDebtRisk"]) ? 1.15 : 0.95;
    params.stop_buffer_multiplier *= hasAnyTag(tags, ["HighDebtRisk"]) ? 1.12 : 0.95;
    params.support_confidence_adjustment += hasAnyTag(tags, ["HighDebtRisk"]) ? -5 : 2;
  }
  if (hasAnyTag(tags, ["HealthInsurance", "HealthcareServices", "Defensive"]) || profile === "healthcare_defensive") {
    params.buy_zone_width_multiplier *= 0.95;
    params.stop_buffer_multiplier *= 0.95;
    params.support_confidence_adjustment += 2;
  }
  if (hasAnyTag(tags, ["ChinaADR"])) {
    params.minimum_zone_gap_atr = Math.max(params.minimum_zone_gap_atr, 0.3);
    params.buy_zone_width_multiplier *= 1.12;
    params.stop_buffer_multiplier *= 1.12;
    params.support_confidence_adjustment -= hasAnyTag(tags, ["RegulatoryRisk"]) ? 5 : 2;
  }
  if (isCnAShare(row)) {
    params.minimum_zone_gap_atr = Math.max(params.minimum_zone_gap_atr, 0.28);
    params.buy_zone_width_multiplier *= 1.1;
    params.stop_buffer_multiplier *= 1.12;
  }
  return params;
}

function rangeMinimumWidthAtr(horizon, params = {}, type = "buy") {
  const multiplier = params.buy_zone_width_multiplier || 1;
  const buyBase = horizon === "short" ? 0.55 : horizon === "mid" ? 0.8 : 1.1;
  const sellBase = horizon === "short" ? 0.55 : horizon === "mid" ? 0.85 : 1.15;
  return (type === "sell" ? sellBase : buyBase) * multiplier;
}

function annotateRange(range, horizon, atr, params, type = "buy") {
  if (!range || range.status !== "available" || !Number.isFinite(range.low) || !Number.isFinite(range.high)) return range;
  if (range.high < range.low) [range.low, range.high] = [range.high, range.low];
  const minWidth = Number.isFinite(atr)
    ? Math.max(atr * rangeMinimumWidthAtr(horizon, params, type), 0.01)
    : Math.max(((range.low + range.high) / 2) * 0.01, 0.01);
  const width = range.high - range.low;
  if (width < minWidth) {
    const midpoint = (range.low + range.high) / 2;
    range.low = Math.max(0.01, midpoint - minWidth / 2);
    range.high = Math.max(range.low + 0.01, midpoint + minWidth / 2);
  }
  range.low = Number(range.low.toFixed(2));
  range.high = Number(range.high.toFixed(2));
  range.midpoint = Number(((range.low + range.high) / 2).toFixed(2));
  range.zone_strength = range.zone_strength || (range.confidence >= 78 ? "strong" : range.confidence >= 58 ? "medium" : "weak");
  return range;
}

function reachabilityThresholds(horizon, companyProfile = {}) {
  const tags = companyProfile?.tags || [];
  const base = {
    short: { high: 1.5, moderate: 2.5, low: 4.0, days: 30 },
    mid: { high: 2.5, moderate: 4.0, low: 6.0, days: 90 },
    long: { high: 4.0, moderate: 6.0, low: 9.0, days: 180 },
  }[horizon] || { high: 2.5, moderate: 4.0, low: 6.0, days: 90 };
  let multiplier = 1;
  if (hasAnyTag(tags, ["AIInfrastructure", "HighGrowth", "HighVolatility", "MemoryStorage"])) multiplier *= 1.18;
  if (hasAnyTag(tags, ["MegaCap", "CashCow", "Defensive", "HealthInsurance"])) multiplier *= 0.92;
  if (hasAnyTag(tags, ["Speculative", "Meme", "NewlyListed", "IPO"])) multiplier *= 1.22;
  return {
    high: base.high * multiplier,
    moderate: base.moderate * multiplier,
    low: base.low * multiplier,
    days: base.days,
  };
}

function estimateRangeReachability(row, range, horizon, side = "buy", companyProfile = {}, marketContext = null) {
  const currentPrice = row?.price ?? null;
  const midpoint = range?.midpoint ?? (
    Number.isFinite(range?.low) && Number.isFinite(range?.high)
      ? (range.low + range.high) / 2
      : null
  );
  const atr = Number.isFinite(row?.technicals?.atr14)
    ? row.technicals.atr14
    : Number.isFinite(currentPrice)
      ? currentPrice * 0.035
      : null;
  const thresholds = reachabilityThresholds(horizon, companyProfile);
  if (!Number.isFinite(currentPrice) || !Number.isFinite(midpoint) || !Number.isFinite(atr) || atr <= 0) {
    return {
      horizon_days: thresholds.days,
      estimated_touch_probability: null,
      expected_move_pct: null,
      required_atr_move: null,
      status: "low",
      explanation: currentLanguage === "zh"
        ? "价格或 ATR 数据不足，可达性只能保守处理。"
        : "Price or ATR data is insufficient, so reachability is treated conservatively.",
    };
  }
  const requiredAtrMove = Math.abs(currentPrice - midpoint) / atr;
  const atrPct = (atr / Math.max(currentPrice, 1)) * 100;
  const expectedMovePct = atrPct * Math.sqrt(thresholds.days / 14);
  let status = "unrealistic";
  if (requiredAtrMove <= thresholds.high) status = "high";
  else if (requiredAtrMove <= thresholds.moderate) status = "moderate";
  else if (requiredAtrMove <= thresholds.low) status = "low";

  const enhanced = marketContext?.enhanced_context || normalizeEnhancedMarketContext(marketContext?.market_engine || {}, marketContext?.macro || {});
  const regime = enhanced?.market_regime || marketContext?.market_regime?.regime || "neutral";
  const isBuy = side === "buy";
  const isSell = side === "sell";
  const trendHelps = isBuy
    ? ["risk_off", "panic"].includes(regime) && midpoint < currentPrice
    : ["risk_on", "overheated"].includes(regime) && midpoint > currentPrice;
  const trendHurts = isBuy
    ? regime === "risk_on" && midpoint < currentPrice
    : ["risk_off", "panic"].includes(regime) && midpoint > currentPrice;
  const probabilityByStatus = { high: 72, moderate: 48, low: 24, unrealistic: 8 };
  let estimatedProbability = probabilityByStatus[status] ?? 24;
  if (trendHelps) estimatedProbability += 6;
  if (trendHurts) estimatedProbability -= 6;
  if (hasAnyTag(companyProfile?.tags || [], ["HighVolatility", "Speculative", "Meme"])) estimatedProbability += 4;
  if (hasAnyTag(companyProfile?.tags || [], ["MegaCap", "Defensive"])) estimatedProbability -= 3;
  estimatedProbability = clamp(Math.round(estimatedProbability), 5, 82);

  const statusText = {
    high: currentLanguage === "zh" ? "较高" : "high",
    moderate: currentLanguage === "zh" ? "中等" : "moderate",
    low: currentLanguage === "zh" ? "较低" : "low",
    unrealistic: currentLanguage === "zh" ? "偏远" : "unrealistic",
  }[status];
  return {
    horizon_days: thresholds.days,
    estimated_touch_probability: estimatedProbability,
    expected_move_pct: Number(expectedMovePct.toFixed(1)),
    required_atr_move: Number(requiredAtrMove.toFixed(1)),
    status,
    explanation: currentLanguage === "zh"
      ? `${thresholds.days} 天窗口内需要约 ${requiredAtrMove.toFixed(1)} ATR 的波动，可达性${statusText}。这是规则型估计，不是精确概率。`
      : `This range requires roughly ${requiredAtrMove.toFixed(1)} ATR within ${thresholds.days} days, so reachability is ${statusText}. This is a rule-based estimate, not a precise probability.`,
  };
}

function applyRangeReachability(row, range, horizon, side, companyProfile, marketContext) {
  if (!range || range.status !== "available") return range;
  range.reachability = estimateRangeReachability(row, range, horizon, side, companyProfile, marketContext);
  if (range.reachability.status === "unrealistic") {
    range.confidence = clamp(Math.round((range.confidence ?? 60) - 14), 20, 100);
    range.reachability_adjustment = currentLanguage === "zh"
      ? "区间偏远，未强行贴近当前价，只降低区间可靠度。"
      : "Range is distant; it was not forced toward spot, only confidence was reduced.";
  } else if (range.reachability.status === "low") {
    range.confidence = clamp(Math.round((range.confidence ?? 60) - 7), 20, 100);
  }
  return range;
}

function classifyRangeSourceType(source = "") {
  const value = String(source).toLowerCase();
  if (/atr|expected move|current/.test(value)) return "dynamic";
  if (/put wall|call wall|gamma/.test(value)) return "options";
  return "structural";
}

function summarizeRangeAnchorWeights(sources = []) {
  const counts = sources.reduce((acc, source) => {
    const type = classifyRangeSourceType(source);
    acc[type] = (acc[type] || 0) + 1;
    return acc;
  }, { structural: 0, dynamic: 0, options: 0 });
  const total = Math.max(1, counts.structural + counts.dynamic + counts.options);
  return {
    structural_anchor_weight: Number(((counts.structural / total) * 100).toFixed(0)),
    dynamic_anchor_weight: Number((((counts.dynamic + counts.options * 0.5) / total) * 100).toFixed(0)),
  };
}

function expectedMoveValidationForRange(range, horizon, side, tradeContext = null) {
  if (!range || range.status !== "available") return null;
  const expectedMove = tradeContext?.options_state?.expected_move;
  if (!expectedMove) {
    return {
      status: "unavailable",
      explanation: currentLanguage === "zh"
        ? "期权预期波动暂不可用，区间仅按结构和 ATR 可达性校验。"
        : "Options expected move is unavailable; range is validated by structure and ATR reachability only.",
    };
  }
  const midpoint = range.midpoint ?? ((range.low + range.high) / 2);
  const lower = horizon === "long" ? expectedMove.lower_30d : horizon === "mid" ? expectedMove.lower_30d : expectedMove.lower_7d;
  const upper = horizon === "long" ? expectedMove.upper_30d : horizon === "mid" ? expectedMove.upper_30d : expectedMove.upper_7d;
  const reference = side === "buy" ? lower : upper;
  if (!Number.isFinite(reference) || !Number.isFinite(midpoint)) {
    return {
      status: "unavailable",
      explanation: currentLanguage === "zh" ? "预期波动单位不足，无法校验。" : "Expected-move unit is insufficient for validation.",
    };
  }
  const aligned = side === "buy" ? midpoint >= reference * 0.85 : midpoint <= reference * 1.15;
  return {
    status: aligned ? "aligned" : "outside_expected_move",
    reference_price: Number(reference.toFixed(2)),
    explanation: currentLanguage === "zh"
      ? aligned
        ? "区间处于期权预期波动可解释范围内；该判断仅用于可达性，不替代结构锚点。"
        : "区间超出当前期权预期波动解释范围；保留结构区间，但降低短期触达预期。"
      : aligned
        ? "Range sits within the options expected-move context; this only validates reachability, not structural anchors."
        : "Range is outside current options expected-move context; structural range is kept but near-term touch odds are lower.",
  };
}

function rangeShiftAnalysisForPlan(row, range, side, tradeContext = null) {
  const priceChangePct = row.changePercent ?? null;
  const structuralAnchorWeight = range?.structural_anchor_weight ?? null;
  const guidance = tradeContext?.guidance_state;
  const fundamental = tradeContext?.fundamental_health;
  const valuation = tradeContext?.valuation_state;
  const structuralChangeDetected = guidance?.direction === "lowered"
    || fundamental?.regime === "weak"
    || valuation?.fair_value_bias === "downward"
    || (side === "sell" && guidance?.direction === "raised")
    || (structuralAnchorWeight != null && structuralAnchorWeight >= 60);
  return {
    previous_midpoint: null,
    new_midpoint: range?.midpoint ?? null,
    stock_price_change_pct: Number.isFinite(priceChangePct) ? Number(priceChangePct.toFixed(1)) : null,
    range_change_pct: null,
    structural_change_detected: Boolean(structuralChangeDetected),
    update_reason: currentLanguage === "zh"
      ? "当前缺少上一版区间快照，先记录本次区间锚点结构；若没有基本面/指引/结构破坏，中长期区间不按股价同比下移。"
      : "Previous range snapshot is unavailable, so this records current anchors; without fundamental/guidance/structural breaks, mid/long ranges should not move one-for-one with price.",
  };
}

function applyTradeContextToBuyRange(row, range, horizon, tradeContext = null) {
  if (!range || range.status !== "available") return range;
  const weights = summarizeRangeAnchorWeights(range.based_on || range.sources || []);
  range.observed_anchor_weights = weights;
  const plannedWeights = {
    short: { structural_anchor_weight: 60, dynamic_anchor_weight: 40 },
    mid: { structural_anchor_weight: 75, dynamic_anchor_weight: 25 },
    long: { structural_anchor_weight: 85, dynamic_anchor_weight: 15 },
  }[horizon] || weights;
  Object.assign(range, plannedWeights);
  range.expected_move_validation = expectedMoveValidationForRange(range, horizon, "buy", tradeContext);
  range.relative_strength_context = tradeContext?.relative_strength_state
    ? {
      regime: tradeContext.relative_strength_state.regime,
      score: tradeContext.relative_strength_state[`${horizon}_score`] ?? null,
      improving: tradeContext.relative_strength_state.improving,
      deteriorating: tradeContext.relative_strength_state.deteriorating,
    }
    : null;
  range.guidance_context = tradeContext?.guidance_state
    ? {
      direction: tradeContext.guidance_state.direction,
      score: tradeContext.guidance_state.score,
      explanation: tradeContext.guidance_state.explanation,
    }
    : null;
  range.invalidation = currentLanguage === "zh"
    ? "若支撑放量跌破、OBV 继续走弱，或指引/基本面下修，该买入区间需要重新计算。"
    : "Recalculate this buy range if support breaks on volume, OBV weakens further, or guidance/fundamentals deteriorate.";
  range.range_shift_analysis = rangeShiftAnalysisForPlan(row, range, "buy", tradeContext);
  if (horizon !== "short" && tradeContext?.guidance_state?.direction !== "lowered" && tradeContext?.fundamental_health?.regime !== "weak") {
    range.anti_chase_down_note = currentLanguage === "zh"
      ? "中长期区间以结构锚点为主；若基本面和指引未恶化，不因股价下跌机械同比下移。"
      : "Mid/long range is structurally anchored; without weaker fundamentals or guidance, it should not chase price lower one-for-one.";
  }
  return range;
}

function applyTradeContextToSellRange(row, range, horizon, tradeContext = null) {
  if (!range || range.status !== "available") return range;
  range.expected_move_validation = expectedMoveValidationForRange(range, horizon, "sell", tradeContext);
  range.relative_strength_context = tradeContext?.relative_strength_state
    ? {
      regime: tradeContext.relative_strength_state.regime,
      score: tradeContext.relative_strength_state[`${horizon}_score`] ?? null,
      improving: tradeContext.relative_strength_state.improving,
      deteriorating: tradeContext.relative_strength_state.deteriorating,
    }
    : null;
  range.guidance_context = tradeContext?.guidance_state
    ? {
      direction: tradeContext.guidance_state.direction,
      score: tradeContext.guidance_state.score,
      explanation: tradeContext.guidance_state.explanation,
    }
    : null;
  range.range_shift_analysis = rangeShiftAnalysisForPlan(row, range, "sell", tradeContext);
  const rs = tradeContext?.relative_strength_state;
  const valuation = tradeContext?.valuation_state;
  const guidance = tradeContext?.guidance_state;
  range.top_anchor_lock = Boolean(
    guidance?.direction !== "raised"
      && (valuation?.regime === "expensive" || valuation?.regime === "extreme" || rs?.deteriorating),
  );
  if (range.top_anchor_lock) {
    range.anti_chase_up_note = currentLanguage === "zh"
      ? "未看到指引或公允价值上修，且估值/相对强度出现压力，卖出区间不应随股价机械上移。"
      : "Without raised guidance or fair value, and with valuation / relative-strength pressure, sell ranges should not mechanically chase price higher.";
  }
  range.invalidation = currentLanguage === "zh"
    ? "若放量突破并成功回踩，同时相对强度和指引继续改善，卖出区间可重新上移。"
    : "Move this sell range higher only after a strong breakout and successful retest with improving relative strength and guidance.";
  return range;
}

function normalizeBuyRanges(shortRange, midRange, longRange, atr, currentPrice, params = {}) {
  const ranges = [
    { key: "short", range: shortRange },
    { key: "mid", range: midRange },
    { key: "long", range: longRange },
  ];
  ranges.forEach(({ key, range }) => annotateRange(range, key, atr, params, "buy"));
  const gap = Number.isFinite(atr)
    ? Math.max(atr * (params.minimum_zone_gap_atr || 0.22), (currentPrice || 1) * 0.0025)
    : Math.max((currentPrice || 1) * 0.003, 0.01);
  const reason = currentLanguage === "zh" ? "买入区间非重叠归一化" : "Non-overlap buy range normalization";
  const forceBelow = (upper, lower, lowerKey) => {
    if (!upper || !lower || upper.status !== "available" || lower.status !== "available") return false;
    if (!(lower.high >= upper.low - gap)) return false;
    const minWidth = Number.isFinite(atr)
      ? Math.max(atr * rangeMinimumWidthAtr(lowerKey, params, "buy"), 0.01)
      : Math.max((currentPrice || 1) * 0.01, 0.01);
    const newHigh = Math.max(0.02, upper.low - gap);
    lower.high = Number(newHigh.toFixed(2));
    lower.low = Number(Math.max(0.01, newHigh - Math.max(minWidth, lower.high - (lower.low || 0))).toFixed(2));
    lower.midpoint = Number(((lower.low + lower.high) / 2).toFixed(2));
    lower.based_on = [...new Set([...(lower.based_on || []), reason])].slice(0, 8);
    lower.sources = [...new Set([...(lower.sources || []), reason])].slice(0, 8);
    lower.normalized_non_overlap = true;
    lower.summary = currentLanguage === "zh"
      ? `${lower.summary || ""} 已按 ATR gap 下移，避免与更短周期买入区间重叠。`.trim()
      : `${lower.summary || ""} Shifted lower by ATR gap to avoid overlap with the shorter horizon range.`.trim();
    return true;
  };
  let changed = false;
  changed = forceBelow(shortRange, midRange, "mid") || changed;
  changed = forceBelow(midRange, longRange, "long") || changed;
  ranges.forEach(({ key, range }) => {
    annotateRange(range, key, atr, params, "buy");
    if (!range || range.status !== "available") return;
    range.ordering_note = currentLanguage === "zh"
      ? "短期区间最高、中期居中、长期最低，且三个低吸区间默认不重叠。"
      : "Short-term range is highest, mid-term is lower, and long-term is lowest; the three pullback ranges are non-overlapping by default.";
  });
  return { changed, gap: Number(gap.toFixed(2)) };
}

function makeHorizonBuyRange(title, rawZone, currentPrice, horizon, companyProfile, summary, style) {
  const available = rawZone && Number.isFinite(rawZone.low) && Number.isFinite(rawZone.high);
  const labels = buyRangeLabels(horizon);
  const confidenceBase = available
    ? computeBuyZoneConfidence(
      horizon === "short" ? "primary" : horizon === "mid" ? "primary" : "deep",
      rawZone,
      rawZone.low,
      rawZone.high,
      currentPrice,
      { maxDrawdownPct: horizon === "short" ? 12 : horizon === "mid" ? 24 : 42, companyProfile },
    )
    : 0;
    return {
      title: currentLanguage === "zh" ? labels.label : labels.english_label,
      label: labels.label,
      english_label: labels.english_label,
      low: available ? Number(Math.min(rawZone.low, rawZone.high).toFixed(2)) : null,
      high: available ? Number(Math.max(rawZone.low, rawZone.high).toFixed(2)) : null,
    midpoint: available ? Number(((Math.min(rawZone.low, rawZone.high) + Math.max(rawZone.low, rawZone.high)) / 2).toFixed(2)) : null,
    confidence: available ? confidenceBase : 0,
    status: available ? "available" : "unavailable",
      based_on: [...new Set(rawZone?.sources || [])].slice(0, 6),
      sources: [...new Set(rawZone?.sources || [])].slice(0, 6),
      style,
      purpose: summary,
      allocation_hint: allocationHintForRange(companyProfile, horizon),
      zone_strength: confidenceBase >= 78 ? "strong" : confidenceBase >= 58 ? "medium" : "weak",
      market_adjustment: null,
      summary,
    };
  }

function shiftRangeBy(range, amount, reason) {
  if (!range || range.status !== "available" || !Number.isFinite(amount) || amount <= 0) return false;
  const width = Math.max(0.01, (range.high ?? 0) - (range.low ?? 0));
  range.low = Number(Math.max(0.01, range.low - amount).toFixed(2));
  range.high = Number(Math.max(range.low + width, range.high - amount).toFixed(2));
  range.based_on = [...new Set([...(range.based_on || []), reason])].slice(0, 8);
  range.sources = [...new Set([...(range.sources || []), reason])].slice(0, 8);
  return true;
}

function enforceBuyRangeOrder(shortRange, midRange, longRange, atr, currentPrice, row = null, companyProfile = null) {
  const params = decisionRangeParameters(row, companyProfile || {});
  const result = normalizeBuyRanges(shortRange, midRange, longRange, atr, currentPrice, params);
  [shortRange, midRange, longRange].forEach((range) => {
    if (!range || range.status !== "available") return;
    range.ordering_note = currentLanguage === "zh"
      ? "短期区间最高、中期居中、长期最低；长期核心布局区间更低代表更大安全边际，不是长期看空。"
      : "Short-term range is highest, mid-term is lower, and long-term core range is lowest; the lower long-term range reflects a larger margin of safety, not a bearish long-term view.";
  });
  return result.changed;
}

function buildRecommendedBuyPlan(row, buyZones, aiDecision, technical, supportResistance = null, companyProfile = null, marketContext = null, fundamental = null, tradeContext = null) {
  const tech = row.technicals || {};
  const price = row.price ?? null;
  const atr = Number.isFinite(tech.atr14) ? tech.atr14 : (Number.isFinite(price) ? price * 0.035 : null);
  const options = row.research?.optionsRead || buildOptionsRead(row);
  const marketAdjustment = marketAdjustmentForPlans(marketContext);
  const add = (list, priceValue, weight, source) => {
    if (Number.isFinite(priceValue) && priceValue > 0) list.push({ price: priceValue, weight, source });
  };
  const fib = (ratio) => (Number.isFinite(tech.rangeLow) && Number.isFinite(tech.rangeHigh))
    ? tech.rangeLow + (tech.rangeHigh - tech.rangeLow) * ratio
    : null;
  const swingLow = Math.min(...(tech.history?.lows || []).slice(-35).filter(Number.isFinite));
  const majorSwingLow = Math.min(...(tech.history?.lows || []).slice(-180).filter(Number.isFinite));
  const expectedMove = tradeContext?.options_state?.expected_move || {};
  const shortCandidates = [];
  const midCandidates = [];
  const longCandidates = [];

  (supportResistance?.supports || []).slice(0, 2).forEach((level, index) => add(shortCandidates, level.price, 1.8 - index * 0.25, level.level));
  add(shortCandidates, tech.ma10, 1.05, "MA10");
  add(shortCandidates, tech.ma20, 1.25, "MA20");
  add(shortCandidates, tech.middleBand, 0.85, currentLanguage === "zh" ? "布林中轨" : "Bollinger Middle");
  if (Number.isFinite(price) && Number.isFinite(atr)) add(shortCandidates, price - atr * 0.75, 0.18, "ATR 0.75 fallback");
  add(shortCandidates, fib(0.382), 0.95, "Fib 38.2%");
  add(shortCandidates, swingLow, 0.95, "Recent Swing Low");
  add(shortCandidates, expectedMove.lower_7d, 0.18, "Expected Move Lower 7D");

  (supportResistance?.supports || []).slice(1, 4).forEach((level, index) => add(midCandidates, level.price, 1.8 - index * 0.22, level.level));
  add(midCandidates, tech.ma20, 0.8, "MA20");
  add(midCandidates, tech.ma50, 1.35, "MA50");
  add(midCandidates, tech.ma100, 1.2, "MA100");
  add(midCandidates, fib(0.5), 1.1, "Fib 50%");
  add(midCandidates, fib(0.618), 1.05, "Fib 61.8%");
  if (Number.isFinite(price) && Number.isFinite(atr)) add(midCandidates, price - atr * 1.35, 0.12, "ATR 1.35 fallback");
  add(midCandidates, expectedMove.lower_30d, 0.16, "Expected Move Lower 30D");
  if (!isCnAShare(row) && options.available) add(midCandidates, options.putWall, 1.15, "Put Wall");

  (supportResistance?.supports || []).slice(2, 5).forEach((level, index) => add(longCandidates, level.price, 1.8 - index * 0.2, level.level));
  add(longCandidates, tech.ma100, 1.1, "MA100");
  add(longCandidates, tech.ma200, 1.55, "MA200");
  add(longCandidates, fib(0.618), 1.15, "Fib 61.8%");
  add(longCandidates, fib(0.786), 1.1, "Fib 78.6%");
  add(longCandidates, tech.rangeLow, 1.2, "52W Support");
  add(longCandidates, majorSwingLow, 1.25, "Major Swing Low");
  if (Number.isFinite(price) && Number.isFinite(atr)) add(longCandidates, price - atr * 2.0, 0.08, "ATR 2.0 fallback");

  const shortRaw = Number.isFinite(price) ? weightedZoneFromCandidates(shortCandidates, price, { minDrawdownPct: -1, maxDrawdownPct: 12 }) : null;
  const midRaw = Number.isFinite(price) ? weightedZoneFromCandidates(midCandidates, price, { minDrawdownPct: 2, maxDrawdownPct: 28 }) : null;
  const longRaw = Number.isFinite(price) ? weightedZoneFromCandidates(longCandidates, price, { minDrawdownPct: 8, maxDrawdownPct: hasAnyTag(companyProfile?.tags || [], ["Speculative", "HighVolatility"]) ? 48 : 38 }) : null;
  const shortWeak = ["Reduce", "Sell", "Sell-Avoid", "Strong Sell", "Short Candidate", "Short"].includes(aiDecision?.short_term?.rating);
  const midWeak = ["Reduce", "Sell", "Sell-Avoid", "Strong Sell", "Short Candidate", "Short"].includes(aiDecision?.mid_term?.rating);
  const weakenBuyConfidence = shortWeak && midWeak ? 12 : 0;
  const volume = technical?.volume_confirmation || {};
  const weakVolume = ["distribution_risk", "panic_selling", "weak_breakout"].includes(volume.behavior_key) || volume.obv_trend_20d === "falling";
  const rightSideConfirmed = ["strong_accumulation", "early_accumulation"].includes(volume.behavior_key)
    && (volume.relative_volume_20d ?? 0) >= 1.1
    && (volume.close_location_pct ?? 0) >= 55
    && !shortWeak;
  const marketConfidencePenalty = marketAdjustment.regime === "panic"
    ? 16
    : marketAdjustment.regime === "risk_off"
      ? 10
      : marketAdjustment.regime === "overheated"
        ? 8
        : 0;
  let opportunityType = marketAdjustment.regime === "panic" || (shortWeak && midWeak) || weakVolume
    ? "wait_for_stabilization"
    : rightSideConfirmed
      ? "right_side_confirmation"
      : "left_side_accumulation";
  const shortRange = makeHorizonBuyRange(
    currentLanguage === "zh" ? "短期回调买入区间" : "Short-Term Pullback Buy Range",
    shortRaw,
    price,
    "short",
    companyProfile,
    currentLanguage === "zh" ? "适合轻仓试探或已有仓位回踩加仓，重点看短期支撑和量能承接。" : "Light starter / pullback add zone anchored to short-term support and volume sponsorship.",
    "pullback_accumulation",
  );
  const midRange = makeHorizonBuyRange(
    currentLanguage === "zh" ? "中期分批加仓区间" : "Mid-Term Accumulation Range",
    midRaw,
    price,
    "mid",
    companyProfile,
    currentLanguage === "zh" ? "适合核心分批加仓，重点看 MA50 / MA100、S2-S3 和成交密集支撑。" : "Core staged accumulation zone anchored to MA50 / MA100, S2-S3, and volume support.",
    "core_accumulation",
  );
  const longRange = makeHorizonBuyRange(
    currentLanguage === "zh" ? "长期核心布局区间" : "Long-Term Core Accumulation Range",
    longRaw,
    price,
    "long",
    companyProfile,
    currentLanguage === "zh" ? "适合底部布局或大幅回调后的长期低吸，不代表必须现在等到这里。" : "Long-term left-side accumulation area after a deeper pullback; not a requirement to wait for it now.",
    "left_side_accumulation",
  );
  const shiftRangeLower = (range, atrMultiple, reason) => {
    if (!range || range.status !== "available" || !Number.isFinite(atr)) return;
    range.low = Number(Math.max(0.01, range.low - atr * atrMultiple).toFixed(2));
    range.high = Number(Math.max(range.low, range.high - atr * atrMultiple).toFixed(2));
    range.based_on = [...new Set([...(range.based_on || []), reason])].slice(0, 7);
    range.sources = [...new Set([...(range.sources || []), reason])].slice(0, 7);
  };
  if (marketAdjustment.regime === "risk_off") {
    shiftRangeLower(shortRange, 0.5, currentLanguage === "zh" ? "市场偏防守下移 0.5 ATR" : "Risk-off 0.5 ATR shift");
    shiftRangeLower(midRange, 0.75, currentLanguage === "zh" ? "市场偏防守下移 0.75 ATR" : "Risk-off 0.75 ATR shift");
    shiftRangeLower(longRange, 1.0, currentLanguage === "zh" ? "市场偏防守下移 1.0 ATR" : "Risk-off 1.0 ATR shift");
  } else if (marketAdjustment.regime === "panic") {
    shiftRangeLower(shortRange, 0.75, currentLanguage === "zh" ? "恐慌环境下移 0.75 ATR" : "Panic 0.75 ATR shift");
    shiftRangeLower(midRange, 1.0, currentLanguage === "zh" ? "恐慌环境下移 1.0 ATR" : "Panic 1.0 ATR shift");
    shiftRangeLower(longRange, 1.25, currentLanguage === "zh" ? "恐慌环境下移 1.25 ATR" : "Panic 1.25 ATR shift");
    if (longRange.status === "available") longRange.confidence = clamp(longRange.confidence + 8, 0, 100);
  } else if (marketAdjustment.regime === "overheated") {
    shiftRangeLower(shortRange, 0.5, currentLanguage === "zh" ? "情绪过热下移 0.5 ATR" : "Overheated 0.5 ATR shift");
    shiftRangeLower(midRange, 0.5, currentLanguage === "zh" ? "情绪过热下移 0.5 ATR" : "Overheated 0.5 ATR shift");
  } else if (marketAdjustment.regime === "risk_on" && hasAnyTag(companyProfile?.tags || [], ["HighGrowth", "AIInfrastructure", "Momentum"])) {
    shortRange.summary = currentLanguage === "zh"
      ? `${shortRange.summary} 风险偏好配合时，高成长股短期区间可以略靠近现价，但仍需量能确认。`
      : `${shortRange.summary} In risk-on tape, high-growth entries can sit slightly closer to spot, but volume confirmation is still required.`;
  }
  const buyRangeOrdering = enforceBuyRangeOrder(shortRange, midRange, longRange, atr, price, row, companyProfile);
  const fundamentalScore = fundamental?.profile_fundamental?.score ?? fundamental?.fundamental_score ?? 50;
  const companySpecificRisk = fundamentalScore < 35 || fundamental?.profile_fundamental?.high_dividend_debt_risk;
  const priceNearMidOrLong = Number.isFinite(price) && (
    (midRange.status === "available" && price <= midRange.high * 1.03)
    || (longRange.status === "available" && price <= longRange.high * 1.05)
  );
  const enhancedMarket = marketContext?.enhanced_context || normalizeEnhancedMarketContext(marketContext?.market_engine || {}, marketContext?.macro || {});
  const vixEasing = (enhancedMarket.vix?.change_5d_pct ?? 0) < -15 || (enhancedMarket.vix?.change_20d_pct ?? 0) < -25;
  const indexRecovering = ["recovering", "bullish"].includes(enhancedMarket.qqq_trend?.trend) || ["recovering", "bullish"].includes(enhancedMarket.spy_trend?.trend);
  if (companySpecificRisk && (shortWeak || midWeak)) {
    opportunityType = "company_specific_risk";
  } else if (marketAdjustment.regime === "panic" && !vixEasing && !indexRecovering) {
    opportunityType = "wait_for_stabilization";
  } else if (["risk_off", "panic"].includes(marketAdjustment.regime) && priceNearMidOrLong && !companySpecificRisk) {
    opportunityType = vixEasing || indexRecovering || rightSideConfirmed ? "left_side_accumulation" : "wait_for_stabilization";
  } else if (rightSideConfirmed || (vixEasing && indexRecovering && !weakVolume)) {
    opportunityType = "right_side_confirmation";
  } else if (weakVolume && shortWeak && midWeak) {
    opportunityType = "avoid_falling_knife";
  }
  const priceAboveShortRange = Number.isFinite(price) && shortRange.status === "available" && price > shortRange.high;
  const ma20Ok = Number.isFinite(price) && Number.isFinite(tech.ma20) && price > tech.ma20;
  const maStructureOk = Number.isFinite(tech.ma20) && Number.isFinite(tech.ma50)
    ? tech.ma20 >= tech.ma50 * 0.98 || price > tech.ma50
    : ma20Ok;
  const obvOk = !["falling", "down"].includes(volume.obv_trend_20d);
  const volumeOk = ["strong_accumulation", "early_accumulation"].includes(volume.behavior_key) || (volume.relative_volume_20d ?? 0) >= 1.1;
  const closeOk = (volume.close_location_pct ?? 0) >= 60;
  const marketOk = ["risk_on", "neutral"].includes(marketAdjustment.regime) || indexRecovering;
  const r1 = supportResistance?.resistances?.[0];
  const breakoutOrRetest = (r1?.price && price > r1.price * 1.003)
    || (Number.isFinite(tech.ma20) && Math.abs((price - tech.ma20) / Math.max(price, 1)) <= 0.06 && price > tech.ma20)
    || rightSideConfirmed;
  const rightSideMissing = [
    priceAboveShortRange ? null : (currentLanguage === "zh" ? "当前价格尚未高于短期回调区间，不需要右侧追踪买入。" : "Price is not above the short-term pullback range, so right-side entry is not needed."),
    ma20Ok ? null : (currentLanguage === "zh" ? "价格尚未站上 MA20。" : "Price has not reclaimed MA20."),
    maStructureOk ? null : (currentLanguage === "zh" ? "MA20 / MA50 趋势结构仍不足。" : "MA20 / MA50 trend structure is not strong enough."),
    obvOk ? null : (currentLanguage === "zh" ? "OBV 20D 尚未确认。" : "OBV 20D has not confirmed."),
    volumeOk ? null : (currentLanguage === "zh" ? "量能确认不足。" : "Volume confirmation is insufficient."),
    closeOk ? null : (currentLanguage === "zh" ? "收盘位置不够强。" : "Close location is not strong enough."),
    marketOk ? null : (currentLanguage === "zh" ? "SPY / QQQ 或风险环境尚未配合。" : "SPY / QQQ or risk backdrop is not supportive yet."),
    breakoutOrRetest ? null : (currentLanguage === "zh" ? "尚未突破 R1 或完成 MA20 回踩确认。" : "No R1 breakout or MA20 retest confirmation yet."),
  ].filter(Boolean);
  const rightSideActive = priceAboveShortRange && ma20Ok && maStructureOk && obvOk && volumeOk && closeOk && marketOk && breakoutOrRetest;
  const rightSideConfirmationEntry = {
    active: rightSideActive,
    label: "右侧确认买入",
    english_label: "Right-Side Confirmation Entry",
    entry_zone: rightSideActive && Number.isFinite(price) && Number.isFinite(atr)
      ? {
        low: Number(Math.max(0.01, price - atr * 0.35).toFixed(2)),
        high: Number((price + atr * 0.25).toFixed(2)),
      }
      : null,
    risk_control: rightSideActive && Number.isFinite(price) && Number.isFinite(atr)
      ? (currentLanguage === "zh" ? `若跌回 MA20 或跌破 ${formatCurrency(price - atr, row.currencyCode)}，右侧买入逻辑失效。` : `If price loses MA20 or breaks ${formatCurrency(price - atr, row.currencyCode)}, the right-side setup is invalidated.`)
      : null,
    reason: rightSideActive
      ? (currentLanguage === "zh" ? "价格高于短期低吸区间，并且趋势、量能、OBV 与市场环境出现右侧确认。" : "Price is above the pullback range and trend, volume, OBV, and market backdrop confirm a right-side setup.")
      : (currentLanguage === "zh" ? `右侧确认未触发：${rightSideMissing.slice(0, 3).join(" / ") || "等待突破或回踩确认。"}` : `Right-side confirmation is not active: ${rightSideMissing.slice(0, 3).join(" / ") || "waiting for breakout or retest confirmation."}`),
    missing_conditions: rightSideMissing.slice(0, 5),
    confidence: rightSideActive
      ? clamp(Math.round(mean([
        volumeOk ? 78 : 50,
        obvOk ? 74 : 45,
        marketOk ? 72 : 45,
        closeOk ? 74 : 45,
      ]) ?? 65), 45, 88)
      : 0,
  };
  [shortRange, midRange, longRange].forEach((range) => {
    if (range) {
      range.market_adjustment = {
        regime: marketAdjustment.regime,
        note: marketAdjustment.note,
      };
    }
    if (range.status === "available" && weakenBuyConfidence) {
      range.confidence = clamp(range.confidence - weakenBuyConfidence, 0, 100);
      range.summary = currentLanguage === "zh"
        ? `${range.summary} 当前短中期偏弱，先降低置信度，等待量能重新确认。`
        : `${range.summary} Short and mid-term signals are weak, so confidence is reduced until volume reconfirms.`;
    }
    if (range.status === "available" && marketConfidencePenalty) {
      const appliedPenalty = range === longRange && marketAdjustment.regime === "panic"
        ? Math.max(0, marketConfidencePenalty - 12)
        : marketConfidencePenalty;
      range.confidence = clamp(range.confidence - appliedPenalty, 0, 100);
    }
    if (range.status === "available" && marketAdjustment.regime === "overheated" && range !== longRange) {
      range.summary = currentLanguage === "zh"
        ? `${range.summary} 情绪偏热时不建议追高，优先等回踩。`
        : `${range.summary} Overheated sentiment argues against chasing; wait for pullbacks.`;
    }
  });
  applyRangeReachability(row, shortRange, "short", "buy", companyProfile, marketContext);
  applyRangeReachability(row, midRange, "mid", "buy", companyProfile, marketContext);
  applyRangeReachability(row, longRange, "long", "buy", companyProfile, marketContext);
  applyTradeContextToBuyRange(row, shortRange, "short", tradeContext);
  applyTradeContextToBuyRange(row, midRange, "mid", tradeContext);
  applyTradeContextToBuyRange(row, longRange, "long", tradeContext);

  return {
    short_term_buy_range: shortRange,
    mid_term_buy_range: midRange,
    long_term_buy_range: longRange,
    right_side_confirmation_entry: rightSideConfirmationEntry,
    market_adjustment_notes: [
      marketAdjustment.note,
      opportunityType === "left_side_accumulation" && ["risk_off", "panic"].includes(marketAdjustment.regime)
        ? (currentLanguage === "zh" ? "宏观冲击型下跌且基本面未明显破坏时，可小仓位分批布局，但等待 VIX / 指数 / OBV 继续确认。" : "Macro-driven selloff with intact fundamentals can support small staged accumulation while waiting for VIX / index / OBV confirmation.")
        : null,
      opportunityType === "right_side_confirmation"
        ? (currentLanguage === "zh" ? "右侧确认需要指数企稳、VIX 回落，以及个股量能 / OBV 配合。" : "Right-side confirmation requires index stabilization, VIX easing, and stock-level volume / OBV confirmation.")
        : null,
      opportunityType === "company_specific_risk"
        ? (currentLanguage === "zh" ? "当前更像个股基本面或资产负债表风险，不按普通宏观错杀处理。" : "This looks more company-specific than macro-driven, so it is not treated as a generic dip-buy.")
        : null,
    ].filter(Boolean),
    opportunity_type: opportunityType,
    market_regime: marketAdjustment.regime,
    explanation: currentLanguage === "zh"
      ? "短期区间最高、中期居中、长期最低。长期核心布局区间更低是为了给长期核心仓位保留更大安全边际，不代表长期看空。右侧确认买入会单独提示，不覆盖三段低吸区间。"
      : "Short-term range is highest, mid-term is lower, and long-term core range is lowest. The lower long-term core range reflects a larger margin of safety, not a bearish long-term view. Right-side confirmation is shown separately and does not replace pullback ranges.",
    summary: currentLanguage === "zh"
      ? "买入计划按短期试探、中期核心加仓、长期底部布局三种周期拆分。"
      : "The buy plan separates short-term starter entries, mid-term core adds, and long-term accumulation.",
    validation: {
      buy_range_overlap: validateBuyRangeOrdering({ short_term_buy_range: shortRange, mid_term_buy_range: midRange, long_term_buy_range: longRange }).has_overlap,
      normalized_non_overlap: Boolean(buyRangeOrdering),
    },
  };
}

function weightedSellZoneFromCandidates(candidates, currentPrice, { minUpsidePct = 0, maxUpsidePct = 60, fallback = null } = {}) {
  const valid = candidates
    .filter((item) => Number.isFinite(item.price) && item.price > 0)
    .map((item) => ({
      ...item,
      upsidePct: ((item.price - currentPrice) / Math.max(currentPrice, 1)) * 100,
    }))
    .filter((item) => item.upsidePct >= minUpsidePct && item.upsidePct <= maxUpsidePct);
  if (!valid.length) return fallback;
  const totalWeight = valid.reduce((sum, item) => sum + (item.weight || 1), 0) || 1;
  const center = valid.reduce((sum, item) => sum + item.price * (item.weight || 1), 0) / totalWeight;
  const priceStd = stdDev(valid.map((item) => item.price)) || 0;
  const spread = Math.max(
    currentPrice * 0.008,
    Math.min(currentPrice * 0.03, priceStd || currentPrice * 0.018),
  );
  return {
    low: center - spread,
    high: center + spread,
    sources: [...new Set(valid.sort((a, b) => (b.weight || 1) - (a.weight || 1)).slice(0, 6).map((item) => item.source))],
    candidate_count: valid.length,
    source_count: [...new Set(valid.map((item) => item.source).filter(Boolean))].length,
    avg_weight: totalWeight / valid.length,
    total_weight: totalWeight,
    price_std: priceStd,
    center,
  };
}

function sellRangeLabels(horizon) {
  const labels = {
    short: { label: "短期止盈区间", english_label: "Short-Term Profit-Taking Range" },
    mid: { label: "中期减仓区间", english_label: "Mid-Term Trim Range" },
    long: { label: "长期估值止盈区间", english_label: "Long-Term Valuation Exit Range" },
  };
  return labels[horizon] || labels.mid;
}

function makeHorizonSellRange(rawZone, currentPrice, horizon, companyProfile, context = {}) {
  const labels = sellRangeLabels(horizon);
  const available = rawZone && Number.isFinite(rawZone.low) && Number.isFinite(rawZone.high);
  const low = available ? Number(Math.max(currentPrice * 1.002, Math.min(rawZone.low, rawZone.high)).toFixed(2)) : null;
  const high = available ? Number(Math.max(low + 0.01, Math.max(rawZone.low, rawZone.high)).toFixed(2)) : null;
  const confidence = available
    ? clamp(Math.round(46 + (rawZone.source_count || 0) * 9 + (rawZone.candidate_count || 0) * 2 + Math.min(rawZone.avg_weight || 1, 2) * 8), 35, 88)
    : 0;
  return {
    title: currentLanguage === "zh" ? labels.label : labels.english_label,
    label: labels.label,
    english_label: labels.english_label,
    low,
    high,
    midpoint: available ? Number(((low + high) / 2).toFixed(2)) : null,
    confidence,
    status: available ? "available" : "unavailable",
    based_on: [...new Set(rawZone?.sources || [])].slice(0, 8),
    sources: [...new Set(rawZone?.sources || [])].slice(0, 8),
    suggested_action: context.suggested_action,
    action_on_weak_rejection: context.action_on_weak_rejection,
    action_on_strong_breakout: context.action_on_strong_breakout,
    valuation_context: context.valuation_context,
    volume_context: context.volume_context,
    zone_strength: confidence >= 78 ? "strong" : confidence >= 58 ? "medium" : "weak",
  };
}

function normalizeSellRanges(shortRange, midRange, longRange, atr, currentPrice, params = {}) {
  const ranges = [
    { key: "short", range: shortRange },
    { key: "mid", range: midRange },
    { key: "long", range: longRange },
  ];
  ranges.forEach(({ key, range }) => annotateRange(range, key, atr, params, "sell"));
  const gap = Number.isFinite(atr)
    ? Math.max(atr * (params.sell_gap_atr || params.minimum_zone_gap_atr || 0.22), (currentPrice || 1) * 0.0025)
    : Math.max((currentPrice || 1) * 0.003, 0.01);
  const reason = currentLanguage === "zh" ? "卖出区间非重叠归一化" : "Non-overlap sell range normalization";
  const forceAbove = (lower, upper, upperKey) => {
    if (!lower || !upper || lower.status !== "available" || upper.status !== "available") return false;
    if (!(upper.low <= lower.high + gap)) return false;
    const minWidth = Number.isFinite(atr)
      ? Math.max(atr * rangeMinimumWidthAtr(upperKey, params, "sell"), 0.01)
      : Math.max((currentPrice || 1) * 0.01, 0.01);
    const newLow = lower.high + gap;
    const currentWidth = Math.max(minWidth, (upper.high || 0) - (upper.low || 0));
    upper.low = Number(newLow.toFixed(2));
    upper.high = Number((newLow + currentWidth).toFixed(2));
    upper.midpoint = Number(((upper.low + upper.high) / 2).toFixed(2));
    upper.based_on = [...new Set([...(upper.based_on || []), reason])].slice(0, 8);
    upper.sources = [...new Set([...(upper.sources || []), reason])].slice(0, 8);
    upper.normalized_non_overlap = true;
    return true;
  };
  let changed = false;
  changed = forceAbove(shortRange, midRange, "mid") || changed;
  changed = forceAbove(midRange, longRange, "long") || changed;
  ranges.forEach(({ key, range }) => annotateRange(range, key, atr, params, "sell"));
  return { changed, gap: Number(gap.toFixed(2)) };
}

function validateBuyRangeOrdering(plan = {}) {
  const shortRange = plan.short_term_buy_range || {};
  const midRange = plan.mid_term_buy_range || {};
  const longRange = plan.long_term_buy_range || {};
  const shortMidOverlap = shortRange.status === "available" && midRange.status === "available"
    ? !(shortRange.low > midRange.high)
    : false;
  const midLongOverlap = midRange.status === "available" && longRange.status === "available"
    ? !(midRange.low > longRange.high)
    : false;
  return {
    has_overlap: Boolean(shortMidOverlap || midLongOverlap),
    short_mid_overlap: Boolean(shortMidOverlap),
    mid_long_overlap: Boolean(midLongOverlap),
  };
}

function validateSellRangeOrdering(plan = {}) {
  const shortRange = plan.short_term_sell_range || {};
  const midRange = plan.mid_term_sell_range || {};
  const longRange = plan.long_term_sell_range || {};
  const shortMidOverlap = shortRange.status === "available" && midRange.status === "available"
    ? !(shortRange.high < midRange.low)
    : false;
  const midLongOverlap = midRange.status === "available" && longRange.status === "available"
    ? !(midRange.high < longRange.low)
    : false;
  return {
    has_overlap: Boolean(shortMidOverlap || midLongOverlap),
    short_mid_overlap: Boolean(shortMidOverlap),
    mid_long_overlap: Boolean(midLongOverlap),
  };
}

function validateStopOrdering(plan = {}) {
  const shortStop = plan.short_term_stop?.price;
  const midStop = plan.mid_term_stop?.price;
  const longStop = plan.long_term_stop?.price;
  const valid = [shortStop, midStop, longStop].every(Number.isFinite);
  return {
    valid,
    ordered: valid ? shortStop > midStop && midStop > longStop : false,
  };
}

function normalizeStops(stopPlan, buyPlan, atr, params = {}) {
  const shortStop = stopPlan?.short_term_stop;
  const midStop = stopPlan?.mid_term_stop;
  const longStop = stopPlan?.long_term_stop;
  if (!shortStop || !midStop || !longStop || ![shortStop.price, midStop.price, longStop.price].every(Number.isFinite)) {
    return { changed: false };
  }
  const gap = Number.isFinite(atr)
    ? Math.max(atr * (params.minimum_zone_gap_atr || 0.22) * 0.75, 0.01)
    : 0.01;
  let changed = false;
  const forceBelow = (upperStop, lowerStop, rangeLow, label) => {
    if (!Number.isFinite(upperStop.price) || !Number.isFinite(lowerStop.price)) return;
    const maxAllowed = upperStop.price - gap;
    if (lowerStop.price < maxAllowed) return;
    lowerStop.price = Number(Math.max(0.01, maxAllowed).toFixed(2));
    if (Number.isFinite(rangeLow)) {
      lowerStop.risk_pct_from_buy_range_low = Number((((rangeLow - lowerStop.price) / Math.max(rangeLow, 1)) * 100).toFixed(1));
    }
    lowerStop.based_on = [...new Set([...(lowerStop.based_on || []), label])].slice(0, 8);
    lowerStop.normalized_order = true;
    changed = true;
  };
  forceBelow(shortStop, midStop, buyPlan?.mid_term_buy_range?.low, currentLanguage === "zh" ? "止损顺序归一化" : "Stop ordering normalization");
  forceBelow(midStop, longStop, buyPlan?.long_term_buy_range?.low, currentLanguage === "zh" ? "止损顺序归一化" : "Stop ordering normalization");
  return { changed };
}

function buildSellPlan(row, supportResistance, companyProfile, technical, fundamental, marketContext = null, tradeContext = null) {
  const tech = row.technicals || {};
  const price = row.price ?? null;
  const atr = Number.isFinite(tech.atr14) ? tech.atr14 : (Number.isFinite(price) ? price * 0.035 : null);
  const params = decisionRangeParameters(row, companyProfile || {});
  const options = row.research?.optionsRead || buildOptionsRead(row);
  const expectedMove = tradeContext?.options_state?.expected_move || {};
  const add = (list, priceValue, weight, source) => {
    if (Number.isFinite(priceValue) && Number.isFinite(price) && priceValue > price * 0.995) {
      list.push({ price: priceValue, weight, source });
    }
  };
  const fibExtension = (ratio) => (Number.isFinite(tech.rangeLow) && Number.isFinite(tech.rangeHigh))
    ? tech.rangeHigh + (tech.rangeHigh - tech.rangeLow) * ratio
    : null;
  const shortCandidates = [];
  const midCandidates = [];
  const longCandidates = [];
  (supportResistance?.resistances || []).slice(0, 2).forEach((level, index) => add(shortCandidates, level.price, 1.8 - index * 0.25, level.level));
  add(shortCandidates, tech.upperBand, 1.05, currentLanguage === "zh" ? "布林上轨" : "Bollinger Upper");
  if (Number.isFinite(price) && Number.isFinite(atr)) {
    add(shortCandidates, price + atr * 0.8 * (params.sell_upside_multiplier || 1), 0.18, "ATR 0.8 fallback");
    add(shortCandidates, price + atr * 1.5 * (params.sell_upside_multiplier || 1), 0.14, "ATR 1.5 fallback");
  }
  add(shortCandidates, expectedMove.upper_7d, 0.18, "Expected Move Upper 7D");
  if (!isCnAShare(row) && options.available) add(shortCandidates, options.callWall, 1.1, "Call Wall");

  (supportResistance?.resistances || []).slice(1, 4).forEach((level, index) => add(midCandidates, level.price, 1.8 - index * 0.22, level.level));
  add(midCandidates, fibExtension(0.272), 1.05, "Fib Extension 127.2%");
  add(midCandidates, fibExtension(0.618), 0.95, "Fib Extension 161.8%");
  if (Number.isFinite(price) && Number.isFinite(atr)) {
    add(midCandidates, price + atr * 1.5 * (params.sell_upside_multiplier || 1), 0.12, "ATR 1.5 fallback");
    add(midCandidates, price + atr * 2.5 * (params.sell_upside_multiplier || 1), 0.1, "ATR 2.5 fallback");
  }
  add(midCandidates, expectedMove.upper_30d, 0.14, "Expected Move Upper 30D");

  (supportResistance?.resistances || []).slice(2, 5).forEach((level, index) => add(longCandidates, level.price, 1.8 - index * 0.2, level.level));
  add(longCandidates, tech.rangeHigh, 1.25, "52W High");
  add(longCandidates, fibExtension(1.0), 1.05, "Long-Term Fib Extension");
  if (Number.isFinite(price) && Number.isFinite(atr)) {
    add(longCandidates, price + atr * 2.5 * (params.sell_upside_multiplier || 1), 0.08, "ATR 2.5 fallback");
    add(longCandidates, price + atr * 4.0 * (params.sell_upside_multiplier || 1), 0.06, "ATR 4.0 fallback");
  }
  if (Number.isFinite(fundamental?.valuation?.forward_pe) && fundamental.valuation.forward_pe > 45) add(longCandidates, price * 1.08, 0.9, "Forward PE upper band");
  if (Number.isFinite(fundamental?.valuation?.peg) && fundamental.valuation.peg > 2.5) add(longCandidates, price * 1.1, 0.85, "PEG upper band");

  const shortRaw = Number.isFinite(price) ? weightedSellZoneFromCandidates(shortCandidates, price, { minUpsidePct: 0.5, maxUpsidePct: 18 }) : null;
  const midRaw = Number.isFinite(price) ? weightedSellZoneFromCandidates(midCandidates, price, { minUpsidePct: 4, maxUpsidePct: 35 }) : null;
  const longRaw = Number.isFinite(price) ? weightedSellZoneFromCandidates(longCandidates, price, { minUpsidePct: 8, maxUpsidePct: hasAnyTag(companyProfile?.tags || [], ["HighVolatility", "Speculative"]) ? 70 : 55 }) : null;
  const volume = technical?.volume_confirmation || {};
  const volumeContext = volume.behavior_label || volume.summary || (currentLanguage === "zh" ? "量能中性" : "Volume neutral");
  const valuationContext = hasAnyTag(companyProfile?.tags || [], ["AIInfrastructure", "HighGrowth"])
    ? (currentLanguage === "zh" ? "高成长 / AI 基建放量突破时，不因单一 PE 偏高过早止盈。" : "For high-growth / AI infrastructure, do not exit solely on one elevated PE multiple if breakout and fundamentals confirm.")
    : hasAnyTag(companyProfile?.tags || [], ["MemoryStorage", "DRAMNAND", "NAND"])
      ? (currentLanguage === "zh" ? "存储周期需结合毛利率、库存周期和行业景气，不只看 PE / PEG。" : "Memory-cycle exits should account for gross margin, inventory cycle, and sector cycle, not only PE / PEG.")
      : hasAnyTag(companyProfile?.tags || [], ["REIT", "Dividend"])
        ? (currentLanguage === "zh" ? "REIT / 分红股止盈需结合股息率压缩、10Y 利率、债务和现金流。" : "REIT / dividend exits should account for yield compression, 10Y rates, debt, and cash flow.")
        : (currentLanguage === "zh" ? "结合估值、增长、利润率和压力位判断止盈。" : "Profit-taking blends valuation, growth, margins, and resistance levels.");
  const shortRange = makeHorizonSellRange(shortRaw, price, "short", companyProfile, {
    suggested_action: currentLanguage === "zh" ? "靠近该区间可考虑短期止盈或降低追高风险。" : "Consider short-term profit protection or avoid chasing near this range.",
    action_on_weak_rejection: currentLanguage === "zh" ? "若放量冲高回落，可先止盈一部分。" : "If price rejects on volume, trim a portion.",
    action_on_strong_breakout: currentLanguage === "zh" ? "若放量突破并站稳，暂不急于卖出，观察 R2/R3。" : "If price breaks out on strong volume, do not rush to sell; watch R2/R3.",
    valuation_context: valuationContext,
    volume_context: volumeContext,
  });
  const midRange = makeHorizonSellRange(midRaw, price, "mid", companyProfile, {
    suggested_action: currentLanguage === "zh" ? "适合中期分批减仓或保护利润。" : "Suitable for staged mid-term trimming or profit protection.",
    action_on_weak_rejection: currentLanguage === "zh" ? "若压力位反复失败，减仓比例提高。" : "If resistance repeatedly rejects, increase trim size.",
    action_on_strong_breakout: currentLanguage === "zh" ? "强突破时上移到长期止盈区间再评估。" : "On strong breakout, reassess at the long-term exit range.",
    valuation_context: valuationContext,
    volume_context: volumeContext,
  });
  const longRange = makeHorizonSellRange(longRaw, price, "long", companyProfile, {
    suggested_action: currentLanguage === "zh" ? "长期估值止盈或核心仓再平衡区间。" : "Long-term valuation exit or core-position rebalance range.",
    action_on_weak_rejection: currentLanguage === "zh" ? "若基本面没有同步改善，考虑明显降低仓位。" : "If fundamentals do not improve alongside price, materially reduce exposure.",
    action_on_strong_breakout: currentLanguage === "zh" ? "若增长、FCF、margin 同步增强，可只做再平衡，不机械清仓。" : "If growth, FCF, and margins improve together, rebalance rather than mechanically exit.",
    valuation_context: valuationContext,
    volume_context: volumeContext,
  });
  const normalization = normalizeSellRanges(shortRange, midRange, longRange, atr, price, params);
  applyRangeReachability(row, shortRange, "short", "sell", companyProfile, marketContext);
  applyRangeReachability(row, midRange, "mid", "sell", companyProfile, marketContext);
  applyRangeReachability(row, longRange, "long", "sell", companyProfile, marketContext);
  applyTradeContextToSellRange(row, shortRange, "short", tradeContext);
  applyTradeContextToSellRange(row, midRange, "mid", tradeContext);
  applyTradeContextToSellRange(row, longRange, "long", tradeContext);
  return {
    short_term_sell_range: shortRange,
    mid_term_sell_range: midRange,
    long_term_sell_range: longRange,
    profit_protection_rules: [
      currentLanguage === "zh" ? "放量冲高回落：先保护短期利润。" : "Volume-backed rejection: protect short-term gains.",
      currentLanguage === "zh" ? "强势放量突破：不要机械止盈，观察下一档压力。" : "Strong volume breakout: avoid mechanical selling; watch next resistance.",
      currentLanguage === "zh" ? "估值扩张快于基本面改善：提高减仓优先级。" : "Valuation expanding faster than fundamentals: raise trim priority.",
    ],
    fundamental_exit: {
      triggers: [
        currentLanguage === "zh" ? "营收或利润率明显恶化" : "Revenue or margin deterioration",
        currentLanguage === "zh" ? "自由现金流恶化" : "Free cash flow deterioration",
        hasAnyTag(companyProfile?.tags || [], ["Dividend", "REIT"]) ? (currentLanguage === "zh" ? "分红安全性下降或债务风险上升" : "Dividend safety falls or debt risk rises") : null,
        hasAnyTag(companyProfile?.tags || [], ["MemoryStorage", "DRAMNAND", "NAND"]) ? (currentLanguage === "zh" ? "库存周期或毛利率周期见顶" : "Inventory cycle or gross margin cycle peaks") : null,
        hasAnyTag(companyProfile?.tags || [], ["RegulatoryRisk"]) ? (currentLanguage === "zh" ? "监管冲击改变核心逻辑" : "Regulatory shock changes the thesis") : null,
      ].filter(Boolean),
    },
    explanation: currentLanguage === "zh"
      ? "卖出计划按短期止盈、中期减仓、长期估值止盈拆分；强趋势突破时不机械卖出。"
      : "Sell plan separates short-term profit-taking, mid-term trimming, and long-term valuation exits; strong breakouts are not sold mechanically.",
    validation: {
      sell_range_overlap: validateSellRangeOrdering({ short_term_sell_range: shortRange, mid_term_sell_range: midRange, long_term_sell_range: longRange }).has_overlap,
      normalized_non_overlap: Boolean(normalization.changed),
    },
  };
}

function buildStopLossPlan(row, buyPlan, supportResistance, companyProfile, aiDecision, technical, marketContext = null, tradeContext = null) {
  const price = row.price ?? null;
  const atr = Number.isFinite(row.technicals?.atr14) ? row.technicals.atr14 : (Number.isFinite(price) ? price * 0.035 : null);
  const marketAdjustment = marketAdjustmentForPlans(marketContext);
  const rangeParams = decisionRangeParameters(row, companyProfile || {});
  const optionsState = tradeContext?.options_state || {};
  const expectedMove = optionsState.expected_move || {};
  if (!Number.isFinite(price) || !Number.isFinite(atr)) {
    return {
      short_term_stop: {
        price: null,
        stop_type: "unavailable",
        based_on: [],
        applies_to: currentLanguage === "zh" ? "短期交易 / 轻仓试探" : "Short-term trade / starter position",
        action_if_triggered: t("dataUnavailable"),
      },
      mid_term_stop: {
        price: null,
        stop_type: "unavailable",
        based_on: [],
        applies_to: currentLanguage === "zh" ? "中期分批加仓" : "Mid-term accumulation",
        action_if_triggered: t("dataUnavailable"),
      },
      long_term_stop: {
        price: null,
        stop_type: "unavailable",
        based_on: [],
        applies_to: currentLanguage === "zh" ? "长期底仓 / 左侧布局" : "Long-term core / left-side accumulation",
        action_if_triggered: t("dataUnavailable"),
      },
      fundamental_stop: { triggers: [] },
    };
  }

  const marketStopWidening = marketAdjustment.regime === "panic"
    ? 1.18
    : marketAdjustment.regime === "risk_off"
      ? 1.1
      : 1;
  const multiplier = atrStopMultiplier(row, companyProfile) * marketStopWidening * (rangeParams.stop_buffer_multiplier || 1);
  const shortWeak = ["Reduce", "Sell", "Sell-Avoid", "Strong Sell", "Short Candidate", "Short"].includes(aiDecision?.short_term?.rating);
  const midWeak = ["Reduce", "Sell", "Sell-Avoid", "Strong Sell", "Short Candidate", "Short"].includes(aiDecision?.mid_term?.rating);
  const volumeRisk = ["distribution_risk", "panic_selling", "weak_breakout"].includes(technical?.volume_confirmation?.behavior_key);

  const expectedMoveStopCandidate = (horizon) => {
    if (horizon === "short" && Number.isFinite(expectedMove.lower_7d)) return expectedMove.lower_7d;
    if (["mid", "long"].includes(horizon) && Number.isFinite(expectedMove.lower_30d)) return expectedMove.lower_30d;
    return null;
  };
  const buildStop = (range, horizon, atrMultiple, supportIndexes, maKeys, label) => {
    const rangeLow = Number.isFinite(range?.low) ? range.low : null;
    const supports = supportIndexes
      .map((index) => supportResistance.supports[index])
      .filter((level) => level && Number.isFinite(level.price));
    const maCandidates = maKeys
      .map((key) => ({ value: row.technicals?.[key], source: key.toUpperCase() }))
      .filter((item) => Number.isFinite(item.value));
    const candidates = [
      { value: Number.isFinite(rangeLow) ? rangeLow - atr * (horizon === "short" ? 0.25 : horizon === "mid" ? 0.4 : 0.55) : null, type: "range_low_atr_stop", source: `${label} low + ATR buffer` },
      ...supports.map((level) => ({ value: level.price * (horizon === "long" ? 0.975 : 0.985), type: "support_stop", source: level.level })),
      ...maCandidates.map((item) => ({ value: item.value * (horizon === "long" ? 0.975 : 0.985), type: "ma_stop", source: item.source })),
      { value: expectedMoveStopCandidate(horizon), type: "expected_move_stop_context", source: horizon === "short" ? "7D Expected Move lower" : "30D Expected Move lower" },
      { value: price - atr * atrMultiple, type: "atr_stop", source: `ATR x ${atrMultiple.toFixed(1)}` },
    ].filter((item) => Number.isFinite(item.value) && item.value > 0 && item.value < price);
    const belowRange = Number.isFinite(rangeLow)
      ? candidates.filter((item) => item.value < rangeLow * 0.998)
      : candidates;
    const chosenPool = belowRange.length ? belowRange : candidates;
    const chosen = chosenPool.sort((a, b) => b.value - a.value)[0];
    const stopPrice = chosen?.value ?? price - atr * atrMultiple;
    const distancePct = ((price - stopPrice) / price) * 100;
    const riskPctFromRangeLow = Number.isFinite(rangeLow)
      ? ((rangeLow - stopPrice) / Math.max(rangeLow, 1)) * 100
      : null;
    let riskLevel = distancePct <= 5 ? "low" : distancePct <= 10 ? "medium" : "high";
    if ((shortWeak && midWeak) || volumeRisk) riskLevel = riskLevel === "low" ? "medium" : "high";
    return {
      price: Number(stopPrice.toFixed(2)),
      stop_type: chosen?.type || "atr_stop",
      stop_distance_pct: Number(distancePct.toFixed(1)),
      risk_pct_from_buy_range_low: riskPctFromRangeLow == null ? null : Number(riskPctFromRangeLow.toFixed(1)),
      risk_level: riskLevel,
      linked_buy_range: horizon === "short" ? "short_term_buy_range" : horizon === "mid" ? "mid_term_buy_range" : "long_term_buy_range",
      applies_to: label,
      based_on: candidates.slice(0, 4).map((item) => item.source),
      expected_move_context: {
        option_chain_status: optionsState.option_chain_status || "unavailable",
        expected_move_lower: expectedMoveStopCandidate(horizon),
        term_structure: optionsState.term_structure || "unavailable",
        gap_risk: optionsState.term_structure === "backwardation" || optionsState.options_risk_regime === "event_risk",
      },
      volatility_adjustment: {
        market_regime: marketAdjustment.regime,
        iv_regime: optionsState.iv_regime?.combined_state || "unavailable",
        stop_buffer_multiplier: Number((marketStopWidening * (rangeParams.stop_buffer_multiplier || 1)).toFixed(2)),
      },
      invalidation_reason: currentLanguage === "zh"
        ? `跌破 ${formatCurrency(stopPrice, row.currencyCode)}，说明${label}的支撑逻辑失效。`
        : `A break below ${formatCurrency(stopPrice, row.currencyCode)} invalidates the ${label} support logic.`,
      action_if_triggered: currentLanguage === "zh"
        ? (horizon === "short" ? "停止短线加仓，减仓或等待重新确认。" : horizon === "mid" ? "暂停中期加仓，检查趋势和量能是否继续恶化。" : "重新评估长期逻辑，检查基本面是否破坏。")
        : (horizon === "short" ? "Stop short-term adds, reduce, or wait for reconfirmation." : horizon === "mid" ? "Pause mid-term adds and review trend / volume deterioration." : "Reassess the long-term thesis and check whether fundamentals broke."),
      market_adjustment_note: marketAdjustment.note,
      confidence: clamp(Math.round(72 - Math.max(0, distancePct - 8) * 1.4 + (candidates.length >= 3 ? 6 : 0)), 35, 88),
    };
  };

  const shortStop = buildStop(
    buyPlan.short_term_buy_range,
    "short",
    Math.min(multiplier, 1.2),
    [0, 1],
    ["ma10", "ma20"],
    currentLanguage === "zh" ? "短期买入区间" : "short-term buy range",
  );
  const midStop = buildStop(
    buyPlan.mid_term_buy_range,
    "mid",
    clamp(multiplier, 1.2, 1.8),
    [1, 2, 3],
    ["ma50", "ma100"],
    currentLanguage === "zh" ? "中期买入区间" : "mid-term buy range",
  );
  const longStop = buildStop(
    buyPlan.long_term_buy_range,
    "long",
    clamp(multiplier + 0.4, 2.0, 3.0),
    [2, 3, 4],
    ["ma100", "ma200"],
    currentLanguage === "zh" ? "长期买入区间" : "long-term buy range",
  );
  const tags = companyProfile?.tags || [];
  const fundamentalTriggers = [
    tradeContext?.guidance_state?.direction === "lowered" ? (currentLanguage === "zh" ? "前瞻指引下调" : "Forward guidance lowered") : null,
    hasAnyTag(tags, ["Dividend", "REIT"]) ? (currentLanguage === "zh" ? "分红削减或分红安全性明显恶化" : "Dividend cut or dividend-safety deterioration") : null,
    hasAnyTag(tags, ["HighDebtRisk", "REIT"]) ? (currentLanguage === "zh" ? "债务风险继续上升或再融资压力加大" : "Debt risk rises or refinancing pressure worsens") : null,
    currentLanguage === "zh" ? "营收增长明显坍塌" : "Revenue growth collapses",
    currentLanguage === "zh" ? "利润率持续恶化" : "Margins deteriorate materially",
    currentLanguage === "zh" ? "自由现金流转负或持续恶化" : "Free cash flow turns negative or deteriorates",
    hasAnyTag(tags, ["MemoryStorage", "DRAMNAND", "NAND"]) ? (currentLanguage === "zh" ? "库存周期或毛利率周期明显恶化" : "Inventory cycle or gross-margin cycle deteriorates") : null,
    currentLanguage === "zh" ? "监管冲击或核心投资逻辑被破坏" : "Regulatory shock or core thesis broken",
  ].filter(Boolean);
  const stopPlan = {
    short_term_stop: shortStop,
    mid_term_stop: midStop,
    long_term_stop: longStop,
    current_entry_stop: {
      ...shortStop,
      deprecated: true,
      compatibility_note: "Use short_term_stop in the new decision model.",
    },
    buy_zone_stop: {
      ...midStop,
      deprecated: true,
      compatibility_note: "Use mid_term_stop / long_term_stop in the new decision model.",
    },
    fundamental_stop: {
      triggers: fundamentalTriggers.slice(0, 6),
    },
  };
  const stopNormalization = normalizeStops(stopPlan, buyPlan, atr, rangeParams);
  stopPlan.current_entry_stop = {
    ...stopPlan.short_term_stop,
    deprecated: true,
    compatibility_note: "Use short_term_stop in the new decision model.",
  };
  stopPlan.buy_zone_stop = {
    ...stopPlan.mid_term_stop,
    deprecated: true,
    compatibility_note: "Use mid_term_stop / long_term_stop in the new decision model.",
  };
  stopPlan.validation = {
    stop_ordering: validateStopOrdering(stopPlan),
    normalized_order: Boolean(stopNormalization.changed),
  };
  return stopPlan;
}

function buildVolumeConfirmation(row, companyProfile = null, supportResistance = null) {
  const tech = row.technicals || {};
  const metadata = row.metadata || {};
  const move = row.changePercent ?? 0;
  const closePosition = tech.closePosition ?? 0.5;
  const closes = tech.history?.closes || [];
  const volumes = tech.history?.volumes || [];
  const turnovers = tech.history?.turnovers || [];
  const todayVolume = positiveOrNull(tech.latestVolume ?? latest(volumes));
  const avgVolume5d = averageLast(volumes, 5);
  const avgVolume10d = averageLast(volumes, 10);
  const avgVolume20d = averageLast(volumes, 20) ?? tech.vol20 ?? null;
  const avgVolume50d = averageLast(volumes, 50);
  const avgVolume60d = averageLast(volumes, 60);
  const avgVolume120d = averageLast(volumes, 120);
  const avgVolume250d = averageLast(volumes, 250);
  const relativeVolume5d = todayVolume != null && avgVolume5d ? todayVolume / avgVolume5d : null;
  const relativeVolume20d = todayVolume != null && avgVolume20d ? todayVolume / avgVolume20d : (tech.volumeRatio ?? null);
  const relativeVolume60d = todayVolume != null && avgVolume60d ? todayVolume / avgVolume60d : null;
  const floatShares = positiveOrNull(metadata.floatShares ?? metadata.float_shares ?? row.floatShares);
  const reportedSharesOutstanding = positiveOrNull(metadata.sharesOutstanding ?? metadata.shares_outstanding ?? row.sharesOutstanding);
  const estimatedSharesOutstanding = positiveOrNull(row.marketCap) && positiveOrNull(row.price)
    ? row.marketCap / row.price
    : null;
  const sharesOutstanding = reportedSharesOutstanding ?? estimatedSharesOutstanding;
  const shareBase = floatShares ?? sharesOutstanding;
  const shareBaseSource = floatShares
    ? "float_shares"
    : reportedSharesOutstanding
      ? "shares_outstanding"
      : estimatedSharesOutstanding
        ? "market_cap_price_estimate"
        : null;
  const directTurnoverRate = positiveOrNull(metadata.turnoverRate ?? metadata.turnover_rate ?? latest(turnovers));
  const avgDirectTurnover5d = averageLast(turnovers, 5);
  const avgDirectTurnover20d = averageLast(turnovers, 20);
  const avgDirectTurnover60d = averageLast(turnovers, 60);
  const avgDirectTurnover120d = averageLast(turnovers, 120);
  const turnoverRate = directTurnoverRate ?? turnoverFromVolume(todayVolume, shareBase);
  const avgTurnover5d = avgDirectTurnover5d ?? turnoverFromVolume(avgVolume5d, shareBase);
  const avgTurnover20d = avgDirectTurnover20d ?? turnoverFromVolume(avgVolume20d, shareBase);
  const avgTurnover60d = avgDirectTurnover60d ?? turnoverFromVolume(avgVolume60d, shareBase);
  const avgTurnover120d = avgDirectTurnover120d ?? turnoverFromVolume(avgVolume120d, shareBase);
  const obvTrend5d = obvTrend(closes, volumes, 5);
  const obvTrend20d = obvTrend(closes, volumes, 20);
  const obvTrend60d = obvTrend(closes, volumes, 60);
  const upDown20d = upDownVolumeStats(closes, volumes, 20);
  const upDown60d = upDownVolumeStats(closes, volumes, 60);
  const volumeTrendRatio60 = avgVolume60d && avgVolume120d ? avgVolume60d / avgVolume120d : null;
  const volumeTrendRatio120 = avgVolume120d && avgVolume250d ? avgVolume120d / avgVolume250d : null;
  const turnoverScore = turnoverActivityScore(turnoverRate, row, companyProfile);
  const brokeResistance = supportResistance?.resistances?.[0]?.price
    && Number.isFinite(row.price)
    && row.price > supportResistance.resistances[0].price * 1.005;
  const behaviorSignal = classifyVolumePriceBehavior({
    move,
    relativeVolume: relativeVolume20d ?? relativeVolume5d,
    turnoverRate,
    turnoverScore,
    closePosition,
    obvTrendValue: obvTrend5d,
    brokeResistance,
  });
  const shortComponents = {
    relative_volume: scoreRelativeVolume(relativeVolume5d ?? relativeVolume20d),
    turnover_rate: turnoverScore,
    close_location: scoreCloseLocation(closePosition),
    obv_trend: scoreObvTrendValue(obvTrend5d),
    volume_price_behavior: behaviorSignal.score,
  };
  const midComponents = {
    volume_20d_vs_60d: Number.isFinite(volumeTrendRatio60) ? scoreRelativeVolume(volumeTrendRatio60) : scoreRelativeVolume(relativeVolume20d ?? relativeVolume60d),
    turnover_20d_vs_60d: Number.isFinite(avgTurnover20d) && Number.isFinite(avgTurnover60d) && avgTurnover60d > 0
      ? scoreRelativeVolume(avgTurnover20d / avgTurnover60d)
      : turnoverActivityScore(avgTurnover20d ?? turnoverRate, row, companyProfile),
    obv_20d_60d: Math.round(mean([scoreObvTrendValue(obvTrend20d), scoreObvTrendValue(obvTrend60d)]) ?? 50),
    up_volume_vs_down_volume: scoreRatioConfirmation(upDown60d.ratio ?? upDown20d.ratio),
    volume_price_behavior: behaviorSignal.score,
  };
  const longComponents = {
    obv_3m_6m: scoreObvTrendValue(obvTrend60d),
    volume_60d_120d_250d: Math.round(mean([
      Number.isFinite(volumeTrendRatio60) ? scoreRelativeVolume(volumeTrendRatio60) : null,
      Number.isFinite(volumeTrendRatio120) ? scoreRelativeVolume(volumeTrendRatio120) : null,
    ].filter(Number.isFinite)) ?? 50),
    turnover_60d_120d: Number.isFinite(avgTurnover60d) && Number.isFinite(avgTurnover120d) && avgTurnover120d > 0
      ? scoreRelativeVolume(avgTurnover60d / avgTurnover120d)
      : turnoverActivityScore(avgTurnover60d ?? turnoverRate, row, companyProfile),
    accumulation_distribution: Math.round(mean([
      scoreRatioConfirmation(upDown60d.ratio),
      behaviorSignal.score,
      scoreCloseLocation(closePosition),
    ]) ?? 50),
  };
  const shortScore = weightedComponentScore(shortComponents, {
    relative_volume: 25,
    turnover_rate: 25,
    close_location: 20,
    obv_trend: 20,
    volume_price_behavior: 10,
  });
  const midScore = weightedComponentScore(midComponents, {
    volume_20d_vs_60d: 25,
    turnover_20d_vs_60d: 20,
    obv_20d_60d: 25,
    up_volume_vs_down_volume: 20,
    volume_price_behavior: 10,
  });
  const longScore = weightedComponentScore(longComponents, {
    obv_3m_6m: 35,
    volume_60d_120d_250d: 25,
    turnover_60d_120d: 20,
    accumulation_distribution: 20,
  });
  const score = clamp(Math.round(shortScore * 0.45 + midScore * 0.35 + longScore * 0.2), 0, 100);
  const stage = volumeStageFromScore(score);
  const localizedStage = localizedVolumeStage(stage);

  const behavior = behaviorSignal.summary;

  const missingFields = [];
  if (todayVolume == null) missingFields.push("today_volume");
  if (avgVolume20d == null) missingFields.push("avg_volume_20d");
  if (avgVolume60d == null) missingFields.push("avg_volume_60d");
  if (shareBase == null && directTurnoverRate == null) missingFields.push("float_shares_or_shares_outstanding");
  if (turnoverRate == null) missingFields.push("turnover_rate");
  if (obvTrend60d === "unavailable") missingFields.push("obv_trend_60d");
  if (upDown60d.ratio == null) missingFields.push("up_down_volume_ratio_60d");
  let confidence = 92 - missingFields.length * 6;
  if (shareBase == null && directTurnoverRate == null) confidence -= 8;
  if (volumes.length < 60) confidence -= 8;
  if (volumes.length < 120) confidence -= 4;
  confidence = clamp(Math.round(confidence), 42, 94);

  const makePeriodSignal = (horizon, periodScore, relVolume, avgTurnover, obvTrendValue, upDownRatio, note) => {
    const periodStage = volumeStageFromScore(periodScore);
    return {
      horizon,
      score: periodScore,
      status: periodStage,
      status_label: localizedVolumeStage(periodStage),
      label: periodStage,
      label_localized: localizedVolumeStage(periodStage),
      relative_volume: Number.isFinite(relVolume) ? Number(relVolume.toFixed(2)) : null,
      turnover_rate: Number.isFinite(avgTurnover) ? Number(avgTurnover.toFixed(2)) : null,
      obv_trend: obvTrendValue,
      up_down_volume_ratio: Number.isFinite(upDownRatio) ? Number(upDownRatio.toFixed(2)) : null,
      summary: note,
    };
  };

  return {
    score,
    volume_signal_score: score,
    status: stage,
    status_label: localizedStage,
    label: stage,
    label_localized: localizedStage,
    behavior,
    behavior_label: behaviorSignal.label,
    behavior_key: behaviorSignal.key,
    volume_price_behavior_score: behaviorSignal.score,
    stage: localizedStage,
    money_flow_core_score: score,
    money_flow_core: {
      short_term: {
        score: shortScore,
        components: shortComponents,
        weights: {
          relative_volume: 25,
          turnover_rate: 25,
          close_location: 20,
          obv_trend: 20,
          volume_price_behavior: 10,
        },
      },
      mid_term: {
        score: midScore,
        components: midComponents,
        weights: {
          volume_20d_vs_60d: 25,
          turnover_20d_vs_60d: 20,
          obv_20d_60d: 25,
          up_volume_vs_down_volume: 20,
          volume_price_behavior: 10,
        },
      },
      long_term: {
        score: longScore,
        components: longComponents,
        weights: {
          obv_3m_6m: 35,
          volume_60d_120d_250d: 25,
          turnover_60d_120d: 20,
          accumulation_distribution: 20,
        },
      },
    },
    today_change_pct: move,
    today_volume: todayVolume,
    avg_volume_5d: avgVolume5d,
    avg_volume_10d: avgVolume10d,
    avg_volume_20d: avgVolume20d,
    avg_volume_50d: avgVolume50d,
    avg_volume_60d: avgVolume60d,
    avg_volume_120d: avgVolume120d,
    avg_volume_250d: avgVolume250d,
    average_volume: avgVolume20d,
    relative_volume_5d: Number.isFinite(relativeVolume5d) ? Number(relativeVolume5d.toFixed(2)) : null,
    relative_volume_20d: Number.isFinite(relativeVolume20d) ? Number(relativeVolume20d.toFixed(2)) : null,
    relative_volume_60d: Number.isFinite(relativeVolume60d) ? Number(relativeVolume60d.toFixed(2)) : null,
    relative_volume: Number.isFinite(relativeVolume20d) ? Number(relativeVolume20d.toFixed(2)) : null,
    float_shares: floatShares,
    shares_outstanding: sharesOutstanding,
    share_base_source: directTurnoverRate != null ? "reported_turnover_rate" : shareBaseSource,
    turnover_rate: Number.isFinite(turnoverRate) ? Number(turnoverRate.toFixed(2)) : null,
    avg_turnover_5d: Number.isFinite(avgTurnover5d) ? Number(avgTurnover5d.toFixed(2)) : null,
    avg_turnover_20d: Number.isFinite(avgTurnover20d) ? Number(avgTurnover20d.toFixed(2)) : null,
    avg_turnover_60d: Number.isFinite(avgTurnover60d) ? Number(avgTurnover60d.toFixed(2)) : null,
    avg_turnover_120d: Number.isFinite(avgTurnover120d) ? Number(avgTurnover120d.toFixed(2)) : null,
    obv: tech.obv ?? null,
    close_position: closePosition,
    close_location_pct: Number((closePosition * 100).toFixed(1)),
    obv_trend_5d: obvTrend5d,
    obv_trend_20d: obvTrend20d,
    obv_trend_60d: obvTrend60d,
    up_volume_20d: upDown20d.upVolume,
    down_volume_20d: upDown20d.downVolume,
    up_down_volume_ratio_20d: upDown20d.ratio,
    up_volume_60d: upDown60d.upVolume,
    down_volume_60d: upDown60d.downVolume,
    up_down_volume_ratio_60d: upDown60d.ratio,
    short_term_volume_signal: makePeriodSignal(
      "1-30 days",
      shortScore,
      relativeVolume5d ?? relativeVolume20d,
      turnoverRate,
      obvTrend5d,
      upDown20d.ratio,
      currentLanguage === "zh" ? "短期更重视当日量价、5/20日量比、换手率和 OBV。" : "Short term emphasizes daily price/volume, 5/20D relative volume, turnover, and OBV.",
    ),
    mid_term_volume_signal: makePeriodSignal(
      "1-3 months",
      midScore,
      relativeVolume20d ?? relativeVolume60d,
      avgTurnover20d,
      obvTrend20d,
      upDown60d.ratio,
      currentLanguage === "zh" ? "中期更重视20/60日量能、平均换手率和上涨/下跌成交量。" : "Mid term emphasizes 20/60D participation, average turnover, and up/down volume.",
    ),
    long_term_volume_signal: makePeriodSignal(
      "3-6 months",
      longScore,
      relativeVolume60d,
      avgTurnover60d,
      obvTrend60d,
      upDown60d.ratio,
      currentLanguage === "zh" ? "长期更重视60日以上资金趋势和持续性。" : "Long term emphasizes 60D+ participation trend and persistence.",
    ),
    confidence,
    missing_fields: missingFields,
    price_volume_pattern: behavior,
    summary: currentLanguage === "zh"
      ? `${localizedStage}：${behavior}。置信度 ${confidence}%`
      : `${stage}: ${behavior}. Confidence ${confidence}%`,
  };
}

function buildTechnicalModule(row, supportResistance, companyProfile = null) {
  const tech = row.technicals || {};
  const price = row.price ?? 0;
  const volumeConfirmation = buildVolumeConfirmation(row, companyProfile, supportResistance);
  const aboveMa20 = Number.isFinite(tech.ma20) && price > tech.ma20;
  const aboveMa50 = Number.isFinite(tech.ma50) && price > tech.ma50;
  const aboveMa200 = Number.isFinite(tech.ma200) && price > tech.ma200;
  const bullishMaStack = Number.isFinite(tech.ma10) && Number.isFinite(tech.ma20) && Number.isFinite(tech.ma50) && tech.ma10 > tech.ma20 && tech.ma20 > tech.ma50;
  const bearishMaStack = Number.isFinite(tech.ma10) && Number.isFinite(tech.ma20) && Number.isFinite(tech.ma50) && tech.ma10 < tech.ma20 && tech.ma20 < tech.ma50;
  const maStructureScore = bullishMaStack && aboveMa20 && aboveMa50
    ? 78
    : bearishMaStack && !aboveMa20 && !aboveMa50
      ? 28
      : Math.round(mean([
        aboveMa20 ? 62 : 38,
        aboveMa50 ? 66 : 34,
        aboveMa200 ? 70 : 36,
      ]) ?? 50);
  const macdScore = (tech.macd ?? 0) > 0 && (tech.macdHistogram ?? 0) > 0
    ? 72
    : (tech.macd ?? 0) < 0 && (tech.macdHistogram ?? 0) < 0
      ? 32
      : (tech.macdHistogram ?? 0) > 0
        ? 58
        : 45;
  const rsiValue = tech.rsi14 ?? 50;
  const rsiScore = !Number.isFinite(rsiValue)
    ? 50
    : rsiValue >= 50 && rsiValue <= 68
      ? 66
      : rsiValue > 75
        ? 45
        : rsiValue < 35
          ? 38
          : 52;
  const kdjJ = tech.kdj?.j ?? 50;
  const kdjScore = !Number.isFinite(kdjJ)
    ? 50
    : kdjJ >= 40 && kdjJ <= 78
      ? 60
      : kdjJ > 90
        ? 42
        : kdjJ < 20
          ? 40
          : 52;
  const priceTrendComponents = {
    ma_structure: maStructureScore,
    macd: macdScore,
    rsi: rsiScore,
    kdj: kdjScore,
  };
  const priceTrendConfirmScore = weightedComponentScore(priceTrendComponents, {
    ma_structure: 40,
    macd: 25,
    rsi: 20,
    kdj: 15,
  });
  const longTrendConfirmScore = Math.round(mean([
    aboveMa200 ? 74 : 34,
    Number.isFinite(tech.ma50) && Number.isFinite(tech.ma200) && tech.ma50 > tech.ma200 ? 70 : 38,
    maStructureScore,
    macdScore,
  ]) ?? priceTrendConfirmScore);
  const trendScore = priceTrendConfirmScore;

  const rsiState = (tech.rsi14 ?? 50) >= 72 ? "Overbought" : (tech.rsi14 ?? 50) <= 34 ? "Oversold" : (tech.rsi14 ?? 50) >= 55 ? "Healthy Bullish" : "Neutral";
  const kdjState = (tech.kdj?.j ?? 50) >= 85 ? "Overbought" : (tech.kdj?.j ?? 50) <= 20 ? "Oversold" : "Neutral";
  const volatilityScore = price >= (tech.middleBand ?? price) && price <= (tech.upperBand ?? price * 2)
    ? 60
    : price > (tech.upperBand ?? Number.POSITIVE_INFINITY)
      ? (volumeConfirmation.money_flow_core?.short_term?.score ?? 50) >= 70 ? 58 : 42
      : price < (tech.lowerBand ?? Number.NEGATIVE_INFINITY)
        ? 40
        : 50;
  const nearestSupport = supportResistance.supports?.[0];
  const nearestResistance = supportResistance.resistances?.[0];
  const nearSupport = nearestSupport?.price && Number.isFinite(price) ? Math.abs((price - nearestSupport.price) / Math.max(price, 1)) * 100 <= 3 : false;
  const nearResistance = nearestResistance?.price && Number.isFinite(price) ? Math.abs((nearestResistance.price - price) / Math.max(price, 1)) * 100 <= 3 : false;
  const supportResistanceScore = nearSupport && (volumeConfirmation.money_flow_core?.short_term?.score ?? 50) >= 45
    ? 66
    : nearResistance && (volumeConfirmation.money_flow_core?.short_term?.score ?? 50) < 65
      ? 38
      : Math.round(mean([
        nearestSupport?.score,
        nearestResistance?.score != null ? 100 - nearestResistance.score : null,
      ].filter(Number.isFinite)) ?? 52);
  const momentumScore = Math.round(mean([macdScore, rsiScore, kdjScore, volatilityScore]) ?? 50);
  const profileKey = companyProfile?.scoring_profile || companyProfile?.classification?.scoring_profile || "generic";
  const technicalProfile = companyProfile?.decision_profile?.technical_weights || TECHNICAL_PROFILE_WEIGHTS[profileKey] || TECHNICAL_PROFILE_WEIGHTS.generic;
  const breakoutQualityScore = Math.round(mean([
    (volumeConfirmation.behavior_key === "strong_accumulation" || volumeConfirmation.behavior_key === "volume_breakout") ? 82 : null,
    (volumeConfirmation.behavior_key === "weak_breakout") ? 35 : null,
    (volumeConfirmation.relative_volume_20d ?? 1) >= 1.2 ? 68 : 45,
    (volumeConfirmation.close_location_pct ?? 50) >= 60 ? 66 : 42,
    ["rising", "neutral"].includes(volumeConfirmation.obv_trend_20d) ? 64 : 38,
  ].filter(Number.isFinite)) ?? 50);
  const shortComponents = {
    money_flow_core: volumeConfirmation.money_flow_core.short_term.score,
    trend_confirm: priceTrendConfirmScore,
    support_resistance: supportResistanceScore,
    volatility: volatilityScore,
    breakout_quality: breakoutQualityScore,
  };
  const midComponents = {
    money_flow_core: volumeConfirmation.money_flow_core.mid_term.score,
    trend_confirm: priceTrendConfirmScore,
    support_resistance: supportResistanceScore,
    volatility: volatilityScore,
  };
  const longComponents = {
    long_money_flow: volumeConfirmation.money_flow_core.long_term.score,
    long_trend: longTrendConfirmScore,
    support_resistance: supportResistanceScore,
    volatility_regime: volatilityScore,
  };
  const weightToPercent = (weights) => Object.fromEntries(Object.entries(weights || {}).map(([key, value]) => [key, value * 100]));
  const shortTechnicalScore = weightedComponentScore(shortComponents, weightToPercent(technicalProfile.short));
  const midTechnicalScore = weightedComponentScore(midComponents, weightToPercent(technicalProfile.mid));
  const longTechnicalScore = weightedComponentScore(longComponents, weightToPercent(technicalProfile.long));
  const technicalScore = clamp(Math.round(shortTechnicalScore * 0.35 + midTechnicalScore * 0.35 + longTechnicalScore * 0.3), 0, 100);
  const summary = technicalScore >= 70
    ? (currentLanguage === "zh" ? "技术结构偏强，主要由量能/换手率和趋势验证共同支撑。" : "Technicals are constructive, led by money-flow confirmation and trend validation.")
    : technicalScore >= 55
      ? (currentLanguage === "zh" ? "技术面中性偏稳，仍需要量能或趋势给出更明确确认。" : "Technicals are stable, but need clearer money-flow or trend confirmation.")
      : (currentLanguage === "zh" ? "技术面偏弱，主要因为量能/换手率或趋势验证不足。" : "Technicals are weak mainly because money flow or trend validation is insufficient.");

  return {
    technical_score: technicalScore,
    technical_analysis: {
      money_flow_core_score: volumeConfirmation.money_flow_core_score,
      price_trend_confirm_score: priceTrendConfirmScore,
      long_trend_confirm_score: longTrendConfirmScore,
      volatility_score: volatilityScore,
      support_resistance_score: supportResistanceScore,
      final_technical_score: technicalScore,
      components: {
        price_trend_confirm: priceTrendComponents,
        money_flow_core: volumeConfirmation.money_flow_core,
      },
      short_term: {
        money_flow_core_score: volumeConfirmation.money_flow_core.short_term.score,
        price_trend_confirm_score: priceTrendConfirmScore,
        breakout_quality_score: breakoutQualityScore,
        volatility_score: volatilityScore,
        support_resistance_score: supportResistanceScore,
        final_technical_score: shortTechnicalScore,
        weights: technicalProfile.short,
        components: shortComponents,
      },
      mid_term: {
        money_flow_core_score: volumeConfirmation.money_flow_core.mid_term.score,
        price_trend_confirm_score: priceTrendConfirmScore,
        volatility_score: volatilityScore,
        support_resistance_score: supportResistanceScore,
        final_technical_score: midTechnicalScore,
        weights: technicalProfile.mid,
        components: midComponents,
      },
      long_term: {
        long_term_money_flow_obv_score: volumeConfirmation.money_flow_core.long_term.score,
        long_trend_confirm_score: longTrendConfirmScore,
        support_resistance_score: supportResistanceScore,
        volatility_regime_score: volatilityScore,
        final_technical_score: longTechnicalScore,
        weights: technicalProfile.long,
        components: longComponents,
      },
    },
    trend_score: trendScore,
    momentum_score: momentumScore,
    volume_confirmation_score: volumeConfirmation.score,
    volume_signal_score: volumeConfirmation.score,
    short_term_signal: scoreBucketLabel(shortTechnicalScore),
    mid_term_signal: scoreBucketLabel(midTechnicalScore),
    long_term_signal: scoreBucketLabel(longTechnicalScore),
    trend: {
      state: trendScore >= 80 ? "Strong Bullish" : trendScore >= 65 ? "Bullish" : trendScore >= 45 ? "Neutral" : trendScore >= 30 ? "Bearish" : "Strong Bearish",
      ma10: tech.ma10 ?? null,
      ma20: tech.ma20 ?? null,
      ma50: tech.ma50 ?? null,
      ma100: tech.ma100 ?? null,
      ma200: tech.ma200 ?? null,
      macd: tech.macd ?? null,
      fibonacci: tech.fibPosition ?? null,
    },
    momentum: {
      state: momentumScore >= 70 ? "Healthy Bullish" : momentumScore >= 55 ? "Neutral" : momentumScore >= 35 ? "Weak Momentum" : "Oversold",
      rsi: tech.rsi14 ?? null,
      kdj: tech.kdj ?? null,
      macd_histogram: tech.macdHistogram ?? null,
      bollinger_position: price >= (tech.upperBand ?? Number.POSITIVE_INFINITY)
        ? "Upper Band"
        : price <= (tech.lowerBand ?? Number.NEGATIVE_INFINITY)
          ? "Lower Band"
          : currentLanguage === "zh" ? "中轨附近" : "Near middle band",
      rsi_state: rsiState,
      kdj_state: kdjState,
    },
    volume_confirmation: volumeConfirmation,
    volume_signal: volumeConfirmation,
    summary,
  };
}

function buildFundamentalModule(row, research) {
  const metrics = research.metrics || {};
  const quality = {
    score: research.qualityScore ?? 50,
    roe: metrics.roe ?? null,
    gross_margin: metrics.grossMargin ?? null,
    operating_margin: metrics.operatingMargin ?? null,
    net_margin: row.profile ? clamp((metrics.operatingMargin ?? 0) * 0.82, 0, 0.34) : null,
    debt_ratio: metrics.debtRatio ?? null,
    cash_ratio: metrics.cashReserve ?? null,
  };
  const growth = {
    score: research.growthScore ?? 50,
    revenue_growth: metrics.revenueGrowth ?? null,
    eps_growth: metrics.epsGrowth ?? null,
    free_cash_flow_growth: metrics.fcfGrowth ?? null,
    forward_guidance: metrics.guidance ?? null,
    analyst_growth_expectation: metrics.analystView ?? null,
  };
  const valuation = {
    score: research.valuationScore ?? 50,
    pe: metrics.pe ?? null,
    forward_pe: metrics.forwardPe ?? null,
    peg: metrics.peg ?? null,
    ps_ratio: metrics.psRatio ?? null,
    ev_ebitda: metrics.evEbitda ?? null,
    price_fcf: Number.isFinite(metrics.freeCashFlow) && Number.isFinite(row.marketCap) && metrics.freeCashFlow !== 0
      ? Math.abs((row.marketCap / 1e9) / metrics.freeCashFlow)
      : null,
    state: research.valuationState,
  };
  const financialHealthScore = clamp(Math.round(mean([
    metricScore(metrics.freeCashFlow ?? 0, -3, 8),
    metricScore((metrics.cashReserve ?? 0) * 100, 8, 45),
    inverseMetricScore((metrics.debtRatio ?? 0.6) * 100, 30, 80),
    metricScore((metrics.operatingMargin ?? 0) * 100, 6, 28),
  ]) ?? 50), 0, 100);
  const financialHealth = {
    score: financialHealthScore,
    free_cash_flow: metrics.freeCashFlow ?? null,
    cash_reserve: metrics.cashReserve ?? null,
    debt: metrics.debtRatio ?? null,
    capital_expenditure: row.profile ? clamp((row.profile.growth ?? 0.3) * 0.12, 0.02, 0.18) : null,
    cash_flow_stability: row.profile ? clamp((row.profile.cash ?? 0.2) * 100, 20, 90) : null,
  };
  const strengths = [];
  const risks = [];
  if ((quality.score ?? 0) >= 75) strengths.push(currentLanguage === "zh" ? "企业质量较高" : "Business quality is strong");
  if ((growth.score ?? 0) >= 70) strengths.push(currentLanguage === "zh" ? "成长仍在健康区间" : "Growth profile remains healthy");
  if ((metrics.freeCashFlow ?? 0) > 0) strengths.push(currentLanguage === "zh" ? "自由现金流为正" : "Free cash flow is positive");
  if ((valuation.score ?? 50) >= 60) strengths.push(currentLanguage === "zh" ? "估值处于更可接受区间" : "Valuation looks more reasonable");
  if ((valuation.score ?? 50) < 40) risks.push(currentLanguage === "zh" ? "估值偏高" : "Valuation remains rich");
  if ((metrics.freeCashFlow ?? 0) < 0) risks.push(currentLanguage === "zh" ? "自由现金流为负" : "Free cash flow is negative");
  if ((metrics.debtRatio ?? 0) > 0.62) risks.push(currentLanguage === "zh" ? "债务压力偏高" : "Debt load is elevated");
  if ((growth.score ?? 50) < 45) risks.push(currentLanguage === "zh" ? "成长兑现还不够强" : "Growth execution still looks soft");
  return {
    fundamental_score: research.fundamental ?? 50,
    quality,
    growth,
    valuation,
    financial_health: financialHealth,
    financial_health_score: financialHealthScore,
    summary: buildFundamentalConclusion(row, research),
    key_strengths: strengths.slice(0, 4),
    key_risks: risks.slice(0, 4),
  };
}

function weightedAvailableScore(components, weights, fallback = 50) {
  const valid = Object.entries(weights || {})
    .map(([key, weight]) => ({ key, weight, value: components?.[key] }))
    .filter((item) => Number.isFinite(item.value) && Number.isFinite(item.weight) && item.weight > 0);
  const total = valid.reduce((sum, item) => sum + item.weight, 0);
  if (!valid.length || total <= 0) {
    return {
      score: fallback,
      used_weights: {},
      missing_fields: Object.keys(weights || {}),
      confidence: 0.55,
    };
  }
  const usedWeights = {};
  const score = valid.reduce((sum, item) => {
    const normalized = item.weight / total;
    usedWeights[item.key] = Number(normalized.toFixed(4));
    return sum + item.value * normalized;
  }, 0);
  return {
    score: clamp(Math.round(score), 0, 100),
    used_weights: usedWeights,
    missing_fields: Object.keys(weights || {}).filter((key) => !valid.some((item) => item.key === key)),
    confidence: clamp(total / Object.values(weights || {}).reduce((sum, value) => sum + value, 0), 0.35, 1),
  };
}

function buildProfileFundamentalScore(row, fundamental, companyProfile) {
  const profile = companyProfile?.decision_profile?.base_profile || companyProfile?.scoring_profile || companyProfile?.classification?.scoring_profile || "generic";
  const dividendYield = normalizeDividendYield(row.metadata?.dividendYield);
  const revenueGrowthScore = metricScore((fundamental.growth.revenue_growth ?? 0) * 100, 0, 25);
  const profitMarginScore = metricScore((fundamental.quality.operating_margin ?? fundamental.quality.net_margin ?? 0) * 100, 4, 28);
  const grossMarginTrendScore = metricScore((fundamental.quality.gross_margin ?? 0) * 100, 20, 55);
  const fcfScore = metricScore(fundamental.financial_health.free_cash_flow ?? 0, -2, 8);
  const forwardPeScore = inverseMetricScore(fundamental.valuation.forward_pe ?? fundamental.valuation.pe ?? null, 15, 70);
  const pegScore = inverseMetricScore(fundamental.valuation.peg ?? null, 0.8, 3.2);
  const valuationRiskScore = Math.round(mean([
    forwardPeScore,
    inverseMetricScore(fundamental.valuation.ev_ebitda ?? null, 8, 35),
    inverseMetricScore(fundamental.valuation.price_fcf ?? null, 10, 55),
  ].filter(Number.isFinite)) ?? 50);
  const balanceSheetScore = Math.round(mean([
    inverseMetricScore((fundamental.quality.debt_ratio ?? 0.5) * 100, 25, 85),
    metricScore((fundamental.quality.cash_ratio ?? 0.3) * 100, 8, 45),
  ]) ?? 50);
  const dividendSafetyScore = Math.round(mean([
    fcfScore,
    inverseMetricScore((fundamental.quality.debt_ratio ?? 0.5) * 100, 30, 90),
    metricScore((fundamental.quality.operating_margin ?? 0) * 100, 4, 22),
  ]) ?? 50);
  const dividendYieldScore = Number.isFinite(dividendYield)
    ? metricScore(dividendYield * 100, 2, 8)
    : null;
  const debtRiskScore = inverseMetricScore((fundamental.quality.debt_ratio ?? null) * 100, 35, 90);
  const interestRateSensitivityScore = hasAnyTag(companyProfile?.tags || [], ["REIT", "Dividend", "InterestRateSensitive"])
    ? 48
    : 58;
  const inventoryCycleScore = Math.round(mean([
    grossMarginTrendScore,
    row.changePercent != null ? metricScore(row.changePercent, -4, 4) : null,
    fundamental.growth.revenue_growth != null ? revenueGrowthScore : null,
  ].filter(Number.isFinite)) ?? 50);
  const normalizedValuationScore = Math.round(mean([
    inverseMetricScore(fundamental.valuation.ev_ebitda ?? null, 6, 30),
    inverseMetricScore(fundamental.valuation.price_fcf ?? null, 8, 50),
    forwardPeScore,
  ].filter(Number.isFinite)) ?? 50);
  const regulatoryRiskScore = hasAnyTag(companyProfile?.tags || [], ["RegulatoryRisk", "ChinaADR"])
    ? 45
    : 60;
  const earningsGrowthQualityScore = Math.round(mean([
    revenueGrowthScore,
    fundamental.growth.eps_growth != null ? metricScore(fundamental.growth.eps_growth * 100, -10, 25) : null,
    fcfScore,
  ].filter(Number.isFinite)) ?? 50);
  const components = {
    revenue_growth: revenueGrowthScore,
    profit_margin: profitMarginScore,
    gross_margin_trend: grossMarginTrendScore,
    inventory_cycle: inventoryCycleScore,
    free_cash_flow: fcfScore,
    forward_pe: forwardPeScore,
    peg: pegScore,
    valuation_risk: valuationRiskScore,
    valuation_normalized: normalizedValuationScore,
    balance_sheet_quality: balanceSheetScore,
    earnings_growth_quality: earningsGrowthQualityScore,
    dividend_yield: dividendYieldScore,
    dividend_safety: dividendSafetyScore,
    debt_risk: debtRiskScore,
    ffo_affo_proxy: fcfScore,
    interest_rate_sensitivity: interestRateSensitivityScore,
    valuation_vs_yield: Math.round(mean([dividendYieldScore, valuationRiskScore].filter(Number.isFinite)) ?? 50),
    regulatory_risk: regulatoryRiskScore,
  };
  const profileWeights = {
    software_cloud: { revenue_growth: 0.20, profit_margin: 0.15, free_cash_flow: 0.20, forward_pe: 0.15, peg: 0.15, balance_sheet_quality: 0.10, earnings_growth_quality: 0.05 },
    platform_ads: { revenue_growth: 0.20, profit_margin: 0.15, free_cash_flow: 0.20, forward_pe: 0.15, peg: 0.15, balance_sheet_quality: 0.10, earnings_growth_quality: 0.05 },
    ai_infrastructure: { revenue_growth: 0.25, profit_margin: 0.15, free_cash_flow: 0.15, forward_pe: 0.10, peg: 0.10, valuation_risk: 0.20, balance_sheet_quality: 0.05 },
    high_growth_cyclical: { revenue_growth: 0.25, profit_margin: 0.15, free_cash_flow: 0.15, forward_pe: 0.10, peg: 0.10, valuation_risk: 0.20, balance_sheet_quality: 0.05 },
    memory_cycle: { revenue_growth: 0.15, gross_margin_trend: 0.25, inventory_cycle: 0.20, free_cash_flow: 0.15, valuation_normalized: 0.15, balance_sheet_quality: 0.10 },
    reit_dividend: { dividend_yield: 0.15, dividend_safety: 0.20, debt_risk: 0.25, ffo_affo_proxy: 0.20, interest_rate_sensitivity: 0.10, valuation_vs_yield: 0.10 },
    healthcare_defensive: { revenue_growth: 0.15, profit_margin: 0.20, free_cash_flow: 0.20, forward_pe: 0.15, balance_sheet_quality: 0.15, regulatory_risk: 0.15 },
    china_adr: { revenue_growth: 0.20, profit_margin: 0.15, free_cash_flow: 0.20, forward_pe: 0.15, peg: 0.10, valuation_risk: 0.10, balance_sheet_quality: 0.10 },
    generic: { revenue_growth: 0.20, profit_margin: 0.15, free_cash_flow: 0.20, forward_pe: 0.15, peg: 0.10, valuation_risk: 0.10, balance_sheet_quality: 0.10 },
  };
  const weighted = weightedAvailableScore(components, companyProfile?.decision_profile?.fundamental_weights || profileWeights[profile] || profileWeights.generic, fundamental.fundamental_score ?? 50);
  const highDividendDebtRisk = (dividendYield ?? 0) >= DIVIDEND_TAG_MIN_YIELD && (fundamental.quality.debt_ratio ?? 0) > 0.65;
  const adjustedScore = highDividendDebtRisk ? Math.min(weighted.score, 58) : weighted.score;
  return {
    profile,
    score: adjustedScore,
    raw_score: weighted.score,
    components,
    used_weights: weighted.used_weights,
    missing_fields: weighted.missing_fields,
    confidence: weighted.confidence,
    dividend_yield: dividendYield,
    dividend_safety_score: dividendSafetyScore,
    income_attractiveness: dividendYieldScore,
    high_dividend_debt_risk: highDividendDebtRisk,
    summary: highDividendDebtRisk
      ? (currentLanguage === "zh" ? "股息率有吸引力，但债务/现金流安全性限制评级上调。" : "Dividend income is attractive, but debt and safety checks cap the score.")
      : fundamental.summary,
  };
}

function strategyTone(action) {
  if (action === "Recommended") return "buy";
  if (action === "Avoid") return "sell";
  return "hold";
}

function dataUnavailableSource(missingSource, suggestedSource) {
  return {
    status: t("dataUnavailable"),
    missing_source: missingSource,
    suggested_source: suggestedSource,
  };
}

function buildShortSqueezeBlock(row) {
  const shortData = row.research?.shortInterest || row.shortInterest || row.profile?.shortInterest || {};
  const shortInterestPct = shortData.short_interest_percent_float ?? shortData.shortInterestPercentFloat ?? null;
  const shortInterestShares = shortData.short_interest_shares ?? shortData.shortInterestShares ?? null;
  const daysToCover = shortData.days_to_cover ?? shortData.daysToCover ?? null;
  const borrowFee = shortData.borrow_fee ?? shortData.borrowFee ?? null;
  const utilization = shortData.utilization ?? null;
  const floatShares = shortData.float ?? shortData.floatShares ?? null;
  const recentPriceMomentum = row.changePercent ?? null;
  const recentVolumeSpike = row.technicals?.volumeRatio ?? null;
  const hasCoreData = [shortInterestPct, shortInterestShares, daysToCover, borrowFee, utilization].some(Number.isFinite);

  if (!hasCoreData) {
    return {
      short_interest_pct_float: null,
      short_interest_shares: null,
      days_to_cover: null,
      borrow_fee: null,
      utilization: null,
      float: null,
      recent_price_momentum: recentPriceMomentum,
      recent_volume_spike: recentVolumeSpike,
      squeeze_risk: null,
      explanation: currentLanguage === "zh"
        ? "当前没有可用的卖空数据源，无法可靠判断逼空风险。"
        : "Short-interest feeds are unavailable, so squeeze risk cannot be judged reliably yet.",
      source_info: {
        short_interest: dataUnavailableSource("Nasdaq / FINRA / NYSE / Cboe", "Nasdaq Short Interest / FINRA / Fintel / Polygon"),
        borrow_fee: dataUnavailableSource("Prime broker / Fintel / Ortex", "Fintel / Ortex / Massive"),
      },
    };
  }

  let risk = "Low";
  if ((shortInterestPct ?? 0) > 30 || (((borrowFee ?? 0) > 20) && ((utilization ?? 0) > 85) && ((recentPriceMomentum ?? 0) > 3))) {
    risk = "Extreme";
  } else if ((shortInterestPct ?? 0) >= 15 || (((daysToCover ?? 0) > 5) && (((borrowFee ?? 0) > 8) || ((recentVolumeSpike ?? 0) >= 1.5)))) {
    risk = "High";
  } else if ((shortInterestPct ?? 0) >= 5 || (daysToCover ?? 0) >= 2 || (recentVolumeSpike ?? 0) >= 1.2) {
    risk = "Medium";
  }

  const explanationParts = [];
  if (Number.isFinite(shortInterestPct)) explanationParts.push(currentLanguage === "zh" ? `卖空占比 ${formatOneDecimal(shortInterestPct)}%` : `Short interest ${formatOneDecimal(shortInterestPct)}%`);
  if (Number.isFinite(daysToCover)) explanationParts.push(currentLanguage === "zh" ? `回补天数 ${formatOneDecimal(daysToCover)}` : `Days to cover ${formatOneDecimal(daysToCover)}`);
  if (Number.isFinite(borrowFee)) explanationParts.push(currentLanguage === "zh" ? `借券费率 ${formatOneDecimal(borrowFee)}%` : `Borrow fee ${formatOneDecimal(borrowFee)}%`);
  if (Number.isFinite(recentVolumeSpike)) explanationParts.push(currentLanguage === "zh" ? `量比 ${formatRatio(recentVolumeSpike)}` : `Relative volume ${formatRatio(recentVolumeSpike)}`);

  return {
    short_interest_pct_float: shortInterestPct,
    short_interest_shares: shortInterestShares,
    days_to_cover: daysToCover,
    borrow_fee: borrowFee,
    utilization,
    float: floatShares,
    recent_price_momentum: recentPriceMomentum,
    recent_volume_spike: recentVolumeSpike,
    squeeze_risk: risk,
    explanation: explanationParts.join(" · "),
    source_info: {
      short_interest: dataUnavailableSource("Nasdaq / FINRA / NYSE / Cboe", "Nasdaq Short Interest / FINRA / Fintel / Polygon"),
      borrow_fee: dataUnavailableSource("Prime broker / Fintel / Ortex", "Fintel / Ortex / Massive"),
    },
  };
}

function inferOptionStrikeStep(currentPrice, rawStrike) {
  const reference = Math.abs(Number.isFinite(rawStrike) ? rawStrike : currentPrice);
  if (reference < 25) return 0.5;
  if (reference < 200) return 1;
  if (reference < 500) return 2.5;
  if (reference < 1000) return 5;
  return 10;
}

function snapToOptionStrike(rawStrike, currentPrice) {
  if (!Number.isFinite(rawStrike)) return null;
  const step = inferOptionStrikeStep(currentPrice, rawStrike);
  const snapped = Math.round(rawStrike / step) * step;
  const decimals = step < 1 ? 1 : step === 2.5 ? 1 : 0;
  return Number(snapped.toFixed(decimals));
}

function choosePlanStrike(candidates, target, side, currentPrice) {
  const valid = candidates
    .filter((item) => Number.isFinite(item.price))
    .filter((item) => side === "put" ? item.price < currentPrice : item.price > currentPrice);
  if (!valid.length) return null;
  valid.sort((a, b) => Math.abs(a.price - target) - Math.abs(b.price - target));
  const chosen = valid[0];
  return {
    strike: snapToOptionStrike(chosen.price, currentPrice),
    sources: [...new Set(chosen.sources || [chosen.source].flat().filter(Boolean))],
  };
}

function closestPlanRangeKey(strike, ranges = []) {
  if (!Number.isFinite(strike)) return null;
  let best = null;
  ranges.forEach(({ key, range }) => {
    if (!rangeIsAvailable(range)) return;
    const midpoint = Number.isFinite(range.midpoint) ? range.midpoint : (range.low + range.high) / 2;
    const distance = strike >= range.low && strike <= range.high ? 0 : Math.abs(strike - midpoint);
    if (!best || distance < best.distance) best = { key, distance };
  });
  return best?.key || null;
}

function buildOptionsStrategies(row, optionsRead, idealBuyZone, supportResistance, decisionHints = {}) {
  const shortTermRating = decisionHints.shortTermRating || "Hold";
  const longTermRating = decisionHints.longTermRating || "Hold";
  const tags = decisionHints.companyProfile?.tags || [];
  const price = row.price ?? 0;
  const marketAdjustment = marketAdjustmentForPlans(decisionHints.marketContext || null);
  const optionsAvailable = Boolean(optionsRead?.available);
  const buyZones = decisionHints.buyZones || {};
  const buyPlan = decisionHints.buyPlan || null;
  const primaryZone = buyPlan?.mid_term_buy_range || buyPlan?.short_term_buy_range || buyZones.primary_buy_zone || idealBuyZone || {
    low: Number.isFinite(price) && Number.isFinite(row.technicals?.atr14) ? Math.max(0.01, price - row.technicals.atr14) : null,
    high: Number.isFinite(price) ? price : null,
    status: "fallback",
  };
  const deepZone = buyPlan?.long_term_buy_range || buyZones.deep_pullback_zone || {};
  const momentumZone = buyPlan?.short_term_buy_range || buyZones.momentum_entry_zone || {};
  const atr = Number.isFinite(row.technicals?.atr14) ? row.technicals.atr14 : Math.max(price * 0.035, 0.5);
  const ivRank = optionsRead.ivRank ?? null;
  const premiumWeak = Number.isFinite(ivRank) && ivRank < 30;
  const bearishShortTerm = ["Reduce", "Sell", "Sell-Avoid", "Strong Sell", "Short Candidate", "Short"].includes(shortTermRating);
  const bullishLongTerm = ["Buy", "Strong Buy"].includes(longTermRating);
  const volume = decisionHints.technical?.volume_confirmation || {};
  const volumeDistributionRisk = ["distribution_risk", "panic_selling"].includes(volume.behavior_key)
    || (["falling"].includes(volume.obv_trend_20d) && (volume.close_location_pct ?? 50) < 45);
  const strongVolumeBreakout = volume.behavior_key === "strong_accumulation" && (volume.relative_volume_20d ?? 0) >= 1.2;
  const speculativeProfile = hasAnyTag(tags, ["Speculative", "HighVolatility", "NewlyListed", "IPO", "Crypto", "StoryStock"]);
  const semAiProfile = hasAnyTag(tags, ["Semiconductor", "AIInfrastructure", "AI", "HighGrowth"]);
  const megaCashProfile = hasAnyTag(tags, ["MegaCap", "CashCow"]);
  const reitDividendProfile = hasAnyTag(tags, ["REIT", "Dividend", "InterestRateSensitive"]);

  if (isCnAShare(row)) {
    return {
      sell_put_plan: { status: "not_supported", plans: [] },
      covered_call_plan: { status: "not_supported", plans: [] },
      cash_secured_put: {
        recommendation: "Neutral",
        suggested_dte: t("dataUnavailable"),
        suggested_strike: null,
        assignment_risk: t("dataUnavailable"),
        suggested_zone: t("dataUnavailable"),
        premium_yield: null,
        reason: t("optionsUnavailable"),
      },
      covered_call: {
        recommendation: "Neutral",
        suggested_dte: t("dataUnavailable"),
        suggested_strike: null,
        assignment_risk: t("dataUnavailable"),
        suggested_zone: t("dataUnavailable"),
        premium_yield: null,
        reason: t("optionsUnavailable"),
      },
    };
  }
  const fallbackReason = optionsAvailable
    ? ""
    : (currentLanguage === "zh" ? " 期权链暂不可用，当前使用支撑压力、ATR 和买入区间做技术位 fallback，置信度降低。" : " Option chain is unavailable, so this uses support / resistance, ATR, and buy ranges as a lower-confidence technical fallback.");

  const supportCandidates = [
    { price: supportResistance.supports[1]?.price, sources: ["S2", ...(supportResistance.supports[1]?.sources || supportResistance.supports[1]?.source || [])] },
    { price: supportResistance.supports[2]?.price, sources: ["S3", ...(supportResistance.supports[2]?.sources || supportResistance.supports[2]?.source || [])] },
    { price: supportResistance.supports[3]?.price, sources: ["S4", ...(supportResistance.supports[3]?.sources || supportResistance.supports[3]?.source || [])] },
    { price: optionsRead.putWall, sources: ["Put Wall"] },
    { price: primaryZone.low, sources: [currentLanguage === "zh" ? "短期 / 中期买入区间" : "Short / Mid Buy Range"] },
    { price: primaryZone.high, sources: [currentLanguage === "zh" ? "短期 / 中期买入区间" : "Short / Mid Buy Range"] },
    { price: deepZone.status === "available" ? deepZone.high : null, sources: [currentLanguage === "zh" ? "长期买入区间" : "Long-Term Buy Range"] },
    { price: price - atr, sources: ["ATR"] },
    { price: price - atr * 1.35, sources: ["ATR"] },
  ];
  const resistanceCandidates = [
    { price: supportResistance.resistances[1]?.price, sources: ["R2", ...(supportResistance.resistances[1]?.sources || supportResistance.resistances[1]?.source || [])] },
    { price: supportResistance.resistances[2]?.price, sources: ["R3", ...(supportResistance.resistances[2]?.sources || supportResistance.resistances[2]?.source || [])] },
    { price: supportResistance.resistances[3]?.price, sources: ["R4", ...(supportResistance.resistances[3]?.sources || supportResistance.resistances[3]?.source || [])] },
    { price: optionsRead.callWall, sources: ["Call Wall"] },
    { price: momentumZone.status === "available" ? momentumZone.high : null, sources: [currentLanguage === "zh" ? "短期突破参考" : "Short-Term Breakout Reference"] },
    { price: price + atr, sources: ["ATR"] },
    { price: price + atr * 1.35, sources: ["ATR"] },
  ];
  const basePutConservativeMultiplier = speculativeProfile
    ? 1.85
    : semAiProfile
      ? 1.45
      : reitDividendProfile
        ? 1.25
        : megaCashProfile
          ? 0.9
          : 1.15;
  const marketPutShift = marketAdjustment.regime === "panic"
    ? 0.9
    : marketAdjustment.regime === "risk_off"
      ? 0.45
      : marketAdjustment.regime === "risk_on"
        ? -0.1
        : 0;
  const putConservativeMultiplier = Math.max(0.75, basePutConservativeMultiplier + marketPutShift);
  const volumeRiskShift = volumeDistributionRisk ? 0.45 : 0;
  const put30Target = Number.isFinite(primaryZone.low)
    ? Math.min(primaryZone.low, price - atr * (0.65 + volumeRiskShift), price - atr * putConservativeMultiplier * 0.75)
    : price - atr * (putConservativeMultiplier + volumeRiskShift);
  const put45Target = Number.isFinite(deepZone.high)
    ? Math.min(deepZone.high, price - atr * (premiumWeak ? 1.15 : 1.45) * putConservativeMultiplier)
    : price - atr * (premiumWeak ? 1.15 : 1.45) * putConservativeMultiplier;
  const put30 = choosePlanStrike(supportCandidates, put30Target, "put", price);
  const put45 = choosePlanStrike(supportCandidates, put45Target, "put", price);
  const callDistanceBoost = (bullishLongTerm || semAiProfile || strongVolumeBreakout) ? 0.35 : 0;
  const weakBounceTighten = volume.behavior_key === "weak_breakout" || ((volume.relative_volume_20d ?? 1) < 0.9 && (row.changePercent ?? 0) > 0) ? -0.15 : 0;
  const call30 = choosePlanStrike(resistanceCandidates, price + atr * Math.max(0.85, (bullishLongTerm ? 1.25 : 1) + callDistanceBoost + weakBounceTighten), "call", price);
  const call45 = choosePlanStrike(resistanceCandidates, price + atr * Math.max(1.15, (bullishLongTerm ? 1.6 : 1.4) + callDistanceBoost), "call", price);
  const putRisk = marketAdjustment.regime === "panic" || bearishShortTerm || volumeDistributionRisk || speculativeProfile ? "high" : premiumWeak || marketAdjustment.regime === "risk_off" ? "medium" : "low";
  const callRisk = bullishLongTerm || strongVolumeBreakout || speculativeProfile ? "medium" : "low";
  const avoidSellPut = marketAdjustment.regime === "panic" || volumeDistributionRisk || (speculativeProfile && bearishShortTerm);
  const marketContextNotes = [
    marketAdjustment.note,
    marketAdjustment.regime === "risk_off"
      ? (currentLanguage === "zh" ? "市场偏防守，Sell Put 行权价优先靠近长期买入区 / S4-S5。" : "Risk-off tape pushes sell-put strikes toward long-term buy range / S4-S5.")
      : null,
    marketAdjustment.regime === "panic"
      ? (currentLanguage === "zh" ? "恐慌环境下 Sell Put 只考虑极低行权价或直接回避。" : "In panic, sell puts should use very low strikes or be avoided.")
      : null,
    marketAdjustment.regime === "overheated"
      ? (currentLanguage === "zh" ? "情绪过热时不追高，Covered Call 吸引力提高。" : "Overheated sentiment improves covered-call appeal and discourages chasing.")
      : null,
  ].filter(Boolean);
  const sellPutPlans = [put30, put45].map((plan, index) => ({
    dte: index === 0 ? 30 : 45,
    suggested_strike: plan?.strike ?? null,
    risk_level: putRisk,
    assignment_risk: bearishShortTerm || volumeDistributionRisk ? "high" : index === 0 ? "medium" : "low",
    reason: plan?.strike
      ? (currentLanguage === "zh"
        ? `${index === 0 ? "30D" : "45D"} 行权价低于现价，贴近 ${plan.sources.slice(0, 3).join(" / ")}，定位为相对保守、较低被行权概率方案。${premiumWeak ? " 当前 IV Rank 偏低，权利金环境较弱。" : ""}${bearishShortTerm ? " 短期趋势偏弱，Sell Put 需更保守。" : ""}${volumeDistributionRisk ? " 量能出现出货/弱承接，行权价已下移且风险提高。" : ""}${speculativeProfile ? " 投机/高波动画像要求更远 OTM。" : ""}${marketAdjustment.regime === "risk_off" ? " 市场偏防守，strike 下移。" : ""}${fallbackReason}`
        : `${index === 0 ? "30D" : "45D"} strike is below spot and near ${plan.sources.slice(0, 3).join(" / ")}, designed as a relatively conservative lower-assignment-probability setup.${premiumWeak ? " IV rank is low, so premium quality is weaker." : ""}${bearishShortTerm ? " Short-term trend risk argues for a more conservative put strike." : ""}${volumeDistributionRisk ? " Distribution / weak sponsorship shifts the strike lower and raises risk." : ""}${speculativeProfile ? " Speculative / high-volatility profile requires farther OTM strikes." : ""}${marketAdjustment.regime === "risk_off" ? " Risk-off tape shifts the strike lower." : ""}${fallbackReason}`)
      : t("dataUnavailable"),
    sources: plan?.sources || [],
  }));
  const coveredCallPlans = [call30, call45].map((plan, index) => ({
    dte: index === 0 ? 30 : 45,
    suggested_strike: plan?.strike ?? null,
    risk_level: callRisk,
    assignment_risk: bullishLongTerm ? "medium" : "low",
    reason: plan?.strike
      ? (currentLanguage === "zh"
        ? `${index === 0 ? "30D" : "45D"} 行权价高于现价，贴近 ${plan.sources.slice(0, 3).join(" / ")}，用于较低被行权概率的 Covered Call。${bullishLongTerm || semAiProfile ? " 长期偏多/高成长画像，因此 strike 保持更远，避免过早限制上涨空间。" : ""}${strongVolumeBreakout ? " 量能强突破，Covered Call 更保守或上移。" : ""}${premiumWeak ? " 当前 IV Rank 偏低，权利金吸引力一般。" : ""}${marketAdjustment.regime === "overheated" ? " 情绪偏热，Covered Call 吸引力提高。" : ""}${fallbackReason}`
        : `${index === 0 ? "30D" : "45D"} strike is above spot and near ${plan.sources.slice(0, 3).join(" / ")}, intended as a lower-assignment-probability covered call.${bullishLongTerm || semAiProfile ? " Long-term / high-growth setup keeps the strike farther out." : ""}${strongVolumeBreakout ? " Strong volume breakout shifts covered calls farther out or conservative." : ""}${premiumWeak ? " Low IV rank makes premium less attractive." : ""}${marketAdjustment.regime === "overheated" ? " Overheated sentiment improves covered-call appeal." : ""}${fallbackReason}`)
      : t("dataUnavailable"),
    sources: plan?.sources || [],
  }));
  const cspStrike = sellPutPlans[0]?.suggested_strike ?? null;
  const ccStrike = coveredCallPlans[0]?.suggested_strike ?? null;
  const cspRecommended = Boolean(cspStrike) && !bearishShortTerm && !avoidSellPut && ratingAtLeast(longTermRating, "Hold-Watch");
  const ccRecommended = Boolean(ccStrike) && shortTermRating !== "Strong Buy" && !strongVolumeBreakout;

  return {
    sell_put_plan: {
      status: optionsAvailable ? "available" : "fallback",
      plans: sellPutPlans,
      market_context_notes: marketContextNotes,
    },
    covered_call_plan: {
      status: optionsAvailable ? "available" : "fallback",
      plans: coveredCallPlans,
      market_context_notes: marketContextNotes,
    },
    cash_secured_put: {
      recommendation: cspRecommended ? "Recommended" : (avoidSellPut || speculativeProfile || bearishShortTerm) ? "Avoid" : ratingAtLeast(longTermRating, "Buy") ? "Neutral" : "Avoid",
      suggested_dte: "30D / 45D",
      suggested_strike: Number.isFinite(cspStrike) ? cspStrike : null,
      strike_distance_pct: Number.isFinite(cspStrike) && row.price ? Number((((row.price - cspStrike) / row.price) * 100).toFixed(1)) : null,
      ideal_buy_zone_relation: Number.isFinite(cspStrike) && cspStrike >= primaryZone.low && cspStrike <= primaryZone.high
        ? (currentLanguage === "zh" ? "位于主要买入区内" : "Inside the Primary Buy Zone")
        : (currentLanguage === "zh" ? "低于主要买入区，偏保守" : "Below the Primary Buy Zone, more conservative"),
      support_relation: supportResistance.supports[1]?.price
        ? `${supportResistance.supports[1].level} ${formatCurrency(supportResistance.supports[1].price, row.currencyCode)}`
        : t("dataUnavailable"),
      premium_yield: null,
      assignment_risk: cspRecommended ? (currentLanguage === "zh" ? "中等" : "Medium") : (currentLanguage === "zh" ? "偏高" : "Elevated"),
      reason: cspRecommended
        ? (currentLanguage === "zh" ? "行权价低于现价并靠近支撑 / Put Wall / ATR，属于相对保守的 Sell Put 方案。" : "The strike is below spot and anchored to support / put wall / ATR for a relatively conservative sell-put setup.")
        : avoidSellPut
          ? (currentLanguage === "zh" ? "量能出货/弱承接或短期趋势偏弱，Sell Put 暂时回避。" : "Distribution / weak sponsorship or bearish short-term trend makes sell puts unattractive for now.")
          : ratingAtLeast(longTermRating, "Buy")
          ? (currentLanguage === "zh" ? "长期逻辑仍成立，但当前行权价和理想埋伏区还不够贴近，先保持中性。" : "The long-term thesis still works, but the strike is not close enough to the ideal buy zone yet.")
          : (currentLanguage === "zh" ? "中长期条件还不够扎实，Sell Put 先回避。" : "The mid / long-term setup is not stable enough for a cash-secured put yet."),
    },
    covered_call: {
      recommendation: longTermRating === "Strong Buy" || strongVolumeBreakout ? "Avoid" : ccRecommended ? "Recommended" : "Neutral",
      suggested_dte: "30D / 45D",
      suggested_strike: Number.isFinite(ccStrike) ? ccStrike : null,
      strike_distance_pct: Number.isFinite(ccStrike) && row.price ? Number((((ccStrike - row.price) / row.price) * 100).toFixed(1)) : null,
      resistance_relation: supportResistance.resistances[1]?.price
        ? `${supportResistance.resistances[1].level} ${formatCurrency(supportResistance.resistances[1].price, row.currencyCode)}`
        : t("dataUnavailable"),
      call_wall_relation: Number.isFinite(optionsRead.callWall) ? formatCurrency(optionsRead.callWall, row.currencyCode) : t("dataUnavailable"),
      premium_yield: null,
      assignment_risk: ccRecommended ? (currentLanguage === "zh" ? "较低" : "Low") : (currentLanguage === "zh" ? "中等" : "Medium"),
      reason: longTermRating === "Strong Buy" || strongVolumeBreakout
        ? (currentLanguage === "zh" ? "长期趋势或量能突破较强，过早卖 Covered Call 可能限制上涨空间。" : "Long-term upside or volume breakout looks strong, so a covered call can cap gains too early.")
        : ccRecommended
          ? (currentLanguage === "zh" ? "行权价高于现价并参考压力位 / Call Wall / ATR，更适合持仓收租。" : "The strike is above spot and references resistance / call wall / ATR, which fits income harvesting.")
          : (currentLanguage === "zh" ? "当前压力位还不够清晰，或者趋势仍偏强，Covered Call 先保持中性。" : "Resistance is not clean enough yet or upside still looks too strong, so covered calls stay neutral."),
    },
  };
}

function buildOptionsModule(row, supportResistance, idealBuyZone, decisionHints = {}) {
  if (isCnAShare(row)) {
    const shortSqueeze = buildShortSqueezeBlock(row);
    return {
      status: "not_supported",
      options_score: 50,
      put_wall: null,
      call_wall: null,
      gamma_flip: null,
      net_gex: null,
      implied_volatility: null,
      historic_volatility: null,
      iv_percentile: null,
      iv_rank: null,
      max_pain: null,
      options_flow: null,
      sell_put_plan: { status: "not_supported", plans: [] },
      covered_call_plan: { status: "not_supported", plans: [] },
      cash_secured_put: { recommendation: "Neutral", suggested_dte: null, suggested_strike: null, assignment_risk: null, suggested_zone: null, premium_yield: null, reason: currentLanguage === "zh" ? "该市场暂不支持期权结构分析。" : "Options structure analysis is not supported for this market." },
      covered_call: { recommendation: "Neutral", suggested_dte: null, suggested_strike: null, assignment_risk: null, suggested_zone: null, premium_yield: null, reason: currentLanguage === "zh" ? "该市场暂不支持期权策略分析。" : "Options strategy analysis is not supported for this market." },
      short_squeeze: shortSqueeze,
      summary: currentLanguage === "zh" ? "该市场暂不支持期权结构分析。" : "Options structure analysis is not supported for this market.",
    };
  }
  const optionsRead = row.research?.optionsRead || buildOptionsRead(row);
  const strategies = buildOptionsStrategies(row, optionsRead, idealBuyZone, supportResistance, decisionHints);
  const score = !optionsRead.available ? 50 : clamp(50 + optionsRead.scoreAdjustment * 4, 20, 85);
  return {
    status: optionsRead.available ? "available" : "unavailable",
    options_score: score,
    put_wall: optionsRead.available ? optionsRead.putWall : null,
    call_wall: optionsRead.available ? optionsRead.callWall : null,
    gamma_flip: optionsRead.available ? optionsRead.gammaFlip : null,
    net_gex: optionsRead.available ? optionsRead.netGex : null,
    implied_volatility: optionsRead.impliedVolatility,
    historic_volatility: optionsRead.historicVolatility,
    iv_percentile: optionsRead.ivPercentile,
    iv_rank: optionsRead.ivRank,
    max_pain: null,
    options_flow: null,
    sell_put_plan: strategies.sell_put_plan,
    covered_call_plan: strategies.covered_call_plan,
    cash_secured_put: strategies.cash_secured_put,
    covered_call: strategies.covered_call,
    short_squeeze: buildShortSqueezeBlock(row),
    summary: optionsRead.summary,
  };
}

function optionPlanRecommendationLabel(value) {
  if (currentLanguage !== "zh") return value || "Unavailable";
  if (value === "Recommended") return "推荐";
  if (value === "Conservative") return "保守考虑";
  if (value === "Neutral") return "中性";
  if (value === "Avoid") return "回避";
  return value || "暂不可用";
}

function optionRiskLevelLabel(value) {
  if (currentLanguage !== "zh") return value || "unavailable";
  if (value === "low") return "低";
  if (value === "medium") return "中";
  if (value === "high") return "高";
  if (value === "extreme") return "极高";
  return value || "暂不可用";
}

function rangeMidpoint(range) {
  if (!rangeIsAvailable(range)) return null;
  return Number(((range.low + range.high) / 2).toFixed(2));
}

function uniqueText(items = [], limit = 8) {
  return [...new Set(items.filter(Boolean))].slice(0, limit);
}

function optionStrikeRangeAround(preferred, atr, side, currentPrice) {
  if (!Number.isFinite(preferred)) return { low: null, high: null };
  const width = Math.max((Number.isFinite(atr) ? atr : currentPrice * 0.03) * 0.3, currentPrice * 0.005);
  const low = side === "put" ? Math.min(preferred, preferred - width) : Math.max(currentPrice * 1.001, preferred - width);
  const high = side === "put" ? Math.min(currentPrice * 0.999, preferred + width) : preferred + width;
  return {
    low: Number(Math.max(0.01, snapToOptionStrike(low, currentPrice)).toFixed(2)),
    high: Number(Math.max(0.01, snapToOptionStrike(high, currentPrice)).toFixed(2)),
  };
}

function buildUnifiedOptionsStrategyPlan({
  row,
  optionsModule,
  supportResistance,
  buyPlan,
  sellPlan,
  stopLossPlan,
  actionPlan,
  technical,
  fundamental,
  marketContext,
  companyProfile,
  tradeContext,
}) {
  if (isCnAShare(row)) {
    return {
      options_data_status: "not_supported",
      sell_put_plan: {
        status: "not_supported",
        recommendation: "Avoid",
        expiration_days: [],
        strike_range: { low: null, high: null },
        preferred_strike: null,
        risk_level: "high",
        confidence: 0,
        based_on: [],
        avoid_conditions: [currentLanguage === "zh" ? "A股暂不支持美股期权策略。" : "US options strategies are not supported for A-shares."],
        plans: [],
      },
      covered_call_plan: {
        status: "not_supported",
        recommendation: "Avoid",
        expiration_days: [],
        strike_range: { low: null, high: null },
        preferred_strike: null,
        risk_level: "high",
        confidence: 0,
        based_on: [],
        avoid_conditions: [currentLanguage === "zh" ? "A股暂不支持美股期权策略。" : "US options strategies are not supported for A-shares."],
        plans: [],
      },
      gamma_flip: null,
      confidence: 0,
      explanation: currentLanguage === "zh" ? "该市场暂不支持期权策略计划。" : "Options strategy plans are not supported for this market.",
    };
  }

  const price = row.price ?? null;
  const atr = Number.isFinite(row.technicals?.atr14) ? row.technicals.atr14 : (Number.isFinite(price) ? price * 0.035 : null);
  const marketRegime = marketRegimeFromContext(marketContext);
  const volume = technical?.volume_confirmation || {};
  const profileFundamental = fundamental?.profile_fundamental || {};
  const tags = companyProfile?.tags || [];
  const optionsAvailable = optionsModule?.status === "available";
  const optionsDataStatus = optionsAvailable ? "available" : "fallback";
	  const optionsState = tradeContext?.options_state || buildOptionsState(row, optionsModule?.expected_move || optionsModule?.options_expected_move || {}, optionsModule);
	  const gapDownRisk = tradeContext?.gap_down_risk || {};
	  const gapDownPutRisk = gapDownRisk.active
	    && ["event_driven_gap_down", "company_specific_breakdown", "falling_knife"].includes(gapDownRisk.classification)
	    && gapDownRisk.follow_through_confirmation?.confirmed !== true;
	  const gammaFlip = Number.isFinite(optionsModule?.net_gex) && Number.isFinite(optionsModule?.gamma_flip) ? optionsModule.gamma_flip : null;
  const validPutWall = optionsAvailable && Number.isFinite(optionsModule?.put_wall) ? optionsModule.put_wall : null;
  const validCallWall = optionsAvailable && Number.isFinite(optionsModule?.call_wall) ? optionsModule.call_wall : null;
  const ivRank = optionsModule?.iv_rank ?? null;
  const highIv = Number.isFinite(ivRank) && ivRank >= 55;
  const lowIv = Number.isFinite(ivRank) && ivRank < 30;
  const optionFallbackNote = optionsAvailable
    ? null
    : (currentLanguage === "zh" ? "期权链暂不可用，策略使用技术位 fallback，置信度降低。" : "Option chain unavailable; strategy uses technical-level fallback with lower confidence.");

  const overallAction = actionPlan?.overall_action?.final_action || "hold_watch";
  const entryShortAction = actionPlan?.entry_action?.short_term?.final_action || actionPlan?.short_term?.final_action || "hold_watch";
  const entryMidAction = actionPlan?.entry_action?.mid_term?.final_action || actionPlan?.mid_term?.final_action || "hold_watch";
  const entryLongAction = actionPlan?.entry_action?.long_term?.final_action || actionPlan?.long_term?.final_action || "hold_watch";
  const positionShortAction = actionPlan?.position_management_action?.short_term?.final_action || actionPlan?.short_term?.final_action || "hold_watch";
  const positionMidAction = actionPlan?.position_management_action?.mid_term?.final_action || actionPlan?.mid_term?.final_action || "hold_watch";
  const positionLongAction = actionPlan?.position_management_action?.long_term?.final_action || actionPlan?.long_term?.final_action || "hold_watch";
  const entryActions = [entryShortAction, entryMidAction, entryLongAction];
  const positionActions = [positionShortAction, positionMidAction, positionLongAction];
  const entryIsConstructive = entryActions.some((action) => ["strong_buy", "accumulate"].includes(action));
  const positionIsExit = positionActions.some((action) => ["trim_reduce", "take_profit"].includes(action));
  const strongestPositionExit = positionActions.includes("take_profit") ? "take_profit" : positionActions.includes("trim_reduce") ? "trim_reduce" : "hold_watch";
  const volumeRisk = ["distribution_risk", "panic_selling", "weak_breakout"].includes(volume.behavior_key)
    || (volume.obv_trend_20d === "falling" && (volume.close_location_pct ?? 50) < 45);
  const strongBreakout = ["strong_accumulation", "breakout_confirmation"].includes(volume.behavior_key)
    || ((volume.relative_volume_20d ?? 1) >= 1.25 && (volume.close_location_pct ?? 0) >= 68 && volume.obv_trend_20d !== "falling");
  const companyRisk = profileFundamental.score < 40
    || profileFundamental.high_dividend_debt_risk
    || (profileFundamental.components?.free_cash_flow ?? 50) < 30
    || (profileFundamental.components?.debt_risk ?? 55) < 30;
  const highGrowthAi = hasAnyTag(tags, ["AIInfrastructure", "HighGrowth", "GPU", "DataCenter"]);
  const reitDividend = hasAnyTag(tags, ["REIT", "Dividend", "InterestRateSensitive"]);
  const speculative = hasAnyTag(tags, ["Speculative", "Meme", "NewlyListed", "IPO", "HighVolatility", "Crypto", "Stablecoin"]);
  const chinaAdr = hasAnyTag(tags, ["ChinaADR", "RegulatoryRisk"]);
  const dividendUnsafe = reitDividend && (profileFundamental.high_dividend_debt_risk || (profileFundamental.components?.dividend_safety ?? 60) < 45);
  const marketRiskRising = ["risk_off", "panic"].includes(marketRegime) && ((marketContext?.enhanced_context?.vix?.change_5d_pct ?? 0) > 8);
  const marketRecovering = (marketContext?.enhanced_context?.vix?.change_5d_pct ?? 0) < -12
    || ["risk_on", "neutral"].includes(marketRegime);
  const qqqOverextended = Boolean(marketContext?.enhanced_context?.qqq_trend?.overextended);

  const supportLevels = supportResistance?.supports || [];
  const resistanceLevels = supportResistance?.resistances || [];
  const midRange = buyPlan?.mid_term_buy_range || {};
  const longRange = buyPlan?.long_term_buy_range || {};
  const midPutRange = midRange.base_pullback_range || midRange;
  const longPutRange = longRange.base_pullback_range || longRange;
  const shortSell = sellPlan?.short_term_sell_range || {};
  const midSell = sellPlan?.mid_term_sell_range || {};
  const longSell = sellPlan?.long_term_sell_range || {};

  const putTargetByMarket = (() => {
    if (!Number.isFinite(price) || !Number.isFinite(atr)) return null;
    if (marketRegime === "panic") return Math.min(longPutRange.low ?? price - atr * 2.2, supportLevels[4]?.price ?? price - atr * 2.3, price - atr * 2.3);
    if (marketRegime === "risk_off") return Math.min(longPutRange.high ?? price - atr * 1.7, supportLevels[3]?.price ?? price - atr * 1.8, price - atr * 1.7);
    if (marketRegime === "risk_on") return Math.min(midPutRange.low ?? price - atr, supportLevels[1]?.price ?? price - atr, price - atr);
    return Math.min(midPutRange.low ?? price - atr * 1.25, supportLevels[2]?.price ?? price - atr * 1.25, price - atr * 1.25);
  })();
  const putCandidates = [
    { price: putTargetByMarket, sources: [currentLanguage === "zh" ? "市场环境调整目标" : "Market-adjusted target"] },
    { price: midPutRange.low, sources: [currentLanguage === "zh" ? "中期基础回调区间下沿" : "Mid-term base pullback low"] },
    { price: longPutRange.high, sources: [currentLanguage === "zh" ? "长期基础核心区间上沿" : "Long-term base core range high"] },
    { price: supportLevels[1]?.price, sources: ["S2", ...(supportLevels[1]?.sources || [])] },
    { price: supportLevels[2]?.price, sources: ["S3", ...(supportLevels[2]?.sources || [])] },
    { price: supportLevels[3]?.price, sources: ["S4", ...(supportLevels[3]?.sources || [])] },
    { price: supportLevels[4]?.price, sources: ["S5", ...(supportLevels[4]?.sources || [])] },
    { price: validPutWall, sources: ["Put Wall"] },
    { price: Number.isFinite(price) && Number.isFinite(atr) ? price - atr * 1.0 : null, sources: ["ATR 1.0"] },
    { price: Number.isFinite(price) && Number.isFinite(atr) ? price - atr * 1.5 : null, sources: ["ATR 1.5"] },
  ];
  const putChoice = choosePlanStrike(putCandidates, putTargetByMarket, "put", price);
  const putPreferred = putChoice?.strike ?? null;
  const putStrikeRange = optionStrikeRangeAround(putPreferred, atr, "put", price);
  const putAvoidConditions = [
    marketRegime === "panic" ? (currentLanguage === "zh" ? "市场仍处恐慌状态，Sell Put 只考虑极低价或回避。" : "Market panic: use only very low strikes or avoid sell puts.") : null,
    marketRiskRising ? (currentLanguage === "zh" ? "VIX 快速上升或市场风险继续释放。" : "VIX / market risk is rising quickly.") : null,
	    volumeRisk ? (currentLanguage === "zh" ? "OBV 或量价结构偏弱，存在接飞刀风险。" : "OBV / price-volume structure is weak.") : null,
	    gapDownPutRisk ? (currentLanguage === "zh" ? "单日急跌尚未确认止稳，不能因为 IV / 权利金高而激进 Sell Put。" : "Sharp gap-down has not stabilized; do not sell puts aggressively just because IV / premium is high.") : null,
	    companyRisk ? (currentLanguage === "zh" ? "个股基本面或资产负债表风险偏高。" : "Company-specific fundamental or balance-sheet risk is elevated.") : null,
    dividendUnsafe ? (currentLanguage === "zh" ? "高股息伴随分红安全或债务风险，不能因股息率直接卖 Put。" : "High yield comes with dividend safety or debt risk.") : null,
	    (!entryIsConstructive || ["trim_reduce", "take_profit", "avoid"].includes(overallAction)) ? (currentLanguage === "zh" ? "买入 / 加仓视角未支持积极建仓，Sell Put 不宜激进。" : "Entry view does not support aggressive accumulation; sell puts should not be aggressive.") : null,
	  ].filter(Boolean);
	  let sellPutRecommendation = "Neutral";
		  if (gapDownPutRisk || putAvoidConditions.length >= 2 || overallAction === "avoid" || marketRegime === "panic") sellPutRecommendation = "Avoid";
	  else if (entryIsConstructive && !companyRisk && !volumeRisk) sellPutRecommendation = highIv || marketRecovering ? "Recommended" : "Conservative";
	  else if (positionIsExit) sellPutRecommendation = "Avoid";
  else if (lowIv) sellPutRecommendation = "Neutral";
  const putRisk = sellPutRecommendation === "Avoid" || marketRegime === "panic" || speculative || companyRisk
    ? "high"
    : ["risk_off"].includes(marketRegime) || volumeRisk || chinaAdr
      ? "medium"
      : "low";
  const putConfidence = clamp(Math.round(
    (optionsAvailable ? 72 : 54)
    + (putChoice ? 8 : -8)
    + (highIv ? 5 : lowIv ? -7 : 0)
	    + (entryIsConstructive ? 5 : 0)
    - (putAvoidConditions.length * 6)
    - (speculative ? 5 : 0)
    - (chinaAdr ? 4 : 0)
  ), 20, 92);
  const sellPutPlan = {
    status: optionsDataStatus,
    suitability: sellPutRecommendation,
    recommendation: sellPutRecommendation,
    recommendation_label: optionPlanRecommendationLabel(sellPutRecommendation),
    expiration_days: [30, 45],
    strike_range: putStrikeRange,
    preferred_strike: putPreferred,
    linked_buy_range: marketRegime === "risk_on" ? "mid_term_buy_range" : "long_term_buy_range",
    expected_move_context: optionsState.expected_move || {},
    iv_context: optionsState.iv_regime || {},
    skew_context: {
      skew: optionsState.skew ?? null,
      put_skew_high: Number(optionsState.skew) > 8,
      note: Number(optionsState.skew) > 8
        ? (currentLanguage === "zh" ? "Put skew 偏高，行权价更保守。" : "Put skew is elevated; use more conservative strikes.")
        : (currentLanguage === "zh" ? "Skew 未显示明显额外下行保护需求。" : "Skew does not show major extra downside-hedging demand."),
    },
    term_structure_context: {
      term_structure: optionsState.term_structure || "unavailable",
      backwardation: optionsState.term_structure === "backwardation",
      note: optionsState.term_structure === "backwardation"
        ? (currentLanguage === "zh" ? "近月事件风险集中，Sell Put 降低仓位或回避。" : "Near-term event risk is concentrated; reduce size or avoid sell puts.")
        : null,
    },
    assignment_action: currentLanguage === "zh"
      ? "若被行权，只应作为低价建仓，且必须符合中长期买入区间和基本面条件。"
      : "If assigned, treat it only as a lower-price entry consistent with mid/long buy ranges and fundamentals.",
    risk_level: putRisk,
    risk_level_label: optionRiskLevelLabel(putRisk),
    confidence: putConfidence,
    based_on: uniqueText([
      ...(putChoice?.sources || []),
      marketRegime,
      highIv ? "IV Rank high" : lowIv ? "IV Rank low" : null,
      profileFundamental.score != null ? `Fundamental ${Math.round(profileFundamental.score)}/100` : null,
	      `entry:${entryActions.join("/")}`,
      optionFallbackNote,
    ]),
    avoid_conditions: putAvoidConditions,
    market_context_notes: uniqueText([
      marketRegime === "risk_on" ? (currentLanguage === "zh" ? "risk_on：strike 可接近中期买入区或 S2。" : "risk_on: strike can sit near mid buy range or S2.") : null,
      marketRegime === "neutral" ? (currentLanguage === "zh" ? "neutral：strike 优先参考 S3 或中期区间下沿。" : "neutral: strike prioritizes S3 or mid range low.") : null,
      marketRegime === "risk_off" ? (currentLanguage === "zh" ? "risk_off：strike 下移到长期区间上沿或 S4。" : "risk_off: strike shifts to long range high or S4.") : null,
      marketRegime === "panic" ? (currentLanguage === "zh" ? "panic：极低 strike 或回避。" : "panic: very low strike or avoid.") : null,
      optionFallbackNote,
    ]),
    plans: [30, 45].map((dte, index) => {
      const dteTarget = index === 0
        ? putPreferred
        : Math.min(putPreferred ?? price, longPutRange.high ?? supportLevels[3]?.price ?? (Number.isFinite(price) && Number.isFinite(atr) ? price - atr * 1.5 : putPreferred));
      const strike = Number.isFinite(dteTarget) ? snapToOptionStrike(dteTarget, price) : null;
      return {
        dte,
        suggested_strike: strike,
        risk_level: putRisk,
        assignment_risk: putRisk,
        reason: strike == null
          ? t("dataUnavailable")
          : (currentLanguage === "zh"
            ? `${dte}D Sell Put 参考 ${uniqueText(putChoice?.sources || [], 3).join(" / ") || "买入区间 / 支撑位"}，定位为辅助低价建仓策略。${optionFallbackNote || ""}`
            : `${dte}D sell put references ${uniqueText(putChoice?.sources || [], 3).join(" / ") || "buy ranges / support"} as an auxiliary lower-entry strategy. ${optionFallbackNote || ""}`),
        sources: uniqueText(putChoice?.sources || []),
      };
    }),
  };

	  const callTargetByAction = (() => {
	    if (!Number.isFinite(price) || !Number.isFinite(atr)) return null;
	    if (positionIsExit) {
	      const linkedRange = strongestPositionExit === "take_profit" ? longSell : positionMidAction === "trim_reduce" ? midSell : shortSell;
	      return Math.min(linkedRange.low ?? price + atr * 1.1, resistanceLevels[1]?.price ?? price + atr * 1.2);
	    }
	    if (highGrowthAi && (strongBreakout || entryLongAction === "strong_buy")) return Math.max(longSell.high ?? price + atr * 2.3, price + atr * 2.0);
	    return Math.min(shortSell.low ?? price + atr * 1.2, midSell.low ?? price + atr * 1.5, price + atr * 1.35);
	  })();
  const callCandidates = [
    { price: callTargetByAction, sources: [currentLanguage === "zh" ? "操作方向调整目标" : "Action-adjusted target"] },
    { price: shortSell.low, sources: [currentLanguage === "zh" ? "短期止盈区间下沿" : "Short-term sell range low"] },
    { price: midSell.low, sources: [currentLanguage === "zh" ? "中期减仓区间下沿" : "Mid-term trim range low"] },
    { price: longSell.low, sources: [currentLanguage === "zh" ? "长期估值止盈区间下沿" : "Long-term exit range low"] },
    { price: resistanceLevels[1]?.price, sources: ["R2", ...(resistanceLevels[1]?.sources || [])] },
    { price: resistanceLevels[2]?.price, sources: ["R3", ...(resistanceLevels[2]?.sources || [])] },
    { price: resistanceLevels[3]?.price, sources: ["R4", ...(resistanceLevels[3]?.sources || [])] },
    { price: resistanceLevels[4]?.price, sources: ["R5", ...(resistanceLevels[4]?.sources || [])] },
    { price: validCallWall, sources: ["Call Wall"] },
    { price: Number.isFinite(price) && Number.isFinite(atr) ? price + atr * 1.0 : null, sources: ["ATR 1.0"] },
    { price: Number.isFinite(price) && Number.isFinite(atr) ? price + atr * 1.5 : null, sources: ["ATR 1.5"] },
  ];
	  const callChoice = choosePlanStrike(callCandidates, callTargetByAction, "call", price);
	  const callPreferred = callChoice?.strike ?? null;
	  const callStrikeRange = optionStrikeRangeAround(callPreferred, atr, "call", price);
	  const preferredCoveredCallLinkedSellRange = positionLongAction === "take_profit" || positionLongAction === "trim_reduce"
	    ? "long_term_sell_range"
	    : positionMidAction === "take_profit" || positionMidAction === "trim_reduce"
	      ? "mid_term_sell_range"
	      : positionShortAction === "take_profit" || positionShortAction === "trim_reduce"
	        ? "short_term_sell_range"
	        : null;
  const callAvoidConditions = [
	    entryActions.includes("strong_buy") ? (currentLanguage === "zh" ? "买入 / 加仓视角为强烈买入，不应卖近价 Covered Call 压制上行。" : "Entry view is strong buy; avoid near-the-money covered calls.") : null,
    highGrowthAi && strongBreakout ? (currentLanguage === "zh" ? "AI / 高成长放量突破，Covered Call 需上移或回避。" : "AI / high-growth volume breakout: move covered call farther out or avoid.") : null,
    ["inside_buy_range", "below_buy_range"].includes(actionPlan?.short_term?.price_position?.status) ? (currentLanguage === "zh" ? "价格仍在买入区附近，不适合过早卖出上涨空间。" : "Price is near the buy range; avoid capping upside too early.") : null,
    reitDividend ? (currentLanguage === "zh" ? "分红股需注意除息日前被行权风险。" : "Dividend stocks require ex-dividend assignment-risk awareness.") : null,
  ].filter(Boolean);
  let coveredCallRecommendation = "Neutral";
	  if (entryActions.includes("strong_buy") || (highGrowthAi && strongBreakout)) coveredCallRecommendation = "Avoid";
	  else if (positionIsExit || marketRegime === "overheated" || qqqOverextended) coveredCallRecommendation = "Recommended";
	  else if (entryLongAction === "strong_buy" || (rangeIsAvailable(longSell) && Number.isFinite(price) && price < longSell.low * 0.92)) coveredCallRecommendation = "Conservative";
  const callRisk = coveredCallRecommendation === "Avoid"
    ? "high"
    : highGrowthAi || strongBreakout || reitDividend
      ? "medium"
      : "low";
  const callConfidence = clamp(Math.round(
    (optionsAvailable ? 72 : 54)
    + (callChoice ? 8 : -8)
	    + (positionIsExit ? 8 : 0)
    + (marketRegime === "overheated" ? 5 : 0)
    - (callAvoidConditions.length * 5)
	    - (entryLongAction === "strong_buy" ? 6 : 0)
  ), 20, 92);
  const coveredCallPlan = {
    status: optionsDataStatus,
    suitability: coveredCallRecommendation,
    recommendation: coveredCallRecommendation,
    recommendation_label: optionPlanRecommendationLabel(coveredCallRecommendation),
    expiration_days: [30, 45],
    strike_range: callStrikeRange,
    preferred_strike: callPreferred,
	    linked_sell_range: preferredCoveredCallLinkedSellRange || closestPlanRangeKey(callPreferred, [
	      { key: "short_term_sell_range", range: shortSell },
	      { key: "mid_term_sell_range", range: midSell },
	      { key: "long_term_sell_range", range: longSell },
	    ]) || (positionLongAction === "take_profit" ? "long_term_sell_range" : positionMidAction === "trim_reduce" ? "mid_term_sell_range" : positionShortAction === "trim_reduce" ? "short_term_sell_range" : "long_term_sell_range"),
    expected_move_context: optionsState.expected_move || {},
    iv_context: optionsState.iv_regime || {},
    skew_context: {
      skew: optionsState.skew ?? null,
      call_skew_high: Number(optionsState.skew) < -8,
      note: Number(optionsState.skew) < -8
        ? (currentLanguage === "zh" ? "Call skew 偏高，上行投机需求强，Covered Call 需更远。" : "Call skew is elevated; upside demand argues for farther covered-call strikes.")
        : null,
    },
    term_structure_context: {
      term_structure: optionsState.term_structure || "unavailable",
      backwardation: optionsState.term_structure === "backwardation",
    },
    upside_sacrifice: coveredCallRecommendation === "Recommended"
      ? (currentLanguage === "zh" ? "用部分上行空间换取权利金或利润保护。" : "Trades some upside for premium / profit protection.")
      : (currentLanguage === "zh" ? "当前不宜牺牲太多上行空间。" : "Do not sacrifice too much upside here."),
	    breakout_risk: highGrowthAi || strongBreakout || entryLongAction === "strong_buy"
      ? (currentLanguage === "zh" ? "突破风险较高，近价 Covered Call 容易限制上涨。" : "Breakout risk is elevated; near-strike covered calls can cap upside.")
      : (currentLanguage === "zh" ? "突破风险中性。" : "Breakout risk is neutral."),
    risk_level: callRisk,
    risk_level_label: optionRiskLevelLabel(callRisk),
    confidence: callConfidence,
    based_on: uniqueText([
      ...(callChoice?.sources || []),
      marketRegime,
      qqqOverextended ? "QQQ overextended" : null,
      highGrowthAi ? "AI / High Growth" : null,
	      `position:${positionActions.join("/")}`,
      optionFallbackNote,
    ]),
    avoid_conditions: callAvoidConditions,
    market_context_notes: uniqueText([
      marketRegime === "overheated" ? (currentLanguage === "zh" ? "情绪过热时 Covered Call 吸引力提高。" : "Overheated sentiment improves covered-call appeal.") : null,
      qqqOverextended ? (currentLanguage === "zh" ? "QQQ 过度延伸时，可以更重视保护利润。" : "QQQ overextension increases profit-protection value.") : null,
      optionFallbackNote,
    ]),
    plans: [30, 45].map((dte, index) => {
      const dteTarget = index === 0
        ? callPreferred
        : Math.max(callPreferred ?? price, midSell.high ?? resistanceLevels[2]?.price ?? (Number.isFinite(price) && Number.isFinite(atr) ? price + atr * 1.5 : callPreferred));
      const strike = Number.isFinite(dteTarget) ? snapToOptionStrike(dteTarget, price) : null;
      return {
        dte,
        suggested_strike: strike,
        risk_level: callRisk,
        assignment_risk: callRisk,
        reason: strike == null
          ? t("dataUnavailable")
          : (currentLanguage === "zh"
            ? `${dte}D Covered Call 参考 ${uniqueText(callChoice?.sources || [], 3).join(" / ") || "卖出区间 / 压力位"}，用于持仓收租或保护利润。${optionFallbackNote || ""}`
            : `${dte}D covered call references ${uniqueText(callChoice?.sources || [], 3).join(" / ") || "sell ranges / resistance"} for income or profit protection. ${optionFallbackNote || ""}`),
        sources: uniqueText(callChoice?.sources || []),
      };
    }),
  };
  const confidence = clamp(Math.round(mean([sellPutPlan.confidence, coveredCallPlan.confidence].filter(Number.isFinite)) ?? 50), 0, 95);
  return {
    options_data_status: optionsDataStatus,
    options_state: optionsState,
    sell_put_plan: sellPutPlan,
    covered_call_plan: coveredCallPlan,
    gamma_flip: gammaFlip,
    confidence,
    explanation: currentLanguage === "zh"
      ? `${optionsAvailable ? "期权链可用" : "期权链暂不可用，使用技术位 fallback"}；策略综合买入区间、卖出区间、支撑压力、ATR、量能、基本面和市场环境。Gamma Flip 仅在真实 GEX 数据可靠时显示。`
      : `${optionsAvailable ? "Option chain available" : "Option chain unavailable; using technical fallback"}; plan blends buy ranges, sell ranges, S/R, ATR, volume, fundamentals, and market context. Gamma flip is shown only with reliable GEX data.`,
  };
}

function marketEventLabel(type) {
  const map = {
    fed_rate_hike: currentLanguage === "zh" ? "美联储加息" : "Fed Rate Hike",
    fed_rate_cut: currentLanguage === "zh" ? "美联储降息" : "Fed Rate Cut",
    fed_hawkish: currentLanguage === "zh" ? "美联储偏鹰" : "Fed Hawkish",
    fed_dovish: currentLanguage === "zh" ? "美联储偏鸽" : "Fed Dovish",
    cpi_hot: currentLanguage === "zh" ? "通胀偏热" : "Hot CPI",
    cpi_cool: currentLanguage === "zh" ? "通胀降温" : "Cool CPI",
    jobs_hot: currentLanguage === "zh" ? "就业偏热" : "Hot Jobs",
    jobs_weak: currentLanguage === "zh" ? "就业转弱" : "Weak Jobs",
    tariff_risk: currentLanguage === "zh" ? "关税风险" : "Tariff Risk",
    war_geopolitical_risk: currentLanguage === "zh" ? "地缘风险" : "Geopolitical Risk",
    oil_price_spike: currentLanguage === "zh" ? "油价冲击" : "Oil Price Spike",
    bank_stress: currentLanguage === "zh" ? "银行压力" : "Bank Stress",
    government_shutdown: currentLanguage === "zh" ? "政府停摆风险" : "Government Shutdown",
    debt_ceiling_risk: currentLanguage === "zh" ? "债务上限风险" : "Debt Ceiling Risk",
  };
  return map[type] || type || t("dataUnavailable");
}

function marketRegimeLabel(regime) {
  if (regime === "risk_on") return currentLanguage === "zh" ? "偏进攻" : "Risk-On";
  if (regime === "risk_off") return currentLanguage === "zh" ? "偏防守" : "Risk-Off";
  return currentLanguage === "zh" ? "中性" : "Neutral";
}

function hasAnyTag(tags = [], candidates = []) {
  return candidates.some((tag) => tags.includes(tag));
}

function midFearGreedContribution(label) {
  if (label === "Extreme Fear") return -2;
  if (label === "Fear") return -1;
  if (label === "Greed") return -1;
  if (label === "Extreme Greed") return -3;
  return 0;
}

const MARKET_CONTEXT_PROFILE_WEIGHTS = {
  software_cloud: { vix: 0.25, fear_greed: 0.15, ten_year_yield: 0.25, spy_trend: 0.15, qqq_trend: 0.20 },
  platform_ads: { vix: 0.25, fear_greed: 0.20, ten_year_yield: 0.20, spy_trend: 0.15, qqq_trend: 0.20 },
  ai_infrastructure: { vix: 0.25, fear_greed: 0.15, ten_year_yield: 0.25, spy_trend: 0.10, qqq_trend: 0.25 },
  memory_cycle: { vix: 0.20, fear_greed: 0.15, ten_year_yield: 0.15, spy_trend: 0.25, qqq_trend: 0.25 },
  reit_dividend: { vix: 0.15, fear_greed: 0.10, ten_year_yield: 0.45, spy_trend: 0.25, qqq_trend: 0.05 },
  healthcare_defensive: { vix: 0.20, fear_greed: 0.10, ten_year_yield: 0.15, spy_trend: 0.45, qqq_trend: 0.10 },
  high_growth_cyclical: { vix: 0.25, fear_greed: 0.15, ten_year_yield: 0.25, spy_trend: 0.10, qqq_trend: 0.25 },
  china_adr: { vix: 0.20, fear_greed: 0.20, ten_year_yield: 0.10, spy_trend: 0.25, qqq_trend: 0.25 },
  generic: { vix: 0.25, fear_greed: 0.15, ten_year_yield: 0.20, spy_trend: 0.20, qqq_trend: 0.20 },
};

const MARKET_CONTEXT_MODIFIER_RANGES = {
  software_cloud: { short: [-5, 4], mid: [-4, 4], long: [-3, 3] },
  platform_ads: { short: [-6, 4], mid: [-5, 4], long: [-3, 3] },
  ai_infrastructure: { short: [-8, 5], mid: [-6, 5], long: [-4, 4] },
  memory_cycle: { short: [-6, 5], mid: [-5, 5], long: [-4, 4] },
  reit_dividend: { short: [-8, 4], mid: [-8, 4], long: [-7, 4] },
  healthcare_defensive: { short: [-3, 3], mid: [-3, 3], long: [-2, 2] },
  high_growth_cyclical: { short: [-8, 5], mid: [-7, 5], long: [-5, 4] },
  china_adr: { short: [-8, 5], mid: [-7, 5], long: [-5, 4] },
  generic: { short: [-5, 4], mid: [-4, 4], long: [-3, 3] },
};

function normalizeYieldValue(value) {
  if (!Number.isFinite(value)) return null;
  return value > 15 ? Number((value / 10).toFixed(2)) : Number(value.toFixed(2));
}

function marketChangeValue(source, keys = []) {
  for (const key of keys) {
    const value = source?.[key];
    if (Number.isFinite(value)) return Number(value);
  }
  return null;
}

function vixRegime(value) {
  if (!Number.isFinite(value)) return null;
  if (value < 13) return "complacency";
  if (value < 18) return "normal";
  if (value < 25) return "elevated";
  if (value <= 35) return "risk_off";
  return "panic";
}

function fearGreedRegime(value, label = null) {
  if (label === "Extreme Fear") return "extreme_fear";
  if (label === "Fear") return "fear";
  if (label === "Greed") return "greed";
  if (label === "Extreme Greed") return "extreme_greed";
  if (!Number.isFinite(value)) return null;
  if (value <= 25) return "extreme_fear";
  if (value <= 45) return "fear";
  if (value <= 55) return "neutral";
  if (value <= 75) return "greed";
  return "extreme_greed";
}

function tenYearYieldRegime(value) {
  if (!Number.isFinite(value)) return null;
  if (value < 3.5) return "growth_friendly";
  if (value < 4.25) return "neutral";
  if (value <= 4.75) return "rate_pressure";
  return "high_rate_pressure";
}

function normalizeIndexTrend(raw = {}) {
  if (!raw) return null;
  const price = raw.price ?? raw.value ?? raw.last ?? null;
  const ma20 = raw.ma20 ?? raw.sma20 ?? null;
  const ma50 = raw.ma50 ?? raw.sma50 ?? null;
  const ma200 = raw.ma200 ?? raw.sma200 ?? null;
  const change20 = marketChangeValue(raw, ["change_20d_pct", "change20d_pct", "change_20d", "return_20d"]);
  let trend = raw.trend || raw.signal || "neutral";
  if (Number.isFinite(price) && Number.isFinite(ma20) && Number.isFinite(ma50) && Number.isFinite(change20)) {
    if (price > ma20 && ma20 > ma50 && change20 > 0) trend = "bullish";
    else if (price < ma20 && ma20 < ma50 && change20 < 0) trend = "bearish";
    else if (price > ma20 && ma20 < ma50) trend = "recovering";
    else trend = "neutral";
  }
  const overextended = Boolean(
    raw.overextended
    || (Number.isFinite(price) && Number.isFinite(ma20) && ma20 > 0 && ((price - ma20) / ma20) * 100 >= 6),
  );
  return {
    price: Number.isFinite(price) ? price : null,
    change_5d_pct: marketChangeValue(raw, ["change_5d_pct", "change5d_pct", "change_5d", "return_5d"]),
    change_20d_pct: change20,
    change_60d_pct: marketChangeValue(raw, ["change_60d_pct", "change60d_pct", "change_60d", "return_60d"]),
    change_120d_pct: marketChangeValue(raw, ["change_120d_pct", "change120d_pct", "change_120d", "return_120d"]),
    ma20: Number.isFinite(ma20) ? ma20 : null,
    ma50: Number.isFinite(ma50) ? ma50 : null,
    ma200: Number.isFinite(ma200) ? ma200 : null,
    trend,
    overextended,
  };
}

function normalizeEnhancedMarketContext(engine = {}, macro = {}) {
  const vixValue = engine.vix?.value ?? macro.vix ?? null;
  const fearValue = engine.fear_greed?.value ?? macro.fear_greed ?? null;
  const yieldValue = normalizeYieldValue(engine.ten_year_yield?.value ?? macro.treasury_yield ?? null);
  const spyTrend = normalizeIndexTrend(engine.equity_trend?.spy);
  const qqqTrend = normalizeIndexTrend(engine.equity_trend?.qqq);
  const vix = {
    value: Number.isFinite(vixValue) ? vixValue : null,
    change_1d_pct: marketChangeValue(engine.vix, ["change_1d_pct", "change1d_pct", "change_1d"]),
    change_5d_pct: marketChangeValue(engine.vix, ["change_5d_pct", "change5d_pct", "change_5d"]),
    change_20d_pct: marketChangeValue(engine.vix, ["change_20d_pct", "change20d_pct", "change_20d"]),
    percentile_1y: marketChangeValue(engine.vix, ["percentile_1y", "one_year_percentile", "percentile"]),
    regime: vixRegime(vixValue),
  };
  const fearGreed = {
    value: Number.isFinite(fearValue) ? fearValue : null,
    change_5d: marketChangeValue(engine.fear_greed, ["change_5d", "change_5d_pct", "change5d"]),
    change_20d: marketChangeValue(engine.fear_greed, ["change_20d", "change_20d_pct", "change20d"]),
    regime: fearGreedRegime(fearValue, engine.fear_greed?.label),
  };
  const tenYearYield = {
    value: yieldValue,
    change_5d_bps: marketChangeValue(engine.ten_year_yield, ["change_5d_bps", "change5d_bps"]),
    change_20d_bps: marketChangeValue(engine.ten_year_yield, ["change_20d_bps", "change20d_bps"]),
    change_60d_bps: marketChangeValue(engine.ten_year_yield, ["change_60d_bps", "change60d_bps"]),
    regime: tenYearYieldRegime(yieldValue),
  };
  const indicators = [
    vix.value != null,
    fearGreed.value != null,
    tenYearYield.value != null,
    spyTrend?.price != null || spyTrend?.trend,
    qqqTrend?.price != null || qqqTrend?.trend,
  ];
  const availableCount = indicators.filter(Boolean).length;
  const marketRegime = deriveMarketRegimeFromContext({ vix, fear_greed: fearGreed, ten_year_yield: tenYearYield, spy_trend: spyTrend, qqq_trend: qqqTrend }, engine.regime);
  return {
    vix,
    fear_greed: fearGreed,
    ten_year_yield: tenYearYield,
    spy_trend: spyTrend,
    qqq_trend: qqqTrend,
    market_regime: marketRegime,
    status: availableCount >= 4 ? "available" : availableCount > 0 ? "partial" : "unavailable",
    updated_at: engine.updated_at || macro.updated_at || null,
    available_count: availableCount,
  };
}

function deriveMarketRegimeFromContext(ctx, fallbackRegime = "neutral") {
  const vix = ctx.vix || {};
  const fg = ctx.fear_greed || {};
  const spy = ctx.spy_trend || {};
  const qqq = ctx.qqq_trend || {};
  const vixRising = (vix.change_1d_pct ?? 0) > 10 || (vix.change_5d_pct ?? 0) > 20 || (vix.change_20d_pct ?? 0) > 30;
  const vixFalling = (vix.change_5d_pct ?? 0) < -15 || (vix.change_20d_pct ?? 0) < -25;
  const anyBullish = spy.trend === "bullish" || qqq.trend === "bullish";
  const bothBearish = spy.trend === "bearish" && qqq.trend === "bearish";
  const overextended = spy.overextended || qqq.overextended;
  if (vix.regime === "panic" || (fg.regime === "extreme_fear" && bothBearish)) return "panic";
  if (fg.regime === "extreme_greed" && overextended && vix.regime === "complacency") return "overheated";
  if (["elevated", "risk_off"].includes(vix.regime) && (vixRising || bothBearish)) return "risk_off";
  if (["normal", "complacency"].includes(vix.regime) && (vixFalling || anyBullish) && fg.regime !== "extreme_greed") return "risk_on";
  return fallbackRegime || "neutral";
}

function marketContextWeightsForProfile(companyProfile = {}) {
  const profile = companyProfile?.decision_profile?.base_profile || companyProfile?.scoring_profile || "generic";
  return MARKET_CONTEXT_PROFILE_WEIGHTS[profile] || MARKET_CONTEXT_PROFILE_WEIGHTS.generic;
}

function marketModifierRangeForProfile(companyProfile = {}, horizon = "mid") {
  const profile = companyProfile?.decision_profile?.base_profile || companyProfile?.scoring_profile || "generic";
  return (MARKET_CONTEXT_MODIFIER_RANGES[profile] || MARKET_CONTEXT_MODIFIER_RANGES.generic)[horizon] || [-4, 4];
}

function scoreMarketFactorScores(ctx, horizon = "short") {
  const vix = ctx.vix || {};
  const fg = ctx.fear_greed || {};
  const tenYear = ctx.ten_year_yield || {};
  const spy = ctx.spy_trend || {};
  const qqq = ctx.qqq_trend || {};
  const vixEasing = (vix.change_5d_pct ?? 0) < -15 || (vix.change_20d_pct ?? 0) < -25;
  const vixSpike = (vix.change_1d_pct ?? 0) > 10 || (vix.change_5d_pct ?? 0) > 20;
  const factor = {
    vix: 0,
    fear_greed: 0,
    ten_year_yield: 0,
    spy_trend: 0,
    qqq_trend: 0,
  };
  if (vix.value != null) {
    factor.vix += vix.regime === "panic" ? -1 : vix.regime === "risk_off" ? -0.75 : vix.regime === "elevated" ? -0.35 : vix.regime === "normal" ? 0.1 : -0.15;
    if (vixSpike) factor.vix -= horizon === "short" ? 0.45 : 0.25;
    if (vixEasing) factor.vix += horizon === "long" ? 0.35 : 0.25;
  }
  if (fg.value != null) {
    if (fg.regime === "extreme_fear") factor.fear_greed += horizon === "long" ? 0.45 : -0.35;
    else if (fg.regime === "fear") factor.fear_greed += horizon === "long" ? 0.2 : -0.1;
    else if (fg.regime === "greed") factor.fear_greed -= horizon === "short" ? 0.2 : 0.05;
    else if (fg.regime === "extreme_greed") factor.fear_greed -= horizon === "short" ? 0.65 : horizon === "mid" ? 0.35 : 0.15;
    if ((fg.change_5d ?? 0) > 8 && ["extreme_fear", "fear"].includes(fg.regime)) factor.fear_greed += 0.2;
  }
  if (tenYear.value != null) {
    factor.ten_year_yield += tenYear.regime === "high_rate_pressure" ? -0.7 : tenYear.regime === "rate_pressure" ? -0.35 : tenYear.regime === "growth_friendly" ? 0.25 : 0;
    if ((tenYear.change_5d_bps ?? 0) >= 15) factor.ten_year_yield -= horizon === "short" ? 0.45 : 0.25;
    if ((tenYear.change_20d_bps ?? 0) >= 30) factor.ten_year_yield -= horizon === "long" ? 0.25 : 0.35;
    if ((tenYear.change_60d_bps ?? 0) >= 50) factor.ten_year_yield -= horizon === "long" ? 0.4 : 0.15;
    if ((tenYear.change_5d_bps ?? 0) <= -15 || (tenYear.change_20d_bps ?? 0) <= -30) factor.ten_year_yield += 0.35;
  }
  const trendScore = (trend) => {
    if (trend === "bullish") return 0.55;
    if (trend === "recovering") return 0.3;
    if (trend === "bearish") return -0.55;
    return 0;
  };
  if (spy.trend) {
    factor.spy_trend += trendScore(spy.trend);
    if (horizon === "short" && spy.overextended) factor.spy_trend -= 0.25;
    if (horizon === "long" && (spy.change_60d_pct ?? 0) < -8 && vixEasing) factor.spy_trend += 0.2;
  }
  if (qqq.trend) {
    factor.qqq_trend += trendScore(qqq.trend);
    if (horizon === "short" && qqq.overextended) factor.qqq_trend -= 0.3;
    if (horizon === "long" && (qqq.change_60d_pct ?? 0) < -10 && vixEasing) factor.qqq_trend += 0.25;
  }
  return Object.fromEntries(Object.entries(factor).map(([key, value]) => [key, clamp(value, -1, 1)]));
}

function buildMarketContextImpact(companyProfile = {}, marketContext = {}, horizon = "mid") {
  const ctx = marketContext.enhanced_context || normalizeEnhancedMarketContext(marketContext.market_engine || {}, marketContext.macro || {});
  const baseWeights = marketContextWeightsForProfile(companyProfile);
  const factorScores = scoreMarketFactorScores(ctx, horizon);
  const availableEntries = Object.entries(baseWeights).filter(([key]) => {
    if (key === "vix") return ctx.vix?.value != null;
    if (key === "fear_greed") return ctx.fear_greed?.value != null;
    if (key === "ten_year_yield") return ctx.ten_year_yield?.value != null;
    if (key === "spy_trend") return ctx.spy_trend?.trend != null;
    if (key === "qqq_trend") return ctx.qqq_trend?.trend != null;
    return false;
  });
  const totalWeight = availableEntries.reduce((sum, [, weight]) => sum + weight, 0);
  const usedWeights = totalWeight > 0
    ? Object.fromEntries(availableEntries.map(([key, weight]) => [key, Number((weight / totalWeight).toFixed(4))]))
    : {};
  const weightedSignal = Object.entries(usedWeights).reduce((sum, [key, weight]) => sum + (factorScores[key] ?? 0) * weight, 0);
  const [minMod, maxMod] = marketModifierRangeForProfile(companyProfile, horizon);
  const modifier = totalWeight > 0
    ? Number((weightedSignal >= 0 ? weightedSignal * maxMod : Math.abs(weightedSignal) * minMod).toFixed(1))
    : 0;
  const drivers = [];
  const warnings = [];
  if (ctx.vix?.regime) {
    const text = currentLanguage === "zh" ? `VIX ${ctx.vix.value ?? "N/A"}，状态 ${ctx.vix.regime}` : `VIX ${ctx.vix.value ?? "N/A"} regime ${ctx.vix.regime}`;
    (factorScores.vix >= 0 ? drivers : warnings).push(text);
  }
  if (ctx.ten_year_yield?.regime) {
    const text = currentLanguage === "zh" ? `10Y ${ctx.ten_year_yield.value ?? "N/A"}%，状态 ${ctx.ten_year_yield.regime}` : `10Y ${ctx.ten_year_yield.value ?? "N/A"}% regime ${ctx.ten_year_yield.regime}`;
    (factorScores.ten_year_yield >= 0 ? drivers : warnings).push(text);
  }
  if (ctx.qqq_trend?.trend) {
    const text = currentLanguage === "zh" ? `QQQ 趋势 ${ctx.qqq_trend.trend}` : `QQQ trend ${ctx.qqq_trend.trend}`;
    (factorScores.qqq_trend >= 0 ? drivers : warnings).push(text);
  }
  if (ctx.spy_trend?.trend) {
    const text = currentLanguage === "zh" ? `SPY 趋势 ${ctx.spy_trend.trend}` : `SPY trend ${ctx.spy_trend.trend}`;
    (factorScores.spy_trend >= 0 ? drivers : warnings).push(text);
  }
  const confidence = Math.round(clamp((totalWeight || 0) * 100, 0, 100));
  return {
    market_regime: ctx.market_regime,
    profile_market_sensitivity: usedWeights,
    modifier,
    key_drivers: [...new Set(drivers)].slice(0, 4),
    warnings: [...new Set(warnings)].slice(0, 4),
    market_context_confidence: confidence,
    factor_scores: factorScores,
    missing_fields: Object.keys(baseWeights).filter((key) => usedWeights[key] == null),
  };
}

function marketRateSensitivity(companyProfile, row, engine, horizon) {
  const tags = companyProfile.tags || [];
  const metadataBlob = `${row.metadata?.sector || ""} ${row.metadata?.industry || ""}`.toLowerCase();
  const ratePressureActive =
    engine.ten_year_yield?.trend === "rising"
    || (engine.ten_year_yield?.change_5d_bps ?? 0) >= 10
    || (engine.ten_year_yield?.change_20d_bps ?? 0) >= 25;
  if (!ratePressureActive) {
    return { multiplier: 1, reason: null };
  }
  if (hasAnyTag(tags, ["REIT", "Dividend", "InterestRateSensitive"])) {
    return {
      multiplier: horizon === "short" ? 1.45 : horizon === "mid" ? 1.5 : 1.35,
      reason: currentLanguage === "zh"
        ? "REIT / 分红 / 利率敏感类型会放大利率环境影响。"
        : "REIT, dividend, and rate-sensitive profiles amplify the rates backdrop.",
    };
  }
  if (hasAnyTag(tags, ["HighMultiple", "Growth", "HighGrowth", "StoryStock", "Speculative", "UnprofitableGrowth"])) {
    return {
      multiplier: horizon === "short" ? 1.35 : horizon === "mid" ? 1.3 : 1.2,
      reason: currentLanguage === "zh"
        ? "高估值 / 成长 / 叙事股会放大利率与 Fed 影响。"
        : "High-multiple and growth profiles amplify Fed and yield sensitivity.",
    };
  }
  if (hasAnyTag(tags, ["MegaCap", "CashCow"])) {
    return {
      multiplier: horizon === "short" ? 0.75 : horizon === "mid" ? 0.8 : 0.65,
      reason: currentLanguage === "zh"
        ? "Mega Cap / Cash Cow 现金流更稳，对利率扰动相对更钝化。"
        : "Mega-cap and cash-cow profiles absorb rate shocks better than average.",
    };
  }
  if (/financial|bank|insurance|capital markets/.test(metadataBlob)) {
    return {
      multiplier: 0.95,
      reason: currentLanguage === "zh"
        ? "金融类公司对利率影响并不总是单边负面。"
        : "Financials do not react to rates in a purely negative way.",
    };
  }
  return { multiplier: 1, reason: null };
}

function marketProfileSpecialAdjustment(companyProfile, row, engine, horizon) {
  const tags = companyProfile.tags || [];
  const metadataBlob = `${row.metadata?.sector || ""} ${row.metadata?.industry || ""}`.toLowerCase();
  const vixShock = (engine.vix?.change_5d ?? 0) >= 2 || (engine.vix?.trend === "rising" && (engine.vix?.value ?? 0) >= 20);
  const risingYield = engine.ten_year_yield?.trend === "rising" || (engine.ten_year_yield?.change_5d_bps ?? 0) >= 10;
  let delta = 0;
  const reasons = [];

  if (/financial|bank|insurance|capital markets/.test(metadataBlob) && risingYield) {
    if (!vixShock) {
      delta += horizon === "long" ? 1 : 2;
      reasons.push(currentLanguage === "zh" ? "利率上升对金融股可能略有利，但在高波动环境下不会激进加分。" : "Higher rates can modestly help financials unless volatility is also spiking.");
    } else {
      delta -= 1;
      reasons.push(currentLanguage === "zh" ? "虽然利率上升可能利好净息差，但 VIX 上行意味着风险偏好下降。" : "Rates may help margins, but rising VIX offsets that benefit for financials.");
    }
  }

  return { delta, reasons };
}

function buildMarketContextHorizonBreakdown(horizon, companyProfile, row, engine, broadMacroNews) {
  const base = 50;
  const breakdown = engine.breakdown || {};
  const fearGreedContribution = horizon === "short"
    ? (breakdown.fear_greed_short ?? 0)
    : horizon === "mid"
      ? midFearGreedContribution(engine.fear_greed?.label)
      : (breakdown.fear_greed_long ?? 0);
  const rawYield = Number(breakdown.ten_year_yield ?? 0);
  const rawFed = 0;
  const sensitivity = marketRateSensitivity(companyProfile, row, engine, horizon);
  const rawRateBlock = rawYield + rawFed;
  const adjustedRateBlock = Number((rawRateBlock * sensitivity.multiplier).toFixed(1));
  const profileMultiplierDelta = Number((adjustedRateBlock - rawRateBlock).toFixed(1));
  const specialProfile = marketProfileSpecialAdjustment(companyProfile, row, engine, horizon);
  const macroNewsContribution = 0;
  const score = Math.round(clamp(
    base
      + Number(breakdown.vix ?? 0)
      + Number(breakdown.vix_momentum ?? 0)
      + fearGreedContribution
      + adjustedRateBlock
      + Number(breakdown.equity_trend ?? 0)
      + macroNewsContribution
      + specialProfile.delta,
    20,
    92,
  ));

  const reasons = [];
  if ((breakdown.vix ?? 0) < 0 || (breakdown.vix_momentum ?? 0) < 0) reasons.push(engine.vix?.impact);
  if (fearGreedContribution !== 0 && engine.fear_greed?.impact) reasons.push(engine.fear_greed.impact);
  if (rawRateBlock !== 0 && engine.ten_year_yield?.impact) reasons.push(engine.ten_year_yield.impact);
  if ((breakdown.equity_trend ?? 0) !== 0 && engine.equity_trend?.summary) reasons.push(engine.equity_trend.summary);
  if (sensitivity.reason && profileMultiplierDelta !== 0) reasons.push(sensitivity.reason);
  reasons.push(...specialProfile.reasons);

  return {
    base,
    vix: Number(breakdown.vix ?? 0),
    vix_momentum: Number(breakdown.vix_momentum ?? 0),
    fear_greed: fearGreedContribution,
    ten_year_yield: rawYield,
    fed_event: rawFed,
    equity_trend: Number(breakdown.equity_trend ?? 0),
    macro_news: macroNewsContribution,
    profile_multiplier: sensitivity.multiplier,
    profile_multiplier_delta: profileMultiplierDelta,
    profile_adjustment: specialProfile.delta,
    profile_reason: [sensitivity.reason, ...specialProfile.reasons].filter(Boolean).join(" · "),
    final_score: score,
    reason: [...new Set(reasons.filter(Boolean))].slice(0, 4).join(" · "),
  };
}

