          <div class="detail-line-note">${currentLanguage === "zh" ? "主要原因" : "Main Reasons"}: ${(invalidItems || []).slice(0, 3).map(localizedDashboardText).join(" / ") || (currentLanguage === "zh" ? "趋势结构不足" : "Trend structure is insufficient")}</div>
